begin;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('d3f8263a-3b7a-509c-b94e-6f0dd453445d', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-07', '17:30:00', null, '通常 / ジャンピングゲーム', 'やる気満々にジャンピングゲームを作りに来てくれました。まずは前回の終わりのジャンプを復習して、コスチュームの変化をつけれ行きました。自分で早すぎきるコス変化に何秒待つを入れて、修正できていました。障害物の動きでは、前に習ったことあるかと思ってノーヒントで渡しましたが、「まで繰り返す」にたどり着けていませんでした。ただ、x座標での演算式は不等号のヒントを上げれば、作れていました。その後は、自分で調整して適切な難易度のゲームが作れていました。このままだと基本操作コースの幹事なので、prgの変数に挟んだやつまで進めていきたいです', null, null),
  ('4eb6bf6d-ba58-59f8-b4aa-a19f26f59d8b', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-07', '17:30:00', null, '通常 / 自由制作の続き', '前回終わらなかった最後のボス戦（？）みたいなところを完成させようとしていましたが、途中で、ゲームクリアのさせ方を変更することにしました。ボスがクイズを出して、それに対して正しい回答ができたらゲームクリア（もといた時代に戻る）、間違ったらゲームオーバーみたいな感じにしたようです。ほぼ、そのスクリプトは作成させたようですが、まだ完全に終わっていないようなので、来週が最終仕上げになるのかなと思います。', null, null),
  ('189be8a9-c591-568a-aa10-84fedb3294cf', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-07', '17:30:00', null, '通常 / エクセル', '今までExcelに触れたことがなかったので、興味がかなり沸いていました。ショートカットや繰り返し操作の動きを教えていくと、かなり感動していきました。操作の不慣れさでクリックを押し間違いなどはあるが、練習問題では関数どもに使いこなせていました。余った時間でほかの書式などもいじっていて興味度がかなり高まっていました。', null, null),
  ('1875acf3-2153-5848-9623-c435ff127e42', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-07', '17:30:00', null, '通常 / 基本操作コース04 追跡ゲーム', '追跡ゲームを作成してもらいました。最初は与えられた課題をスムーズに簡単にこなしていましたが、最後の方のレベルアップという項目でつっかかり、ヘルプを求めてきました。変数「スコア」の値がある一定値になったら、レベルアップの処理をする物ですが、だいぶ時間をかけて考えてもどうすればよいかわからないとのことだったので、「〜まで待つ」というのを使うというヒントを与えて先に進めるようになりました。「〜まで待つ」の使い方がわからなかったり、思い浮かばない人が結構多いので、次回、この部分だけでもまずは、復習した方が良いのかなと思います。', null, 'タイピング: タイピングは飽きたから今日はやらないとのこと'),
  ('a341a807-e87b-5d2b-9932-a7b26df3695d', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-07', '18:40:00', null, '通常 / エクセル演習', '右下の繰り返し動作のクリックは覚えていましたが、shiftやctrlなど範囲選択、ショートカットキー、桁区切り、は忘れていました。右下クリックが最重要なので、そこから徐々に覚えてもらったいいです。速さ面でいうと、問題１のフォントや書式設定に時間がかかっていました。それで、問題2の関数はすぐできていましたが、授業終了でした。まだ、触れていないグラフのところができなかったので、次回です。場所がわからない所はすぐ聞いてくれるのでいいです。', null, null),
  ('53d1d5c2-1059-5dfb-aa2d-1d375bb5ac21', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-07', '18:40:00', null, '通常 / Excel演習', '手を止めることなく、作業はできていますが、若干ゆったりです。そこで、抽出の問題で、わからなかったそうでしたが、みずき君の対応していて、一人で迷い進んでいたそうです。次回はそこから見直しを', null, null),
  ('74131bbe-0ba1-5b7d-86e6-c8d91bcbd43c', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-03-08', '17:30:00', null, '通常 / 自由制作', '餅つきゲームの続きを作成していきました。残っていたスコア部分と終わりの部分についてアイデアは構想することができていたようなので、作成はスムーズに進めていくことができました。プログラム面ではつまることなく順調に進めていましたが、デザイン面で思いついたものをどんどん入れていったため、時間がかかってしまいましたが本人の満足のいくものが出来上がった様子でした。あと少し修正を加えていきたいと言っていたので、最初の時間は修正を行い、その後に別の課題へと取り組んでいきたいです。', null, null),
  ('4f22598c-07b3-5168-9b09-cbc2256268d2', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-08', null, null, '通常 / 検定１級準備', '今回が１級問題の２回目ということで、１級の難易度に慣れている最中なのだと感じました。間違ってしまった箇所の特徴として、記述内容が曖昧な部分に関してはかなり悩んでいるようで、今まで明確なことしか書いていなかった音大部分に突如現れた曖昧な表記に苦戦しているようです。しかし、その部分を差し引いても80点ほどは獲得できる内容となっていたため、ひたすら練習を積んでいくことで慣れていきながら成長を促していくことが最適であると思います。', null, '時間帯: その他'),
  ('a4615317-2744-5ce7-902c-2b47bfe53ec5', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-08', null, null, '通常 / 検定１級対策', '検定１級準備２回目。前回のGold➀は、ちょっと難しくて６０点取れるたかどうか微妙な感じでしたが、今回のgold②は、100点ではありませんが、特に質問等何もなく80点以上で合格できるくらいの手応えはあったと思います。検定１級対策のために、できれば、定義、クローン、リストの見直しをしておいてねと言っておきました。', null, '時間帯: その他'),
  ('931db728-bc84-5156-b938-722c138f8da2', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-08', null, null, '通常 / 自由製作つづき', '背景スクロールと登場人物のコスチュームチェンジのタイミングを主に調整しました。背景スクロールは二重でプログラムを書いていた部分があったので訂正をしたり、スクロールのタイミングを調整したりしました。白紙が存在していたので、スクロールの仕組みを説明しつつ調整をしました。大まかな考え方の部分は繰り返し説明しました。次にクリア条件を設定していました。コインを集めてクリアを目指すそうです。コインの動きが完成していないので、次回は続きをやりたいそうです。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('9a247256-c05d-573a-b910-66f47ce63bf4', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-03-08', '17:30:00', null, '通常 / Excel実技練習問題１', '前回のExcelにて基本的な操作は学んでいたため、頻出されている問題部分についてはしっかりと特ことができていました。しかし、Roundなどの関数部分についてはどれがどのような働きをしているのかをあまり理解できていないようでしたので、繰り返しおこなって覚える必要があると感じました。最後の印刷部分に関しては、ほとんど触れたことがなかったようで困惑していましたが、説明しながら一緒に進めていったところなんとなくではありますが理解することができていたようです。次回以降も模擬問題を問題を解答していき、慣れていくことが重要となってくるのではないかと感じました。', null, null),
  ('d218a921-6e79-5aa5-9ae5-e802fa958f15', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-08', null, null, '通常 / 検定問題_S011(2級初回)', '前回検定をやったことはよく覚えていて、スムーズに取り組むことができました。前半、「ずつ変える」「にする」を間違えていてうまく進まなかったそうですが、自分で悩みつつしっかり時間内に最後まで取り組めました！とてもよくできていて、細かなケアレスミスがひとつありました。プログラムの修正前のブログラムがそのまま残っていたので、必要ないことを伝えました。アレンジはあまり取り組む時間がありませんでしたが、自分でイメージできていてとても良かったです。', null, '時間帯: その他'),
  ('c35aad68-d7ed-5f28-b32d-cfe2cbfd5b43', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-08', null, null, '通常 / あるくんの冒険-レベル2', 'オリジナル作品は前回で完成しました。マリオみたいなゲームを作りたいそうなので、今日はジャンプの方法を増やすという目的で、あるくんの冒険2に動画を見ながら挑戦してもらいました。丁寧に取り組んでいました。動画の質問にも自分で考えてきちんと正答できていました！すごい！！最後まで完成しました！アレンジはしませんでしたが、台の上でジャンプをできる理屈を理解できていて良かったです！', null, '時間帯: その他
タイピング: 最初にタイピングを練習する意義を聞かれたので、遠くの人に簡単にすぐ連絡できることを紹介しました。「電話でいいじゃん！！」ともいわれましたが、ちょーーーっとは理解してくれた様子です。 次回からはしっかりタイピングの練習したいそうなので、時間をとった方が良いかもしれません。'),
  ('1db433ff-7d77-583e-b58f-099938bab4e9', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-08', null, null, '通常 / ジャンプゲームを作りたかったが、オリジナルゲームに', '前回まで取り組んでいたオリジナルゲームが完成し、ジャンプゲームに取り掛かりました。ゲームとしてかなり面白かったようです。y座標の「～にする」と「～ずつかえる」を混同していたので、解説しましたが、理解できたかどうかは分かりません。「～回繰り返す」を使うとジャンプしているように見えることを紹介したのですが、移動距離が大きすぎて画面の端から端までスプライトが動くようになりました。その光景が面白かったようで、その後はアレンジしつつジャンプのみをプログラムしていきました。楽しそうで良かったです。 次回はちゃんと内容に入ることを伝えました。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('c0faeb7e-eddb-5667-81cb-77742bfd36cf', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-08', null, null, '通常 / 検定対策', '初めての検定対策だったので、最初、問題の解き方に戸惑っていて、３級の最初の問題とはいえ、少し時間がかかっていました。ただ、途中で問題の解き方のコツがわかってきたのか、急にスピードアップしてギリギリ時間内に終了。１００点でした。次回は２級問題を解く。で良いと思います。', null, '時間帯: その他'),
  ('9076e409-7f93-5553-90f9-91b626fa75fc', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-08', null, null, '通常 / Scratchの作品', 'あまりやる気がない？というか興味がない状態になっていました。ジオメトリーダッシュや、その他のゲームなとをいくつか勧めたり、卒業がてらひとつ作品をつくることを提案したのですが、どれも気が向かなかったようです。ただ手は動かないものの、プログラムについては会話をし、ジオメトリーダッシュの主人公の消え方や、ときどき起こるバグの仕組みなどについて考察をしました。次回からは完全にロブロックスに移るようです。', null, '時間帯: その他'),
  ('845584f9-4a88-5c5f-9b19-074d21977f4d', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-08', null, null, '通常 / オリジナル作品', '自分で素材からプログラムまで完全に一人で作っているようです。スプライトもアルスパークの画面のみで作っているそうです。定義などを使ってプログラムがかなり複雑になっていたので、かなり大きく困ったことがあれば授業後に先生に相談→次の授業のときにプログラムを変更＆解決の流れにすることを提案しました。休憩せずにずっとやっていたのでびっくりしました...', null, '時間帯: その他'),
  ('9eb3da09-2a0c-5ecb-8e70-fa6e9d679d9c', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-08', null, null, '通常 / 検定対策', '２級の問題に少し苦戦していたようです。途中どうしてもわからないところを質問されました。「点数は◯点だよ」と２秒いうというスクリプトを「○と○」を使って表現できなかったようです。「点数は」「○」「点だよ」という３つに分かれているので、「○と○」を入れ子で二つ使う必要があることを説明して納得してくれました。ただ、この問題自体は、時間内に終わらせることができずに、答え合わせもできていない状態ですので、次回は答え合わせからする必要があると思います。', null, '時間帯: その他'),
  ('3e41b8af-b6cc-508f-ab57-fcbe745ec5fa', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-08', null, null, '通常 / スキルチェックを兼ねて単元別演習', '条件分岐の演習を一番最初から行いました。基本的には、条件分岐のスクリプトを何もアドバイスしなくても、スラスラとかけています。ちょっと気になるところがあるとすれば、日本語の問題をきちんと最後まで読んでなくて、ささっとスクリプトは書くけど、問題文通りの動きが再現できていないことです。検定だと減点ですね。ただ、この辺の基礎スキル自体は問題なくて、出された問題を解くだけでなく、アレンジして簡単なゲームを作っていました。', null, '時間帯: その他'),
  ('def5226a-40d2-5623-bdef-c992e3357d68', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-08', '17:30:00', null, '通常 / イラストコースガイダンス、1章①顔のアタリ~④瞳', '直近の制作物として、学校の出し物にミニキャラを作って3Dでモデリングしたいとのことで、イラストに意欲的な姿が見られました。 ただ、絵のモチベーションを上げたいため、3Dに繋がりそうな背景よりはキャラコースを選択したいとのことでした。 アイビスではツールの使い方は合成レイヤー以外は知っていました。 ただ描く機会は今まであまりなかったらしく、綺麗な線を描くのに苦戦していたので 対象定規を使うことや、一気に線を描かずはらうように描くことをアドバイスしました。 生徒さんに描いてもらうにあたって、高さを出すために台があった方がいいかもしれないと感じました。', null, 'タイピング: なし'),
  ('28c7c19f-fab7-596d-bec8-062a25f33a88', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-03-08', '16:30:00', null, '通常 / 単元Aの続き', '前回の続きで、A-4から始めていきました。特定の色を踏んだ際にボールの色も変化するという問題で、色が変わらないと苦戦していましたがスポイト機能を覚えた後はスラスラと解いていくことができました。A-5においても、先ほどのスポイトツールを使うことで、色での判定をしっかりとこなすことができていました。残り時間で、A-4をアレンジしていきました。色を増やしたり、ボールの動きや速度を変えたりと幅広い動きを自分で考えて実行することができていました。', null, 'タイピング: ミスをしないように集中して取り組めていました。'),
  ('d7b022fa-ccdd-525b-a204-863b3df11d05', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-03-10', '17:30:00', null, '通常 / Excelの続き', '前回まで作成していた模擬問題の続きで、表やグラフの作成を行なっていきました。やったことのない部分が多かったようですが、一度教えればしっかりと覚えて次に進むことができたため、印刷の設定部分まで教えることができました。復習として一人でグラフを作成させたところ、完璧に作り上げることができたため、しっかりと知識を定着させることができていました。', null, null),
  ('89b27786-ddf6-5331-bc5e-4ebeb6af9b97', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-10', '17:30:00', null, '通常 / 検定問題に慣れる', '検定の準備はやる気で来てくれたようで、授業時間になったら「すぐに問題をやる」と自分から申し出ていました。 問題の冒頭で、対象のスプライトに既にたくさんのコードがあること、問題1問目の「旗が押されたときの動作」で、どこのコードにつなげればよいのか混乱していたので、とにかく問題文の指示通りにすること、どこかのコードにつなげたり修正したりする場合は問題文に書いてあるため、この問題の場合は新規に作成すればよいことを伝えると、ちょっとスッキリしたようで、そこからはおとなしく問題に集中していました。 途中で「意外とできるかも」と嬉しそうにコメントしたりもしましたが、30分ほど熱心に取り組んでいました。 最後の2問の意味がわからなかったようで質問してきたため、問題文の通りにするためにはブロックの位置が今のままでよいのかというヒントを出すと、直すことができていました。 引数のブロックの使い方がわからなかったようで、コスチュームがSTARTとFINISHに切り替わらずに混乱していたため、引数ブロックの使い方を教えました。 上記の3回のヒントで無事に解き終えることができ、とても自信がついたようでした！ 残り時間はのんびりとアレンジを楽しんでいました。', null, '盛り上がり: 今日の問題を自力で最後までできたことが、とても自信につながったようで、100点を目指したいという意欲も戻ってきたようでした。'),
  ('08f3a93c-c682-5864-ac02-7172b2788a93', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-10', '17:30:00', null, '通常 / 基本操作コース02、デジタル水族館', '※遅刻していたため30分後ろ倒しでスタートしています。 基本操作コース02では「踊らせよう」〜「あちこち動かそう」まで完了しました。 座標の概念を確認しながら、あちこち動かす方法を確認しました。 「1秒でここまで移動するのに座標を変える必要がある」ときちんと理解して取り組んでくれたようです。 色の効果についても、この後取り組んでもらった水族館でのアレンジに取り入れてもらえる程度には上手く使いこなせていたようでした。', null, 'タイピング: なし'),
  ('4bf552b2-59e3-5941-b00b-051039210267', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-03-10', '17:30:00', null, '通常 / オリジナルゲーム制作', 'ロブロックスを用いてオリジナルのゲームを制作していました。内容としては、TPSのシューティングゲームのようで、武器種やステージの制作を自身のアイデアを使って行なっていきました。アイデアは十分にあるようなので、次々と作品内に取り入れていき自分の思い描く作品に近づけることができている様子でした。', null, null),
  ('b7448dfd-eea1-5884-af60-bf79a343517a', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-10', '17:30:00', null, '通常 / 見た目の色々なブロックを学ぶ', 'メッセージの使い方、スタンプなどはしっかり覚えていて、どんなことをするのか説明を聞くとすぐに、自分から作成に入ることができていました。 明るさの効果、色の効果の変更なども、楽しんでできていました。 「さあ踊ろう」が完成したあとは、以前作成していた目白駅のプログラムを見直していて、「いつかこれの中央線バージョンを作りたい」と言っていました。 残り時間は横浜線、日光線、りんかい線などの駅名タイピングをとても熱心に楽しんでいました。', null, 'タイピング: 授業の終了時に少し時間が余ったので、マイタイピングの中の駅名タイピングを教えたところ、とても盛り上がって、色々な電車のタイピングを熱心にやっていました。
盛り上がり: 電車以外のプログラムも、きちんと頑張って取り組んでいましたが、その反動か、授業の終わりごろには電車熱が盛り上がって、熱心に電車について語りながらパソコンに向かっていました。'),
  ('f9a00c32-9c75-5bad-91cd-4d1124cddcd4', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-10', '17:30:00', null, '通常 / コード探求【ではないまで待つ】 レース順位ゲーム', 'ではないまで待つの仕組みについて、押しっぱなしでも進まない方法があるということに関心ていました。途中で詰まった部分などは特に無かった様子です。 授業終了の30分前に制作が終わったため、アレンジとしてレースに参加している動物のスプライトを自分で描いたキャラに置き換えることを提案しました。', null, 'タイピング: 集中して取り組めていました'),
  ('e9f24175-7698-5eea-8107-734d37c1fe1f', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-07', '16:30:00', null, '通常 / 教室のルールや授業に慣れる', '開始直後は他のことばかりが気になってしまって、りょうまくんをのぞきに行ったり入口のお寿司のミニチュアで遊んだりと、まったくPCに向かう気がなさそうでした…。 それでも、タイピングは良真君の話を聞いて「やってみよう」と思ったのか、一度スイッチが入ると熱心にキリの良いところまで進めようとしていました。 プログラミングについてもファイルを開いて見せて、「この表をスタンプで埋めたら楽しくゲームが作れるようになる」と話したところ、ゲーム作成ができるようになるということよりも、コンプリート欲がわいたのか、そこからはひたすら熱心に「次！」「次！」という感じで進めていきました。 スイッチが入りさえすれば、理解力もそこそこあり、勘も悪くありません。 授業終了後も、お迎えまでの待ち時間を遊ぶのではなく、次の課題を熱心に進めようとしていました。', null, 'タイピング: タイピングは初めてとのことでしたが、りょうまくんに刺激されたのか、頑張ってFGHJのキーを覚えようとしていました。表示色によって左右の手を使い分けることや、Enterキーを小指で打つことなど、こちらの指示を守ろうとする姿勢が見られました。
盛り上がり: スイッチが入ってからは、とにかく熱心に取り組んでいました。口ではわりと冷めたことを言ったりもしますが、そのわりには楽し気に、満足そうに課題をこなしていました。'),
  ('835e7584-a1fb-5c0d-a89b-c90d3ec83d3f', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-15', null, null, '通常 / 【体験】Scratchの基本操作を体験する', '教室1年目に見学に来たそうで、通えそうな年齢になったので体験にいらしたとのことでした。 Scratchやマウスは初めてとのことでしたが、こちらの話を一生懸命に聞いて、一つ一つコードができるたびに楽しそうに盛り上がってくれました。 マウスも初めに教えると、頑張って使おうとしていました。 各教材に対してとても丁寧に取り組めていました。大きさや速さを変えるアレンジや、コスチュームや背景を変えるアレンジ、どちらも楽しんでできていました。', null, '時間帯: その他
盛り上がり: 作成もアレンジも、とにかく楽しんで熱心にやってくれました。 授業終了後、「いちごの反乱」にとても盛り上がって、ギリギリまで遊んでいました。
備考: 鷺山塁くんと同じクラスだそうです。 お母さんからは、「引っ込み思案ですが慣れるとうるさいです。怖がりです。」とのこと。'),
  ('bdf12d6c-40fd-5fa8-b4b7-4a714d1fae57', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-11', '16:30:00', null, '通常 / バレーボール完成', '前回やっていたことは終わったので、prgのゲームから興味のあるものを選んでもらいました。ただ普通に作るより積極的にアレンジをしたいとのことでそうしました。ゲーム自体は面白いが難易度が低いので難しくしていました。対戦相手が使う道具を大きくすることに加え、クローンを使って複数のお邪魔オブジェクトを動かしていました。本体の動きとクローンの動きについて、自分でしっかり区別したうえで作れていました。面白かったようでかなり集中して作成していました。', null, 'タイピング: けっこう正確に打てていました'),
  ('10339a50-3c34-5b29-b333-7d2c1b6abcc1', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-11', '16:30:00', null, '通常 / バレーボール完成', 'だいたい作り終わってボールが跳ねる部分だけバグっていたので修正予定でしたが、おそらく前回リミックスを忘れたため、作ったものが保存されていませんでした。これからはリミックスしたかどうかの確認をしようねと促しました。次にバレーボールの完成版のコードを見て、ボールが跳ねる部分のコードを探してもらい、内容を理解してもらいました。変数「向き」で場合分けすることやジャンプに似た動きをすることを分かっていました。その後はリミックスしたあとアレンジを進めました。落ちるだけで跳ねさせられないダミーのボールを作るなどしていました。ゲームオーバーの動きを作る時は、「ボールが床に着いたら」という条件を、自分で考えながら座標で表現できていました。', null, 'タイピング: 何回か続けていました'),
  ('4e8cfde7-f952-5d75-b3f6-1fced9d7b6c1', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-13', '17:30:00', null, '通常 / コード探求【もし●●なら】 だるまさんがころんだ', 'アルくんの横移動までは自力で作成していましたが、「だるまさんが転んだ」を言わせるコード作成では「〜秒待つ」を使い、セリフを等間隔ごとに言わせようとして詰まっていました。乱数自体は昨年習っていましたが発想に無かったようなので、改めて乱数について説明しました。詰まったら実際のゲームに戻ってもらい、どこが違うのかをよく確認してもらいました。', null, 'タイピング: 集中して取り組めていました。'),
  ('6991271f-f6b3-5035-a7fb-fff5c6491f73', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-13', '17:30:00', null, '通常 / ジオメトリダッシュ続き', '前回の続きで、プレイヤーがジャンプした際、ブロックの上に乗った時にゲームオーバーになるバグの修正に取り組んでいました。しばらく考えて悩んでいたようですが、最終的に元のゲームと比較しながら自力で修正できたようです。 残り時間は少なかったですが、アレンジを提案するとプレイヤーを別のキャラに入れ替えてみようかと考えていました。', null, 'タイピング: 集中して取り組めていました。'),
  ('e7065825-107e-5782-8191-f6a0f15f051f', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-13', '17:30:00', null, '通常 / アルスタジオ/【Prg】21 アイテムで脱出ゲームを作ろう！', 'ステージ１→２への転換で、ステージが１になったままというバグが途中発生していたようです。ステージ番号の変数を打ち込めていなかったのが原因でした。他は動画を見ながら自力で作成ができていました。今回の時間で完成したようなので、次回はアレンジに進んでみても良さそうです。', null, 'タイピング: 集中して取り組んでいました。'),
  ('f11b6d03-c90d-5262-8fbe-755386fdf5c3', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-11', '16:30:00', null, '通常 / デジタル水族館アレンジ_ゲームっぽく', '本人の希望で前回作ったデジタル水族館をアレンジしました！～に触れたらを使ってゲームっぽくしました。楽しかったようです。 具体的には背景を変える、音を出す、スプライトの表示非表示を作りました。背景の設定の仕方と音の鳴らし方を紹介しました。ひとつのスプライトで作った後、他のスプライトには自分でプログラムを書いてもらいました。「次の背景にする」のブロックがなかなか覚えられない様子でした。他のブロックの使い方は徐々に慣れたようで、だんだん作業時間が短くなりました！！ 大きめに音がなると少し怖い？ようです。', null, 'タイピング: 初級に取り組みました。集中して取り組めました。'),
  ('07735aeb-6c85-5e78-ab5e-7d05a303d89a', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-11', '17:30:00', null, '通常 / 変数の使い方が初めて バレーボール＿ボールのバウンドについて', '以前は途中だったようで、むらっちの顔にボールが当たるようになっていたので修正しました。考え方はこちらが質問をすると、きちんと考えて答えてくれました！考え方は理解できていたようですが、プログラムを作るのは難しかったようです。今回は新しい変数の使い方に挑戦していることを伝えた後、いくつか使うブロックをヒントに出すと自分で進められました！！ただ既存のプログラムを今回作ったもので置き換える必要があったのですが、既存のものの論理構造を読み切れていなくてすこし時間がかかりました。 その後は制限時間をつけて（自力でできました）、ゲームクリアとゲームオーバーを作製しました。「〇点以下」のプログラムを作るのに苦戦していたのでアドバイスをしました！しっかり取り組めました！', null, 'タイピング: 集中して取り組めました。'),
  ('f6b330da-7307-53f6-bef6-32d1f0f807e2', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-13', '16:30:00', null, '通常 / アレンジ', '前回の作品をもっとアレンジしたいのことだったので進めていきました。最初のセレクト画面を追加したく、いろいろとスタートボタンなどを追加していきました。ボタンは推しカラーにしたり、熱中していました。次回は左右ボタン押したらキャラが左右にスライドして動く仕組みを作りたいそうです', null, 'タイピング: 寿司打にもはまっているようです'),
  ('816663c0-0b07-5d9b-a138-5e2cd168d3d6', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-13', '16:30:00', null, '通常 / 検定練習', '着々と問題を解き進めることができていましたが、数文か1文が長いところだと止まってしまう場面がみられました。その際は、区切り線を付けたらよく自力ですすめていけました。ただ、問題文がかなり長いので、途中で飽きてしまいました。それで、コスの色変化を加えたりしてました。敵のクローンのところは文章が難しいところもあるので、次回はそこを一緒に見に行ってほしいです。', null, null),
  ('804b647b-9e3e-5857-90f5-29ca02065e78', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-13', '17:30:00', null, '通常 / エクセル体験', '基本的にエクセルを知らなかったので、基本の四則演算、sum, average, max, min関数、書式せってい、列幅を教えていきました。 １つ１つ教えていくと、「おー」と驚きの表情をしてくれるので、すごさに共感してくれています。ほんとに最初だったので、練習問題では関数なんだっけと迷う場面もあり、ゆったり進んでいました。', null, null),
  ('2c07b5e7-d3fb-580c-b4a5-1181c22d5e80', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-13', '17:30:00', null, '通常 / Excel検定問題練習', '前回の続きをやっていきました。基本的に問題に対してスムーズに解き進めることができてました。関数に関しては無駄操作なく作れています。ただ、罫線の引く作業に関してはまだおぼつかない感じです。印刷設定の設問があったので、そこで、レイアウトの設定方法も教えていきました。印刷メニューが異なる場所にあるので、迷っていました。 問題文のウィンドウをクリックで切り返していたいたので、tab+altでのショートカットキーを教えてあげると、結構活用してくれました。', null, null),
  ('149a1d2c-8b2e-54de-9beb-240fb353657a', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-14', '16:30:00', null, '通常 / 自由製作', '過去に作り残ったものを完成させることにしました。ジャンプアクションがうまくいかずに頓挫にしたものを形にしていきました。自然落下とジャンプが組み合わさっていないことがバグになっていました。そこで、バイクランの仕組みを紹介したところ、自分でかみ砕いて、適することができました。回転しながらジャンプゲームになったので、見ごたえあるものができました。', null, null),
  ('0fbc8e6f-10af-5144-b1ac-41c0d20dd4e1', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-14', '17:30:00', null, '通常 / 検定練習', 'やっている最中は、スクラッチで音楽を流しながら、作っていき、途中問題文の長さに切れながら、飽きれながらやって1通りは問題は解きました。だが、バグは残り、もう嫌だな名勘定になっていました。一緒に見直したところ、主語と目的語のブロックが入れ子になっている個所が何個か見られました。変数をコス番号にするところをコス番号を変数にしていました。また、修正の個所で「ずつかわる」と「になる」が変わっていないところも多くありました。ほかは、リストを利用した構造がうまくできいないのがありました。 上から2つのことは落ち着けば直ると思うので頑張ってほしい', null, null),
  ('b353fd6f-7c6f-50ff-9dcd-85cdc1b5ed4a', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-14', '17:30:00', null, '通常 / 検定練習', '今回はクローンの問題だったが、本体に作るコードクローンに作るコードかが地続きになって場面がみられました。また、四則演算を用いた組み合わせた座標指定がなかなか上手くいかず悩んでいました。何個か組み合わさったコードを扱うのが苦手かもしれません。あいまにイラストのアレンジに走ってしまい3ページの②で終わりました。', null, null),
  ('d037d3ce-a65b-57ef-8ead-8c99f0555157', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-14', '17:30:00', null, '通常 / 作品完成', '今回は、クイズに出す内容に悩んでいました。ちゃんと作品は完成させたい思いはあるので、ないがしろにせずにかなり悩んでいました。そこで、自らブレストカードを使ってアイデアをひねり出していました。本会のブレストカードで対戦しながらする場面も見られました（笑）複数門は出来上がったので、完成できたかどうか確認をしてみてください', null, 'タイピング: 早です'),
  ('1c07a262-0dca-5c73-85a6-f11149703ee1', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-14', '18:40:00', null, '通常 / ジャンプゲームを作ろう', 'まずはジャンプの基礎をもう一度振り返って、見てみました。ジャンプからの解像度はなかなか贖いが、なんとなく程度に振り替えられました。障害物として蛇を登場して、「まで繰り返す」の仕組みを教えました。繰り返し出てることには喜んでいました。できた時かなりシビアな難易度だったので、動きを調節したり、蛇の数を減らしたりして、ゲームバランスを調整してできていました。本人的には満足して完成はできていました。', null, '盛り上がり: ブレストカードの出し合いしながらの対戦がうまくストーリーを作れていてうまかったです。'),
  ('02991f25-fd5d-5085-9200-53edef9f6573', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-15', null, null, '通常 / 初レッスン', 'レッスン最初にいつもタイピングをしていることを伝え、実際に最初にプレイグラムをしてもらった。タイピングはそこそこできるようです。基本操作コース２を全部完了させました。スクラッチは初めてだったと思うので、スプライトのクリックで色が変わったり、動いたりするだけで、喜んでいて反応が良かったです。最後にx座標とy座標について（画面の真ん中が(0,0)右に行けばXがプラス、上に行けばYがプラス等）説明しましたが、駆け足で説明時間が短かかったのもあるかもしれませんが、完全に理解できていないような感じでした。とはいえ、全体的には、飲み込みは良いかなと思いますし、ずっと集中できていましたし、楽しんでいる感じでしたので、良かったと思います。レッスン始まったばかりなので、基本操作コースを進めていくので良いのかなと思います。', null, '時間帯: その他
タイピング: タイピングは結構できるようです。集中して取り組みました'),
  ('6816d478-5954-5c4c-aa3d-cfc0d8c06f43', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-15', null, null, '通常 / 自由制作', '今日で終わらせる予定が、バグに悩まされて完了させることができませんでした。スクリプト同士でのイベントメッセージのやり取りが複雑になっていて、バグの解決に時間がかかってしまいました。まだ低学年なので、バグが起こりにくくわかりやすいスクリプトを書くのは難しいと思いますが、少しずつこういう点も考慮して教えていきたいと思います。 現在、過去１、過去２、未来１、未来２があって、それぞれでミニゲームをクリアすることでゲーム終了とする予定でしたが、過去２、未来２は削除して、次回は未来１のミニゲームを作って、このゲーム制作を終了させたいとのことです。', null, '時間帯: その他'),
  ('3952b6d1-4ed9-51ff-a369-dd8a44932111', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-15', '17:30:00', null, '通常 / 基本操作コース10キャッチゲーム', '03 キャッチするまで 一番上からりんごが降ってくるから〜と何度か説明しましたが、作ったり遊んだりするのに夢中で理解してもらうのに時間がかかりました。 ヒントを出しながら本人に考えてもらいましたが最終的に写していました。 ただ写すだけでなく、改めて何故このコードなのかを説明してあげると理解してくれました 矢印キーでカゴを複製する辺りは簡単だったようで、本人の中でやりたいアレンジなどが強いらしく授業が終わった後も続けてやろうとしていました', null, 'タイピング: なし'),
  ('4fc9d02c-8eb2-5f21-a8fa-4fea6fa1aa03', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-17', '17:30:00', null, '通常 / コード探求【ではないまで待つ】 レース順位ゲーム キャラクターをオリジナルに置きかえ 完成したら、イラストコースの模写レッスン', 'アルスタジオで背景の画像を透過してアップロードする、スプライトを差し替える方法を教えました。 授業中は眠たそうだったので少し雑談を交えて制作をさせました。 完成後、残り時間は鉛筆を使ってメガネのデッサンに挑戦してもらいました。 描くときの角度を再現するのが難しかったようで、かなり苦戦していました。 制作後はどこが難しかったのか、どうしたらうまく書けそうかを一緒に話し合いました。', null, 'タイピング: 集中して取り組めていました。'),
  ('f8e95905-349e-5b93-b463-fe2855bec5cb', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-17', '16:30:00', null, '通常 / スプライトの動きを考えながら、手順に沿って作成することに慣れる', '開始後10分くらいは、自由制作で岳くんが作成したゲームをクリアするまでやめない！と遊んでいましたが、唐突に切り替えて授業モードになりました。 教材のゲーム自体はかなり面白かったようで、盛り上がって何度もプレイしていました。 岳くんとは対照的に、手順に沿って進めたいという意志がハッキリしていて、手順書をよく見て長いコードでも途中で投げ出さず、熱心に写そうとしていました。写経していく中で、このコードでは何をしているのか、などを話しながら進めたため、スプライト名や大きさなど、オリジナルに変えたところでもとまどわずにうまく置き換えができていました。 背景のゲームオーバーのみ着手できませんでしたが、ゲームとして動くようになり、ダイヤの代わりのパンサーの画像効果に大喜びしていました。', null, '盛り上がり: 今日から1年生が3人になり、全員マイクラが好きなためか、授業前後にかなり楽しそうに遊んでいました。授業でも、40分間は集中して、しっかりと手順書と自分の作成したコードを見比べながら進めることができ、完成まであきらめずに取り組むことができていました。達成感も味わえたようでした。'),
  ('3428c422-087f-5f81-bff0-734b8754867e', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-17', '16:30:00', null, '通常 / スプライトの動きを考えながら、手順に沿って作成することに慣れる', '開始後10分くらいは、自由制作で作成したゲームを熱心にプレイしていましたが、唐突に切り替えて授業モードになりました。 教材のゲーム自体はかなり面白かったようで、盛り上がって何度もプレイしていました。 勇作くんとは対照的に、ゲームの動きからどんなコードになるのか考えて自分でわかるところから作成していくタイプで、手順書は見ずに、細分化した状態のコードを作成してはつなげていく手法で進めていました。個々のコードは意外と的を射ていて、なかなかのセンスが見受けられました。 一方で、感覚的に作成していくため、細かいところ（どこまでを条件分岐の中に入れるか、変数や見た目ブロックの初期値の設定など）がやや適当で、うまく動かないと質問してくるところもありました。', null, '盛り上がり: 勇作君とは全く違ったアプローチながら、ゲームの完成まで持っていくことができて、とても満足そうでした。'),
  ('e0542f91-cf8c-5f33-b6b4-e4f76296fc2e', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-17', '17:30:00', null, '通常 / ロブロックス', 'ロブロックスで教材をやろうという提案もしましたが、やはり先週に続きロブロックスの自由作成をしました。建物や道路などを配置して街を作っていました。置いた物体の大きさや高さを変えるなどして調整もしていました。', null, null),
  ('99ed471f-2f47-5541-a78f-586aa5a2d38f', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-17', '17:30:00', null, '通常 / 「～まで待つ」の使い方と、メッセージの活用を学ぶ', 'ゲームをプレイして、1キーが押されるまでは2、3キーを押しても動かないようにするためにはどうすればよいか、一緒に考えながら進めました。 単純に「数字キーが押されたとき」で作成するのではなく、メッセージと「まで待つ」を使うことを意識した上で、自分で一から作成させてみましたが、最初のヒントで納得できたようで、途中からはノーヒントで自力で完成させることができました。 スロットマシーン自体も面白かったようで、何度もプレイしなおしていました。 課題が一つクリアできたので、後半は自作の目白駅ゲームの作りこみをしていました。改札音を追加して、場面が途中で変わるようにしたり、駅の件騒音を自作して駅らしい雰囲気にしたりと、楽しそうに作成していました。', null, 'タイピング: 前回やった駅名タイピングが気に入ったようで、八高線などの駅名タイピングを楽しそうにやっていました。
盛り上がり: 授業の課題も自由作成も、どちらも楽しそうに取り組めていました。'),
  ('be5fae05-c48f-53b6-9809-1f7a058e1938', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-17', '16:30:00', null, '通常 / ゲームを作る楽しさを体験してもらいながら、基本のブロックを学ぶ', '追跡ゲームを作り、楽しく取り組みました。アルスタジオで細分化されたものを見せながら作りましたが、ある程度自分の中で細分化のイメージはできていたようでした。必要な「ずっと」ブロックを忘れることもありましたが、きちんと動いていないことがわかるとその都度気づくことができていました。x座標とy座標、「～ずつ変える」「～にする」など、座標に関して紛らわしい部分もきちんと理解できていました。今回はスコアで変数と等式を初めて使いましたが、内容を速く飲み込めていました。ブロックを配置する順番を間違えているときもありましたが、どういう順番で動いてほしいか問いかけると考えて修正できていました。クリアの処理までできてゲームは完成しました。', null, '盛り上がり: 1年生3人が同じ机で盛り上がっていました。'),
  ('86ea4e10-7f90-530f-8b6e-d3a802a85f7b', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-17', '17:30:00', null, '通常 / 検定練習', '検定練習をしました。引数を使ったブロック定義は初めてとのことだったので使い方を説明するとすぐに理解してその部分を作成できていました。かなり時間を残して一通り解き終わりテストプレイをしたのですが、キャラの着地ができず全く動かなかったようでした。バグの内容をもとに違っているコードの当たりをつけようという話をしてみましたが、バグ探しは嫌という様子だったので答え合わせに入りました。しかしミスは長めの数式のちょっとした入力間違いくらいでした。そのため、ゲームがあまり動かない状況でも少しバグを直せばきちんと直ることもあることを伝えました。また、検定本番で100点を取ったら追加のおこづかいがもらえるとのことだったので、そのためにも時間が余ったら見直すことを促しました。', null, null),
  ('abecb4fb-7778-59ca-a314-e64f97397f90', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-17', '17:30:00', null, '通常 / Excelの模擬問題を自力で解いてみる', 'Excel自体に結構やる気があるようで、模擬問題も「やってみたい」とのことで、すぐに取りかかっていました。 途中でIF関数の書き方に悩んでいたため、論理式の書き方と、何も返さない("")を教えましたが、あとは自力で50分くらいで完成させていました。 本人は、グラフ内のフォントサイズを変えるところでかなり悩んだそうですが、最終的には自己解決できたとのことでした。 時間内に問題を解けているので、何度か練習をし、3年生の1学期のうちに検定を受けてみようという話をしました。', null, '盛り上がり: Excelの操作にもかなり慣れてきて、熱心に取り組めていました。 手ごたえも感じているようで、検定受験にもやる気を見せていました。'),
  ('305037a7-c537-531c-840d-b61e4aa46e59', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-14', '16:30:00', null, '通常 / 基本操作コースのスタンプコンプリートを目指す。', '今日はシューティング系のゲームが作りたいとのことだったので、きょうざいやさんの「シューティングゲーム」を使用しました。 要くんのアイディアを形にするために、矢印キーでスプライトを動かす、弾丸がキャラクターから発射されるようにする方法（○○へ行く、と、表示非表示の切り替え）、スコアの作成などを一緒に学習していきました。 やりたいこと、アイディアがどんどん出るため、最終的に、クローンまで使用しましたが、熱心にこちらの説明を聞いて、臆することなく作成をしていました。 最終的に、なかなかおもしろいゾンビゲームになりました。', null, 'タイピング: 今日はすぐにプログラミングの気分だとのことで、省略
盛り上がり: 自分のアイディアがどんどん形になっていくのがとても楽しそうでした。
備考: 学校で友達に作品を見せたいとのことで、Scratchへのログイン方法を教えてあげる予定です。'),
  ('53db9d04-ca1b-582d-bd4c-95a4accf1821', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-18', '17:30:00', null, '通常 / 変数の使い方', '前回までのバレーボールで、「向き」によってキャラの動きを変えるという変数の使い方を復習しました。その後の走り幅跳びゲームの製作中で、右キーと左キーが押されたことをそれぞれ変数で管理したときは、バレーボールの向き変数に似た特別な使いかたであることを理解してもらいました。ジャンプ作成の際は、変数を使った放物ジャンプを以前もやったことを思い出して、内容を把握することができました。コード内容に対して問いかけをすると積極的にリアクションを取りながら進めてくれて、完成までできました。', null, 'タイピング: 頑張っていました
盛り上がり: 今日の最初は眠くてやる気が出ないとのことだったので、少しやったところで数分間寝てもらうとそのあとはとても集中できました。'),
  ('e15c6817-b9a5-5bde-b8a0-7521f3fbbb90', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-18', '16:30:00', null, '通常 / 乱数', '前回ダイヤのゲームで「(スプライト)に向ける」と「～度に向ける」を間違えて使っていたので違いを整理しました。そのあと、渦巻き効果を使ったゲームオーバーの演出をやって完成しました。アレンジする気はなく次のゲーム制作に行きたいとのことだったのでモンスターハントに入りました。前回使った乱数をここで応用していることを伝えてつながりを意識してもらおうとしましたが、乱数の概念自体の理解が曖昧なようでした。毎回違う数字にしたいときに乱数を使うといいことは伝えました。', null, null),
  ('6e17a13e-23e4-5c4d-bc43-8ff6f1acc551', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-18', '16:30:00', null, '通常 / 基本操作コース', '前回までの水族館の製作を続けました。前回コスチュームの変更をコードで行いましたが、忘れてしまったようなので復習しました。コスチューム関連でやりたいことは終わったと言うので、他の基本操作コースの内容に基づいて魚の角度や大きさを変えることを勧めましたが、興味がないと言っていました。その代わり、色の効果を使ってスプライトの色をずっと変え続けるのは面白そうにやってくれました。', null, null),
  ('ea582243-bbf7-547e-8550-4951e3677a89', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-14', '17:30:00', null, '通常 / シューティングゲームを作れるようになる', '前回作成していたジャンプゲームは満足のいくところまでできたとのことで、今日はシューティングゲームを作りたいという希望により、宇宙バトル3にチャレンジしました。 「クローン」という少し上級のスキルを使って、弾が発射されるのを面白くしようという目標に興味を持ち、素直にレッスンに取り組んでいました。 上下の動きなどは、さすがに自力で作成できていました。 レッスン通りに作成してから、敵の動きの角度などをいろいろと変えて楽しんでいました。', null, '盛り上がり: ゲームを作る、ということが楽しいようで、今日は希望通りのシューティングゲームを作り上げることができ、満足そうでした。'),
  ('4ea9221e-71e7-5ad9-ab4c-b8d3f830692a', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-14', '18:40:00', null, '通常 / Excel検定対策', '授業ではもうExcelは終わってしまったそうですが、熱心に課題に向かっていました。 一通りの操作は覚えていたようでしたが、問題の中に「個人合計」と「合計」という似た名前のセルがあり、問題文を読み飛ばしていたために混乱していました。問題文中のセル番地や名前などはしっかり読むように伝えました。 順位に使うRANK.EQ関数と、フィルタの使用が初めてだったため、説明をしました。 他の部分はほぼ自力で解くことができ、検定受験にも前向きなようでした。', null, '盛り上がり: 雑談をしながらExcelの問題に取り組むのは楽しいのか、終始機嫌よく取り組めていました。'),
  ('1ce54aa1-612b-5c3a-bde2-1cdf38b8b813', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-14', '18:40:00', null, '通常 / クローンや横スクロールの復習', '今日はジオメトリーダッシュ（簡単プログラムVer）_完成版の残像スプライトを用いて、前回学習したクローンの復習を予定していましたが、授業開始早々に「クローンは疲れた」と言ってきたので、残像ではなく横スクロールの復習に切り替えました。 課題を提示すると乗り気になってくれて、スクロールにもクローンが使用されることは嫌がらず、お手本の「【小技】簡単な横スクロール② 完成版 クローンを使う」を参照しながら黙々と作成していました。 x座標が〇まで繰り返す、のところで+-が逆になっていたため、スクロールがおかしいと悩んでいましたが、自力で間違いを見つけて修正することができました。 スクロール部分の作成が完成した後は、スプライトのコスチュームを編集して楽しんでいました。', null, '盛り上がり: 最初にゲームをプレイしたときは、「これを作るの～？」とちょっと引いていましたが、作成する箇所とお手本を明確にしたらやる気になって頑張っていました。 隔週のせいか、時間内に作り終わるくらいの課題の方がやる気が出るようでした。'),
  ('16ec5c48-04ff-58f7-88da-1c3b267a0727', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-13', '16:30:00', null, '通常 / ジオメトリーダッシュアレンジ', '前回のゲームが完成かと思われましたが、まだやりたいことがあるとのことでアレンジを進めました。作ったゲームをこたろうくんと交換して遊ぶという約束をして、モチベーションができたようでした。氷の色に触れたらゲームオーバーということを利用して、その色でたくさんの障害物を描いていきました。通るのが難しいところの障害物は小さくしたり、見た目だけのダミー障害物を作ってみたりするなど、ゲームバランスを良くしようとしていました。', null, null),
  ('4451e7a8-204c-562b-bee9-2c1ce29325a2', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-13', '16:30:00', null, '通常 / ジオメトリーダッシュアレンジ', '前回はそこまでやる気がなかったようですが、今日作ったゲームを塁くんと交換して遊ぶという約束をしたところやる気になったようでした。難しく作って塁くんを苦戦させたいという気持ちでアレンジをしていきました。地面のスプライトの見た目を変えてみたり、邪魔するキャラクターがいくつも出てくるようにしていました。そのキャラに動きがあるともっといいねと伝えましたがそこまではできませんでした。', null, null),
  ('d87fce03-e177-534f-bf4f-63ad9c9213a3', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-13', '17:30:00', null, '通常 / 検定練習', '検定練習をしました。乱数ブロックを使うべきところで使えていなかったというミスはありましたが、それ以外はほぼできていました。前回は慣れておらず文章の読み落としやブロック構造の読み取りミスなどがありましたが、だんだん確実にできるようになってきています。', null, null),
  ('ba04a2f4-a9c2-5e8c-9121-8c7be083e80b', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-15', null, null, '通常 / 自由製作', 'スクロールするコインが一番左に行っても右に戻らないバグを修正しました。該当のコードの意味を一緒に理解しながら考えていきました。一番左に行ったときのx座標を確認し、x座標がどうなったら戻ればいいのかを考えてもらいました。このとき不等式の使い方についても理解を深めました。その後、3枚のコインを横の列に並べて連動させるのをしたいとのことでした。「1枚だけコインを動かして他のコインはついてくればいいね」とヒントは出しましたがあまりピンと来ていないようでした。「～に行く」ブロックを使うことは分かったようでしたが、その後の座標の調整で詰まっていました。', null, '時間帯: その他'),
  ('5f372095-da05-5fc4-a5ce-d9073ee18db8', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-15', null, null, '通常 / 演算の練習', '単元別演習で演算を扱いました。放物ジャンプについてスローモーションを見せると、段々遅くなったあと落ちるときは速くなってくることが分かっていました。ただそれを変数で表現するのは難しく、そもそも負の数の概念が曖昧なようでした。 その次の課題はコスチュームの変更によるカエルのジャンプでした。コスチュームを変える順番や、表示が一瞬すぎるため「～秒待つ」を使うことは理解できていました。ただそれを実装するときに、ブロックの順番が逆になったり、「もし～なら」と「ずっと」が入れ替わっていたりしました。 全体的に、細分化のイメージはできているもののそれをコードの細かい場所に反映するのが難しいという様子でした。', null, '時間帯: その他
タイピング: 英文タイピングを頑張っていました'),
  ('500ddd3a-a26f-54d8-b37f-8c53ffb77316', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-15', null, null, '通常 / 演算の練習', '単元別演習に取り組みました。「りんごとバナナ」ブロックは使いどころがよく分かっていました。タイマーや「聞いて待つ」は初めて扱いましたが飲み込みは速かったです。最初はタイマーを止める条件として等式を使っていましたが、ぴったりの時間にならず止まらないことがあると伝えると、今までの経験から考えて不等式に切り替えていました。時間にやや余裕を持って終わり、最後は自分の好きなゲームを作っていました。最近はよくミニゲームを作っているようです。', null, '時間帯: その他
タイピング: 今までココアタイピングでしたがplaygramを初めてやりました。難しい文が打てるのが楽しいようで、腕試しモードを熱心に続けていました。'),
  ('570f1bf9-c72e-5fd4-8dd4-5cdf958c67ca', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-21', '17:30:00', null, '通常 / 乱数・迷路チーズ', '前回の続きで追跡ゲームのクリア設定を頼むと「～まで待つ」を使ってとてもスムーズにプログラムできました。前回のを参考に作製したのかもしれませんが、使い方は分かっているのかな？と感じました。 次にサイコロのレッスンを一緒に見ながら乱数の使い方について解説しました。6割くらいは理解できているようです。その後、迷路チーズを作製しました。ミミのプログラムでは探すのブロックにある「～キーに触れたら」を使うようにリクエストしたところ、少し困っていた（ヒントを渡せばできた）ので、繰り返し動きについては練習した方がいいかな？と感じました。壁に跳ね返るプログラムは質問したり説明したりしましたが、イマイチ理解できなかったようです。チーズについてはおおよそよく考えてプログラム作製できました。', null, 'タイピング: 集中して取り組めました。'),
  ('803c64f7-2cd4-5216-9bc6-1d7dad5184a8', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-21', null, null, '振替 / ジャンプのスクリプトの理解続き', '１０分ほど遅刻してきて、いきなりのレッスンは嫌な感じみたいで、雑談＆ゲームを少ししてキリの良いところでレッスン開始。前回、アルくんの冒険２をやったとのことで、その続き物としてアルくんの冒険３を終わらせました。このところジャンプ系のものを連続でやっているので、その辺は徐々にわかってきたように思います。今日はあまりレッスンに集中してくれなかったのですが、こちらがレッスンに戻るように促すとイヤイヤながらも戻ってくれたので、なんとか一つのレッスンを終わらせることができました。最後に、タイピングが興味が出てきたという前回コメントを見て、タイピングを促したらやってくれました。', null, '時間帯: その他
タイピング: レッスン始時ではなく、最後の方に挑戦していました。まだ基礎のところですが、少しでもタイピングに対してのやる気が出てきたので良い傾向です'),
  ('bcc590b3-55a7-5a24-9778-086d3d6d4031', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-21', null, null, '通常 / クイズ問題', 'リストを使ったクイズ問題を作製しました。リストは苦手なようだったので、復習を含めて取り組みました。 正解or不正解の論理構造はおおよそ頭の中でできているようですが、それをプログラムで書くのが難しいようです。最初は自分で作ってもらい、その後一緒に確認しながら修正を加えてもらいました。問題は算数の計算問題です。「～と聞いて待つ」のブロックの存在もあまり覚えていないようでした。 繰り返し処理なので変数を使って書き換えるように提案しました。「5回繰り返す」のアイデアがすぐにでてきて良かったです。一方で変数の設定に苦戦していました。 冒頭ではクリアタイムがあったら面白いかもと提案しましたが、クリアタイムのプログラムはなしで完成しました。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('e0cd8599-816f-506d-8cf4-220079378d38', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-21', null, null, '通常 / Excel_3級模擬問題1', '集中して取り組めました。前半は問題なかったようですが、コピペの仕方（数式がそのまま移動されるor値のみが抽出される）とスパークラインの設定の仕方は一緒に確認しました。とくにコピペについてはセルをクリックして中身を比較するように伝えました。スパークラインについては挿入タブからうまく操作することができました（＄マークも適切に使えていました）おおよそ問題2まで終わっています。', null, '時間帯: その他'),
  ('e79d813f-b6e8-5f7b-a01c-1e70ac3a3d7a', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-21', '17:30:00', null, '通常 / Excel_3級模擬問題1 Excel2回目', '前回やったことをほぼ覚えていないようだったので、前半は一緒に取り組みました。入力方式はだんだんと思い出したようです。行と列の向きを誤解していたので、覚え方を含めて解説しました。関数の使い方はよく覚えていてROUND関数の使い方を一緒に確認しました。（桁数の設定など）問題2のスパークラインの部分は出来ていません。 最後にシフトとコントロールの便利な使い方について共有しました。', null, null),
  ('f60e1e06-912d-53a8-a65e-229b169819f8', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-21', '16:30:00', null, '通常 / 追跡ゲーム途中まで', '追跡ゲームはまあまあ気に入ったようで、スムーズに作製に入れました。キャラの右左上下のプログラムもよく覚えていて、矢印キーと座標変化のブロックの組み合わせにはつまずきましたが、その他はよくできました。敵の動きもスムーズにプログラムできました。（どこかの場所へ行くをよく覚えていました）スコアの初期化についてはあまり意識できていなかったので、前回の内容をふまえつつおさらいをしました。楽しそうで良かったです。 折り紙とレゴが好きなようです。細かくいろいろ教えてくれました！！', null, 'タイピング: 時間を割いてやりませんでしたが、作品名や変数名などタイピングは頑張っていました！'),
  ('8db19076-a2c0-5111-875b-578e5f0230fc', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-21', null, null, '通常 / ジャンピングゲームのアレンジ', '少し前に完成させたprg20のジャンピングゲームのアレンジをしたいとのことで（本当は別のものを提案したのですが）、ジャンプ周りの処理の復習になるし良いかと考え、アレンジをしてもらいました。実際には、アレンジというか、１から処理を作り始めていました。ですので、主人公のジャンプ処理、敵に触れた時に開始地点に移動させる処理、ゴールフラッグに触れた時のクリア処理の作成後に、敵の動きを変えたり、ゴールフラッグに移動を加えたりのアレンジをしていました。ちょっとアドバイスした程度で、自分の力でスクリプトを書いていたので、力はついてきたかなと感じます。', null, '時間帯: その他'),
  ('9e11516a-42c8-569b-9037-c17668e5eb50', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-21', null, null, '通常 / 検定準備', '検定１級問題に挑戦。途中様子を窺うと、全然わからないところで立ち止まっている様子。６割取れれば合格なので、わからないところを長時間考えずに次に進んでどんどん進めていった方が良いよと話しました。が、後にまた進捗を確認してみると、さほど進んでいない様子、似たようなところで長い時間考えて先に進めていない感じでした。結局制限時間内に、あまり回答できず、６０点には足りない状態、本人も全然ダメ、わからないという感想でした。わからない部分としては例えば、”...割った値を「切り下げて」６０をかけた値に..."という問題に対して、「切り下げて」をどう表現して良いかわからずだいぶ長い時間考え込んでいたようです。ただし、これは、スクリプトで「切り下げる」というものがあって、これを知っていレバすぐわかるし、知っていなければ解けないようなもの。わからないものは早く見切りをつけて次の問題を解けるよう強く意識づける必要がありそうです。', null, '時間帯: その他'),
  ('b23768f1-c08b-522f-a917-a410040e0c05', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-21', null, null, '通常 / ジャンプゲームの復習', '前回、前々回と作ったジャンプゲームの難易度を上げたりしてアレンジをしていました。ジャンプの処理をきちんと理解した上で、ジャンプの高さを変えたり速さを変えたり、敵の数を増やしたり大きくしたりして、より難しくなるように調整していました。その調整も、きちんと処理をわかっていないとできないので、きちんと理解した上でできていたので良かったです。レッスン最後の方は、キャラクタを変えたいとのことで、自作のキャラを作成していましたが、素晴らしいキャラでできたと思います。あさひくんはデザインセンスというか、キャラメイクのセンスはあるかもしれません。', null, '時間帯: その他
タイピング: 集中して取り組んでいました'),
  ('d599bc27-c6a9-554f-8240-dd9a2491705d', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-21', null, null, '通常 / エクセル練習', '集中して取り組んでいました。途中、列の挿入の仕方等、基本的な操作方法でわからない点があったようなので、その都度教えました。それ以外は、特にアドバイス等なしで黙々と進めていました。最後に練習問題２・問題３の（２）のところがわからないという質問を受けたところで時間になりました。次回はここの説明からスタートになると思います。', null, '時間帯: その他'),
  ('f5f4ac26-4808-531b-b70e-1a51f68258d0', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-03-15', null, null, '通常 / 検定問題１級応用課題１', '検定本番に向けて１級問題を引き続き行っていきました。内容についてすぐに理解することができ、制限時間を半分ほど残して終えることができていました。間違いなどをすることなく終えることができていたため、残った時間で見直しなどをすることでさらに難しい内容でもより高得点を狙えると感じました。レベルとしては十分なため、このまま経験を積んでいくことが重要ではないかと思います。', null, '時間帯: その他'),
  ('c8c9a9c2-d8fe-525e-bd06-c8749e53d1c0', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-03-15', null, null, '通常 / 検定問題１級応用課題１', '前回に引き続き１級問題をおこなっていきました。時間制限ギリギリでの終了となっていましたが、問題を間違うことなく完璧に解くことができていました。そのため、次回以降の検定問題ではスピードに関しても重視して取り組むことでさらに成長することができると思います。', null, '時間帯: その他'),
  ('ce94cf1d-2141-5849-89cf-528d475f4ed2', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-03-15', '16:30:00', null, '通常 / クイズRoblox！', 'Robloxの教材に今回初めて挑戦していきました。普段からRobloxで遊んでいるため、基礎部分は十分に行うことができていました。今回行っていた内容もかなり簡単であったようで、動画を見ながらスラスラと作っていくことができていました。この調子で次回も同じように作っていきつつ、メニュー部分などで分からない箇所があれば都度説明を行っていく方式で大丈夫だと思います。', null, null),
  ('9a2cba4a-4fda-5970-9a19-9b3dba91cf1b', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-03-15', '16:30:00', null, '通常 / Excel練習問題2', '前回に練習問題１をやっていたので、今回は練習問題の２に挑戦していきました。やっているときはスラスラと解けているように見えましたが、答え合わせをおこなって見ると解答漏れやミスが多く見られました。本人としては、最後まで終えたつもりのようでしたので確認を怠っている部分が本番でも大きく響いてしまうと感じました。そのため、問題を解いている際に抜けがないか時々確認しながら見直しを行う癖をつけた方があると思いました。', null, null),
  ('3a32748a-ad39-5a97-9bb6-78e4853f9590', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-22', null, null, '通常 / 座標の+と-の確認、変数を使ってだんだん速くする動きの確認', '授業開始直後は、マイクラのキャラを使ったプラットフォーマー的なゲームをしていて、なかなか切り替えができませんでしたが、ゲームに「クリア」が設定されていないことに気付くと、キリが良いところまで遊ぶことをあきらめて授業モードになりました。 座標については、横方向がxということをなんとなく覚えていたようでしたが、あらためてxとyの違い、中央が0ということを解説して実際にコードをいじって確認し、納得ができたようでした。 B-3のコードの書き方は覚えていて、「ずっと」を入れることも覚えていました。学校の授業で先生が「ずっと」の場所がわからなくて迷っていた時に教えてあげた、と得意そうに話していました。授業では一番詳しかった！とのことです。 課題を1つクリアするごとに、名前をつけて保存をし、スタンプを押すことでやる気が出てきたようで、今日はＢとＣを全部クリアする、と宣言し、集中して頑張っていました。 C-1では、前回のジャンプで速さを変数で変えたことを思い出しながら取り組ませました。のあくんもイメージが付きやすかったのか、何を作成するのか意識して取り組むことができました。変数の初期値の設定などは忘れがちでしたが、プログラムを動かすと気づくことができました。 C-1は少しアレンジをして、速さが200をこえたらだんだん遅くして止まる、というコードを付け加えてみました。この動きがとても気に入ったようで、面白がって何度も実行していました。 文字の入力がだいぶ慣れてきたためか、変数名やファイル名の入力を積極的にやっていました。 「もし～なら」と「～まで待つ」を併用しようとしたり、同じ類のコードをわざわざ別のスクリプトで書こうとしたりすることもありましたが、個々のコードは何をしているのかその都度考えるよう誘導していくことでだいぶ整理ができたようでした。', null, '時間帯: その他
タイピング: 今日は気分ではなかったそうです
盛り上がり: 課題を2つ終わらせることを目標にし、時間に余裕をもって終わらせることができたのが嬉しかったようでした。学校でプログラミングのヒーローになれたことも、モチベアップにつながったようでした。'),
  ('72b4ef88-8435-5891-bb6f-be63a9449dfe', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-22', null, null, '通常 / 自由制作の完成を目指す', '自分から、背景3つがうまく続けて出てこないバグを直したいのと、コインが3つ並んでて来るようにしたいという今日の課題を話してくれました。 背景については、メッセージの番号をやや適当に増やして入れていたせいで、メッセージ番号がきちんと一致していない箇所があったため、個々のコードの関係性を順番に見直していきました。最終的に、不必要だったメッセージが2つあり、番号をきちんと整理したため、うまく横スクロールができるようになりました。 コインが3つ連なって出るようにしたいというところでは、小技を使って残像を出す方法を学習しました。これはこれで面白がっていたのと、初めてクローンを使ったという満足感は得られたようでしたが、かんたろうくんが求める動きとは少し違うということで、コスチュームの編集でコインの数を変えるようにしてみました。 コインが減っていくのは魚に触れた側からにしたい、などのこだわりから、コスチュームの編集を工夫していました。', 'やりたいことを紙に書いて、ファイルの一番上にはさんであるので、それを解決できるよう誘導してください。', '時間帯: その他
タイピング: 数か月ぶりにタイピングスコアに記入しました。
盛り上がり: やりたいことがしっかりと頭の中にあり、それを自分の言葉で熱心に説明しようとしていました。一つずつ課題がクリアできるのが嬉しそうでした。'),
  ('1d9f2d40-2f72-55a1-9d46-bdfc66c379f6', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-22', null, null, '通常 / ロブロックス', '今回も進めていきましたが、やはり最初のステージの方は簡単に感じているようで、なかなかに動画を飛ばして確認テストをやっていきました。あまりにも動画を飛ばすので、実際にここではどんなことをやるのか説明してもらいました。答えることができていたので、よかったです。なんでこんな簡単からやるの？と聞かれたので、スクラッチから移行してきた子もすぐコードのプログラミングになれるように簡単なところからだから、だいきくんはモナカとかも触れているからその理解力はもうできてると言って納得してくれました。', null, '時間帯: その他'),
  ('ebfd81e0-d875-54dc-a053-d2ea4ce1ab31', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-22', '16:30:00', null, '通常 / キャラクターコース前回の復習＋模写', '今回は対象定規を使って正面からの顔を描いてもらいました。 髪型も前回とは違う見た目に変えてもらい、表情差分も描いてもらいました。 残りの時間で「漫画のキャラの特定のポーズが模写したい」とのことで、 ただネットで検索した画像をそのまま模写させるのはまずいと思い、ポーズを講師がスケッチし、それを模写する練習をしてもらいました。 ポーズの模写は普段描き慣れているのか、重心がしっかりとしたポーズが描けていてとてもよかったです。 次回はフィギュアを観察しながら模写してみたいと提案があったので、次会えるタイミングでまた声をかけてみようと思います。', null, 'タイピング: なし'),
  ('27d5f8d8-6da4-5b4d-80bd-b0e67804f270', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-22', '17:30:00', null, '通常 / キャラクターコース前回の復習（目の描き方）', '前回取り組んでくれた目の描き方を復習してもらいました。 前回よりスムーズに取り組んでくれて、教材と全く同じように模写してもらいました。 教材の解説や資料をよく見て取り組んでくれているようで、仕上がりもとても丁寧でよかったです。 残りの時間は模写以外にも、自分が好きな思った目の特徴をオリジナルで考えてみようと提案して途中まで制作してもらいました。', null, 'タイピング: なし'),
  ('4f811472-0aab-5b40-85ab-0c6be8338e1b', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-22', '16:30:00', null, '通常 / 検定練習', '基本的には２，３このミスくらいで合格県内です。切り捨てなども新しい要素も対応できていたので良かったです。ずつ増えるとになるの違いだけは気を付けてもらいたいです。', null, null),
  ('6c24c762-3493-514d-a47b-740830869629', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-22', null, null, '通常 / 自由製作', '全体的な細かいバグつぶしを行っていました。それにより弾を打った時の反動がうまく機能していました。目指している完成度まで85%程度まで進めることができているらしいので、のこりの球の種類の演出や遠近感を出すことをこだわる予定です。', null, '時間帯: その他'),
  ('5e5bf265-5090-580a-9ebd-63db606ada02', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-22', null, null, '通常 / ジャンプを通して定義を慣れよう', '定義に対して触れるためにアル君の冒険3をやっていきました。定義に関しては存在を知っていたが、あまり触れていなかったそうです。今回の動き「段差に上る」「下からの貫通登りを防ぐ」に発想のヒントを与えてあげれば大体はできていました。「下からの貫通登りを防ぐ」はチーズを探せのような仕組みの考えで近づけくれたが、少しの滞空がありました。なので、正規の途中で止めるやり方でscratchの定義特融の「繰り返し動作からの抜け出し」の有用性を教えてあげました。また、もとからあった台座の横から貫通してしまうバグを自力で上にあげる修正をできてすごかったです。アレンジで、ステージ全体が揺れる演習も加わり凝ったものになりました。', null, '時間帯: その他
タイピング: 集中して早めにやっていました。'),
  ('b85f5e28-cf27-5db9-8fad-cc5d85c9aad1', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2025-03-24', '17:30:00', null, '休み（未対象）', null, null, null),
  ('b4dd7817-a49c-51b7-b187-a492aa0b3856', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-24', '17:30:00', null, '通常 / 課題に従ってアレンジをする', '最初にコンテストにチャレンジしてから、ミッションにチャレンジするかExcelかを選ばせたところ、久しぶりにScratchをやってみたいとのことで、アレンジをしてもらいました。 素直にミッションに取り組んでいて、①と②はサクサクとクリアしていました。 ③については、池に一定時間いると、足が速くなるというギミックを作成していました。 アレンジを楽しめていたように見えました。', null, '盛り上がり: 着実にミッションをクリアしていて、集中して取り組んでいました。③のアレンジについても満足のいく出来になったのか、得意そうに説明してくれました。'),
  ('0d6f412a-bf7f-5c60-a755-afabfb3e7f12', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-24', '16:30:00', null, '通常 / たいよう君の逃走中オンラインv1.5 ーアレンジ（表示・非表示）', 'プレイをしてかなり気に入った様子でした。アレンジ内容もたくさん自分で考えられました。ゲームオーバーではなくハッピーエンドにしたいとのことだったので、メッセージ名も変えて新しいスプライトを作製しました。絵や文字を入れるのは慣れていないようだったので、詳しく説明しました。またタイミングよく出現させるために表示非表示のブロックの使い方を説明しました。また同様のブロックを使って、ハンターが20秒経ったら増えるようにしました。考え方はおおよそ理解できたようでうまく応用できました。また作品名・メッセージ名などのタイピングも頑張っていました！', null, null),
  ('c7fa7f45-3e81-58b6-bcf5-dfdb269f37e4', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-24', '17:30:00', null, '通常 / ・たいよう君の逃走中オンラインv1.5 --アレンジ（～または～） ・目白駅', '作品は少し気に入ったようです。ハンターのあたり判定を全員分作りました。「～に触れたら」を使ってプログラムを作ることを予想できていましたが、プログラムをどこに作るかはアドバイスをしました。このとき「～または～」の使い方について詳しく説明しました。並列の理解ができたかは分かりませんが、おおよそは理解できていました。その後ハンターが公園部分に入らないようにプログラムを作成しました。このときも「～または～」を使ってプログラムすることを提案しました。 その後は自分のオリジナル作品「目白駅」のメロディを作製しました。音の選び方、プログラムのきっかけについては自分でよく考えてプログラムすることができていました。', null, 'タイピング: 集中して取り組めました。'),
  ('b93b011d-a8e2-5421-a081-dedc815636bd', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-24', '17:30:00', null, '通常 / たいよう君の逃走中オンラインv1.5 --アレンジ（スイッチとしての変数）', 'あたり判定をハンター全員に作製していました。その後は少しアレンジ内容に悩んでいたようです。キーボードの長押しで変数が変化する仕組みを作っていました。「まで待つ」の方がシンプルで良いかな？と思いましたが、ずっとともしを使うことで長押しで変化する仕組みになっていました。よく考えられていてよいと思います。変数で何が変化するのかはまだ作っていません。 部活でかなり疲れていたようなので、時間の途中で思い切って仮眠をとることを進めました。次回もこの作品を進めるかは本人次第です。', null, null),
  ('e2ae75d3-b772-5197-8c5d-68ae7e8e2f2a', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-24', '17:30:00', null, '通常 / 検定準備をする', '授業時間まではコンテストチャレンジに盛り上がっていましたが、時間になったらすぐに「検定する」と切り替えていました。 問題自体は30分ほどで解き終わっていて、「左右に動かない」「穴を掘っても下にいかない」というバグ以外はできていると思う、との感想でした。実際のコードもざっとチェックした感じではしっかりできていました。 上記２つのバグは、いずれも色の指定ミスでした。濃い茶色と薄い茶色が違っていたりというミスだったため、本人もすぐに納得して修正できていました。', null, '盛り上がり: 最後にチャレンジした問題が納得のいく出来だったことで、自信もついたようでした。100点をとってお小遣いをもらう！と元気に帰っていきました。'),
  ('cb0d8f47-baf8-5236-98f7-beefbe8c266d', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-24', '16:30:00', null, '通常 / コンテスト_逃走中ゲームアレンジ', 'コード内でハンターがプレイヤーに触ってもゲームオーバーにならないバグがありましたが、そこはそのままで、背景のステージを変えるアレンジをしました。 最初は好きな色や図形を配置して作っていましたが、これだとそもそもプレイヤーやハンターが出てこなかったため、緑色がコードで反応するように枠線を配置したり、旗が押された時にガク君の作成したステージになるようイベントで指定した背景を一つずつ変える作業をしました。 今回でマウスカーソルで図形を選択すること、中身の色を塗りつぶさないで枠線を塗ることを知ることができました。', null, 'タイピング: なし'),
  ('b1afb21f-c782-554f-adab-f2a8f73e0f80', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-24', '17:30:00', null, '通常 / コンテスト_逃走中アレンジ', '今回はアレンジよりバグ修正がメインで、安置が出来ないように背景の図形を調節してもらったり、プレイヤーや逃走者がハンターに触れた時にゲームオーバーになるよう、演算と調べるのコードを使って修正してもらいました。 残りの時間はipadで自由に絵を描いて過ごしてもらいました。', null, 'タイピング: なし'),
  ('143bddb7-c43f-5036-8db8-eaab6865badb', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-24', '16:30:00', null, '通常 / ゲームのおかしいところを見つけて修正する', '授業時間前に試したコンテスト作品がとても気に入ったようで、授業でもこれをやりたい、となりました。 ゲームへの観察眼はとても優秀で、捕まる判定のないハンターが二人いることや、安全地帯があることに気が付いたのは勇作君でした。 安全地帯で記録を伸ばすことに集中してしまい、なかなか授業に入れなかったため、勇作君が気が付いたミッション①をクリア出来たら授業内容を好きなことにしようともちかけると、あっという間に修正箇所を見つけていました。集中力は長続きしませんが、瞬発力はなかなかあるタイプかと思われます。 今日は「または」の使い方を覚えよう、ということで、一緒にバグを修正した後、自力でハンターを6人に増やし、コードの修正をさせました。コードが横に長くなるので操作が少しやりづらそうでしたが、マウスを使った方がやりやすいことに気付き、マウス操作を頑張ってコードの修正をやり切ることができました。', null, 'タイピング: タイピングはやりたくない～、とのことでした
盛り上がり: ミッション①のクリアと、ハンターを増やすアレンジをした後は、岳くんやこうすけくんの作品を見に行ったり、ゲームの記録更新をして盛り上がったりと、授業に集中した時間は短かったですが、終始とても楽しそうでした。'),
  ('f18016d8-ecb9-5ef9-9b23-ed06c9aead6e', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-27', '16:30:00', null, '通常 / 逃走中のアレンジ', 'コンテストの作品の裏技を早くも見つけて、放置の時間が始まりました。りょうやくんは検定練習のせいもあってか、ほんのわずか比較的に自分から作る場面がみられました。アレンジのハンターがすべて機能するようにするコードでは、先生のコードを見られてしまったが、そのコードがどんなものだったか言葉にして説明するようにしてフォローをしました。はやり、ゲームエンドを変えたりして、あおるようなアレンジになりました。', null, null),
  ('6a4cbb19-25c3-585f-aa22-b74e39387b5a', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-27', '16:30:00', null, '通常 / 検定準備/1級②', '授業前にプレイしていた逃走中を引きずってしまい、集中力がかなり低かったです。午前中に集中する作業をしていたようで、それも影響していたようです。 変数の使い方について確認しました。またリストの使い方についてよく覚えていなかったので説明しました。概要だけ伝えるとその後自分でプログラムできていて良かったです。y座標の変化に演算が入るところは不安だったようで聞かれましたが、おおよそよく理解できていました。 完成はしませんでしたが、おおよそよくできていました。', null, null),
  ('90ba449a-bb4a-5e24-8e6b-345167de8dc2', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-27', '17:30:00', null, '通常 / コンテスト「たいよう君の逃走中オンラインv1.5」 プレイしてから、ミッション①②あたり', '集中して取り組めました！作品をとても気に入ったようです。あたり判定を増やすプログラムもリクエストすると自分で全部プログラムできました！時間差での出現もプログラムの中身を把握するように促がすと作製できました。ハンターの数を増やしたり、見た目をアレンジしたりして楽しんでいました。作品が好きなので(?)、検証にも進んで取り組めて良かったです。 クリア画面を作るように伝えましたが、あまり乗り気でなかったようで完成はしませんでした。本人はこれでも満足かな？と思いましたが、なにかリクエストがあれば次回も続けても良いと思います。', null, null),
  ('27097f8c-1c54-5aec-ae42-d86e7e85233d', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-27', '17:30:00', null, '通常 / 検定練習', '途中途中で試遊しながら進められていました。そのため、すぐにバグになっているところや違和感に気づくことができました。それでも、直せてない箇所があったので、答え合わせを一緒に見直すと、音の部分が間違っていました。「終わるまで鳴らす」が必要なところでなかったり、また逆もしかりで、すべてにつっかっていました。なので、本番にも音の部分を見直すようにアドバイスをしました。', null, null),
  ('06fe7442-1bba-5683-9655-2f54bbb67b5e', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-27', '17:30:00', null, '通常 / コード探求【もし〇〇なら】だるまさんがころんだなら', 'アルごんへの指示の出し方に苦戦していました。 コスチュームの向きを変える指示を出す際、どのタイミングで右向きにするかや、繰り返しの中に何を入れたら左を向いた後に右に戻ってくれそうか…などを考えるのが大変そうでした。途中、向きまではなんとか誘導しながら順番を組めたのですが、うまく動作することができませんでした。 原因となった「終わるまで音を鳴らす」のコードの意味を新しく学べたかと思います。 時間がまだ余っていたので、アルくんのコードで「もし〜なら」を使って右向きに移動するように作成をしました。', null, 'タイピング: 集中して取り組めていました'),
  ('8b3ae65f-fe75-56f8-b7f8-360d15fd73a0', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-27', '17:30:00', null, '通常 / 作品の修正とアレンジをする', 'Excelは難しいと言っていたので、今日は息抜きにコンテスト作品のミッションを勧めました。よくしゃべりながら、楽しそうに取り組んでいました。 ①と②はさすがにすぐにできていました。②ではクローンを使って大量放出をしていました。 ③については、初めはクリスタルを拾ったら10秒間無敵モードでハンターをたおせる、というギミックを作成していましたが、クローンの当たり判定がうまくいかずに断念して、HPを増やすギミックに変えてみると言って作成し始めたところで時間切れとなりました。', 'Excelは暗記が大変、と言っていたのですが、暗記というよりも慣れが必要だということを説明してあるので、Excelと今回の続きの半々くらいでもよいかもしれません。', 'タイピング: 授業後にやっていました
盛り上がり: 久しぶりのScratchは楽しそうで、いろいろとアイディアを話しながら作成していました。'),
  ('963cbb6e-5ade-5927-a3b4-130804f6e55b', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-22', null, null, '通常 / 検定準備 1級応用課題2', '時間内で一通り確認することができました。ブロック定義も自分でよく取り組めていました。念のため使い方については一緒に確認しました。制御の部分で2ミス。前半は明らかな読み飛ばし。2つ目は誤解でした。アレンジは時間がなく、取り組みませんでした。', null, '時間帯: その他'),
  ('bdf805d8-e1c7-5a02-938d-c11cc8893989', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-22', null, null, '通常 / 検定準備 1級応用課題2', '時間の都合で最後までできませんでした。ブロック定義の使い方に困っていたようなので、詳しく解説して使い方まで概要を説明しました。引数のところもいくつか使用例を説明するとおおよそ理解できた様子でした。他の部分で大きく詰まっている様子はあまりありませんでした。', null, '時間帯: その他'),
  ('fa695ea6-c61e-5372-ad17-99dbf1354be1', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-22', null, null, '通常 / 自由制作 未来1のミニゲーム作成をして完成', 'もちつきゲームの後に未来へ行けるように、過去へのボタンが表示されない問題を修正しました。先週自分で頑張ってもうまくいっていなくてかなり困っていたようなので、一緒にデバックしながら問題を考えたり修正案を考えたりしました。一度修正してからは気分が上向いてきたのか、修正してからはしっかり取り組めました。ずっと・もしを使ったプログラムを「まで待つ」を使って考え直すことを提案すると、他のものにも同じように応用して考えられていました。未来1は未来2のゲーム説明を行うことになり、未来2のゲームをプログラムを始めました。どういうときに未来2のゲームを始めるのか、「ずっと」の有効範囲に気を付けるなど、工夫が必要そうです。 ずっとの使い方をよく考えなきゃいけないフェーズに入っていそう。本人いわく「もし～でなければ～」の使い方がよく分かっていないそうです。 次回はゲーム内容を詳しく作製します。', null, '時間帯: その他
タイピング: 気乗りがしなかったようで、途中で終了'),
  ('02f958dc-fe73-55ff-83d1-c7f57509e54a', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-22', null, null, '通常 / キャッチゲーム続き', 'スコアのプログラムは自分で作製しましたが、よくできていました。もしの使い方もおおよそ理解できていました。落ちてくるものの表示非表示のプログラムが論理が通っていないが動いていましたが、それ以上深追いすることはありませんでした。得点が必ず入っているわけではないが、本人の満足度がかなり高かったので指摘しませんでした。次回以降しっかり調整するようにこそっと伝えました。クレジットカードを使うアイデアとゲーム終わりのプログラムもよく考えられていました。 プログラムを動かしたい気持ちが大きく、論理を飛び越えることがあるかも。他のと同じようにプログラム作るのは得意。やりたいことがなくてもこちらから少し助言するとすぐに想像が広がるタイプかな？と思いました。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('17d1b308-53ae-5a01-9884-1eb0b0afb877', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-22', null, null, '通常 / 検定受験確認、前回の見直し（検定2級①）', '30分ほど自分で取り組みましたが、その間は質問等はほとんどなしでした。右へ歩くときに座標でプログラムしていたので、問題文をよく見て「向く・歩く」と「座標」でコントロールすることを伝えました。また論理関係の部分で1ミス、変数設定の部分で質問をした後に変数を変更していたのでプログラムが動いていない部分がありました。身近なものに置き換えて考えるポイントを共有しました。', null, '時間帯: その他
タイピング: 集中して取り組めました'),
  ('b6f8774d-ee82-54ba-87dd-88bba9ac7dcd', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-25', '16:30:00', null, '振替 / 逃走中デバッグ、アレンジ', '前日に振替で同じテーマをやっていましたが、みんなにネタバレしないようにとお願いすると、当然と言って受け入れてくれました。まだデバッグが完成していない場所があったので、まずそこを無事に終えました。アレンジでは、マップを増やすことにチャレンジしていました。背景をいじるので、「どのときに、どの背景になるのか」を細分化してもらうとよくできていました。元のコードから背景を変えている場所を頑張って見つけ、自分の思う通りに変更することができました。', null, null),
  ('59ed1aa7-520c-5195-9260-fd542233ac8c', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-25', '16:30:00', null, '通常 / 逃走中デバッグ、アレンジ', 'バグ直し自体にはそこまで興味がなかったようですが、バグのあるスクリプトの場所を教えてそれを読んでもらうと、ハンター3や4が足りないことを理解することができました。今までと見た目の違う「または」ブロックを初めて使いましたが、いくつものブロックをパズルのように組み合わせるという操作を楽しんでやっていました。アレンジではスプライト複製のやり方を覚え、ハンターを大量に出して面白がっていました。', null, null),
  ('8dae5757-b6f9-54e4-b7c8-68d5384724bb', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-25', '16:30:00', null, '振替 / 逃走中デバッグ、アレンジ', 'ハンターが反応しないバグの直しで少し困っていましたが、当たり判定はどこのスプライトでやっているかを問いかけると、自分で答えを出せて、ハンター3と4の判定を追加できました。その後のアレンジ時間で、クローンを使ってスプライトをたくさん増やせることをしょうたくんに教えてもらっていました。実際に自分でクローンを作るには至りませんでしたが興味を持っていました。', null, null),
  ('3e2e6650-0933-5410-ade5-f3c475aef268', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-25', '16:30:00', null, '通常 / 逃走中デバッグ、アレンジ', '普段興味を持たないゲームも多い中で、このゲームは比較的楽しんで遊んでいました。ハンターのデバッグは簡単そうに終えていました。時間がたつごとに、見た目を変えた新しいハンターを順次放出することもできていました。', null, null),
  ('6ea50843-61d9-5ec4-89e1-f9b6737e2913', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-25', '16:30:00', null, '通常 / 逃走中デバッグ、アレンジ', 'デバッグに関しては、しばらく原因を探っていましたが一度気づくと「めっちゃ簡単」と言ってすぐに直せていました。アレンジではクローンを使って放射状にハンターを放出するということをしていました。クローンについては、興味を持ったのあくんに説明してあげていました。', null, null),
  ('f103a2b2-5189-5ae1-9090-127608668abd', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-25', '17:30:00', null, '通常 / 逃走中デバッグ、アレンジ', 'ハンターが反応しないバグの直しについて、「ハンターが猫に触れたら」という条件があると考えてハンターのコードを探していました。しかし実際は猫のコードに書かれていたので、「逆転の発想が必要」とヒントを出すとひらめいていました。 ハンターを大量に増やすにあたって、クローンを初めて使いました。最初はクローン関連のブロックの置きかたがごちゃごちゃでしたが、「クローンを作る→クローンされたときの動きを決める」という流れが必要なことを理解することができました。', null, null),
  ('61dbc07b-9906-51d0-a7c8-4d9ecab12224', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-07', '17:30:00', null, '通常 / ロブロックス体験', 'robloxをもともと触れていたこともあり、体験でデジタネのコースを見てきました。動画の感想を聞いてみると、ほぼ知っていたこともあり、見つかれ飽きていました。帰りの際に、イラストコースの方にも興味を占めていました。', null, null),
  ('1cf04341-f721-5dd6-99cc-87139ef8df8f', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-07', '17:30:00', null, '通常 / exel', '今回は練習問題をやってきました。これ表政策やフォントなどは止まらずに順調に進んでいきました。途中、順位のrank.eq関数や個数のカウント関数の知らない関数があったので、順次教えていきました。特に苦しんでいる場面がなく多少授業時間が終わってもやっていたので、やる気は継続中です。', null, null),
  ('6e12e1fb-f923-5abe-971b-79a6a66fc99b', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-07', '17:30:00', null, '通常 / ジャンプの基礎を取得しよう', 'ジャンピングゲームをやっていきましたが、ほぼほぼ理解はできていました。ジャンプの上がり下がりも自分で解明して、自由に高さを変えられていました。ほかにも障害物の繰り返しの動きも自力で作れていました。ここで、卵の当たり判定で、「まで待つ」の使い方を教えていきました。コードが見やすくなって、喜んでくれました。変数のスコアもつけられていて完成させることができました。', null, 'タイピング: 何回も繰り返していました。'),
  ('01cb6af0-d8c6-54ee-bc7f-352b4821b274', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-07', '17:30:00', null, '通常 / robloxを始めよう', 'レッスン1はさわりのさわりの部分でしたが、ロブロックスでできる全体像がぼんやりと見えて遊んで楽しんでいました。好きなことに近づくから意外と動画に集中してトコトンっ進んでいました。本人も気が付いたら授業時間が終わりそうになっている程度に集中していました。実際に次回からは自分で作って動かすと思います。', null, null),
  ('f387abee-6810-55ff-8e99-75d98eb67135', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-07', '16:30:00', null, '通常 / ジャンプの基礎を作ろう', '最初はこのゲームを作ったことがあったので、作る気力はあまりありませんでした。だが、マイクラのようなジャンプが作れるために基礎を積み上げることが必要だと教えてあげたら作り始めてくれました。何も見ずに作ってほしい方針でしたが、前回が半年前だったので、大体忘れかけていました。だが、何回繰り返すなどの最初のヒントを教えてあげると、そのセクションのコードを自力で作り上げることが出来ていました。そして、それを先生に見せて、次に進むといういい流れで完成まで作ることが出来ました。また、障害物の動きの時、先生の見ぬ隙にカードを見て進めることがあったが、何とかして進める意欲があるはいいです。まだ、座標系の感覚が苦手だと感じます。', null, null),
  ('873ae002-21c1-5082-b10c-af0269a67dea', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-07', '16:30:00', null, '通常 / ジャンプげーむになれよう', '今日はかなり早くから来ていたこともあり、頭がかなりゲーム遊びモードをなっていました。30分くらいは遊んだり、周りに気が行ったりしていました。ジャンプの基礎のコードを教えていきましたが、頭にうまく刻まれていない感じがします。岳君は感覚的に作っていくので、先に障害物の動きではなく判定を作ったり、作り順番がごちゃごちゃになる場合にありました。今は工程は少ないですが、どこから作ればよい考えさせる必要はあると思います。', null, null),
  ('814b9c3a-91af-523e-8bb7-eab70500e00b', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-29', null, null, '【体験】', '・一通りのブロックはいじったことがあるとのこと。使ったことのないブロックはあるかとの質問に、三角関数は使ったことがないと答えたので、定義やクローンなども経験済みのよう。 ・一方で、音楽にはあまりこだわりがなかったのか、ブロックは知っていたけれど実際にはほとんど使ったことがなかったらしい。「音を鳴らす」と「終わるまで鳴らす」との違いを感心して聞いていた。 ・経験者ではあるが、独学だったという意識はしっかりと持てているようで、説明を「知っているから」とひったくることもなく、どのような説明もこちらの顔を見て熱心に聴いていた。 ・なんとなくやっていたことの理屈が通るとスッキリするのか、「ずっと」の条件分岐と、まで待つの違い、後者を使うメリットなどの説明も楽しそうに聴いていた。説明の後に自分で試して納得することも。 ・色々なアイディアはわくが、そこだけ作って満足しがちで、自覚もあるとのこと。組み合わせた一つの作品を仕上げたことはないらしい。そのため、コンテストで1年に1回、完成させる体験をしてみるという提案にはとても乗り気だった。 ・Javascriptは独学でいじり始めたところで、興味はとてもあるよう。Monacaでスマホで作品が見られるという説明に「こういうのがやりたかった！」と興奮していた。', '体験で作成したピンポンゲームをアルスタジオに入れてあるので、これのバグ修正だけしてあげてください。 コンテスト（U16かな？）に参加する気満々です。', '時間帯: その他
盛り上がり: ピンポンゲームの作成とそのアレンジを、ひたすら楽しんでやっていました。 帰宅後も、とても楽しかった、ぜひ通いたい、と「中学生活に慣れてからの方がよいのでは…」という親御さんの心配を押し切っての入会だそうです。'),
  ('3e773656-8f12-5e0b-99a0-54abd4af00c5', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-08', '16:30:00', null, '通常 / アレンジを通して基本的なスキルを習得する', '前回学習したスプライトの複製が楽しかったのか、「今日はハンターを大量発生させる！」と張り切って、ひたすら複製を繰り返し、112くらいまで増やしていました。画面が大量の黒いハンターで埋まるのを見て大喜びしてました。 複製とゲームプレイで満足している様子で、他のことは面白く見えない、と言っていましたが、基本操作コースのファイルを開いて、このゲームで使える機能を勉強してみないかと誘ったところ、「このゲームで勉強できるならやる！」と乗ってきました。 大量のハンターから一人を「選ばれしハンター」にして、基本操作コース02の「色を変える」「サイズを変える」、基本操作コース03の「おしゃべりさせよう」を学習し、コードに付け加えさせました。大量のハンターから、色やサイズを目印に「選ばれしハンター」を探すのをとても面白がってくれました。新しいスタンプを押せるのも楽しかったようです。', null, '盛り上がり: 本人としては、ゲームで遊びながら新しいコードを覚えてスタンプを押せた、という認識だったようで、終始ハイテンションで、満足げに授業を終えていました。
備考: PC操作は自分でやりたいようで、手を出されるのを嫌います。手を出して指示しようとすると焦るようなので、先生は触らないから、どのキーを押すか指差しだけさせてね、と話してからにすると、素直に指示を待つことができました。'),
  ('7b644a3e-5cfb-55d6-bf75-3392f207c86c', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-10', '17:30:00', null, '通常 / イラストコース', '雑談も交えながら集中して取り組めていました。', null, null),
  ('1f3114d6-3e5b-5984-a1d8-0fbbaf82c990', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-10', '16:30:00', null, '通常 / 作品アレンジ', '以前検定で完成させた魔法使いがドラゴンを撃ち落とすゲームのアレンジをしていきました。キャラクターセレクト機能を実装したいと話していたため、キャラクターのデザインとシステムについて相談しながら作成していきました。特にデザイン面に関してはこだわっており、杖や装飾品の細かな変化も取り入れていました。しかし、イラスト部分に力を入れすぎてしまいコード部分について少し疎かになっている部分も見られました。そのため、両方をバランスよく行っていくことでさらに完成度の高い作品を完成させることができると感じました。', null, 'タイピング: 集中して取り組めていましたが、ホームポジションを意識して取り組めれば尚良いです！'),
  ('5b53dab7-bb92-52ee-9b18-6afbdaa03a0b', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-10', '16:30:00', null, '通常 / プラットフォームゲームのアレンジ', '前に作っていたプラットフォームゲームのアレンジをしていきました。ただステージに進むだけで途中にコインを追加していきたいとの考えでした。ランダムに配置をしたいところまではできていたが、集中力切れがみられました。でも、横に流れていくためには、どうしたらよいか考えてブロックを動かしてくれたり、試行はしてくれました。ステージと同じ動きを持ってくればよいとコピペまでできたが座標の関係でうまく機能しない場面がありました。そこは、一緒に座標の調整をして感覚の調整をしました。そして、完成させることができました。', null, null),
  ('ed748874-4e76-54e7-9888-ab1effe9936b', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-10', '17:30:00', null, '通常 / Excel練習問題１', '全ての作業を通しで行っていくのは初めてだったようで、少し戸惑っている部分も見られましたが、慣れてからは順調に進めていくことができていました。ショートカットキーや複数選択などをいまいち理解できていない部分があるようで、基本的な操作も復習しながら問題を解いていくことで、より早く解くことができると感じました。本日は問題３まで終えることができたため、次回では問題4のグラフと問題5の印刷まで終えて完成させていきたいです。', null, null),
  ('49e27c57-63f4-556b-ad0f-a91d5381b99b', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-10', '16:30:00', null, '通常 / プラットフォームのゲームのアレンジ', '前に残っていたプラットフォームのアレンジの続きをしていきました。アレンジとして何がしたいと丸投げする形が多かったです。イラストを持ってくるのもいいが、そのまま置いただけになっている場面で放置なこともありました。ルイ君の作成にアドバイスすることはよいが、なかなか自分のことが進めずに終わっていきました。', null, null),
  ('99739c69-fdb7-5018-a5d3-d7099c8e9c75', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-10', '17:30:00', null, '通常 / Excel試験問題１', 'Excel問題に挑戦していくのが久しぶりということもあり、場所や操作に戸惑っている部分が多くありました。特に、関数部分で指定場所の確認や固定するかどうかの判断について悩んでいる様子でした。しかし、一緒に進めていくうちにだんだんと思い出すことができたようでスピードも少しずつ上げていくことができていました。今回で問題２まで終えることができたため、来週で問題３〜５の表とグラフと印刷部分について終わらせていきたいです。', null, null),
  ('2213b612-f8ca-57f7-9f8a-081004b41f73', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-10', '17:30:00', null, '通常 / アレンジのスキルを上げる', 'アレンジ大賞へのやる気は満々で、たいようくんがアルスタジオでアレンジ大賞作品を見つけたところすぐにやりたがって始めていました。 追加したい要素などはすぐに思いついたようで、トイレタイムを入れるかわりに満足度の減りを遅くするなど、いろいろと考えていました。 コードを見ることはだいぶ慣れてきたようで、たくさんのスプライトを熱心に見て、どこで変数を管理しているのかなどをとても熱心に探していました。 お客がそれぞれ注文を同時に出すようにして、どのお客に出来上がった商品を渡すかを選べるようにする仕様に考え込んでいました。', null, '盛り上がり: アレンジのアイディアはすぐに思いついたようで、「優勝ねらいたい！自分の作品をコンテストで使ってほしい！」と盛り上がっていました。'),
  ('600763e0-7b29-5e22-a845-5b59b443a545', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-10', '17:30:00', null, '通常 / robloxの操作に慣れよう', '今回は政策画面の使い方に慣れてもらいました。操作について詰まることがなく、キーとマウスを活用できていました。りょうやくんの創作意欲が高いので、動画を見ずに次から次へとあたらいいものをつっていく場面がみられました。基本となる移動、拡大、回転、固定、を覚えることができ、確認テストもミスなくできたので良かったです。 次回からは動画で細かい動作もあるのでもうちょい見ながら作るに慣れてほしい', null, null),
  ('f9290bb9-f2f3-51ee-b890-48616c0a5a9d', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-10', '17:30:00', null, '通常 / アレンジのスキルを上げる', '授業開始後は、「アレンジ」といっても何をしていいのかわからない、といった感じでしたが、最初はわかりやすいところから、大きさや速さを変えてゲームの難易度を変えてみる、ということをやってみました。コードを見るのに慣れてきたころには、少し楽しくなったのか、細かい数値を変えてみたり、コスチュームをいじったりと楽しそうにしていました。 コスチュームへの書き込みが細かく、器用に描けていました。 これまで一人の席で先生とだけ向かい合うことが多かったのですが、今日はScratch組4人でお互いの作品を見ながらやったのが楽しかったようでした。', null, '盛り上がり: 他の子の作品を見たりするのが良い刺激になったようで、発言も積極的にしていて楽しそうでした。'),
  ('fcc1c372-921b-5d48-9662-4631593bdef8', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-11', '16:30:00', null, '通常 / ピンポンゲーム', '今回は、今までに行ってきた内容の復習も兼ねてピンポンゲームを作成していきました。今までに行ってきたことが多く含まれていたため、スムーズに作成を進めていくことができました。アレンジ部分に関しても、ボールを虹色に光らせたりと視覚的にわかりやすい部分で工夫をおこなっていました。今回で完成させることができたため、次回からのアレンジ大賞で想像力を強く発揮してほしいです。', null, null),
  ('6f03de4c-8984-5566-9bdd-0ac8d6d53059', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-11', '17:30:00', null, '通常 / メッセージ、演算の練習', 'かくれんぼゲームを作りました。メッセージや変数についてその仕組みを復習しながら作ることができました。全体的に自分の力で集中して作成できました。ただセリフのタイピングや「～との距離」を含んだ複雑な制御ブロックが難しく、終わったのは全体の半分ほどになりました。', null, '盛り上がり: 授業中はおおむね良い様子でしたが、渋滞でお迎えが遅れたときに寂しくて泣いてしまったため寄り添いました。'),
  ('2b5d6f66-ec54-51a3-8cb1-330a7ae82f82', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, null, '2025-04-11', '18:40:00', null, '休み（振替対象）', null, null, null),
  ('9896115a-2818-5b3a-9dda-196268d3c68a', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-11', '17:30:00', null, '通常 / 演算によるゲーム作成', 'かくれんぼゲームを作りました。キャラの役割はそのままにスプライトの種類を変えたり、セリフを若干変えたりと、方向性は変わらない程度のアレンジをしながら進めました。演算の部分は内容がわかりづらいので一緒に確認しました。「～との距離」を入れた不等式については、位置関係がどうなったという意味なのかを理解してもらいました。また、「AかつBかつC」という構造については、すべての条件が満たされたときという全体像を整理しました。集中して最後の方で全て作り終えました。', null, null),
  ('5f961cfc-d6e3-5536-acf7-5263ea4e966e', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-11', '17:30:00', null, '通常 / Prg28まゆ猫を探せ', '動画を見ながら作成を進めていきました。動画時間としてもそれほど長くなく、技術もあったため余裕を持って終えることができていました。残った時間では、来週から始まるアレンジ大賞の練習として、思いつくさまざまなアイデアを作品に取り入れていくことで、どんなアレンジ内容が気にいるのかを試していました。', null, null),
  ('43460a53-fbdc-5d1a-bb25-5b7c29a39486', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-11', '17:30:00', null, '通常 / Prg28まゆ猫を探せ', '動画を見ながらプレイグラムを進めていきました。クローンの使い方について少し悩んでいたようですが、動画を見ながら作成していくことで理解することができた様子でした。残った時間では作品のアレンジに取り組んでいき、セリフの内容を変更したり、デザインを変えたりと作品にストーリー性を持たせるようにアレンジしていきました。', null, null),
  ('d0548670-a043-59fe-9e72-0fce1291915d', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-11', '16:30:00', null, '通常 / ゲームを一つ完成させる', '来週からアレンジ大賞なので、今日中に一つ簡単なゲームを作ろうということになり、サッカーゲームを作ろうということになり作成しました（教材のとあるゲームを提案したのですが、自分で作りたいとのことで、自作ゲームにしました）。サッカーボールをゴールまでドリブルしていくゲームで、キャラがサッカーボールに触れた時の動き（ドリブル）と、ゴールに入ったかどうかの判定処理がうまく考えられないようだったので、一緒に考えました。ドリブルは、サッカーボールに触れた時に、向きをキャラの方向へ向けて、１８０度回転させることで、キャラが進方向にボールを動かしてドリブルしているように見せることに成功、ゴール判定処理は、X座標、Y座標チェックの仕方を説明。いずれも、納得してもらい自力でスクリプトを書いてもらいました。今日のゲーム制作で座標の復習と、一つ小ネタのようなものを覚えられたと思います。', null, null),
  ('b3391a36-35de-5970-80ec-760793dc2140', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-11', '17:30:00', null, '通常 / ロブロックス１回目', '初めてのロブロックスの説明でしたが、ちょうど大雨と雷のタイミングで教室も少しゴタゴタして、しかも、デジタネの配信サーバーの調子が雷の影響で調子が悪いのか、デジタネ動画が途中で止まったり、あまり良い状況ではない中でのスタート。基本、動画を見てもらって、動画内で説明された通りのことをRoblox Studioで進めるだけということを話しましたが、その時点から、あまり乗り気ではない雰囲気。動画を見始めたのですが、集中して動画を見続けるのが苦痛なのか、時々、動画を飛ばし飛ばしみるようなところもありました。「動画内容は、一つ残らず全部見ないと、わからなくなてしまうよ。だから、きちんと飛ばさないでみてね」、と言っても、返事が上の空でした。結局、動画内で説明された内容をきちんと理解しておらず、どうすればいいの？となって、じゃあ一緒にやろっかという言葉も拒否されて、Roblox studioを自分なりに勝手にいじって、なんかの違うゲームみたいなのをしたりしていました。最後に「ロブロックスとスクラッチどっちがいい？」と聞いたら「スクラッチの方が良い、ロブロックスはやらない」とまでいっていたので、よほどハル君とは合わないのか？ロブロックス自体が嫌というよりは、動画中心の講義スタイルが嫌なのかもしれません。が、正直、何が気に入らないのかをはっきりさせて、今後の方針を決めた方が良いのかなと思います。', null, null),
  ('50b18c22-af18-5dea-8ae6-b649749f69c7', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-11', '17:30:00', null, '通常 / 初ロブロックス', '教室にくるなり、早くRobloxを始めたいと、とても楽しみにしている様子でした。動画を見るのがメインの講義ですが、集中して試聴して、「そっかー、なるほど」とか、とても興味ありそうな雰囲気でした。今日は、一番最初の動画のみ見ていましたが、初めてスクリプトを書いて、地面の色が変わるのを見て、喜んでいました。こういう小さい積み重ねで面白いゲームが作れるようになるから頑張ろうと励まして、本人もやる気がかなりあるようです。一つ、ちょっと気になったのが、隣に座っている人が動画で説明を流しっぱなしは、結構集中力を削がれてしまうのではないかと心配しています、ヘッドホンを使う、動画を流しっぱなしにする人は、距離を多めに取るなどの対策をした方が良いかなと思いました。', null, null),
  ('0df86a9b-0bba-5f61-a29c-4119c3efc8f5', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-11', null, null, '通常 / アレンジ大賞前にゲームを一つ作る', '来週からアレンジ大賞ということで、Prg34ビルの隙間を抜けようゲームの重要部分を押さえて動くものを作ろうということになりました。鳥は、自由落下（加速する）するのと、スペースを押すことで飛び上がることを、「とぶ」という変数で表現して、Y座標をその変数の値で変えていく手法を納得して作ってもらいました。ビルも乱数でY座標で高さ調整しながら、左側に自動で流れていく処理を、X座標の変化で実現させることを説明して納得の上、スクリプトを書いてもらいました。結果、最低限ゲームとして成り立つものはできたと思いますが、クローンでビルを複数表示させるところまではできませんでした。また機会があれば、この続きをやっても良いかもしれません。', null, '時間帯: その他
タイピング: 集中して取り組んでいました'),
  ('43100cf6-d45d-5f51-b9cd-93bfef91f607', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-12', null, null, '通常 / イラストコース_初回ガイドと目の描き方まで', 'アイビスペイントを使うこと自体がほとんど初めてで、レイヤーなど用語はいくつか知っていたようですが覚えることがたくさんあったようでした。 今回は「定規ツールを使う」「不透明度を下げる」「レイヤー分けして線画・塗り作業をする」ということを学べました。特に、レイヤーを分けて作業する技術には「こっちの方が便利だ」と気づいてもらえたようで良かったです。', null, '時間帯: その他'),
  ('e18e76d4-019b-5c0d-94a7-c1e00ab7b88c', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-12', null, null, '通常 / イラストコース_初回ガイドと目の描き方まで', 'アイビスのレイヤーや変形ツールについては既に理解していたようです。 こちらが言わなくとも対称定規を使って器用に図形のガイドを描いていました。 目を塗る時の配色も落ち着いた緑を使って綺麗に配色出来ていて、デザインセンスがあるのだなと感心しました。', null, '時間帯: その他'),
  ('af654815-adf0-5427-87f9-c73ebfd55664', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-12', null, null, '通常 / イラストコース_初回ガイドと目の描き方まで', '佑香ちゃん同様アイビスの知識はある程度は知っていたようで、定規ツールを使って器用に描画していました。慣れているのか、完成スピードが少し早かったような気がします。 瞳の配色も真っ黒よりかは落ち着いた青やそれにあった黒を選べていてすごく感心しました。', null, '時間帯: その他'),
  ('824ad5b9-5faf-52a3-811f-249e90a3438f', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-12', '17:30:00', null, '通常 / イラストコース_横顔の描き方', '今回は難易度がやや高い横顔を描いてもらいました。 ガイドがあると描きやすかったのか、詰まることなく目や口の線を引くことが出来ました。 自分で描きたい髪型に関しては検索していくつか写真資料を参考に描いてもらいました。 ご自宅でipadの準備がまだなのと、偶然教室のipadのペンの充電が無かったため一旦は私のipadで作業をしてもらいました。親御さんによると再来週までにはご準備いただけそうとのことでした。 またデータ共有の際、PNG/JPEGとPSDについてざっくり説明をしており、次週機会があれば覚えているか確認してみようと思います。', null, null),
  ('ff9d8896-60c9-5c6f-b3f3-46218de31b0e', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-12', '17:30:00', null, '通常 / イラストコース_髪の描き方', 'Airdropでデータを送付しようとipadの設定に少し時間がかかってしまいました。 自宅でアイビスペイントの初期設定などの講座動画をいくつか見ているようで、 参照ウィンドウを使った引きで絵を見て完成させるやり方が出来ていて良いなと思いました。', null, null),
  ('3ff3389a-ee5c-58d7-a588-c246857d7cf7', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-12', null, null, '通常 / メッセージのやり取りを覚えよう', 'メッセージでの単元別練習でしたが、座標や変数、制御の復習にもなりました。D-1での鳴き声のところでは、「終わるまで鳴らす」との違いについて説明をして、自分の言葉で解釈をして分かってくれました。D-2では移動を滑らかに動かしたいと考えつつも度のブロックを使ったらいいかわからないときがありました。そこで、「何回繰り返す」の仕組みを一緒に考えて復習しました。メッセージや変数についてはスムーズに使いこなせていたので、ブロックのよい見直しになりました。', null, '時間帯: その他
タイピング: スコアが伸びていました'),
  ('c0dae365-7843-5541-b9b2-69e40a81f26b', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-12', null, null, '通常 / ドリル3', 'アレンジ対象のためにスキルの確認を行っていきました。球を発射する形でしたが、こちらが道筋を立てなくても何を作っていけばよいか考えることはできていました。ただ、考えはあるけど、ブロックを使いこなせていない場面があったので、「まで繰り返す」などを新たに取り入れて一緒にやっていきました。コスも自分好み選んで楽しんでいました。', null, '時間帯: その他
盛り上がり: ひっさしぶりで常にテンション高めでした！'),
  ('fa811e41-5c04-54c5-a413-3e0718fbe37b', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-12', null, null, '通常 / 自由製作', '今日は水平思考クイズの持ってきて、このゲームを作りたいということで、さっそく作っていきました。本に書いてある問題を八王子のモノでリメイクしたいのことでしたが、案が思いつかず、先に配置つくりをやっていきました。ヒントや説明のスプライトを作り下準備は終わりました。', null, '時間帯: その他'),
  ('0b0d56e1-4f0d-5abb-8927-cb988aecaa4e', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-08', '16:30:00', null, '通常 / 逃走中アレンジ', 'アレンジ大賞を始める前回として、逃走中アレンジの続きに取り組みました。ハンターの中に自動車やハチを混ぜるなどしてキャラクターを多様にしていました。逃げる猫側も色々とデザインを変えていました。', null, null),
  ('7f21f752-f74a-503f-86ec-f8c2af9d788b', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-08', '16:30:00', null, '通常 / 変数によるジャンプ', '逃走中アレンジと単元別演習を提示したところ、後者をやる気になり、放物ジャンプを扱いました。「まずは普通にジャンプのコードを作ってみて」と伝えたところ、上や下に瞬間移動する方法でやっていたため、繰り返しを使った等速ジャンプから始めました。そのあと放物ジャンプのお手本を観察してもらうと、速さが「上向き速い→遅くなる→下向き速い」という流れになることを見つけられていました。速さは変数を使ってだんだん変えていくといったヒントを出した後は、自分で考えて試行錯誤ののちコードを組み立てられました。算数的な考えかたが得意なためかしっかり概念を理解することができました。', null, null),
  ('fb4cb281-0756-5489-96f2-51981c3cf18e', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-08', '17:30:00', null, '通常 / 逃走中アレンジ', '単元別演習も検討しましたが、逃走中で先週とは違うアレンジがしたいとのことで進めました。逆にネコがハンターを追いかけるというゲームにしていました。まずはキャラクターに武器をつけてかっこよくしました。そして大量のハンターの中でぶつかってはいけない個体を作って見た目を分けるなど、ゲーム性も高めていました。', null, null),
  ('9223e0e0-5fbb-53cf-9cf9-3cb82460d5f4', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-14', '16:30:00', null, '通常 / アレンジ大賞 初級', '今日からアレンジ大賞開始ということで、初級の内容である間違い探しの作成を行っていきました。どんな動作をするのかを１つずつ確認しながら勇作くんと一緒に作成を行っていくことで、二人で協力して集中することができていました。今回でほとんど完成させることができたため、来週ではゲームクリア時の画面変化を完成させてアレンジに入っていけると思います。', null, null),
  ('c00fc6c3-f17b-58ff-9c9a-7d2761219db2', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-14', '16:30:00', null, '通常 / アレンジ大賞 初級', '今日からアレンジ大賞がスタートということで、初級の間違い探し制作に取り掛かっていきました。正解と不正解の動作方法や、スプライトの変化をどこで管理しているのかを確認しながら、岳くんと一緒に作成を行っていきました。完成度としても、岳くんと同じくほとんど終わらせることができているため、来週で完成とアレンジに取り掛かっていきたいです。', null, null),
  ('68dda2d7-5f89-5107-a87a-10ecd4322763', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-14', '16:30:00', null, '通常 / アレンジ大賞のもとのゲームを作成しよう', '経験はあさいものも、初級のゲームをほぼほぼコードを見ながら一緒に作っていきました。そこで、新しい「メッセージ」の機能を学んでいきました。一つの工程を終わるごとに、試遊が毎回挟まれていたので、丁寧に作られていきました。また、新しく乱数の概念を出てきましたが、カニのコードを作った後のほかのコードを作る際に数字さえ変えればいい良いと気づいいてよい感をしていました。元のゲームのコードは完成したので、次週アレンジです', null, null),
  ('27c360fd-1775-51f8-a601-f054bb4bddd1', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-14', '17:30:00', null, '通常 / イラストコース_体験', '普段絵を描く習慣もなく、初めてipadで絵を描くとのことでまずはレイヤーの概念から伝えました。 教室オリジナルの教材を見ながら授業が終わるまで顔を熱心に描こうとしていて、 終わると「楽しかった」「イラストやってみたい」とかなり意欲的でした。 教えたばかりの投げ縄ツールや図形の左右反転なども駆使していて、 初めてでもかなり上手く描けていて良かったです。', null, null),
  ('282dd61c-af89-5558-9aea-6e03610baa8a', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-14', '17:30:00', null, '通常 / エクセル', '前回のシートが見当たらなかったので、もう1度最初からデモといてくれました。セルの書式設定は難なくできますが、関数に関してはややゆったりといてしまう傾向があります。また、今回のグラフ作成で、離れたセルを選択することがあったので、ctrlを使った選択方法を教えてあげました。順当に積んでいければよいと思います。', null, null),
  ('8131f46c-5049-5393-a2e5-94f300da5438', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-14', '17:30:00', null, '通常 / 【アレンジ大賞2025】上級 星のカービィ風カフェ風ゲーム', 'アレンジ大賞では光梨ちゃんが進歩したと思えるやり方でアレンジをしてみよう、とのことで最初はスクラッチのコード作成に取り組んでもらい、スプライトのアレンジイラストを考えてもらう時間を取りました。コード作成の方は頭を悩ませていて、先生のサポートを受けながら進めていきました。逆にイラストではかなり意欲的で、コックのキャラの代わりに可愛い女の子のキャラを描こうとしていました。 また向かいにイラストコース体験の同学年の子がいて、雑談も交わしながら楽しく制作が出来ていました。', null, 'タイピング: なし'),
  ('a1c0bf1c-2afe-5395-8326-801f9e84b6ee', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-14', '17:30:00', null, '通常 / Roblox Studioに慣れる', 'Roblox2回目。前回確認テストをやっていなかったとのことで、確認テストから。８０％でしたが、１週間時間が空いてるので仕方なし。間違ったところはきちんと今は理解しています。レッスンを始める前に、このデジタネの進め方、どんな感じかを確認しました。そうすると、動画が長くて面倒くさいと言うようなことはチラっと言っていました。子供だとかなり興味がある人じゃないと少し大変かもしれませんね。私が作っているゲームを軽く見せたり、１つの動画毎に覚えなくちゃいけないことが沢山あって、それを続けることで、その集大成として、こんなゲームも作れるので頑張ってみようと言う声がけをしました。動画内の話の速度がゆっくりなので、速度を上げてみても良い。けど、しっかり理解してわからないところがあったら、巻き戻してみてねとも伝え、実際、２倍速で聞いていました。さらに、デジタネで動画を見ながら、Roblox studioで作業をするということで、効率を考えて、Roblox studioをメインで動かせるようにしつつ、動画は画面の端に表示させて、両方を常に見たり操作できるように進めるようしました。私自身は２画面モニタで進めていたので不便なことに気付けていなかったのですが、１画面だけでいかに快適にレッスンを進めるかは今後良い方法を考えて、それを共有できたら良いと思います。レッスン自体は、まだ簡単なRoblox studioの使い方に焦点を当てたもので難しくないので、特に問題はありませんでした。確認テストも１００点でした。', null, null),
  ('9a568097-e787-5f15-9e3c-2ca20d16cde8', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-15', '16:30:00', null, '通常 / アレンジ大賞・初級のゲーム作成', '初級を見本通りに作成するところから始めましたが、まだ経験が浅いこともあり、全てを一つ一つ丁寧に教えないと前に進めない状況でした。何をやるべきか、頭の中で組み立てて自力で作業を進めることがまだ難しのかなと感じました。今日は初級のゲームの作成途中で終わりとなりましたが、このペースだとかなり時間がかかりそうなので、アレンジに早く進むために、要点だけ教えて写経するしかないのかなと思いました。また、アレンジ大賞というと自分で考える力が必要かと思いますので、何かうまくサポートしてあげる必要性を感じました。また、お水を紙コップで飲んでいましたが、水を飲みかけの状態で自分の机に置いたままにしないでねと伝えても、忘れてしまうのかなんなのか、その言葉を守れない時が何回かありました。', null, '盛り上がり: アレンジ大賞の説明で、景品が出ますというところ、「よしやってやろうじゃないか」という感じで乗り気なところを見せてくれていました。'),
  ('3f4011d6-3bee-5959-bafd-7510587b2376', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-15', '17:30:00', null, '通常', '4年生になったので中級を勧めましたが、最初は3Dが難しそうだと言って初級に行きたそうでした。ただ、見た目のインパクトよりは単純な動きをしていること、今までの自分よりもハイレベルな内容への挑戦で採点時に加点が狙えることを伝えると、中級をやる気になったようでした。完全自力では難しそうだったので、考え方プリントに沿って一緒に進めました。操縦艦の作成時、案外普段スプライトは移動ばかりで回転する機会がないためか「～度回す」ブロックが頭から抜けていたので復習しました。「～度に向ける」との違いについても押さえました。また、隕石の動きについてはちょうど先週やったクローンを扱ったため、良い定着の機会になりました。少し混乱していたので「クローンを作る→フィールドに配置する→動かす」の手順で細分化して一緒に作りました。', null, '盛り上がり: アレンジ大賞の賞品に興味を持っていました'),
  ('604c97f2-ca5d-576a-8c77-77fc692f2b29', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-15', '16:30:00', null, '通常 / アレンジ大賞・中級ゲームの作成', 'アレンジ大賞の説明を、うなづきながら反応を示しながら聞いてくれていたので、子供ながら良い聞き手だなと思いました。中級を選択して、ゲーム作成開始、少してこづっていましたが、簡単なアドバイスで途中までは問題なく作成できていましたが、隕石と宇宙空間の作成部分でつまづいています。この部分は、クローン処理や、拡大表示など、いろいろ要素があるので、どのように作成していくべきかを、細分化して自分で考えさせた上で、この部分を自力でできたらと思います。で、来週にはゲーム完成してアレンジに移れれば良い感じかなと。', null, null),
  ('f484a404-3eae-5258-95ab-5748d77a9cd8', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-15', '16:30:00', null, '通常 / アレンジ大賞開始', 'アレンジ大賞を上級レベルで始めました。全体的に難しいと言って詰まっていたため、考え方プリントで序盤に出てきて簡単めなネコの動き方から作ってもらいました。左右キーを押したとき動きすぎてしまうのが解決できていなかったため、レースゲームでやった「～が押されたではないまで待つ」を復習しました。お手本のコードを見てみたところコード量の多さにやる気をなくしかけていましたが、大事な部分だけシンプルに作れれば大丈夫と伝えました。', null, null),
  ('a5d148bd-3b62-5480-a218-b34704cbf942', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-10', '17:30:00', null, '通常 / アレンジ大賞に向けてスキルの確認とアレンジの練習', 'ある程度は自分でわかるといって自力で進めていて、わからないことを聞いてくるという感じで授業が進みました。 カニの動きがワンパターンでつまらないというので、変数で条件分岐して、それぞれで違う動きを入れてみたらという提案に喜んでのっていました。 動きを座標で指定したため、二匹に増やしたカニが開始後すぐに重なってしまうのにしばらく悩んでいましたが、座標ではなく「歩動く」に変える提案をしてみたところ、うまくいったようでした。 なかなか面白いゲームになったと喜んでいました。', null, '盛り上がり: きちんとやりたいことを考えてからコードを作成しているようで、思い通りにゲームが動くことを喜んでいるようでした。'),
  ('64a1359a-1cca-5987-a455-c802da80980c', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-10', '17:30:00', null, '通常 / アレンジ大賞に向けてスキルの確認とアレンジの練習', '自分で今年のアレンジ大賞の作品が公開されているのを見つけ、どうしてもやりたいということで、ノリノリでアレンジを開始しました。 大きく得点が表示されるようにしたり、色々な客が来るようにしたりというアレンジは手慣れたもので、さくさくと進めていました。 授業終了時に、あっさりと完成、と言っていったので、もう少し持続して完成度をあげるよう勧める必要があるかと思います。', null, '盛り上がり: このクラスに移ってきたときは、周りの子が良真くんに比べておとなしかったのか、前のクラスが良かったなあとぼやくこともありましたが、今日は奏太朗くん、晴くん、楓大くんと席を一緒にしてアレンジに取り組んだせいか、それなりに会話も進んでとても楽しかったようでした。'),
  ('e3fc8e5c-4406-5197-a7dd-5711151e288f', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-12', null, null, '通常 / プログラミングの授業に慣れる', '初めてのプログラミングの授業ということで、お母さん曰く「少し緊張していたから」とのことでしたが、パソコンはかなり慣れているようで、すぐにいつのの調子を取り戻していました。 最初に追跡ゲームを提案しましたが、出てくるブロックはほとんどわかるといって、淡々と自力で作成し始めていたので、「少しレベルを上げて、知らないところの穴埋めをしていこう」と声掛けをすると表情が変わって嬉しそうになってきました。 スクラッチでも結構遊んでいて、せっかくプログラミングを習うのに、見慣れたものをするのはちょっとイマイチ…という感じだったので、アルスタジオの小技を見せて習得したいスキルを選ばせました。 スクロールはいつかやってみたかった！と乗ってきたので、完成版を見せてコードの解説をさせてみました。座標の指定などはきちんとわかっていて、背景スプライトをどこに出すための座標なのか、ということも理解できていました。 座標と動きの組み合わせでスクロールができる、ということに感心していました。 一通り理解した後で、オリジナルの作品でスクロールを作成し、満足そうにしていました。', null, '時間帯: その他
タイピング: スラスラと打てていました
盛り上がり: 授業のはじめは、「知っていることをやらされるのか？」という感じでちょっとローテンションでしたが、スクロールになってからは気分が盛り上がってきたようでした。 スクロールを使ったオリジナルゲームを作ろうと、頑張っていました。'),
  ('03ad4dca-ef28-5ebd-88ed-3d0ed7fa9065', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-12', null, null, '通常 / 基本的なスキルを習得する', 'タイピングが得意なせいか、セリフを入れる課題から始めると嬉しそうに会話を考えて入力していました。 矢印キーでスプライトを動かす際にコスチュームを変えてアニメーションのようになるのがとても面白かったらしく、1つを作成したら、その後は同様の動きを熱心に作成していました。 ファイルにスタンプを押して、今日はこれだけ覚えたよと見せると、自分で「すごい！」と感動していました。スプライトが触れたら音を鳴らすようにしたところ、ゲームのようになったのが楽しかったようで、お母さんにも得意そうに見せていました。', null, '時間帯: その他
タイピング: タイピングは得意なようで、とても熱心に打っていました。大会が終わったばかりなのを少し残念がっていて、次回はぜひ参加していい成績を出したいとのこと。
盛り上がり: 新しいことを覚えるのが楽しそうで、終始熱心に取り組めていました。'),
  ('5cce9f68-7954-5024-833b-31f85b84d698', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-17', '16:30:00', null, '通常 / アレンジ大賞 上級', '今回からアレンジ大賞に入っていくということで、選択した上級の作成を行っていきました。とにかく作品をアレンジしたい欲が高いようでコード制作時点で何回もアレンジを行いたいと言っていました。そのため、作品の進捗としてもイマイチな結果となってしまい、来週でアレンジに入れるか微妙な状態となっています。なので、次回ではスピードを上げてアレンジ部分を早く行えるように説明をしていきたいです。', null, null),
  ('097dda81-5089-55d1-9fb0-9c4d949698f9', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-17', '17:30:00', null, '通常 / アレンジ大賞2025中級', 'プリントだけで一から考えてもらうには難しそうだったため、コードを分割したお手本を見せながら少しずつ作ってもらうことにしました。 クローンを使うのが今回初めてなようで、最初の宇宙空間のスプライトにどう指示を出せば見本のように動いてくれるのか、実技を通してスプライトの移動を説明したり、座標の概念を「たて・よこ」で説明してあげることで、少しずつ入力している内容の仕組みを理解をしてくれました。 操縦席の入力の途中で終わってしまっているので、次回は続きを一緒に考えられたら良いなと思います。', null, 'タイピング: なし'),
  ('731651cd-1bf1-5029-9eb4-adc9d32050fc', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-17', '17:30:00', null, '通常 / アレンジ大賞 上級', '本人の希望でエクセルよりもアレンジ大賞に取り組みたいとの要望があったため、上級を作成していきました。コードへの理解はすぐに終えることができため、アレンジ部分に入っていきました。マルチプレイ対応の二人用ゲームとしてアレンジを行っていきたいようで、プレイヤーそれぞれの操作やタスクの内容を分けて行う部分に苦戦していました。しかし、問題部分もすぐに解決することができていたようなので、順調に作成を進めていくことができました。構想はある程度あるようなので、この調子で進めていけばしっかりと完成まで持っていくことができると感じました。', null, null),
  ('af6fc283-d983-516d-b5f9-aaab1df9bf16', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-17', '16:30:00', null, '通常 / アレンジ大賞作成', 'アレンジ大賞のゲームを最初に選んでいきましたが、どれも選べない悩みに入りました。結局のところ、るいくんとはおなじに上級のゲームを選んでいきました。でも、コード作成には、見本のコードを見てはいいが、それをそのまま移す行為が何度か見られました。１つ１つ自分で組み立てるように言いましたが、その行為は治りませんでした。見本の完成が今回はゴールではないので、アレンジの時に困ってしまうので、困っているときはどう困っているか考えるべきです。', null, '盛り上がり: るいくんにも移したことはいけないと言われていました。'),
  ('87bd9f9b-a5f2-51e8-adb0-ca647243d518', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-17', '17:30:00', null, '通常 / アレンジ大賞 上級', 'アレンジ大賞に挑戦してみたいと本人が言っていたため、上級の作成を行っていきました。ゲームやコードの内容についてはすぐに理解することができたため、今日からアレンジ部分に入っていきました。商品のデザインを変更したり、新たなキャラクターを出現されたりと視覚的な変化の導入を多く行っていました。イラストコースを受けているため、そっちで学んだ内容を活かせる部分を積極的に行っており、楽しそうにアレンジしていました。', null, null),
  ('1a27e28f-1a1a-56cb-86a0-92b1f12e0a50', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-17', '16:30:00', null, '通常 / アレンジ大賞', '中級か上級かかなり悩んでいましたが、上級を作ることにしました。基本に手順通りに考えていき、わからない所をしっかりと伝えてくれたので、サポートすることができました。左右キーのことや変数についてどう機能してくれるか、ある程度は考えてくれるようなってきました。新しい子がいると気がそっちに行ってしまうこともあったが、コードも少しずつ作れていきました。', null, 'タイピング: 久しぶりにやりたくなったそうです'),
  ('7eadcfab-94ad-52b2-8b6e-668f05327dde', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-17', '17:30:00', null, '通常 / アレンジ大賞に取り組む', '家のパソコンで、ビンゴおじさんのサイトからゲームを見つけていろいろいじってきたそうです。せっかくだからアルスタジオでやってみることを勧め、ログイン方法とアカウントを教えたところ、とても喜んでいました。 中級のシューティングゲームと両方プレイしてみて、上級にチャレンジする！とのことで取り組みました。手順書だけですべてのコードを組み立てるのは難しいキャリアのため、完成品のコードを一緒に読んでどういう意味なのかを口頭で答えさせ、理解ができたところで自分でコードを作るという流れで進めました。 不等号の向きや変数の変化など、プラスマイナスや向きで少し混乱することもありましたが、面倒そうにすることもなく、一つ一つ丁寧にコードを見て理解して作成するというサイクルが一人でできていました。 お迎えまでの1時間20分、集中して頑張っていました。', null, '盛り上がり: 作成しながらアイディアを出して、少しずつ手を加えていくのが楽しそうでした。 コードを完成させる傍ら、背景や通行人に気を配ってアレンジするのを楽しめていました。'),
  ('c54f58de-20b8-53aa-b563-ec80ea63f18b', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-17', '16:30:00', null, '振替 / アレンジ大賞', 'アレンジ大賞のもととなるゲームを作っていきました。最初、手順書通りにそうさんが進めようとしても、手こずっていたので、ゲームの流れ通りに作っていくことを提案しました。その際、方針を立てれば、必要となる変数やメッセージなどは自分でよく用意できていたので、よくできていました。', null, 'タイピング: よくしゅうちゅうしていました'),
  ('e7d2ad1a-f7cd-572d-aef1-4f1b069545f3', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-17', '17:30:00', null, '通常 / アレンジ大賞', '最初は上級のゲームの方に傾いていたが、前回のと区切りをつけて中級のモノを作っていきました。基本は、まずは見本のゲームを観察して、自分が思うままに作る、次に見本と見比べ、修正して流れで作れていきました。今回は3dゲーム風なので、遠近感を作り出す大きさと変数の活用について説明をしてあげました。見本見返しの中で知ってはいたものの使いこなせてない定義をどうにか活用できるようにしたいと望んでいました。元のゲームは7割くらい完成しています。', null, null),
  ('35dc088e-3bb4-5b47-be96-8cefeac3322f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-17', '17:30:00', null, '通常 / アレンジ大賞', 'アレンジ大賞の説明で、特に賞品狙いで熱量の入り方が高かったです。そのため、ほかの入賞も狙えるようにスプライトコスチューム、変数名などすぐわかるように最初から変更していました。アレンジの内容としては、1人の注文を4人分に変えて、それぞれ選択しながら提供していくようにいきたいようです。今回は、商品を渡す客を選択できる仕組みを作っていきました。選択中は黒色に変化してわかりやすくしていました。次回にもやりたいことが詰まっているので、作業は止まらなそうです。', '商品を渡している間は料理長は動かなくするようにしたいそうです。', '盛り上がり: 熱量が高いので、先生へのやってる作業の説明も事細かに説明してアピールしてました。'),
  ('2389d27b-ebac-5847-9b66-e1be82b1ad40', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-18', '16:30:00', null, '通常 / アレンジ大賞→基礎レッスン', '最初にアレンジ大賞の説明をして、初級を選び、見本通りにゲーム作成を開始。何をすれば良いかが全くわからない様子で、まずは見本を見て、何をどうすれば良いかを言葉で言ってもらい認識してもらい、それをスクリプトでどう表現するかを一つ一つ教える形をとっていました。が、全ての場面において、このようなことが必要で、自力でゲームを作る・アレンジをするにはまだ経験が足りないようです。ですので、アレンジ大賞ではなく、来週からは基礎レッスンをする必要があるかと思います。一つ一つ教えていく中でも、すぐに飴（かなりの頻度）を取りに行く、水を飲む、レッスンと関係がない話をするというのがかなり多いためなかなか前に進みませんでした。集中するのが難しいようです。', 'アレンジ大賞ではなく、簡単なレッスンで、基礎固めをするべきだと思います', null),
  ('4a8f0785-e729-5da1-8bdd-c9b2d47625b7', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-18', '17:30:00', null, '通常 / Roblox', '今日やるのは、アレンジ大賞とRobloxどちらが良いか尋ねたところRobloxということで、前回の続きから始めようとしました。が、Roblox studioを立ち上げようとしたら、エラーが出て起動しませんでした。なんとか起動させようとあれやこれや試しましたが、無理だったので、私のPCのRoblox studioを本日のみの一時しのぎとして使わせました。結果としては、いまだにデジタね教材一回目を終わらせることができませんでした。動画だけを見続けるということがやらないのか、できないのかが原因かと思います。例えば、動画を流しながら、Roblox studioのゲームをしたりしていて、動画の内容がそれじゃ頭に入らないだろうという感じ。きちんと動画に集中するよう促しては見たものの、面倒くさい、自分にはできないという返答で、動画による講義に集中してくれない状況でした。そんな状況で、歩みがあまりにも遅いので、動画の中身に書いてあることを、私がスクリプトを作成してブロックが変わることを実演してみせると少し喜んではいたものの、自分にはできないとか否定的な言葉が返ってきていました。動画を本当に集中してみてくれないと前に進めないので、今後何回か様子を見て今後の進め方を判断していくしかないのかなと、感じています。', null, null),
  ('ab94e022-346c-50f5-8b97-122e673fadb6', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-18', '17:30:00', null, '通常 / roblox', '前回１回目の確認テストからスタート、２回目の動画講義を始めましたが、特に何も質問もなく、スムーズに進められたようです。自作のアスレチックを作成して、それに少しアレンジを加えて、２回目を完了させました。そして自分の作ったものを、晴くんに遊ばせて喜んでいました。問題なく進められていると思います。', null, null),
  ('9cd18500-440f-5d4e-9388-6acf06d49b41', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-18', null, null, '通常 / アレンジ大賞', 'アレンジ大賞の説明をして、それぞれの級のゲームを見ていて、上級のゲームをやりたいとなりました。難しいと思うよと言っても、「こういうのを作りたい、難しいのやればそれも勉強になっていいでしょ」というような前向きな発言。難しいと思いつつも、状況にトライしてみることにしましたが、実際にゲーム作成をするにあたって、やはり難しいだろうということで、初級をする事になりました。あさひくんは、自分のキャラクターを作るのが好きで、得意なので、間違い探しゲームのキャラクターにオリジナルのキャラを混ぜるなどアレンジを楽しめそうな予感はします。今日は前半上級ゲームの事に時間がかかってしまったため、初級ゲームとしては、まだ最初のスペースでスクリーンを切り替えるところまでです。 レッスン時間全体を通して、集中して取り組んでいたと思います。（途中息抜きで落書きをホワイトボードに書いていましたが。。。）', null, '時間帯: その他'),
  ('b7b6fed9-a767-5de5-8e4e-230d68c061d4', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-12', null, null, '通常 / アレンジ大賞に向けてスキルの確認をする', '初めはドリルを提示してみましたがイマイチ乗り気ではなく、自分で何をやるか考えたいと言ってカード教材を見に来て、「最近授業でやった！」とビデオモーションセンサーカードを選んでいました。やることを自分で決めたせいか、しっかりとカードを手元に置いて、1つ完成したら「次はこれ」とページをめくって進めていました。 「エアドラムをつくろう」の課題では、「こういうのがやってみたかった！」ととても喜んで、熱心に作成していました。ただ、音にもこだわりたかったようで、絵の通りの楽器の音が無いのが少し不服そうでした。 1つ完成するごとにタイトルを考えて、楽し気に保存していました。 本来やろうと思って置いておいたドリルのカードを見て、「そういえば、ペンはあまり使ったことがないかも」といって、そこだけ「新しいスキル」として学習してみました。 初めはどのブロックから手をつけたらいいかわからない、と指示待ちをしていましたが、ペンのブロックを自分で確認して、「ペンで描く」にはどのような動作をするか、と発問すると、自力で「ペンをおろす」を選んで作成ができました。', null, '時間帯: その他
盛り上がり: 今日の課題は、興味のある内容だったせいか、かなり熱中して取り組めていました。 学校の授業でScratchを扱うことがあるらしく、「先生に教えてあげることもあるんだ」と得意そうに話していました。'),
  ('b8ff857f-5459-5fa9-aa2f-05b9cab708e1', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-12', null, null, '通常 / スキルチェックと今後の希望の確認', '3月末の体験会からずっと、授業が始まるのを楽しみにしていたそうで、こちらの言うことを一生懸命聞こうとしていました。 ジュニアプログラミング検定の各級出題ブロックの一覧を見せましたが、「経過年数」などの使用範囲が特殊なものと、「絶対値」等数学で未履修のもの、定義の「引数」以外は使用経験があるとのことでした。 今の目標は「U16大会に作品を出す」ことだそうです。独学でかなり作ってきているようなので、独学故の抜けているスキルの穴埋めをしていくことと、たくさんの作品に触れて、ブロックの使い方のバリエーションを増やしていくことを当面の目標にしていこうということで納得していました。 検定受験にも興味があるとのことだったので、2級の問題から選ばせ、「ギャンブルしてみたい」ということで②に取り組みました。30分かからないくらいで解き終わり、ほぼ完璧でした。アレンジもその場でスラスラとやってみせてくれて、コインがあふれて落ちる様子をうまく作成していました。', '1級チャレンジを楽しみにしているようなので、アレンジ大賞と並行してやってあげてください。おそらく50分かからないで解き終わるので、両立できると思います。', '時間帯: その他
タイピング: タイピングはあまり得意ではないと言っていましたが、普通に中学生レベルで打てていました。早く打とうとするためか、少しミスタッチは多いようですが…
盛り上がり: 独学ではできなかったことを色々知りたい！という意欲にあふれているようで、熱心に話を聞き、課題にも取り組んでいました。 2級が簡単そうだったので、次回は1級をやってみようと言うと、とても嬉しそうにしていました。'),
  ('8d84ec4e-9b59-5805-b6ae-292f95524597', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-19', null, null, '通常 / Roblox初回', 'Roblox自体あまりやった事ないようですが、特に問題なく、動画１回目を終わらせることができました。つまづいたところといえば、robloxアカウントのパスワードを忘れてしまったので、教室のアカウントで進めたこと、それと、roblox studioのエクスプローラーの中で、目的のスクリプトファイルまでなかなか辿り着けずにいたくらい。▲ボタンあたり押すことで、下の階層の情報が表示されることが感覚的にまだ掴めていないようでしたので説明しました（あおし君も同じとこでつまづいたので、慣れていないとそうなのかもしれません）。途中、上記以外のこれといった質問もなく、集中して一回目を終わらせました。', null, '時間帯: その他'),
  ('ac4df5ef-b849-534c-9731-aa2094e356a2', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-19', null, null, '通常 / Roblox一回目', 'roblox一回目、まだ導入部分というか、Roblox studioの使い方の説明レベルなので、説明ばかりで退屈になりがちですが、集中して特にこれといった質問もなく終わらせることができました。自分でツールボックスからいろんなオブジェクトを追加して楽しそうにしていました。', null, '時間帯: その他
備考: レッスン後、あおしくんのRobloxアカウントをログアウトしたら、復元用の保護者メールアドレスをついかしてくださいとか、アカウントを失うリスクを受け入れてログアウトするt０か、こわい文言が出てきたので、現状、ログアウトしないでそのままにしています。'),
  ('d4dd8d81-e88c-5f93-94b6-cff1397df736', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-19', null, null, '通常 / roblox→アレンジ大賞', '親が迎えに来るのが３０分遅れるからと、最初少し遊ばせてのことで、OK出して、Robloxで遊んでいました。３０分経つ前くらいから、robloxのレッスン開始を促しましたが、ゲームのキリが悪いとのことで、４０分経ったくらいでレッスン開始。robloxではなく、アレンジ大賞での景品（イヤホンが欲しいとのこと）に釣られてなのか、アレンジ大賞をやると決め、上級レベルの作成に取り掛かりました。ゲーム作成自体は、特に問題なく、自力でサクサク進めていました。', 'Robloxではなく、アレンジ大賞上級の続きかな。', '時間帯: その他'),
  ('7ce8509f-1560-5bb5-83c3-a083714981fc', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-19', null, null, '通常 / アレンジ大賞', 'レッスン開始時くらいの時に、どんなことをやっているのかの様子見ということでお父様が教室へ。アレンジ大賞のこと、どのような流れでみんな進めていっているのか（スクラッチ→ロブロックス→JavaScriptという流れ等）等々説明し、雰囲気は掴めてもらったかと思います。アレンジ大賞は、中級を選択、途中まではスムーズに自力で進めていましたが、隕石の作り込みで、つまづいてしまい、「全くわからない、初級にしようかな」と投げ出しそうだったので、励まして、中級頑張ってみるとのこと。(1)隕石が３Dで迫ってくるような表現方法、(2)クローン、(3)定義など、今まで経験したことのないようなもののオンパレードだったので、大変そうでしたが、半分写経レベルになってしまいましたが、隕石の部分を作り、時間オーバーとなりました。', '次回は、隕石部分のバグ（隕石が周囲に散らばらない）を直すのと、上記まだ理解度が低い３つのものを説明して、そのままゲーム作成終了に向けて進められたらとおもます。', '時間帯: その他'),
  ('efdb6d53-10a6-5450-845b-b34e7554fa2f', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-21', '17:30:00', null, '通常 / Excel検定に向けて', 'Excelはそれなりに楽しみにしてきているのか、自分からすぐに取りかかろうとしていたので、今日から30時間でマスターExcel2021を使って苦手な単元を練習してから模擬問題に取りかかることを説明しました。 もっと勉強したいところは関数だということで、4章をメインに学習しました。 概ね自力でできているのですが、実習17の「実売価格を売上金額÷売上本数で求め、関数を使って四捨五入して」という問題の意図がよくわからなかったようでした。例題が、ROUND関数の数値がすべて一つのセル番地になっていたので混乱したのかもしれません。数値に数式を入れることもできると教えたら、納得したようでした。 実習18のIF関数で4段階の評価をするところでは、数式が異様に長くなると苦笑していました。ネストの書き方が初めてだったようで、すべてのIFの前に=を付けてエラーになり、困惑していました。また、数式の最後にまとめて)が出てくるところで、なぜか)と)との間にすべて"が入っていて、エラーになっていました。 ネストして関数を書くときは、関数名の前には=は必要ないこと、"は文字列を囲むときに使うことを教えました。すべてのエラーが解決したときは珍しく感情を出して「やったー」という感じでした。', null, '盛り上がり: 昨年くらいから、Scratchではほとんど質問することもなかったので、質問をすることによって先生と会話をするのがなんとなく新鮮そうでした。
備考: 1学期中に検定を受けたいとのことでした。'),
  ('28078390-3f53-5d7b-8d3e-6ebde087e125', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-21', '16:30:00', null, '通常 / アレンジ大賞初級', '入って間もないですが飲み込みがよく、たまに周りの子と楽しそうに雑談もしていますが、基本自分のペースで黙々と作業をしています。 まだスキルがあるわけではなさそうなので、間違った路線のまま進んではいないか、声をかけて定期的に確認する必要がありそうです。', null, 'タイピング: なし'),
  ('89ac68b3-3942-5806-80f8-dcbfc3ef45ba', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-21', '17:30:00', null, '通常 / アレンジ大賞の作品制作を進める', '間違い探しのカニ等のスプライトのコードがまだ白紙だったため、変数を表示した上で、もう一度完成版をプレイさせました。変数がいくつのときにどのスプライトが変化しているかを見せると、変数の意味が理解できたようで、自分で適当に入れていた変数に入れる乱数の範囲もすぐに直すことができました。（1～6にしていた） 変数の値が一致したらコスチュームをかえる、正解というセリフを出す、という流れが納得できた上で自走させたところ、きちんと作成ができました。 元の通りのゲームが完成したところで満足してしまい、「もうこのままがいい。あまりいじりたくない」と言い出したので、秋くんの好きな方向にアレンジしていいのだということを伝えたところ、「どこが変わったかな」のところで電車が走っていく演出を入れたいとなり、熱心に電車を描いて走らせるところまで作成し、満足そうでした。', null, '盛り上がり: 自力でコードができたときは嬉しそうで、その都度先生を呼びに来て見てほしがっていました。 アレンジも、本筋とは関係ないところながら、演出としては面白い感じになったのが嬉しそうでした。'),
  ('3f5235d1-c87f-52a7-936e-3b79b7cd9681', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-21', '16:30:00', null, '通常 / アレンジ大賞初級', 'スプライトを別ゲームから画像ごとダウンロードし、キャラクターをたくさん増やすアレンジをしました。画像を移行していく中で重複した画像を整理したり、コードをたくさん書かなければいけない場面がありましたが、面倒だと感じつつも頑張って取り組んでいる様子でした。 コードのアレンジはあまりしたがらないため、もう少しスキルアップができたらそのようなことにチャレンジができると良いと思います。 ★キャラ数が多いため、次回はステージを増やしていく予定とのことです。', null, 'タイピング: なし'),
  ('8a872a2a-7a1f-5036-bf4b-1227f8d625b4', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-21', '17:30:00', null, '通常 / ロブロックスのコースを進める', '時間まではロブロックスで遊んでいましたが、授業が始まったら素直に準備を始めていました。ロブロックスタジオは開いていましたが、デジタネを開くことは忘れていたのか、「あと、何するんだっけ？」と聞いてきました。すぐに思い出したようでしたが…。 動画を2倍速で見ていましたが、やっていることはわかっているようで、たまにのぞきにいくと「今はこういうことをやってるんだ」と言いながらオブジェクトの作成やprint関数の打ち込みなどをやって見せてくれました。 40分くらいで演習問題まで解き終わって、残り時間は嬉々として「ひみつのおるすばん」で遊んでいました。 演習テストは60点で、英語があまりわからなかった、とのことでした。', null, '盛り上がり: のぞきにいくたびに、「こういうことをやってるんだよ」と得意そうに実践して見せてくれました。学習スタイルにも少し慣れてきたようで、途中でだらけることもなく、一気に進めて残り時間を遊びに使おう！という感じでした。'),
  ('26da1d9e-1833-550c-a57b-fedc5e797ca3', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-21', '16:30:00', null, '通常 / アレンジ大賞初級', '旗が押された際にコスチュームが戻らないというバグあり、本人も納得いってない様子でした。 原因として次の動作に行く前に旗を押しすぎているようで、スタートしたら必ず赤いボタン押して止めてからまたを旗を押すように誘導しました。 興味ない部分（例：ステージを変える など）に関しては「いいよ、やらないよ」のスタンスでめんどくさがってやろうとはしませんでした。 音声入れるなど工程が面白そうなものに対してはモチベーションが高く、楽しそうに作業できていました。', null, 'タイピング: なし'),
  ('13776aa0-b12c-51e5-90a3-2411040b0995', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-21', '17:30:00', null, '通常 / イラストコース体験', '※親御さんにipadとアイビスDL案内済み まだ描き慣れていないと判断し、模写やオリジナル教材の続きを通してレイヤーや投げ縄の復習をしました。オリジナル教材に関してはかなり早く進めようとしてたので、一旦待ってもらって身の回りにあるものを模写してもらうよう案内しました。 今回の授業では新しく画像の統合、レイヤーの左右反転を教えました。 本人の様子を見たところ、興味はあるけどまだイラストを漠然と習っているといった様子なので、何か目的や「こういう絵が好き」という好みを基準にして絵を学べると良いのかなと感じました。 何か好みが無いか、次週アイビスのiD作成も含め改めて本人に確認してみる予定です。', null, 'タイピング: なし'),
  ('4db5ca9d-41c4-5f0f-8928-9d5b257e3d01', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-04-22', '16:30:00', null, '通常 / アレンジ大賞初級（ただし、レベルが高いのに挑戦なので、基礎理解も）', 'まだ入校したてのため、知らないことが多すぎるのだが。「アレンジ大賞の商品が欲しい！」入校したばかりで、まだ知らないことが多く、すべてのコードが“初めて”の状態です。 ただし、「アレンジ大賞の商品が欲しい！」という強い意欲はあるが、コードを一つ一つ組む時に「これ？これ？」と確認する癖があり。毎回、「どう思う？やってみ？」と言い続けて ここは直したいところです💦 レッスンでは、「毎回1～2個の新しいコードを理解して覚える」ことを目標にしようね、と何度か伝えました。 今回はアレンジ大賞で以下の内容がたぶん、初めてのブロック： - 全角・半角の違い - メッセージの使い方（送信・受信） - 全画面表示の方法 - 乱数の扱い方 お迎え時に保護者の方にも、「今は10か月先のスキルレベルに挑戦している段階なので、分からないことが多くて当然。ただ、毎回1～2個は覚えて帰るというスタンスでやっています」とご説明しました。 今日は特に「全角・半角の違い」を重点的に確認し、「違いは何だった？」と尋ねたところ、しっかり答えられていました。あわせて「メッセージ機能」も印象に残ったようです。次回、軽く復習する予定です。', '- 「マウス操作がまだ不安定」なため、最初にマウス練習ツールで数回しっかり練習させるとよいです。 - 「全角・半角の違い」「メッセージ機能」の内容を簡単に復習し、覚えているか確認してあげてください。', '盛り上がり: 妖怪ウォッチにハマっているとのこと。Scratchで作られた妖怪ウォッチ風のゲームに興味を示し、「これって作れるの？」と質問があったので、「もちろん作れるよ！」と伝え、本人のアカウントに作品を移植しました。 「これが作れるようになるのを目標にしよう」と声かけしましたが、今のところは“遊ぶ”ことがメインの興味のようです。ただ、将来的にアレンジできるようになると良さそうです。'),
  ('bd51138a-a0f7-5ffb-ad08-7006835f0542', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-22', '16:30:00', null, '通常 / アレンジ大賞', 'やはりお手本のコードの長さにため息をついていたため、重要なポイントを抑えながら作っていきました。見た目の演出は後回しにして、ゲームとして遊ぶために必須の動きからやることを促すと手を動かしてくれました。正誤判定に必要な変数「ポジション」やオーダーを毎回買える仕組みなどを作成し、ある程度動くようになってきました。ただまだバグがあるため、コードの間違いや足りないところを来週修正することで見本の作成が終わる予定です。', null, null),
  ('308e0880-dfe9-50a4-8e5c-1ca755c04a86', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-22', '16:30:00', null, '通常 / アレンジ大賞', '隕石の動きが難しいと言いながらも頑張ろうとしていたので、一緒に細分化しながら作っていきました。座標や角度を乱数で決めるコードがよくわからず混乱していましたが、「まずは普通の数で座標・角度を指定する→その数を乱数に変える」と分解すると腑に落ちたようでした。クローンを削除するタイミングなども問いかけに応じて考えてくれて、自分なりのシンプルなコードでお手本をほぼ再現できました。次からはアレンジに入れそうです。', null, null),
  ('59692445-a122-5b0c-9e76-ddff0ba9ee83', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-24', '17:30:00', null, '通常 / イラストコース_髪の毛の描き方', '前回授業から描いてきたイラストを見せてもらいましたが、イラストの色味を加工する方法を知ったので、瞳がよりキラキラと描けていてよかったです。 今回は雑談も交えながら作業をしてもらいました。以前教えたレイヤーのファイルなどを活用したり、ipadを置く台をうまく活用して描けていました。 今回は教材資料通り描いてもらったので、 次回は自分の好きな髪型を描いてもらう予定です。', null, 'タイピング: なし'),
  ('eb6082e3-3698-5329-94ee-7fc548d40f01', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-24', '16:30:00', null, '通常 / アレンジ大賞 上級', '前回の続きから作成していきました．今回はとにかくスピードを意識して進めていくことにしており，途中で入れたい内容などをアレンジ段階でやると約束して取り組んでいきました．結果として，先週よりも早く進めていくことができ，残りはスプライト１つ分のみとなりました．来週で残り部分を完成させたのち，アレンジ部分に入っていければ良いと考えています．', null, 'タイピング: 集中して取り組めていました．'),
  ('7844d7ed-163e-5a57-bb44-9b25fd8602b2', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-24', '16:30:00', null, '通常 / アレンジ大賞', '前回が気があっちこっちで全然進んでいなかったので、今回は最初から始められていました。るいくんに「ずるして作成している」という言葉に気に障ったらしく一から就く朗々としていました。操縦の左右キーの動かしの部分はなんとか自力で作れはしました。ほかの部分はこちらが見本を見ながら考えながら作ってよいとしたらペースはよくなりました。だが、先生の目を盗んで完成品から複製していく作業もまだ見られました。 後半になると、5時半の子が来るので、集中力が飛び散るので、初めから集中させといたほうがいい。', null, 'タイピング: ルイ君に誘発され久しぶりにやっていました'),
  ('6b9c1893-5ba6-5cde-a0dc-27ca6d24e88e', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-24', '17:30:00', null, '通常 / Excel アレンジ大賞 上級', 'Excelでは，４章の実習１１に取り組んでいきました．関数の固定をどんな時に使用するのかいまいち理解できていない様子でしたので，その部分について復習しながら解いていきました．終了後は，アレンジ大賞の作成にシフトしていきました．二人でプレイできるゲームを作成するにあたり，判定部分をどうしていくのかを悩んでいました．次に作成に取り掛かるまでには考えをまとめてくると言っていたのでスラスラと進めていけると思います．', null, '備考: 結合して中央揃えがわからず不安がっている様子でした'),
  ('5ad640cd-238c-5c2c-994d-89f11b011bd2', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-24', '16:30:00', null, '通常 / アレンジ大賞', 'かなりゲームを好んで進めてくれいるので、変数の条件式なども考えてから修正や作成に取り掛かってくれてます。まだ、不等号の間隔が鈍いですが、作っていくれました。料理長の仕組みをおわったとっころで、ケーキなどの仕組みを表示までを作るところまではかなり収集して作ってくれました。その後は、集中切れたのか先のアレンジのことで頭がいっぱいになり、イラスト探しに奮闘していました；', null, 'タイピング: 育成に励んでいます'),
  ('b16b14a8-4fde-560d-b323-81f12c25fc74', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-04-24', '17:30:00', null, '通常 / アレンジ大賞 中級', '前回で基本部分が半分ほど完成させることができていたため，今回で残り部分を終わらせていきました．音楽が終わるまで鳴る際の違いを理解できていなかったようなので，一緒に作成していきました，完成後は，アレンジとしてステージを宇宙ではなく合戦に変更していたようで，足軽のキャラクターを作成していきまいた．構想は固まっているようなので，次回以降も順調に進めていけそうです．', null, 'タイピング: 真剣に取り組むことができていました．'),
  ('2986e9e5-567a-527f-910e-87d65184ae2c', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-24', '17:30:00', null, '通常 / アレンジ大賞', '操縦の動きから作っていきました。ここで、スプライトの層の説明をしましたが、不思議そうに？？な感じでした。でも、コードで自分で作った後に試遊で確認してみると、何が手前に出てきたのか体感できていました。 隕石のコードでは、見本の動きの説明を考えてもらうと、圧倒されていたが、１つ１つ分けて考えていくと、着実に理解をできていきました。ここで、ランダムの向きに変えることがありましたが、迷うことなく自作で作れていました。 最後まで、時間が過ぎても作り完成させることができました。', null, null),
  ('4e8eb577-e43e-5682-b495-c7672b770cfc', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-24', '17:30:00', null, '通常 / アレンジ大賞', '今回はアレンジを中心に進んでいきました。背景に道路風景にして、出店感を作り出したいそうです。実際に家に人が入っていく様子や車が動き出したりする動きを作成しました。動きの構成に悩みんでいたので、使えそうなコード組などを一緒に考えていきました。GW中にも家で作成を進めていくそうです。', null, null),
  ('868ca08b-69bd-5f60-bc0b-eac6ece3449b', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-24', '17:30:00', null, '通常 / アレンジ大賞', '最初にロブロックスもやってほしいと伝え、先にアレンジ大賞のコスについて切りのいいところまでやってからやるでしたが、ずるずると最後までアレンジ大賞の方に取り掛かっていました。お客さんもホラー調に変わっていて配色も不気味カラーに変化していきました。お客さんもホラー調に変わっていて配色も不気味カラーに変化していきました。そして、店が襲撃されるという面白い切り口もあり、それに活かせるスキル(カウント変数)を一緒に考えていきました。 次はロブロックスやってほしいです。', null, null),
  ('c7368746-b793-59ea-90a7-2bdc05834a83', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-25', null, null, '通常 / 基本操作コース', 'アルスタジオで細分化されたものを見ながら追跡ゲームを作りました。それぞれのステップで、何の動きを作ればいいのかすぐに理解していました。変数や演算(等号)は初めてでしたが、ブロックがおいてある場所だけ教えると、使い方も推測してすぐに飲み込めていました。旗が押されたときに変数や背景を初期化することについて、最初は気づきませんでしたが一度テストプレイすると必要性を理解することができました。一通りゲームとして完成させることができました。', null, '時間帯: その他'),
  ('7a723305-e9d0-56ac-9aad-b1832e4770aa', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-19', null, null, '通常 / アレンジ大賞', 'アレンジ大賞の製作を中級で始めました。ゲーム内容に興味を持ちやる気がありました。手順書に沿って、操縦艦の動きや乱数を使った隕石の設置などは頑張って自力で考えていました。細かいところまでは厳しかったようでお手本のコードを見ていましたが、内容を少しでもつかみながら作っていました。', null, '時間帯: その他'),
  ('0224620d-9d51-56ca-a648-3109e4f83e65', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-19', null, null, '通常 / アレンジ大賞', '休み時間に遊んでいたゲームに偶然近い内容だったこともあり、アレンジ大賞の製作を中級で始めました。操縦艦の動きについては自分で考えてもらいましたが、最初は座標を動かしてしまい、思った動きじゃないと迷いながら、角度を変えているという答えにたどり着きました。その後は制限時間などのゲーム管理から順にお手本を見ながら作成を進めました。', null, '時間帯: その他'),
  ('4d826102-e898-5fce-8fdc-091dcb235c17', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-19', null, null, '通常 / アレンジ大賞', 'アレンジ大賞の製作を中級で始めました。考え方プリントをよく見て考えながら作っていました。隕石のクローンを作成→配置→移動するという流れがよく分かっていて、お手本のコードもあまり見ずに作れていました。元のゲームの再現が早速この時間で終わり、「スペースキーを押さないと打てないようにする」「打ったら減点の隕石を出て来るようにする」とアレンジ計画も話してくれました。', null, '時間帯: その他'),
  ('f66c078b-b25f-5fc4-8f81-cbf084740fd5', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-19', null, null, '通常 / アレンジ大賞', 'アレンジ大賞の製作を初級で始めました。初級と中級を比べたとき、どっちでもできないことはないが自分がよりアレンジできそうなのは前者だという考えで選んでいました。「まず元のゲームと同じものを作ってからアレンジする」というルールは一度伝えましたが、忘れてアレンジを始めてしまったようなので戻ってもらいました。お手本の再現は次回も続けることになりそうです。', null, '時間帯: その他'),
  ('40d07873-d8fa-5d68-b289-be6d4e1dafbf', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-19', null, null, '通常 / アレンジ大賞', '始めて間もないですがスキルはあるので、アレンジ大賞で中級を選んで始めました。考え方プリントを見るだけですらすらと作業が進んでおり、クローンや乱数は完全に使いこなしていました。ゲーム中を検知する際、メッセージを送る代わりにカウントダウンスプライトのコスチュームで管理するなど、自分なりのコーディングスタイルを確立していました。元のゲームの再現を終えることができ、隕石の種類を増やすといったアレンジにも少し取り掛かっていました。', null, '時間帯: その他'),
  ('cb927d1a-56d4-5e6c-8479-9d1bbcca90be', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-22', '17:30:00', null, '通常 / アレンジ大賞', '隕石の動きの続きを作りました。隕石が端まで行ったら消さないといけないことは分かっていましたが、「隠す」でやろうとしていたので「クローンを削除する」を習得しました。爆破の動きについてブロック定義も初めて使い、どういうものなのかを理解しながら使うことができました。終盤にはお手本の再現が終わり、アレンジに取り掛かりました。今日のところは色の変更だけでしたが、今後のイメージを聞くと、当たってはいけない爆弾を置くことを考えているようでした。', null, null),
  ('4468a3a9-77b7-5231-ace1-2d5c7598f153', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-25', '16:30:00', null, '通常 / アレンジ大賞・ゲームを完成させてアレンジを開始', 'アレンジ大賞２回目。クローンした隕石が表示されないという不具合の修正から。クローンを削除するというブロックが不適切な場所に存在していたようです。クローン＋３D表現の処理は、自力で再現するのは難しかったので、半分カンニングしつつ完成させました。どのように３Dっぽく表現するか（初め小さく徐々に大きくなる＋乱数でいろんな方向に分散させる）を説明して、きちんと理解できたようです。その後も特に問題なく、完成形と比較して、ほぼ全てを完成形で再現することができ、アレンジを開始し始めました。順調に進んでいます。', null, null),
  ('d0820d6f-fa60-5e33-a7f4-8c89b1d49cfc', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-25', '17:30:00', null, '通常 / Roblox Studio/ハラハラピンボール', null, null, null),
  ('0b7fa011-933d-5b14-bd05-af2ff98000ce', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-25', '17:30:00', null, '通常 / ロブロックスを進める', '前回は、最初の動画は完全に終わらせたわけではなかったものの、また最初の動画途中からスタートすると一気にやる気が無くなりそうだったので、ブロックを作る作業で多少面白さが出てくる「頂上を目指せ」を授業初めからやってもらいました。最初は、動画を大人しくみていたのですが、動画を見続けるだけの状態がやはり苦痛らしくて、途中からは、動画講義を見るのをやめてしまい、前回のレッスンの一番最後に覚えたツールボックスから大量のオブジェクト（ゾンビやマグマやら、、、）を設置することをして、それを利用したアスレチックぽいものを、作り始めてしまいました。ちゃんと動画通り進めないといけないこと伝えましたが、その都度、面倒くさい面白くないというので、「頂上を目指せ」で覚えるべき重要っポイントを少し離しつつ、そのまま自作のアスレチック作成を進めてもらいました。動画に縛られず、自分の思い通りに作れて、本人もこれだったら楽しいんだけどな。とボソッといっていました。当面は、こんな感じで重要ポイントを教えつつゆっくり進める形になるかもしれません（動画を見ることは、もちろん促しはしますが、、、）', null, null),
  ('baa5faee-c9e0-5b22-93b0-92c42d59179b', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-26', null, null, '通常 / イラストコース_特徴ごとの目の描き方', '黙々と作業が出来ていました。 特に困った様子もなく、綺麗に仕上げられていました。', null, '時間帯: その他
タイピング: なし'),
  ('d885c9e3-f49a-5a57-bd2d-0148cca254aa', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-26', null, null, '通常 / イラストコース_特徴ごとの目の描き方', '前回同様、黙々と作業が出来ていました。授業外で最近アニメのイラストを描いたみたいで、アイビスを活用できているとわかってよかったです。', null, '時間帯: その他
タイピング: なし'),
  ('8191ea6c-6de0-50ec-8968-e466e10a9243', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-26', null, null, '通常 / イラストコース_特徴のある目の描き方', '私物のipadが電源が入らなかったため、しばらくはアナログで瞳のデザインのラフを描いてもらいました。 最終的に教室のipadを使ってもらい、私物のipadは修理に出すとのことです。 前回からアイビスで絵を色々と描いてくれたようで、線画と色でレイヤーを分けることの大切さをよく理解できたと言ってくれました。今回描いてくれた瞳も漫画風でかっこいいデザインに仕上げてくれました。', null, '時間帯: その他
タイピング: なし'),
  ('8890d83d-71e6-532c-bd9f-ff2c785ffc0e', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-26', null, null, '通常 / イラストコース体験', 'ご自宅から持ってきたipadを使って体験をしてもらいました。 デジタルイラストは普段あまり描かないようでしたが、キャラクターの描き方などの教材にかなり関心があるようで、最終的に漫画のキャラが描けたらいいなとのことでした。 今回はレイヤーの説明、投げ縄ツールと移動のやり方、コピーと貼り付けの仕方を教えました。 導入としてリンゴを描いてもらっていたのですが、コピーと貼り付けを駆使してそこからオリジナルの敵キャラを描き上げていました。 スクラッチでもそうでしたが、イラスト素材を使ってイメージを膨らますことが得意なようです。 親御さんともお話しして、本格的にイラスト描きたいとのことだったので、次回までにアカウントと月額加入していただくようお伝えしました。', null, '時間帯: その他
タイピング: なし'),
  ('3dc9e480-9127-55a7-a314-6e8148a3782e', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-26', '17:30:00', null, '通常 / イラストコース_ガザガザのイラスト素材作成', '葉琉くんから「ガザガザの隊長を描いて欲しい」とのことで、最初はもらった資料を直撮りしてトレースしてもらおうとしたのですが、ipadに制限がかけられていたため教室のipadを使って資料を検索して描いてもらいました。他の先生にも協力してもらい、カニを持っている手を見本に描いてみたりなどしました。 ラフを描いてから上から線画を綺麗に描いていたので、丁寧な仕上がりになりそうでした。 今回技術としては、線画の色を変える方法を教えました。', null, 'タイピング: なし'),
  ('4b601c87-f6d6-5e36-9bbf-fc943a02a005', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-26', null, null, '通常 / アレンジ大賞ゲーム完成', '中級のゲーム作成途中から再開、ちょっとしたバグはあったものの、理解はしっかりしているので、特に問題なさそうな感じです。前回にちょっと難しい部分の隕石の処理を終えていたこともあり、質問もあまりなく、ゲームをほぼ見本通りに完成させることができました。 次回は、アレンジからスタートできそうです。', null, '時間帯: その他'),
  ('a652571e-b47e-5302-8d37-7b63933f2350', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-26', '16:30:00', null, '通常 / アレンジ大賞', '今回は人が少なかったので、集中して取り組みていました。コードを見せながら作っていきましたが、作る前に見本の動きがどこに対応しているか考えながらやっていきました。ランダムな出現と向きについてどのように動いいているか探しながら作れていたので、発見の際にはかみしみてできていました。途中、操縦者が欲しいとのことで、イラストも追加したりして楽しみていました。ゲームスタート部分もつまらないながら集中して作れ、見本品は完成できました。', null, null),
  ('af625179-f0fa-5145-99b0-8e24ddf92b97', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-04-26', '17:30:00', null, '通常 / イラストコース_ガザガザのイラスト素材作成', '今回頼まれたイラストを描いてもらうにあたって、事前に資料を用意してから作業に入ってもらいました。魚をトレースして塗ってもらい、一匹分は完成することができました。 他の魚はコピーと貼り付けで量産できるかと思うので、次回5/17までには完成しそうです。', null, 'タイピング: なし'),
  ('893240b1-5109-50b0-9975-b8552de679ba', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-26', null, null, '通常 / アレンジ大賞', '上級ではじめは見本のコードを見てやる気を落としていましたが、始めるとちゃんと動きを理解して作りこみができていました。途中、バグが発生してもどこが違うのか自分で見つけ出して修正できていました。変数の不等号の向きなども景帝の効果もあってか自分で治せていました。全体の8割に進んでみました。', null, '時間帯: その他'),
  ('34eb043d-7137-59bd-9161-c5591e868699', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-26', null, null, '通常 / エクセル→チラシ作り', '記録を元にエクセルを準備したものの、だいぶ前の記録だったようでどこまでやったか記憶が曖昧とのことでした。じゃあ最初からやり直したらと提案したものの、それはやりたくないとのこと。模擬問題に挑戦してみようと準備しましたが、今日はエクセルジャなくても良いとのことで、ガサガサのチラシ作りを進めていました。次回は、模擬問題（１回目からかな？）に挑戦するといっていました。', null, '時間帯: その他'),
  ('23290c01-e5a6-58d9-adf3-c49a91a046bd', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-26', null, null, '通常 / オリジナルゲーム作成→エクセル', 'U16への作品提出用にオリジナルゲームの作成を提案してみましたが、U16は９月で、だいぶ先ということで、エクセルをやりたいとのことだったので、エクセルの練習問題０１に挑戦。４、５回程細かい質問がありましたが、わからなかった点を問題なく理解できたようで、よかったです。次回もエクセルの続きで良いと思います。', null, '時間帯: その他'),
  ('477bed4c-65f7-50f0-9a40-e8d7657a4f92', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-26', null, null, '通常 / アレンジ大賞', '前回の作りから隕石が出てこないバグがあったので、そこを直していきました。メッセージ名違いだったので、バグの内容をはっきりさせてから自力で見つけ出すようにさせました。完成後、アレンジで確率も使ってレアキャラを出るようにしたいとのことだったので、乱数と変数を使って教えていきました。動きについては隕石と同じにしたいのことだったので、そこは元のコードと模倣するように伝えてました。', null, '時間帯: その他'),
  ('64a02714-2e4c-5b8b-b63e-8367bf3bf398', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-26', null, null, '通常 / アレンジ大賞上級', '前回Robloxから、アレンジ大賞に変更。レッスン開始時に、Robloxのゲームに夢中になり、なかなか課題に取り組んでくれず、キリのいいところでアレンジ大賞上級のゲーム作りを初めてくれました。が、途中でゲームしたり電話がかかってきたりと、進みは遅く、なかなか集中して取り組んでくれませんでした。スピーカーとかの景品に興味があるようで、少しは進んでいるようですが、、、次回は集中して一気にアレンジまで進んでくれることを期待したいです。', null, '時間帯: その他'),
  ('9d91de07-1d8b-502f-8607-f4e25277a4d0', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-04-26', '17:30:00', null, '通常', 'スペースキーで打つ動作が機能しないかったので、「かつ」との機能について今一度教えていきました。そして、前回までのアレンジで満足した感があったので、ブレストカードを使ってアイデアを考えました。そこで、隠し要素を追加したいのことだったので、そのBGMについて探していました。確率の作り方も一緒に作ってものできていました。', null, null),
  ('a18f87e7-8b5d-591e-bbb0-2a8ad498539d', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-04-26', null, null, '通常 / アレンジ大賞ゲーム作成完成', '前回の時点で、アレンジ始める前のゲーム完成度合いが50%だったので、今日で完成させることを目標にスタート。最初、間違い探しで、変化するキャラクターは、カニだけにするという気持ちでいたみたいで軌道修正しました。３つのキャラクターのどれが変化するかはゲームするたびに変わるようにする方法を考えてねと、自力で考えさせましたが、なかなか思い浮かばないようでした。これまで、何回か乱数を使った処理をやっていたのですが、乱数を使うというのがピンときていないみたいでした。なんとか、乱数でどれかを変化させる方法を細かく説明し、しっかりと理解してくれました。その勢いで一気にゲーム完成させることができました。次回はアレンジからスタートになると思います。', null, '時間帯: その他'),
  ('59753264-667e-551c-b064-5077048322ba', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-26', null, null, '通常 / アレンジ大賞の作品制作', 'アレンジをしながら作成を進めているようで、今日はどこを作成するかというのも自分で把握して来室しました。 家でも作成を進めていたようで、隕石が当たった時に左右のエンジンが故障中と表示される、一定時間が過ぎると修復完了が出るというアレンジを頑張っていました。 エンジンの様子を表示するスプライトを作成し、コスチュームをたくさん作って「左エンジン故障中」「全エンジン故障中」「エンジン修復完了」などを表示するようにしていたのですが、すべてコスチューム番号で管理をし、表示を変えるときもコスチューム番号+2、のような形で作成していて、意図した通りの文字が表示されないときの検証にとても苦労していました。 そこで、検証の際に現在のエンジンの状態がどうなっているのか可視化することと、コードをシンプルにすることを目的に、エンジンの状態を変数をフラグ的に使うことで管理したらどうかと提案したら、納得してすぐに直していました。変数の値によってコスチュームをシンプルに変更できるようになって、動きも安定したと喜んでいました。 最後に、全エンジン故障中のあと、全エンジン修復完了と出したいところが「左エンジン修復完了」となり、すぐに「故障中」と出てしまうことで悩んでいました。 GW中に家でも考えてくるそうです。', null, '時間帯: その他
タイピング: 授業前にしっかりと取り組んでいました
盛り上がり: コンテストを目指しているためか、コードを第三者にもわかりやすくかく、という提案を熱心に聴いてくれて、素早く対応していました。'),
  ('1dfe1fd3-ba59-520f-92fe-bb9cd60e8ddf', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-04-26', null, null, '通常 / 基本操作コース、ジャンプとスコア', '前回の追跡ゲームで扱ったスコア変数について、今回も使うので復習してから始めました。ジャンプを作るときは「スペースキー押す→上に行く→下に行く」という流れが細分化できており、x座標ではなくy座標を変えることも抑えられていました。スコアについては、開始時の初期化を一度忘れていましたがテストプレイですぐに気づけました。少し複雑な卵の動き(最初数秒隠れてその後は左に流れ続ける)について、最初だけやる動作も「ずっと」の中に入っていたので、ずっと繰り返すのはどこなのかを問いかけました。少し時間を使って考えていましたが、旗が押されたとき瞬間だけやりたい部分を見抜くことができました。レッスン時間ほぼちょうどで完成しました。', null, '時間帯: その他
盛り上がり: 作ったゲームが思い通りに動く喜びを感じているようです'),
  ('0fb8d6e0-004c-519d-be5b-c3f1bf06ebc1', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2025-05-08', '17:30:00', null, '休み（未対象）', null, null, null),
  ('1464bd35-f08a-5f49-9653-54bbf0c1d971', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-24', '17:30:00', null, '通常 / アレンジ大賞', '自分で問題点ややりたいことを発見しては自己解決していました。 今のところは自己解決ができていて、それ自体は素晴らしいのですが、ハマりだすと他人の意見やアドバイスを聞き流して突っ走る傾向もあります💦', null, '盛り上がり: 入賞を目指したい、と前向きに、楽しそうに取り組めています。'),
  ('0cac819b-e818-5f8f-976d-2dbe8894a139', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, null, '2025-04-17', '16:30:00', null, '通常 / 【体験】', '一昨年のプログラミング大会 優秀賞受賞。企業賞にて選出経験あり 。昨年はフィンランドからオンラインでU16大会にエントリーしたそう。コンテストにはいろいろと応募しているとのこと。シミュレーションゲームを作るのが好き。最新作はもやしの育成。学校でScratchクラブを作って友達と教室で使えるツール（当番ルーレットなど）を作ったりして、教室のお金を稼いでいる。将来もそうやって何か作っていきたい。マイクラでPythonの勉強も始めたところ。クリーパーの顔を自動でかけるようにしたい。ゲームは何でもやるそうで、スマブラやRPG、テトリスやぷよぷよなども好き。検定の課題ブロック表はほぼわかっていたので、脱出ゲーム、ツムツム、スマブラをプレイしてコードを見てみる。脱出ゲームはいつか作りたいとのことで、興味を持ってコードを見ていた。ツムツムやスマブラは、リストの使い方が面白いというので、敢えてリストを表示してプレイしてみた。検定1級応用課題4を1ページ解いたが、余裕ありそう。', null, null),
  ('3e0d51ae-5992-5b95-b863-08ec70cbf731', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-08', '16:30:00', null, '通常 / アレンジ大賞_上級', 'ゲームが誤作動で動かないということで、私が横でヒントを与えながら自力で答えを考えてもらいました。えみちゃんはスクラッチについて考えることがあまり得意ではなく、正直答えがわかればいいやのスタンスだったので、ほとんどは答えを誘導して完成してもらいました。 今回は「ゲームがスタートしたら/終了したら」の部分を完成してもらい、途中「ゲームが１の時〜」というコードの説明をしたのですが、やはり興味がなさそうでした。 ゲームはほとんど完成してもらったのですが、コードが正しいにも関わらず食べ物が上へ移動するモーションがバグってしまっているので確認していただければと思います。', null, 'タイピング: なし'),
  ('421857ab-f620-5121-bd29-7f4cdc4830db', '57f45872-1f3e-5540-b676-bf9023444e39', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-06', '16:30:00', null, '通常 / アレンジ対象 中級', '作品のアレンジ部分については，本人の中で構想が固まっているようで一人で進めていました．隕石の速度や範囲を変えていくことで，難易度の変更を加えていくようです．今回で下地部分はできたようなので，次回でアレンジを完成させ，見直しを行っていくようです．', null, null),
  ('12feff07-3f18-5f17-b762-7fe118249a0f', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-08', '17:30:00', null, '通常 / イラストコース_ガザガザの素材', '１時間でバケツと網の両方を描いてもらいました。今回は画像の透過での保存について教えました。2つ完成させてやり切ったのか、描き終わった後はしばらく絵から離れて休憩をしていました。', null, 'タイピング: なし'),
  ('eb162ccf-90fc-5ef3-9a06-4a61c2dbdeb4', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-06', '16:30:00', null, '通常 / アレンジ大賞 上級', '作品のアレンジ部分に関しては進んでいるようですが，動作部分にいくつか支障が出ているようなので，その部分を来週直していきたいです．そして，本人の集中力があまり続いていないようで，作品制作にも支障が出ていると感じました．そのため，なんらかの対策が必要あると感じます．', null, null),
  ('edf39ab0-650a-59a7-abbe-fe4f91ce450c', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-06', '17:30:00', null, '通常 / アレンジ大賞 中級', '作品のデザインを大きく変えており，ステージを宇宙から農村へ，攻撃対象を隕石から足軽への変更とかなりこだわった内容にしていました．今回は，刀に足軽が触れてもスコアに反映されていないようで，刀のコスチューム変更や色変更などを試して，自分で解決しようと頑張っていました．来週にはこのバグを解決して，仕上げに入っていきたいようです．', null, null),
  ('a3e3be06-597b-5ae0-bfe4-4f22818aec80', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-08', '17:30:00', null, '通常 / アレンジ大賞 上級', '背景部分に部分に家や住民を追加して，日常の中にこの店があるのだと印象付けるようなデザインを施していました．プレイヤーがゲームだけでなく，背景部分も楽しめるように入れたとのことです．次回でそのアレンジ部分を完成させて，次次回で最終的な調整を行なって完成まで持っていく予定です．', null, null),
  ('2028b4ba-b075-5f44-8ba5-3252ef0575e8', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-08', '16:30:00', null, '通常 / アレンジ大賞の作品でScratchの基本操作を学ぶ', '体験での様子から、カリキュラムの通りにきっちりするのはまだ難しそうだったため、周りの様子で興味を持ったアレンジ大賞の作品をやってみようかと声をかけ、まちがいさがしゲームで遊ばせました。ゲームには興味を持って、何度か楽しそうにプレイができて、「これをいじっていいの？！」とノッてきたので、そこから授業に入りました。 はじめのうちは、体験のときのように、「〇秒言う」の数字を極端に桁数の多いものにして喜んだりしていましたが、「今日のお勉強として、これは覚えよう」と説明して、数値の半角と全角を教えました。これは素直に聞いてくれて、以降は自分で半角全角キーを押すことを覚えていました。 少し操作に興味を持てたところでファイルの一覧表とスタンプを見せ、できたところに押していこうと誘ったところ、やりたい！ということで盛り上がってくれました。 アレンジ大賞とは完全に離れますが、せっかくスプライトに愛着を持てていたので、好きなスプライトを選んでもらい、動かす、色を変える、回転する、大きさを変える、音を入れる、自分の声を録音する、の単元をやりました。 少しそばを離れるとすぐ追いかけてくるため、課題を与えていてもなかなか目が離せませんが、スタンプの目標がわかりやすかったのか、体験のときよりも授業の形にすることができました。 10分前に終了し、残り時間は塁くんや虎太朗くんおすすめのフォートナイトやいちごの反乱で楽しそうに遊んでいました。', null, '盛り上がり: できたところにスタンプを押すのが楽しかったようで、自分から「次はなに？」と課題を要求して取り組むことができました。'),
  ('f979bbaf-6c34-5150-9d2d-52ce1a86d57c', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-09', '17:30:00', null, '通常 / アレンジ大賞中級の続き', '前回から間があいているからなのか、アレンジ大賞はやる気がでない違うものを新しく作りたいと駄々をこねていましたが、今のアレンジ大賞中級の問題を自分の好きなように作り変えて良いからと言って、なんとか続けてもらうことになりました。が、前回の時点で、中級のゲーム自体の完成まではだいぶ遠く、アレンジに進むまでだいぶ時間がかかりそうだったので、内容を説明しつつ、写経してもらい、見本通りに動くものを作成。アレンジを開始してもらいました。隕石にプラスしてヘーゲルが迫ってきて、ヘーゲル撃破で、隕石より高い得点が得られるようなものを作って喜んでいました。みゆちゃんは、隔週なので、おそらくアレンジ大賞はあと１回くらいと思いますので、次回、アレンジを完成させるようにと伝えておきました。', null, 'タイピング: 授業が始まる前に遊び感覚でタイピングに集中していました'),
  ('ecdad938-4899-5cf1-94f9-703d86f47390', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-09', '17:30:00', null, '通常 / ロブロックス', '確認問題が終わっていないところがあったので、まずそこを思い出しながら問題を解いてもらい、今回の、クイズRobloxの動画を見てもらいました。時々、柚月くんがわからないところがあったり、みゆちゃんがわからないところを、教えてくれたりして、先生みたいなことをしたり、一時休憩でホワイトボードに絵を描いたりしていました。Roblox自体は、特に難しいことはなかったようでスムーズに終わらせることができました。（まだ簡単なところだからかとは思いますが）。', null, null),
  ('b0685595-03cd-52cf-91f2-dbb6c94bfd78', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-09', '16:30:00', null, '通常 / 基本操作コース', '基本操作コースの続きをやりましたが、授業が始まったあとも紙飛行機を飛ばして遊んでいたり、先生以外立ち入り禁止のスペースに入ろうとしたりと落ち着きがありませんでした。席に座っていたときはなんとか進めることができ、跳んだ時に音を鳴らすことや、爆弾に触れたらゲームオーバーにすることができました。「もし～に触れたなら」の中身にどこからどこまでを入れるのかも問いかけて考えてもらいました。ただ終盤は集中力が切れて「これで完成でいいでしょ？」とやめたがり、スコアの作成まではいけませんでした。', null, null),
  ('8387900e-1974-596b-88bf-0b13c9506953', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-09', '16:30:00', null, '通常 / アレンジ大賞', 'お手本の再現は終わったのでアレンジに入りました。点数に応じてクリア/ゲームオーバーにするのはできましたが、それ以外のアレンジが思いつかずにいました。そこで周りの子から「新しい武器を追加してみたら？」という提案が入ったのでライフル弾でも攻撃できるようにしてみました。ただ、y座標を変えているため操縦艦と同じ向きに行くはずの弾丸が上にしか行かず、次回修正が必要そうです。「～歩動く」で好きな方向に直進できることを抑えたほうがよさそうです。', null, null),
  ('bcee8bde-722a-5fca-874e-567f6a9b5e5f', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-09', '17:30:00', null, '通常 / アレンジ大賞', 'アレンジ大賞の続きを進めました。近くにいたけいとくんの助言を採用して、「取ると回転速度がランダムに早くなるか遅くなる薬」を作っていました。乱数を使えばよいことは自分でわかりましたが、「もし(乱数)が1なら」を組み立てるのに苦戦していたので一緒にやり、段階を踏んで理解していました。実際に回転速度を変えるところまでは言っていないので、次回続きになりそうです。', null, null),
  ('8b856dfc-0f80-53e8-9237-5d892d02210d', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-09', null, null, '通常 / ロブロックス', '最初に、デジタネの動画と、Roblox studioを同時に操作しやすい方法等レクチャーした上で、今日はデジタネのクイズRobloxをやってね。と伝えてはじめてもらいました。が、本人曰く、どれをやっていいかわからず、えいやっと、「魔法のレンガブロック」という動画を見始めたらしいです。質問はRoblox Studioの使い方くらい（プロパティやエクスプローラーをどうやって表示させるか等）で、順調に進めている感じだったので、途中まで、私も「クイズRoblox」ではなく違うものをやっていることに気づきませんでしたm(__)m。なので、今回はそのまま今やっている物をすすめてもらいましたが、前回、ケイトくんも、順番を飛ばして違うものをやってしまったので、子供にとって何かしらわかりづらいところがあるのかもしれません。ロブロックスをする人は、きちんと見る動画があっているかを確認したほうがよいですね。後々聞いてみると、スクリプト作成のところがやはりよくわからなかったとのこと。デジタネは、順番に進めること、わからないと感じたらすぐ質問するように伝えました。', null, '時間帯: その他'),
  ('bd5ebe0d-7ae7-5a34-8eef-156cadc4d04d', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-26', null, null, '通常 / 【体験】', '"スクラッチはやったことがある、とのことですが、ネコのコスチュームをばらばらにして「すごいことをしている」と言ったり、小数を「1.200000000000」のような形で入力して喜んだりと、とにかくパソコンをいじって楽しんでいる、という感じでした。しばらくは自由にブロックをいじらせてみましたが、少し満足したところでいつもの基本操作コース01に誘導すると、素直についてきてくれました。コスチュームを変えて歩く動作のアニメーションを作成するところなどは面白がっていました。画面にバッターを出して、バットを振るアニメーションができたことからインスピレーションを得て、ネコがバットに当たると跳んでいくアニメーションを作成し、満足そうにしていました。 洞窟ダイヤでは背景を変えたがった為、基本的なオブジェクトのコピーペーストを教えました。迷路がなくなった代わりにダイヤと敵を複製して1つ以外をダミーとし、ゲーム性を高めていました。 低学年特有の遊び（数字を大量の桁で入れる、スプライトをいじりまくる）などの脱線もありましたが、作品を作ること自体は一生懸命にやっていて、楽しめてもいました。 今一番ハマっているゲームはゼルダの伝説のブレワイで、クリスマスにティアキンを買ってもらうそうです。マイクラも好きで、クリエイティブモードでたくさんアイテムをため込んでいるそうです。"', null, '時間帯: その他'),
  ('6afa96b7-80ff-5c4b-a90b-b632fd8a9dc9', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-10', null, null, '通常 / Roblox２回目', '特にこれといった質問はなく、つまるところもなく、スムーズに進めていたようです。デジタネ動画は最後のアレンジ部分は終わらせることができなかったので、次回ロブロックスの時は、このアレンジ部分がどういったものかを確認して、確認テストをして、次のクイズロブロックスに進めば良いと思います。（ただ、プログラミングとロブロックスを交互にやっているとのことだったので、来週はアレンジ大賞の続きかもしれませんが）', null, '時間帯: その他'),
  ('73f72494-c686-5e68-9133-8a693740a95d', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-10', '16:30:00', null, '通常 / アレンジ大賞', '前回の猫の軌道がうまくいっていなかったので、確かめられるところを提案して、調べていもらいました。そこで、クローンの関係がうまくいっていなかったことが見つけ出せ、修正できいました。その後、アイデアに悩み浸っていたが、照準を3股に拡張して、よりゲーム性が上がるものに仕上がっていました。', null, 'タイピング: よく集中していました。'),
  ('12808336-878d-5175-bbd4-b696651edb8a', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-10', null, null, '通常 / ロブロックス２回目', 'まだ特に難しいこともないので、これといった質問もなくスムーズに進めていたようでした。デジタネ動画の最後のアレンジ部分は終わらなかったようですので、葵史くんと同じく、次回ロブロックスの時はアレンジ部分と確認テストからして、次の動画に進めばよいかと思います。', null, '時間帯: その他'),
  ('440d8ccc-5648-5bec-b00f-2c20cc6c8c99', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-10', null, null, '通常 / アレンジ大賞', 'まだ元のゲームが未完だったので、完成を急ぎました。一塊ごとのコードができると試遊して試してくれることはよいですが、すでに作ってある箇所がバグが見つかることが多かったです。特に変数や「まで繰り返す」の当たりの間違いが多かったので、その機能を今一度確認しながら、作っていきました。ほぼ完成はできたと思うので、次回からアレンジです。', null, '時間帯: その他
タイピング: 長くやっていました。'),
  ('0e2f45d7-2e0c-5148-ba7e-c80a11fd8e1d', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-10', null, null, '通常 / アレンジ大賞', 'アレンジを進めていきました。アンダーテール風に隕石をハートに置き換えて、ハートがはじける演出にかなりこだわっていました。そして、操縦席にもビビットなカラーに配色し、目新しいものになりました。本人的には、アレンジはこれで十分と言ってきていますが、もう1週くらいはアピールポイントの文章も含めて作成してほしいです。', null, '時間帯: その他'),
  ('621eeaa6-182a-58c5-90cd-3079688c9f72', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-10', null, null, '通常 / Roblox一回目', 'Roblox初回だったので導入を行いました。「Robloxでプログラミングにチャレンジ」という動画で重要と思われる部分を口頭で説明したり、Roblox Studioの基礎的な使い方、スクラッチとRobloxの違いを自分なりに、自分のRoblox studioを用いて説明した上で、「デジタね動画：頂上を目指せ」を始めてもらいました。デジタネ動画をピクチャインピクチャでサイズを変えながら必要に応じて速度を変えて視聴すると良いという小ネタも説明しました。実際に動画の視聴が始まってからは何も質問もなく、集中して取り組んでいました。頂上を目指せの途中で終わったので、次回は、その続きからとなります。 Robloxのアカウントを作っていなかったようなので、今日はIT自由研究室のアカウントで実施しましたが、IT自由研究室のメールでログインしようとしたら、セキュリティアラートみたいなのが出て、パスワードをリセットしなくてはいけない状態になり、パスワードを変更することになっていまいました、新らしいRoblox studioのIT自由研究室のアカウント用パスワードは、YYいつもの数字yyとなります。', null, '時間帯: その他'),
  ('0ae52363-6300-5d7e-8462-81472d391702', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-10', '16:30:00', null, '通常 / エクセル模擬演習', '模擬問題をやっていきました。時間的には50分程度で解き終わっていて、自動採点に移ったところ、正答率39%でした。罫線やコンマ区切りなどの細かいミスや、抽出やグラフの大きく間違っているところもありました。時間的に、間違え個所の見直しはできなかったので、次回確認した方がよいと思います。それにつないで、単元別演習もやってもいいかもしれません。', null, null),
  ('4b3439a7-36d2-5ff4-82a1-6cdc0d8f9a6b', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-10', null, null, '通常 / 初レッスンなのでスクラッチに慣れてもらう', '基本操作コース０２を最初から順番にサイズを変えようまでやってスタンプを押してもらいました。「回転させよう」のところで、角度をものすごい大きい数字を入れたり、「踊らせよう」のとこでも移動量をものすごい大きい数を入れたり、スクリプトのブロックを動かすときの挙動が激しかったりと、低学年の子供にありがちな行動が多かったかもしれません。途中集中力が途切れたり脱線することもまあまああったので、進みは早くはなかったです。スクリプトを作って動かした時には、楽しそうな反応を示していたので、楽しく進められているのかなとは思います。次回は続きからかなと思います。', null, '時間帯: その他
タイピング: 最初右手だけで打っていたので、ホームポジションというものを教えて両手で打てるようにと教えてました'),
  ('c283824c-c06c-5a34-b39a-33cb2fbf06f4', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-10', null, null, '通常 / アレンジ大賞の続き', 'アレンジを開始しました。ゲーム終了時の画面を作ったり、間違い探しの登場キャラクターを増やしていました。また、２ステージ構成にしようかとも行っていて、その辺の作業を進めていました。次回もアレンジの続きからですが、初級を選んだのは、挑戦している人が少ないから、そこで良いものを作って優勝してヘッドフォンをもらう戦略なんだよ。みたいに難しい言葉を駆使して説明してくれていました。', null, '時間帯: その他'),
  ('6689be55-a5f8-5ff8-b88d-48deb4f6bfef', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-10', null, null, '通常 / アレンジ大賞の続き', '今記録を入力していて気づいたのですが、昨日は、アレンジ大賞の中級をやっていたようでしたが、今日は、アレンジ大賞の初級のアレンジをしているようでした。レッスン中は気づかなかったのですが、どちらで進める予定なのか？？次回話をしないといけないような気がします。レッスン中は、自分で考えたことを、独り言を言いながら、自力で黙々と作成していて、ずいぶん成長したなあと感じました。実際には、アレンジ大賞の初級の、表示されるキャラクターのコスチュームをいじったり、ボタン入力で背景画面を変えられるようにしたりと、色々いじっていました。もうちょっと何か独創的なアイデアが欲しいところではありますが、まだ時間が残っているので、次回もっと良さげなアイデアを盛り込むことを促すようなアドバイスができたら良いかと思います。', null, '時間帯: その他'),
  ('e676ede4-cae0-5028-a96f-787d59b16e39', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-10', '17:30:00', null, '通常 / アレンジ大賞', 'いつものごとく最初15分くらいロブロックスをしてからアレンジ大賞の方へ移りました。前回ほとんど進んでいなかった気がしたので、今回は程よく進めてくれました。途中、元ゲームのバグの起きやすい箇所を見つけたり、品の仕組みを作ったりしていました。けど、残り15分くらいで疲れたらしく、残りの15分くらいからは塾の宿題をやり始めていました。', null, null),
  ('a7732701-26bc-548d-8ebf-1199958935cd', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-10', '17:30:00', null, '通常 / アレンジ大賞', 'アレンジについては、8割方本人的には終わっていたので、細かいところ詰めていきました。大量発生の動作だったり、隠しコマンドのことだったり、都度都度確かめながらやっていました。そして、やすのりくんに試遊させて、不備がないか確認を取っていました。満足げに仕上げていたので、終わりでもよいかもしれません。', null, 'タイピング: 見たこともない敵と戦っていました。'),
  ('eb3cde55-9ec9-5fed-a8a6-d1a825753d62', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-12', '17:30:00', null, '通常 / イラスト', 'ご自宅のipadを持ってきてくださったのですが、apple pencilが無かったため指での描画をしていました。またアイビスペイントのアプリをまだダウンロードしていない状態だったため、使えそうな描画アプリを使ってもらいました。 授業の内容としては、ガサガサで頼まれていた山のイラストを描いてもらいました。 特殊なペンを使って山と川、山のロッジまで細かく作ってくれました。', null, 'タイピング: なし'),
  ('13eadde1-0741-556b-aa36-2820dd920c34', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-12', '16:30:00', null, '通常 / アレンジ大賞_アレンジ', 'アレンジ大賞のアレンジとして、コック帽を被った可愛い女の子のキャラを描いてもらいました。前回教えてあげた透過での保存方法も覚えてくれていたようでよかったです。', null, 'タイピング: よくできていました。'),
  ('11377762-3789-5f10-ae22-0d32f2c71929', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-12', '17:30:00', null, '通常 / エクセル演習', '前回の復習も含めて、やっていなかった実習16，再度18をやっていきました。表づくりに関して、何度もやっているためかすらすらと作れていました。関数が含まれるところでは、max,averageなどすぐにでき、if関数はネスト構造になっているせいか、コンマやかっこの付け忘れがありましたが、全くわからない状態はなく、自力進める力はつきました。後半は、抽出の部分も説明を交えながら、やっていきました。ここは、難しいことはない感触でしたが、種類が多く、手惑う場面が見れれ増した。おそらく、慣れで解消していくと思います。', null, null),
  ('3ce1b26a-e449-5a1f-8faa-47330d90ea2c', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-12', '16:30:00', null, '通常 / アレンジ大賞', '前回、取り込んだキャラを間違え探しができるように作っていきました。ここで、間違えがランダムで1つに決めているの何か？聞いたところ、「変数」という言葉出てきませんでしたが、「オレンジ色のやつ」と答えて、仕組みを理解できていました。その修正は17戸と数が多かったが、集中を切らさずに、できていました。コスが変わっていないバグも、めんどくさがらずに1つ1つ確認が取れていて、見直しも完璧でした。そして、一部のコスを自分好みに変化させ、間違え探しの難易度もさらに難しくしていました。タイトルも変えて、本人的には完成といっていました。来週も変えたいところがなかったら、終わりでいいと思います。', null, null),
  ('b815d2e9-6b61-5ab2-a721-3a077a2e3572', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-12', '16:30:00', null, '通常 / アレンジ大賞_初級', '「変数が4の時に背景をパステルにしたい」というアイデアを出してくれたので、変数については理解してくれているのかなと感じました。 ただ背景を変えるコードをどこに入れるべきなどがわかっていなかったようなので、 「どのスプライトが変数4に関係してそうか」「背景のスプライトはどこのグループに入ってたっけ」とヒントを与えると、すぐに理解して解決してくれました。タイピングも積極的に行おうとしていてよかったです。', '「メッセージを送る」をアレンジ大賞で初めて教わったとのことなので、復習できる教材が良さそうです。 変数も使い方を理解してそうですが、もう一度確認してみると良いのかなと思います。', 'タイピング: なし'),
  ('ab2714c5-4e59-5f4c-b7da-0179d3d9d37b', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-12', '16:30:00', null, '通常 / アレンジ大賞', '今回は、せっかくとった音声がうまく流れないバグを直していきました。コードが抜けていることは自分で気づけていましたが、元の音声が各スプライトになかったので、一緒に直していきました。繰り返してしまうことも「停止」のコードを教えてあげました。そして、さらにスプライトを増やして、にぎやかなものになっていました。がくくんもアレンジを終わったと言っているので、次回もうやることが生まれなかったら、終わりでいいと思いました', null, null),
  ('c7c92ef1-ca7a-5676-acd8-9479ffee5b76', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-12', '17:30:00', null, '通常 / ロブロックスでコードで色を変えよう', '授業前から早くやりたいと教材の方を進めていきました。倍速で見ながらも、コードの基本的なコードの仕組みは理解できていました。今回は、色を変えていく、ことだったので、色の英語がわからない部分はありましたが、それ以外は難なく進んでいました。確認テストも80％でした。アレンジも素材を変えて楽しんでいました。', null, '盛り上がり: 残り20分くらいは今日のこと終わって、自由に遊んでいました。'),
  ('22f4417f-cb9e-51b8-86b1-d4ce3a4ec27c', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-12', '17:30:00', null, '通常 / アレンジ大賞', '切り替え時に、電車を走らすアレンジに凝っていました。社葬をかなり横浜戦に近づけて、踏切などをつけて、雰囲気が仕上がっていました。ある程度完成したら、先生を呼びつけて見せてくれるほどでした。まだまだ、追加できそうなので順調です。', null, null),
  ('0b1f8307-4601-566f-bc06-42bc30db27b4', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-04-26', null, null, '通常 / 【体験】', 'スクラッチは自分のアカウントを持っていて、公開もしているそうです。2Dゲームが好きとのことで、3Dやテキストコードにもあまり興味がないとのこと。何かがやりたくて、とか作りたい、という明確な希望があるわけではない、あるいは自分でもよくわからないようで、作りたいものがあるかという発問には困ったような顔をしていました。コンテストに出したいというわけでもなく、自分で作ったものを公開したいだけ、という感じでした。 それでも、やったことがないというスクロールを、小技とカーレース、ジオメトリーダッシュの3つのゲームで実践してスラスラ作れるようになったら少しずつ饒舌になってきて、最後に見せたいちごの反乱も面白がって、熱心にコードを見て、一度でゲームオーバーにならないように編集しようとしていました。 とりあえず、今のところ一番興味があるのはScratchのようで、Monacaはイマイチという感じでした。', null, '時間帯: その他'),
  ('3b149982-3b44-5e1f-bdb4-58a8f6598f58', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-13', '16:30:00', null, '通常 / アレンジ大賞の作品に触れながら、基本操作のブロックを1～2個覚える マウスの練習、全角・半角の違い、メッセージ機能の復習をする', '授業開始時は、妖怪ウォッチのゲームで遊びたがりましたが、今日の目標を話して、妖怪ウォッチとアレンジ大賞の作品のどちらで学習をしたいか尋ねると、自分から「アレンジ大賞の続きをやる」と言ってきました。 間違い探しの個々のスプライトのコードが手付かずだったので、「コスチュームを○○にする」「もし～なら～でなければ」「○○と2秒言う」のブロックを覚えることを話してから一緒に作成をしていきました。 文字を自分で入力しようとする意欲はあり、質問しながらではありますが、すべて自分で入力しました。 コードを別のスプライトにコピーする方法を教え、このときはマウスを使った方がやりやすいことを説明しました。今日はこのコピーとコスチュームの編集があったため、マウスの良い練習になりました。 授業の過程で説明した「数字をうつときは「英数」キーを押す」「コスチュームをまとめて編集するときはCtrl+aを押す」などは一度で覚えて、その後は自分からできていました。 メッセージスプライトの「ゲームクリアメッセージを受け取った時」のコードが未作成のときに、ゲームがうまく終了しないことに気付いたため、スムーズに「メッセージを受け取った気にすべてを止める」コードの作成へと誘導することができました。 今日学んだブロックのところにスタンプを押して、満足そうにしていました。 作品は一通り完成し、間違い探し用のスプライトのコスチュームもすべて変更して終了しました。', null, 'タイピング: マウスの練習を勧めましたが、拒否されました💦
盛り上がり: コードが完成して、自作のゲームで遊べるようになったことが嬉しそうでした。'),
  ('bfe585e0-109b-553d-8626-83f7fd6ff5c8', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-13', '16:30:00', null, '通常 / アレンジ大賞', '前回のバグ直しとして「全角数字の修正」「時間と満足度を時間ごとに減らす」と大きく2つあることを伝えると、見通しができたようで集中して取り組んでくれました。アレンジに入り、アイデアに困っていたのでまずは見た目の改変を勧めました。サメやいつも使っているリスを使って世界観を変えていました。その後は、注文を見づらくしたり邪魔したりして難易度を変えることも提案しましたが、難しそうと言って手が止まってしまいました。', null, null),
  ('91838ec2-df17-5bda-a2c4-d9fdfd7af667', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-08', '17:30:00', null, '通常 / アレンジ大賞作品の作成', '今日は座席をたいようくん、晴くん、そうたくんとまとめたためか、ずっとしゃべりながら楽しそうに取り組んでいました。 スペースキーを長押しすると正解数が増え続けてしまうバグにずっと悩んでいて、レースゲームの「○○ではないまで待つ」を思い出させました。 こちらはすぐに思いだして対応したのですが、やはりうまくいかないと言って、別のところを作成していたようです。 こちらで確認したところ、対応したのが1つのスプライトのみだったので、次回、「押されたではないまで待つ」をすべてのブロックに入れて試すよう伝えました。 新しいことにチャレンジするといって定義を使っているのですが、同じような定義をたくさん作成していて定義のメリットが薄れているので、もう少しまとめるように相談に乗って上げる必要があるかもしれません。', null, '盛り上がり: とにかく手も口もずっと動いていて、楽しそうでした。 たいようくんが「中学生は試験があって大変」というのに対して、受験勉強が大変なんだと話していました。'),
  ('97e57db0-d401-52bc-ae37-1af8ead6b056', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-13', '16:30:00', null, '通常 / アレンジ大賞', '引き続きアレンジを進めました。「コードが綺麗」という採点基準があるのを見て、余分なコードをチェックして削除していました。アイデアについては先生とたくさん話し合いながら出していました。隕石より得点の高いダイヤやいろいろな寿司が飛んでくるようにしていて、ゲーム性や見た目の面白さにこだわっていました。次回は、触ってはいけないワサビ入りの寿司を混ぜて完成とする見通しです。', null, '盛り上がり: みうちゃん(TA)コメント: 話しかけると積極的にレスポンスを返してくれた。 アドバイスから発展させる事ができそうなので結論(こういうものを作ろう)より過程(コード例など)をアドバイスして自分でアイデアを出して組み込むのが良いと思った。 細かい調整を後回しにして次のコードを作っていることがあったので区切りのタイミングでここのコードを直そうなどを提案をした。 話に夢中になると少し手が止まってしまうので集中している時は控えめに、逆に疲れたり思い悩んでいたら声をかけて少し休憩しながら話をしてあげると良いと思った。 自分でスプリクトの絵を描いて使用していることが多かった。'),
  ('c8721854-562d-5dbd-889c-40f55ce38fd0', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-08', '17:30:00', null, '通常 / アレンジ大賞の作品作成', '17時半のメンバーにだいぶ慣れてきたのと、たいようくんと歴史の話で盛り上がれることが判明したためか、ずっと楽しそうにおしゃべりなしながら取り組んでいました。 残り時間のカウントダウンが始まらないことで行き詰り、しばらく悩んでいたようでした。該当のコードを何度も見直し、数値もすべて半角かどうか確認するなどをしていましたが、解決できなかったようで質問をしてきました。 結局、スプライトの他のスクリプトを止めるためのメッセージ名が間違っていたことが原因でした。今回の件で、バグ探しの際は該当のコードだけでなく、全体を見ることも必要だということを伝え、本人も納得していました。', null, '盛り上がり: プログラミングの方は、前回から悩んでいたバグが解消してほっとしたようでした。 たいようくんと歴史の話でとても盛り上がり、北条氏や八王子城、川越城など、かなり深い話までできて楽しそうでした。'),
  ('eb278a9d-6126-525b-b474-8a074322d85e', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-08', '16:30:00', null, '通常 / 教室に慣れる、アレンジ大賞に参加する', 'アレンジ大賞に関しては、やりたいことはわりとすぐ思いついたようで、新しく定義をいくつも作成して順調にすすめていました。 質問もほぼなく、好きなようにアレンジするのを楽しめていたようでした。', null, 'タイピング: 問題なくできています
盛り上がり: 同学年のえみちゃんに、自己紹介のときから「友達になろう」と言われて驚きつつも、絵しりとりに付き合ったりと楽しそうにもしていました。 アレンジにはとても熱中して、自分でやっていることを説明しながらひたすら手を動かしていました。'),
  ('ec81d9ca-4290-5857-b381-bf70f725ff1d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-13', '17:30:00', null, '通常 / アレンジ大賞', '今まで内容に挑戦するという評価基準を見て、定義かクローンを使おうということに決めました。どうアレンジを進めていいのか全体像に迷ったので、宇宙という設定から離れてもいいと伝えたうえでゲームのコンセプトについて少し話し合い、猫の町を隕石から救うという設定にしました。ここでクローンを使い、ネコを複製して喋らせ、隕石をたくさん撃てたら喜んでもらうことにしました。次回はゾンビがHPを減らして邪魔してくるのを作ったら完成しそうです。', null, '盛り上がり: 今日は比較的自分の作業に集中したいモードのようでしたが、アイデアについては自分の言葉で話してくれました。'),
  ('3bb2adba-e3b9-5a50-91b4-fe7a4edd0dca', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-15', '16:30:00', null, '通常 / アレンジ大賞', '前回からの隕石が出てこないバグを直していきました。下見段階で、子供にはわかりづらいバグであったので、解決法を教えていきました。それは、メッセージ名は同じだが、そのコードがバックパックから持ってきたなどで反応しないことがあるので、別物と判定されるいたので、再度作り直すことを進めました。その後、隕石などをコインに変え、スマブラ背景風にしたりアレンジしていました。 ただ、後半はルイ君とともに集中力が切れて、遊んでばっかでした。なので、アレンジが中途半端になっていると思います。', null, null),
  ('1b50bf94-5834-5b43-8d1a-f929971d982b', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-15', '16:30:00', null, '通常 / アレンジ大賞', '今日は最初から集中力がありませんでした。アレンジ大賞前に作っていた、ゲームをいじりだして、ちょこちょこアレンジして遊びがメインでした。中盤、アレンジ大賞の作品の方に移りましたが、アレンジは少しできているものの、元の作品のゲーム性が完成していませんでした。なので、作成を始めてようとしたが、またほかのゲームに移り、今日は戻る気配がありませんでした。もとの作品のコードを完成させてほしいです', null, null),
  ('81066a09-94e3-5321-97d4-5de800fd4992', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-15', '16:30:00', null, '通常 / アレンジ大賞作品を完成させる', '作品が決められていることがあまり好きではないようで、アレンジ大賞の締め切りまであと2回、という話をしたら「やったー」という反応でした。 それでもアレンジを続けようとはしていましたが、コードの変更にはほぼ興味がなく、ひたすらスプライトのコスチュームを変更することに熱中していました。 外部サイトからダウンロードした画像をアルスタジオで読み込めないと困っていたので、画像にはファイル形式があることと、アルスタジオで読み込める形式には制限があることを軽く説明し、形式を変換して対応しました。授業内容とは直接関係ないことですが、今日一番喜んでくれたのはこの部分かも…。 店員さんスプライトがポジション1のときしか商品を上に投げないバグがあり、ここだけはコードを見て一緒に考えました。条件分岐の「ゲーム中」と「ポジション」変数が逆になっていたことが原因だったため、スプライトの動きによって変わる変数がなにか、誘導質問をして訂正することができました。 アレンジや自由作成となると、とにかく見た目にばかり注力してコードを見ようとしない傾向があります。検定はきちんとやるので、プログラミングの学習は検定形式の方が向いているのかも？', null, '盛り上がり: アレンジ大賞、早く終わらないかなーと言いつつも、コスチュームの変更は楽しそうにやっていました。'),
  ('9b7d94eb-13e4-5e71-920d-45c24900c738', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-15', '17:30:00', null, '通常 / アレンジ大賞のコード整理', '今までのコードが複雑になりすぎていたので、整理をしようとしました。特に、メッセージと変数が入り乱れていました。ただ、複雑さゆえに客の注文の選択と判定が一向に出来上がっていませんした。中盤まで、そのコードで少し直して、ほかのバグが増え、の繰り返しになっていました。このままだと、整理どころではなくなったので、別のシステムに移すこと決めました。そこは、ざっとやりたい仕組みはそうちゃんが考えました。今まで、１～４キーで選択として、そこからスペースキー渡す仕組みを、asdfキー各だけで判定まで持ってくることにしました。そこで、こちらはその流れを共有していきました。来週にそのコードができるといいですが、、、', null, null),
  ('955b65cd-aeca-5247-a3ba-9260dc6720f4', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-15', '17:30:00', null, '通常 / アレンジ大賞', 'コードは完成したようなので、今日はスプライトでのアレンジを熱心に頑張っていました。 敵だけでなく操縦席の見た目も変えていて、颯太くんの工夫が感じられました。', null, 'タイピング: なし'),
  ('6f3b4cff-b212-5c3e-952c-73d7bbc38609', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-15', '16:30:00', null, '通常 / 動画教材を見ながら「矢印キーで動かす」「座標を使って動かす」「おしゃべりをさせる」の基本操作コースの学習', '矢印キーについて説明する際にまずはX/Y座標の概念について理解してもらいました。ピッチを使って音を変化させるコードが気に入ったようで、「敵にぶつかったらGAMEOVERになるようにしたい」など具体的なアイデアを思いついてやりたがっていました。 ただ、まだ入ったばかりとのことで、アイデアを叶えるにはメッセージを使う必要があり、すぐに実現することはできませんでした。 仕組みについて説明するとき、根気よく聞いてくれるので慣れてきたらどんどんスキルアップできるような教材に取り組めると楽しめるのではないかと思いました。', null, 'タイピング: なし'),
  ('d89cbc32-89f9-5649-bdac-37b4f4230629', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-15', '17:30:00', null, '振替 / アレンジ大賞の作成', '振替の関係で、今日と明日で完成させなければいけないということで、少し焦りながらも熱心に取り組んでいました。 薬をとったときに2分の1の確率で動きが早くなったり遅くなったりする、という動きを作るために、他の箇所で使用している「連動」変数を使いまわしていたので想定した動きになっていないところがありました。 動きの速さ（回転度数）を多くの箇所で変更する必要があったため、これを変数にすることと、薬の効果も独自の変数で管理することを提案したところ、一生懸命に対応していました。 検証するときに速さをイメージで語っていたので、検証中は関連している変数を表示することや、数値を極端に変えて実際に速さが変わっているか確認するなどの方法も伝え、素直に試していました。 結果、変数はきちんと変わっていること、動きの速さも変わっていることが確認できるところまでできましたが、操縦かんと照準のスピードが合っていないようなので、明日はこのあたりの修正をする予告をして終了しました。', null, 'タイピング: 授業前に、鬼気迫る勢いでやっていました
盛り上がり: 薬の効果が半分の確率で変わる動きができたときは嬉しそうでした。 積極的に質問をしながら、がんばっていました。'),
  ('6b6244c0-e5a8-53fe-a656-3c7f16ad6111', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-15', '17:30:00', null, '通常 / 新しいスキルを学ぶ', 'アレンジ大賞はもう完成していて、次のことをやりたい、ということで、本人の要望により、シューティングゲームの作成に入りました。 チュートリアルは特に問題なく、自分で見て作成し、クローンの使い方も納得できたようでした。 レッスンはあっさりと終わってアレンジをしたいということだったので、クローンの学習も兼ねてスクロールを作成しました。スプライトを最初に出す座標、どの座標まで動かしたら次のクローンが必要か、など、しっかりと理解しながら進めることができました。 今日は「クローン」と「スクロール」というスキルを学んだ、ということを再確認して、満足そうに帰っていきました。', 'もう少しシューティングゲームを凝ったものにする予定です', '盛り上がり: ゲームを作る上でのスキルが増えたということに素直に喜んでいました。'),
  ('41794ef5-8e19-5b5a-8a8d-192b06ada5bd', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-09', '18:40:00', null, '通常 / アレンジ大賞', 'アレンジの部分を始めました。元のゲームは簡単だと言って、ダミーキャラを置くなどして難易度を上げたのが良かったです。ただキャラクターを高速で動かしすぎて、狙って押すことがほとんど不可能な状態になっていました。もう少しやりやすくしたほうが他の人が遊んだ時楽しいんじゃないかなと提案しましたが、今のところ変えるつもりはない様子でした。色々な自分の声を録音してBGM風(?)にしていたのはユニークでした。', null, null),
  ('dde8ca40-d0e6-5d18-b8dc-1e6748c714c5', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-10', null, null, '通常 / 基本操作コース', '基本操作コースの中で唯一やっていなかったピンポンゲームに取り組みました。マウスとパドルのx座標をそろえるという考え方は、自力で思いつくまではいきませんでしたが言われるととても納得していました。座標関連のブロックで、「～にする」と「～ずつ変える」など紛らわしいものについてもきちんと区別できていました。今まで何回か触れてきた「もし触れた～なら」は完全にマスターして、使うべき場面で即座に使えていました。ゲームクリアの演出もきちんと出せて完成しました。', null, '時間帯: その他'),
  ('8d464047-6a46-573f-a716-812865c388f3', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-16', '16:30:00', null, '通常 / ドリルで基礎の確認', '最初はいつものようになかなか始めようとしなかったのですが、眠いということだったので10分ほど寝てもらったところリフレッシュして頑張れました。ドリルはゲーム作成よりはつまらない様子でしたが、スタンプを何個押せるかチャレンジすることである程度モチベーションを保てました。 「～歩動かす」や「～秒待つ」といったブロックは使いこなせていましたが、角度が弱かったので「～度に向ける」をしっかり覚えてもらいました。ブロックを並べる順番も最初は適当でしたが、時系列を一緒に追っていくときちんと並べられました。問題1～7までできました。', null, null),
  ('0bc9510f-20d0-558a-a9b4-c8ec5282cd14', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-16', '17:30:00', null, '通常 / アレンジ大賞完成', '操縦かんと照準の回転スピードが噛み合っていないバグを修正しました。新しく追加した惑星や薬の仕様をはっきりさせながら進めました。回転関係の処理の書き方が複雑すぎて重複部分も多かったことがバグの原因だったため、 ・左右キーが押されたら変数「回転度」ずつ回す ・惑星に触れているとき回転度を下げる ・(惑星に触れていないとき)薬を取ったらランダムに回転度を上げるか下げる というように、処理を別のスクリプトに分けていきました。簡潔で間違いのないコードになり、本人も納得しながら進めてくれました。無事に想定通りの動きにできたので、残り時間はゲームクリアの演出をつけるなどして完成しました。', null, '盛り上がり: 達成感のある終わりにできました'),
  ('5efeae38-9991-53e0-995f-7195e14e7757', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-16', '16:30:00', null, '通常 / アレンジ大賞の続き', '前回に引き続きアレンジを加えていきました。易しい・難しいの難易度設定＆変更処理を集中して作り上げていました。途中声がけしても、特に質問やつっかかっているところもないと、夢中で終わらせました。そしてこれで完成で良いと言っていましたが、来週も時間があるので、もう少しアレンジ追加したらと提案しましたが、今日はこれで良いとのことで、最後の１５分くらいは、いろんなスクラッチのゲームで遊んでいました。次回は、アレンジもう少し追加するなり、スクリプトの整理だったり、ブラッシュアップをしたりして本当に完成させられたらと思います。', null, null),
  ('ef6b2295-8ab1-5e78-afe2-39d007c30467', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-16', '17:30:00', null, '通常 / Roblox studio', '前回、IT自由研究室のアカウントでRoblox Studioをしていたので、今回は自分のアカウントで進めるよう言ったら、自分のアカウントIDとパスワードを忘れたようで、今日もIT自由研究室のアカウントで進めました。前回は、デジタネの「頂上を目指せ」の動画を半分くらい見た上で、自分なりにアスレチックゲームを作っていましたが、今日はアスレチックゲームを１から作り直したいと言う事で、実際、１から作り始めました。ブロックの基本操作に関しては、大体覚えているようで、特に問題なく作成自体は進めていました、途中途中で、「固定」ボタンについてや、FボタンでPartの場所に瞬間移動できること等、Partの操作やRoblox Studioをより快適に扱えるような説明を混ぜつつ、アスレチックゲームを進めました。ツールボックスから、ボタンを押して開くドア等、純粋なPart以外のオブジェクトも取り入れて、部屋からドアを開けて脱出する必要があったりと、動画よりも一歩進んだアスレチックゲームができてきたと思います。途中、何回も、Roblox studioのPartの操作をするたびに、面倒くさい、こんなのやりたくないとネガティブな言葉が多かったですが、それとは裏腹に、集中してゲーム作成に取り組んでいたかと思います。レッスン時間を終わっても、修正したい部分や実現したいことがあって、それを続けていました。それでも、終了できず、ゴール部分はまだできていないから、次回はそこからと思うのですが、保存データはIT自由研究室のアカウント上にあるので、次回再開の際は、その点を気を付ける必要があります。(末尾に20250516というファイル名があるのでわかると思います)', null, null),
  ('a915917e-b1a5-50c3-ae2e-44cfaed6f518', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-16', null, null, '通常 / アレンジ大賞の続き', 'アレンジとしては、既に、大量のキャラクターを追加して、それをランダムな場所に瞬間移動しながら表示させて、音楽もユニークなものにしていました。今日は、効果音を自録りしていて、それをゲームに取り込んでいました。ただ、ゲームの終わらせ方に関して悩んでいたようで、良いアイデアがなかなか浮かばない事もあってか、集中力が続かず、ホワイトボードに絵を書いたり、アイビスペイントを使って絵を描き始めたりと、アレンジ以外のことにだいぶ時間を費やしてしまいました。ゲームの終わらせ方に関しては、コスチュームが変わった正解キャラを押したら、ひとまずゲームをストップ処理を入れてました。（そもそもゲームの難易度が高すぎるから、もう少し易しくなるように提案しても聞き入れてもらえませんでした）。次回では、ゲームストップした後に、何かゲーム終了がわかるような表現を入れたりして、きちんとゲームを完成させられたら良いかと思います。', null, '時間帯: その他'),
  ('ab738664-a119-5131-8863-f973cfa55027', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-10', '16:30:00', null, '通常 / アレンジ大賞 中級', 'アレンジ大賞の続きをやっていきました．基本部分はほとんどできたため，アレンジ部分に本格的に入っていきました．やりたいことは決まっているようなので，次回以降も順調に進めていき，完成を目指していきたいです．', null, null),
  ('7eaa93ac-87e9-5dfc-8b7f-c9c474eb3ce9', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-16', '16:30:00', null, '通常 / アレンジ大賞 中級', 'アレンジ大賞中級にチャレンジしていきました．基本部分については，完成しているものを使用していき，アレンジ部分から挑戦していきました．入塾してから日も浅いとため，度売ったアレンジを行えば良いのか悩んでいましたが，今まで自分で作ってきた作品から着想を得て順調に進めていくことができていました．', null, null),
  ('dc70de09-fc50-5725-87b0-1926067eb3cb', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-10', '17:30:00', null, '通常 / アレンジ大賞 中級', '前回の続きから制作していきました．舞台やスプライトのデザイン変更であったり，オリジナルのキャラクター追加といったアレンジ内容を次々に入れていくことができていました．この調子で完成まで持っていきたいです．', null, null),
  ('091c2619-9d8c-511e-b13f-c233ad77a0a5', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-10', '18:40:00', null, '通常 / アレンジ大賞 中級', '前回からの続きを作成していきました．アレンジ大賞の内容についてはしっかりと理解できたようで，システム部分の変更を行っており，定義などを駆使することでゲームとして完成度の高い作品を作成していました．今回バグが発生してしまったようなので，次回修正を行っていく予定です．', null, 'タイピング: 集中して取り組むことができていました．
備考: とあるタイミングで，クローンが出過ぎて処理落ちするバグあり')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('38ab338b-7217-59c9-8871-a324ac2d9bda', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-17', '16:30:00', null, '通常 / ガサガサの魚の絵', '1時間という短い時間内で資料を探し、イラストを仕上げてくれました。 今回はアユを描いてもらいました。 今回の授業では透過での保存方法と参照ウィンドウによる資料の置き方、またレイヤーに写真を追加する方法を教えることができました。', null, 'タイピング: なし'),
  ('455b4666-1496-5647-93ae-2ea5130a8641', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-17', null, null, '通常 / ガサガサ魚のイラスト', '短い時間内で綺麗に仕上げてくれました。今回描いてもらったのはオイカワです。 隣で制作していた夏芽さん同様、今回の制作で透過保存、参照ウィンドウ、レイヤーに写真を追加することを学んでもらいました。', null, '時間帯: その他
タイピング: なし'),
  ('e9b91e3d-2460-567f-97f8-4874109cfa76', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-17', null, null, '通常 / 基本操作の覚える＆復習', '基本操作コース06物語を作ろうは、やっていないとのことで、これをベースに物語作成で重要になることを教えました。一つ一つのスクリプトで動きが変わったりするところで、きちんと動いた時に、自然に嬉しそうな反応を示してくれて、こちらも嬉しくなります。飲み込みも良い感じなので、良いペースで進めることができます。今回は、より細かいことも踏み込んで、X,Y座標の概念を教えて、数多くあるキャラクターの動かし方も色々教えて、きちんと理解してくれたと思います。それと、今日は自分の声を録音して、それをゲームで使うのが楽しかったようで、ゾンビのうめき声みたいなのを作っていました。レッスンの最後に、主人公がゾンビにこんにちはというと、ゾンビが問答無用で呻き声を発して、主人公に向かってきて、それにびっくりして主人公が、助けてーと逃げる、短い物語をスクラッチで表現できました。全体的に良い感じで進められていると思います。', null, '時間帯: その他
タイピング: 集中して取り組んでいました'),
  ('fb5db183-2be6-55a3-97c2-0f5728e4e232', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-17', null, null, '通常 / ガサガサ虫の絵', '自宅のipadで今回はイラスト制作をしてもらいました。 参照ウィンドウの使い方や前回のレイヤーに関する復習など、複雑なことが多い中で無事に時間内に完成してもらうことが出来ました。 透過に関してですが、最初は背景まで丁寧に模写してもらっていました。その際、提出物は背景を消去する必要があるということを写真アプリを使いながら解説しました。 アイビスでの透過保存の流れは私がほとんどやってあげてしまったので、もう一度復習する機会で理解できたか確認してみようと思います。', null, '時間帯: その他
タイピング: なし'),
  ('71839378-e4e3-5b7f-977c-bb85abc50cd1', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-17', null, null, '通常 / 基本操作に慣れる', '前回の復習をかねて、基本操作コース02の続きから、スクリプトをクリックすると、回転したり、大きさが変わったり、上下左右に動いたりするのを、まずは自分でできるかどうかを復習がてら、作ってもらおうとしましたが、なかなかできず、今回ほぼ１から説明するような形となりました。一つの説明をするたびに、ブロックをマウスで左右に激しく動かしたり、数字や文字入力を連打したり、何かと脱線することが多く、歩みはとても遅くなってしまう状態です。最後の方は、X、Y座標が何かをわかっていない感じでしたが、最終的に、X、Yの値を変えることによって、キャラクターがどのように動くかは理解してもらうことができました。今日は、基本操作コース_03_02の初めの部分をやって終わりとなりました。スタンプを押しているので確認を。 途中、やる気がダウン状態の時に、少し雑談しました、スクラッチは、一年位前にちょっと触ったくらい、ゲームは、switchのスマプラ、ゼルダシリーズを好きでやっていたようです。', null, '時間帯: その他
タイピング: 片手の指１本だけでたどたどしくタイピングしていました。時折、押すべきキーがなかなか見つからない時なのか？ぐちゃぐちゃにキーを叩きまくるような事もありました。'),
  ('25880f76-c074-570b-98c3-26c3185a461b', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-17', null, null, '通常 / エクセル→チラシづくり', 'エクセルの模擬問題を予定していましたが、本人からの希望で、ガサガサのチラシづくりを進めたいとのこと。レッスン時間中は、集中してその作成に励んでいました。', null, '時間帯: その他'),
  ('07b12f46-0723-5de9-a504-d15f9cd22878', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-17', null, null, '通常 / ガサガサ甲殻類の絵', '「参照資料を使ってイラスト制作をしてほしい」という指示に、すぐわかった！と言って取り組んでもらいました。今回描いてもらったのはカニです。 Gペンで厚塗り風に描いてくれました。質感がリアルで、きちんとハイライトまで描くことが出来ていてとても良かったです。 今回の授業では参照ウィンドウの使い方と透過保存、写真をレイヤーに追加する方法を学んでもらいました。', null, '時間帯: その他
タイピング: なし'),
  ('211bbcbd-b79a-54bb-948e-d3c2850acb07', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-17', '17:30:00', null, '通常 / ガサガサ魚の絵続き、キャラクター編2章3', '魚の細かい描き込みをしてくれたので、丁寧でクオリティが高いものを提出してもらいました。魚の絵が終わったので「何がやりたい？」と聞いてみたのですが、特に描きたい希望が無さそうだったので2等身のミニキャラの練習をしてもらいました。 学校に関してはレポートの提出が忙しく、最近はアイビスを触ることが出来ていないようです。またblenderなどのクリエイティブ系の授業も2年にやるかも？という具合で、今あまりクリエイティブを落ち着いて考えられる状況じゃないかもしれない、と感じました。 今後としては、具体的に何かに向かって取り組むというよりも息抜き程度でイラストに取り組んでもらえたらと思います。', null, 'タイピング: なし'),
  ('fd72f6d4-b42d-518a-beca-bd408b5ac0da', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-17', null, null, '通常 / アレンジ大賞初級の続き', '前回から引き続きアレンジを加えました。今日は難易度設定処理を作りました。最初は大工事が必要になるから二の足を踏んでいましたが、やるべきことを細分化して、大体理解すると、「やってみる」となって、実際に、難易度設定処理→難易度設定に応じた、ゲームの難易度調整処理まで、終わらせることができました。私がヒントを与えたものの、低学年レベルだとなかなか大変な仕組みを、短時間できちんと理解して、それを実現させたことは素晴らしいと思います。最後に、ランキング？のようなものを作成して、これでほぼ終わりだといっていました。来週は最終確認をして、もし修正できるところ、ブラッシュアップするところがあったら、それをするくらいかなとお思います。', null, '時間帯: その他'),
  ('bd681d17-5126-56d6-82c6-cf674248f1ec', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-17', null, null, '通常 / アレンジ大賞中級続き', '前半は黙々と作業していましたが、後半に、スペースキーを連打して隕石を破壊したいのに、長押しで隕石が連続で破壊されてしまうのをなくしたいと、質問を受けました。何度かトライしてみましたが簡単な方法はおもい浮かばず、このような問題での王道の解決方法を教えましたがそれだと複雑になるから今短時間ではできないから、もうこの振る舞いはそのままでいいとのこと。最後にランキング処理？部分を微調整していました。おそらくほぼほぼこれで完了なのかなと思います。次回は、最終確認、ブラッシュアップ等になるのかなと思います。', null, '時間帯: その他
タイピング: よくわからないタイピングツールなのかゲームを前半１５分くらいずっとやっていました。だいぶハマっているようでした。'),
  ('95958ac8-be97-50cd-8ae8-3f80555e1dae', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-17', '17:30:00', null, '通常 / キャラクター編2章2', '最近アイビスでトレス素材を使って漫画の模写をしていたようで、授業前にお互いの好きな漫画作品について楽しく話しました。その際、「この漫画家はかなり美術解剖学（筋肉や骨に関する知識のことです）を勉強して上手くなった」と導入をし、早く人体を描けるようになった方が楽しいだろうと思い、まずは比率を駆使して全身を描く練習をしてもらいました。 オリジナル教材の方が終わったようなので、アタリ練習帳から同じポーズを抜粋して描いてもらいました。以前教えた対象定規をすっかり使いこなせていて良かったです。 また今回の授業ではフォルダーにレイヤーをまとめる方法を教えました。', null, 'タイピング: なし'),
  ('de21e51a-e094-5ef0-b3df-f6c6f50cee2c', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-16', '18:40:00', null, '通常 / アレンジ大賞', 'アレンジを進めました。ぶつかると減点になるゴミや、最初に押すプレイ時間選択ボタンの作成をしました。一通り完成したところで隣の虎ノ介くんがテストプレイして、バグがないか探していました。実際に、プレイ時間選択ボタンがゲーム中にも反応してしまい時間がリセットされてしまうことを突き止めました。時間設定部分のコードを見なおすよう促すと、そのコードがずっと動き続けていることを発見したので、一度反応したらスクリプトを止めるようにすると直りました。', null, null),
  ('8e578de4-07e5-58a4-b286-c6c86a4875c5', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-16', '18:40:00', null, '通常 / アレンジ大賞', '今日は締め切りの近いアレンジ大賞を進めました。半透明のおじゃまキャラでオーダーを隠し、キーを40回押すとそのキャラが消えてくれるなどやりごたえのあるゲームにしようと頑張っていました。デザインとしては全体的に不気味な世界観で統一していました。一通り作り終わった後は先生にテストプレイをお願いして、客観的な難易度感を測って調整していました。', null, null),
  ('d9e3b5b8-2b92-531f-934e-5f522b75ffb7', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-19', null, null, '通常 / アレンジ大賞 中級', 'アレンジ部分について制作していきました．イラストコースと交互に行なっているため，時間の確保が難しい中で自分なりのアイデアを作品にしっかりと落とし込むことができたようで，喜んでいました．しかし，作品の完成度には少し不満なようでもう少し手入れを行なっていきたいといっていました．そのため，時間が取れるのであれば最後の仕上げに取り掛かっていきたいです．', null, '時間帯: その他'),
  ('65da8772-0f1f-560e-832c-9502ae372cd3', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-19', null, null, '通常 / アレンジ大賞 中級', '前回の続きでアレンジ部分を作成していきました．HPの追加やターゲットマークの移動方法変更，移動の際に慣性をつけるなど非常に多くのアレンジを行っており，ゲームとしての完成度も高いものとなっていました．次回の授業で完成まで持っていき，大会でも入賞を狙っていきたいです．', null, '時間帯: その他'),
  ('206839ca-198f-50ca-ad3b-c176887eb3a1', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-19', '16:30:00', null, '通常 / 八王子プログラミング親子大会_オリジナル部門', '前回の制作が終わってしまったようなので、岳くんと一緒に大会用のオリジナル作品を作ることにしました。今回の時間ではゲームのイメージを考えてもらいました。どうしたらいいかわからない！とのことだったので、「それは冒険するゲームなのか？」や「戦うゲーム？」「敵は何？」などいくつか質問をしてイメージを膨らませてもらいました。質問から、年始に作ってもらったシューティングゲームに近いということがわかりました。攻撃の技や敵や主人公のスプライトが必要だったので、授業の後半ではipadを使って絵を描いてもらいました。', null, 'タイピング: なし'),
  ('3af2d48b-60e1-5ba4-9f14-51e60c63db15', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-19', null, null, '通常 / アレンジ大賞 中級', 'アレンジ部分の続きを行っていきました．隕石のコスチュームの種類を増やしたり，一定時間経過後にターゲットが増えるなど独創性の高いアイデアを作品に取り入れていくことで，他の生徒との差別化を図っていました．ゲームとしての基本部分は変えずにアレンジでオリジナル要素を入れていくことを重視しているようで，ルール内で良い作品を作ることができて満足しているようでした．来週で残っている部分を完成させて終了することができると思います．', null, '時間帯: その他'),
  ('ac8bdcb6-c0d5-54e3-8807-66bad49fcfd6', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-19', '16:30:00', null, '通常 / 親子大会へのアイデア作り', 'アレンジ大賞が終わり、親子大会に向けて作っていきました。最初に概要を説明し、いざ作品を作り始めようとすると、自発的には作りたいものが思い出てきませんでした。そこで、質問で周りのことから聴いていき、岳君はクイズ問題を作りたいとのことでした。まずは、4色のカラーごとにスプライトを選んでいき、問題文の用のスプライトもカラフルなものになりました。正解用の音声は取れて正解の判定のコードは時間が来てできませんでした。だが、アレンジ大賞の間違え探しの変数の仕組みを利用して作りたいと岳君が言っていたのでサポートお願いします。', null, null),
  ('e649ca88-7c58-5873-be45-05e8192846d4', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-19', '17:30:00', null, '通常 / イラストコース_キャラクター編', 'ご自宅からipad用のペンを持ってきてくれたのですが、surface対応のものだったので教室のペンを使ってもらいました。 2頭身のデフォルメキャラが描けるようになりたいとのことで、オリジナル教材を渡したところ、アイビス内の素材を使いながら教材を部分的に参考にして描こうとしてくれました。 順番通りにやるというよりは好きな部分をつまみ食いして完成させる方が好きなようです。 今回のデフォルメキャラではアイデアが出ていましたが、本人の中で「こういうのが描きたい」という明確なアイデアがあまりなさそうなので、飽きが来ないようにカリキュラムを考えていく必要があるかなと感じました。', null, 'タイピング: なし'),
  ('57ccc7a8-e9da-5289-9ff4-b64389acc55c', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-19', '17:30:00', null, '通常 / アレンジ大賞', '作品も細かい所のアレンジが中心になっていました。電車を増やしたことによる、文字の調整やアルネコの色替えなどこだわってアレンジすることができました。また、コインを増やしてまどろしさが増して、ゲーム性も高めることができました。完成まで持ってくることができました。', null, null),
  ('a190f9c9-fc76-5883-b31a-df82ead56663', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-19', '17:30:00', null, '通常 / ロブロックスwhile wait', '今回も20分前に来て早々に始めました。最初のところはつまらなく感じていましたが、要点は捉えていました。waitがアルスタジオの「何秒待つ」の役割と同じ働きをしていて、よくやるループの中でのwaitの入れ忘れによるコードのバグが起きやすことも理解できていました。普段ロブロックスでみる動きがつくれようになって楽しそうです。', null, null),
  ('ba8274dd-ba1f-5940-a226-510ef1c1824b', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-20', '17:30:00', null, '通常 / アレンジ大賞', '前回目標だてたゾンビについてやっていこうとしましたが、数分した内に無理そうだと感じでそそくさにゾンビのスプライトを消してなかったことにしていました。そこで、ほかのアルネコやそうじゅうせきの色を変えたりして、ダークヒーロー的なコスになりました。色付けとかセンスあっていいと思います。最後に、互いに作ったものを見せ合って、壮太君の時間通り終わらないバグを指摘して手助けしていました。', null, 'タイピング: お得までもう少しでした
盛り上がり: 新しく来た壮太君とゲームの話をしていたりして楽しくできていました。'),
  ('34e63b22-dd24-5709-99a4-3e69eae5bb8a', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-20', '17:30:00', null, '通常 / アルスタジオ', '最初にコードに関して、もう少しアレンジをしてほしいと希望を出しましたが、生き物に対してより調理屋ぽさの方向性に切ることにしていました。商品台をコンロに変えて、直火調理風に茶色く色味が変化していて、よりよくなっていました。その際、レイヤーに関してうまく前後ができていなかったので補助をしながら完成できました。', null, null),
  ('3ec65c32-56b5-52a2-9f3a-6e1794b03833', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-20', '16:30:00', null, '通常 / 基本的なブロックを学ぶ', 'アレンジ大賞の作品は、一度見直したうえでもう満足なので新しいことをやりたい、と言う希望により、追跡ゲームに入りました。 数値を入力する前に「英数」キーを押すというのはしっかり身についていました。 「旗が押されたとき」「ずっと」などのブロックがどこにあるかもきちんと覚えていました。 左右の動きを一緒に作ったあとは、上下の動きを一人で作ることもできました。 作成前にプレイした内容をよく覚えていて、その通りに作りたがる傾向がありました。スプライトに触れた時の音楽をかなり熱心に選んでいたので、レベルアップのときも音楽を鳴らしてみようか提案したしたところ、もとのゲームになかったのでやらなくていい、という反応でした。また、一通りの動きが完成した後で、「早く10点になったら画面が変わるやつを作ろう」と催促してきました。 レベルアップのテキスト入力中、手がトラックパッドに触れたりしてカタカナ変換する前に確定してしまうことが続きましたが、辛抱強く何度もチャレンジしていました。 17時10分過ぎに完成したので、残りは色々なゲームを検索して遊んでいました。', null, '盛り上がり: 授業中はしっかりと集中して、意欲的に取り組むことができていました。 一度教えた操作やブロックはよく覚えていて、そのことをお母さんに伝えると感動されていました。
備考: 特性のため、チックのような感じで咳が出ることがあるそうです。ひどくなると戻してしまうそうで、今日は防臭袋を持参していました。 咳がひどくなりそうなら気を紛らわせるか、トイレに促すなどして対応する予定でしたが、授業の方に集中したせいか教室ではおさまっていました。'),
  ('a123f6e3-7928-515a-941b-9eda79bd4827', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-05-20', '16:30:00', null, '通常 / アレンジ大賞の完成', '集中して頑張っていた。 キレイなコードを書くということを意識して行なっていました。 早めにアレンジが終わったので制限時間のカウントが始まるタイミングなど細かな部分の調整を一緒にしました。 細かなゲームバランスの調整に悩んでいたので大きさを変えてみたらなどのアドバイスをした所、大きさを小さくして当たりにくくしたり、出てくる数を減らすなどの工夫をしていました。', null, '盛り上がり: 作品名やコメントも一生懸命考えて、やり切った！という感じでした。
備考: ロブロックスコース(テキストコードをやってみたいと言っていました)に興味があるようでした。 ⇒ 検定受験をお勧め'),
  ('ea7fde88-f09a-578a-b781-f079a6809dda', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-20', '17:30:00', null, '通常 / アレンジ大賞にチャレンジ', 'いきなりですが、アレンジ大賞の説明をしたところ興味を示して、中級に取り組んでいました。 アレンジは慣れた感じで、すぐにレベル別のボタンや背景を変えるボタンを作成し、余裕をもって完成させていました。 体験のときは、Scratchは好きだけれど明確に何かしたいわけではない、という感じで、わりとおとなしかったので、意識してとうきくんや先生達との会話に引き込んでみました。 授業後半にはだいぶ慣れたのか、会話にも積極的に参加するようになり、とうきくんとの作品の見せ合いでも楽しそうにしていました。 とうきくんがプレイしたことで、残り時間が減らないバグが見つかり、残り数分で直すことができていました。 帰り際に、自分のアカウントで作成したという打ち込みした音楽の作品を見せてくれました。', null, 'タイピング: ものすごく早かったです。タイピングコンテストもやってみたいとのことでした。
盛り上がり: 好きなScratchやゲームの話ができることで楽しくなったのか、体験のときよりもリラックスした感じで、教室を楽しんでくれているようでした。 とうきくんも一人の時より楽しそうで、お互いに良かったのではないかと思われます。
備考: 初回ということで、雑談で話したことをメモ… ・部活には入っていない ・寿司打はよくやっている ・休み時間にもScratchをいじっているが、学校の友達はアカウントを持っていない ・Scratchのアカウント上での知り合いはいる ・Switch2の当落の話にはわりと食いついてきた。まだ当たっていないそう。 ・好きな漫画はスパイファミリーで、漫画を全部持っている ・スマホは小4くらいからiPhoneを持っている。妹はキッズスマホ。 ・教室へは一人で通う ・お母さんが和田そうすけくんのお父さんとお知り合いだったようで、ずっと話していた。'),
  ('d2fc132d-af83-51c1-81d0-6a76ca42e840', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-16', '17:30:00', null, '通常 / アレンジ大賞の完成', '久しぶりに余裕を持って来れたせいか、楽しそうに取り組んでいました。 質問等は特になく、自分の思うように作成していたようです。', null, null),
  ('de11eab5-1ebc-5fdf-9a98-120734954afe', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-16', '17:30:00', null, '通常 / アレンジ大賞作品の作成', '間違い探しの部分は前回まででほぼできていたようで、オープニングのスプライトの動きやセリフを面白くしようと手を加えていました。 ネコのスプライトがカウントダウンとともに増えるようにしたいと言ってスプライトの複製をしていたので、クローンやスタンプを使って対応できることを教えました。 基本操作コースのカードを見せたところ、やったことがないのでスタンプを使ってみる、とのことで、ペンツールの基本的な使い方を学習して流用しました。 スタンプが押されるタイミングによって間隔が変わるのを面白がって、色々と試していました。 スタンプで、新規の学習をしたと満足したのか、残りはひたすらコスチュームを描いたりして楽しんでいました。 長いセリフなども、自分でタイピング表を見ながら入力しようと頑張っていました。', '自分で描いた弾丸（カービィ？）のスプライトにコードを追加して完成させる', '盛り上がり: 作成したスプライトの動きやセリフに自分でウケて、楽しそうに取り組んでいました。'),
  ('a2be7efb-8518-5eef-b873-37821f507323', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-16', null, null, '通常 / Excelの学習', '「○○で計算した値を四捨五入する」という問題文の書き方のせいで、割り算などの演算式を入れた後にROUND関数を入れようとして混乱していました。この場合、関数を先に入れて値のところに演算式を入れることを説明し、納得していました。 IF関数でネストをする際、ただのIF関数だと真偽のテキストボックスに文字列を入力すると自動で""がつくのが、論理式のところに手動で入力するとつかないため、また、今回の問題の文字列が「＊」でこれを半角入力していたせいもあり、エラーが直らず困惑していました。文字列は""で囲むことを説明し、クリアできていました。また、ネストの際の)の位置にも迷っていたため、Scratchの条件分岐を複数使った場合を思い出させると、すぐに納得してスッキリしていました。', null, '時間帯: その他
盛り上がり: 上記で困っていた箇所について、それぞれ解説するたびに大きく納得してくれて、本人としてもスッキリしたようでした。'),
  ('38e26286-1e6d-550e-bab0-b0fff85c6390', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-16', null, null, '通常 / Excelの学習', 'まだ不慣れなせいか、問題文をどのように式にしていけばよいのかわからず手が止まっていることが多かったです。 自分から「わからない」とアピールしてこないので、手が止まった際は、しばらく解決できそうか様子を見てから、こちらから声掛けをしていました。声をかけるとほっとしたように質問してくる、というパターンでした。 割り算などの演算式を入れた後にROUND関数を入れようとしてエラーが出たりして混乱していました。この場合、問題文の順序とは逆に、関数を先に入れて値のところに演算式を入れることを説明し、納得していました。 IF関数のネストの問題では、ウィザードの方がわかりにくかったようなので、直に入力する方法も教えてみました。面倒だとは言いつつも、式の構成的にはコチラの方がわかりやすいかも、でも、覚えるのが大変、との感想でした。', null, '時間帯: その他
盛り上がり: 解決ができたときはなるほど！という感じで達成感はあったようでした。'),
  ('41aa2a4e-33d3-5e28-b059-9f7e764dbf51', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-22', '16:30:00', null, '通常 / 基本操作コース04_追跡ゲーム', '今回の授業では変数を習いました。 授業に入る前に前回の復習としてX座標、Y座標や「〜まで待つ」を思い出してもらいました。 途中、触れるとずっとスコアが増えていってしまっていたので「1秒待つ」を使って調整してもらいました。飲み込みが早く、授業残り10分まで根気よく取り組んでくれました。', null, 'タイピング: F、Jを人差し指でタイピングするようにしました。 f,g,h,jが難しかったようなので引き続き練習すると良いなと感じました。'),
  ('441e8bee-7a46-5e64-bb65-07ff87782ed6', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-22', '17:30:00', null, '通常 / 1章7 髪型の復習', 'アレンジ大賞のイラストは終わったので、授業を進める動線として前回までに習った髪の描き方をベースに自分の好きな髪型を描いてもらいました。 授業が無い日もアイビスペイントを使って絵を描いているようで、手先が早く帰るまでに塗りまで完成してもらいました。', null, 'タイピング: なし'),
  ('27d9c1f4-29c8-5ab8-b9c8-4ab2b1be7814', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-22', '16:30:00', null, '通常 / アレンジ大賞', 'グダグダと初めて、スクラッチのゲームから離れていませんでした。作り始めても操作が詰まるところがあると、集中力が切れて、すぐあめやこたろう君のところに気が移っていきます。そのため、アレンジ大賞は中途半端に終わり、自分の過去の作品のコスちゅうーむをいじりだして時間をつぶしていました。本とアレンジ対象期間は集中が持っていなかったです。', null, '盛り上がり: 最近の授業始まりの切り替えが遅くなっています'),
  ('3d7aac2e-c253-5c5f-ba97-d162f092efe0', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-22', '16:30:00', null, '通常 / アレンジ大賞', 'アレンジ大賞の方は、ゲームスタートやエンドの演出を華やかなものにして、きれいに仕上がっていました。完成したのちに、タイトルやアピールポイントで文章におふざけを感じましたが、完成はできました。 次に、親子大会に向けて、依然作っていた魔法とドラゴンのゲームを作りました。最初のセレクトのコードを完成させ、それぞれの魔女のコードを作り上げることができてました。本人的には更なるゲーム性向上したいと考えていたので、周りの子や先生にアイデアを募っていました。', null, null),
  ('7a0ebd20-2532-5513-a651-4f0712df9252', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-22', '16:30:00', null, '通常 / アレンジ大賞の完成', '教室に来て塁くんと遊ぶのが身についてしまってます。 前回に引き続き、大きなげっぷの音を立て始めたのは注意してやめさせました。 学校ではリーダーなどの役職を引き受けたり、先生のPCを許可を得て借りてScratchでゲームを作ったりと、それなりにしっかりと活動しているようなのですが…。 アレンジ大賞も、一瞬だけ取り組もうとして、自分の声を録音して使用するアレンジをしましたが、すぐに飽きて、完成としていました。 後半に飴を食べに来た際、落ち着いたトーンで「ここに何をしに来ているのか、何をしたくて来ているのか」と話しかけてみました。 教室に来るのは楽しくて、クラスでもこの教室はいいよと広めているそうです。 ここで何をやってみたいのか、との問いかけには、学校で作っているゲームをこっちでもやってみたい、とのことで、許可を出すと今作りかけのゲームをすごい勢いで作成し始めていました。 こちらはわりとすぐに時間切れになってしまったのですが、作りたいものがあるという気持ちを学習意欲につなげて、できたという達成感を繰り返し体験させていけたらよいかと思います。 17時半のたいようくんとそうたくんの歴史の話にも、よくわからないと言いつつ混ざって熱心に話していたので、もう少し持っていき方次第で変えられるかもしれません。', null, '盛り上がり: 好きなものを自由に作ってもよい、というと「やった！」と盛り上がっていました。 ここから学習意欲に少しでもつながるように誘導していきたいところです。'),
  ('c9675aec-139b-5fb2-a8fe-3a131b60ed7c', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-22', '16:30:00', null, '通常 / アレンジ大賞', '久々にたいようくんと会えたので、歴史の話に盛り上がっていました。そして、ゲーム内のコスチュームも石垣や武士に書いていて、とても賑やかなものになっていました。今回コードに関してはあまり広げられなかったが、次回のモノにはちゃんと力は入れたいとそうたくんがおっしゃっていました。', null, null),
  ('29346717-6242-58db-9c88-c848338fc939', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-22', '16:30:00', null, '通常 / アレンジ大賞の完成', 'アレンジのイメージはしっかりと持ったうえで来室したようで、すぐに取りかかっていました。 えみちゃんに懐かれていて、机を同じにされていましたが、特に問題なく、ゲームに付き合ったりしていました。お互い、ちょっとだけ脱線してもすぐに自分の作業に戻るタイプなので、こちらが注意するようなことはなかったです。 クラウド変数を使って記録が残るようにアレンジをし、最後に結果発表の画面を表示してゲーム性を高めるアレンジをしていました。作成途中のバグなども、自力で直せたようです。 教室や先生には少し慣れたのか、先週よりも積極的に先生に声掛けをしてきて、できた部分を見せてくれたりしていました。 親子大会の作品作成も進めているそうで、次回から教室で作成できることを喜んでいました。', null, '盛り上がり: アレンジが完成したときは、積極的に先生を呼びに来て見せてくれました。 周りの子に感心されて嬉しそうでした。'),
  ('0cdfe1fe-c62b-542e-870f-87b97918367a', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-22', '17:30:00', null, '通常 / アレンジ大賞', '1週お休みだったので、急ぎ目で作っていきました。もとの操縦者のところを刀に変えて、武士を倒していきカタチになっていきました。端に触れたら消えるの所を川の色判定に変えたいとのことでしたが、最初はそのまま「かくす」を使っていて重くなっていましたが、クローンなので削除のでやり取りすることを教えてあげました。また、武将名を言いたいとのことだったので、リストで管理する方法を提案したら、自力で作ることができていました。本人的には、まだやり高がっていましたが、時間足らずになっていしまいました。', null, null),
  ('494ce810-d693-513a-957e-4bb1e8297540', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-22', '17:30:00', null, '通常 / アレンジ大賞の完成', 'お休みが続いたため、締め切りが今日だと教えるとショックを受けていました。 とりあえずできるところだけ、とアレンジを頑張っていましたが、時間がないのでコードを整理する暇がなく、メッセージを多用しすぎたと自己反省していました。 もう少し手を入れたいとのことだったので、日曜日まではOKということで、自宅での作業を許可しました。 他の机での歴史談義を聞きながら、歴史のテストはイマイチだったと話し、そこから読書の話を楽しそうにしていました。一度に3～4冊用意して読みまくっているそうです。 好きな現代作家のミステリーから、最近は人間失格などの純文学まで読んだりしているとのこと。', null, '盛り上がり: テストで疲れたそうで、教室でScratchをいじることも、おしゃべりをすることも、良い息抜きになっているようでした。今日はずいぶんと饒舌で、楽しそうでした。'),
  ('0a27f0fb-27aa-5792-b921-c4d73e4bbaea', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-22', '17:30:00', null, '通常 / 前回学んだ知識をもとに、よりゲーム性の高い作品を作る', '前回の復習と、シューティングゲームの基本的なコードの定着を目標に、穴埋めプリントを使って【Prg】56 シューティングゲームを作ろう！（簡易版）を作成しました。 素直に穴埋めのところを自力で考えていて、最初は背景スクロールの座標の演算式を=で書いていたためうまくいかずに混乱していましたが、このように動き続けるものの場合、数値が完全に一致する=ではなく不等号を使わないとうまくいかないことがあることを説明すると、自分で納得して修正していました。 弾を発射するための座標の変数の使い方や、幽霊効果などは軽く解説しましたが、すぐに理解して自走することができていました。 ロケットのスプライトが画面からはみ出ないようにするためのマイナスの動きも、チーズを探せでやったことを覚えていて、すぐに作成することができていました。', null, '盛り上がり: だいぶゲームらしい作品ができたことを喜んでくれました。 作品が完成した満足度は高かったようで、次はぜひ違うものをやってみたい、とのことでした。'),
  ('bfba2b85-8563-5375-b223-df3f59123ce4', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-22', '17:30:00', null, '通常 / アレンジ大賞完成', '授業開始前20分前から来て、完成させる気満々でした。先週のとっ散らかったコード大きく変えていくために、事前に立てたシステムの考え方を伝えてあげました。基ここで、そうちゃんに伝わってほしいことは「メッセージを減らして変数の活用を広げよう」でした。スコアなどの加算減算的な使用だけでなく、スプライトやキーなど繋ぐ信号的使い方や情報の置き場などの使い方を教えていきました。基本的に、教えていく形を取りましたが、穴埋め形式て何が埋まっていくか自力で考えて進めていく様子もうかがえました。授業時間ぎりぎりでバグ修正も終わり、何とか完成しました。 そして、アピールポイントも必死に描いて延長15分も奮闘しました。', null, '盛り上がり: 終わった後に、「変数ってやっぱすごいね。使っていかなきゃ」と前向きな発言をいただけました。'),
  ('30897176-01e0-5044-873c-56050ce76694', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-23', '16:30:00', null, '通常 / アレンジ大賞中級の完成', '前回までで大体完成していたので、今日はスクリプトを確認して整理したり、ゲームの最終微調整のようなことをしました。最後に、ゲーム名と説明を記載して完了となりました。ゲーム名がなかなか思い浮かばないようで、最初は「シューティングゲーム」というありきたりなゲーム名にしていたのですが、さすがに、それはありきたりすぎるからと、もっと他の人が聞いてやりたくなるような名前に変えようよということで、ゲーム名を変更して完了。残り１０分ほどあったので、ちょっと休憩がてら遊んで時間となりました。', null, null),
  ('7bd48538-85b6-5ee1-9d57-0a7bf7b79136', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-23', '17:30:00', null, '通常 / Roblox Studio', '前回の続きで、クイズロブロックスを進めました。動画で教えている以上のことをやろうとして、「大改造していい？」と言われて本人のやる気を尊重してOKを出しました。答えのブロックに辿り着くには透明の道を通っていかなければならない作りに変えていました。それプラス、答えのブロックに触れた時にメッセージを出したいとのことで、それを基礎的な考え方から教えました。スクラッチだと、○○に触れたらというブロックがあり、簡単に実現できますが、ロブロックススタジオだと少々面倒（書くべきスクリプトを覚えるだけですが）で、デジタねのステージ２で学ぶことなのですが、ささっと自分なりにわかりやすく教えてみました。身についていると良いですが。今日は、クイズロブロックスの大改造をして最後まで終わらせて確認テストをして終わりとなりました。', null, null),
  ('80282462-3cfd-5c19-b4fd-40676d329c5e', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-23', '17:30:00', null, '通常 / ロブロックススタジオ', '前回、「頂上を目指せ！」でのアスレチックゲーム作成部分をオリジナルで作っていて、未完成ということだったので、それを完成させることを目指して作成をしていました。Roblox studioのツールボックスから大量にいろんなオブジェクトをインポートして、ゲームを作成しており、動画通りの手順は取っておらず、だいぶイレギュラーな進め方になっていますが、「面倒くさい」等愚痴っぽいことをこぼしながら集中して取り組んでいました。ただ、ゲームを完成させることはできなかったみたいで、最後には「もう飽きた」といっていて、来週はどうすべきかちょっと悩むところです。個人的には、次の動画（クイズロブロックス）に進んで、次の動画で覚えるべきことをやってもらいたいとは思っていますが、きちんと動画を見てくれるかが心配です。', null, null),
  ('88a27c22-6973-5e9b-b04b-2afe8ee84d3e', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-23', null, null, '通常 / Excelの学習', '忙しそうに時間を少し過ぎて来室しましたが、今日は途中で眠そうにすることもなく、よくしゃべって楽しそうにやっていました。 前回練習問題2は一通り終わったそうですが、自分で納得いかなかったところを復習したいとのことで、一緒に確認していきました。 ・スパークラインが合っているかわからない⇒これはきちんと正解していました ・並び替えがおかしくなっている気がする⇒並べ替えの最優先と指定された列を選択してから並び替えをしていました。このやり方だと、選択した列だけが並び替えされるため、行ごとのデータが完全に崩れてしまうことを実演して納得させ、基本的には表の中のどこか一つのセルを選択した状態で並び替えのメニューを出すと自動的に表全体が選択されることを学習させました。2番目に優先される列がある場合のやり方も教えたところ、とてもスッキリしたようでした。次の例題で復習として並び替えをしたときは表が自動選択されなかったため、こういうときの対処法も一緒に学びました。 ・グラフが見本と同じようにならない⇒凡例等、画面上に出ていない要素の入れ方と、各要素の書式設定を一緒に確認しました。また、テキストボックスとして挿入した場合の編集方法を学習し、納得できたようでした。 前回疑問だったところの解決ができて、かなりスッキリしたようでした。作業しながらの雑談も、いつもより積極的でした。 グラフが不安で学習したようでしたが、教材がまだ用意できていなかったため、スパークラインの練習として例題10に取り組みました。自力できちんとできていました。', null, '時間帯: その他
盛り上がり: 今日は色々な疑問が解決したのか、最後まで集中して楽しそうに取り組むことができていました。'),
  ('c7b0627e-843e-5732-87ab-be876e66fcc9', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-23', null, null, '通常 / アレンジ大賞完成', '今日でアレンジ大賞を完成させるということだったのですが、何か新たなキャラクターのようなスプライトを作っていましたが、時間的にそれをゲームに入れ込むことができず、現状のゲームで、ゲーム名をつけて、説明を書いて完成としました。まだタイピングでの文字入力は慣れていないようで、文字の表を見ながら文章を丁寧に打ち込んで完了しました。その後、新しく作ったキャラをスクラッチ上の動かすスクリプトを作って遊んでいました。', null, '時間帯: その他
備考: 途中、要くんの行動が少しうるさかったのと、ちょっかいを結構出されたのもあって、朝陽くんの集中も普段よりだいぶ削がれて進みが遅くなっていました。こちらの記録で書くのもどうかと思いましたが、レッスン中に誰か他の子供が、過剰に迷惑な行為をしていたときに、どうすべきか迷ってしまいます。どれくらいを過剰と判断するか、具体的にどう対応するか難しいところです。'),
  ('cb065e12-f28f-5528-983b-631c09bc133d', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-23', null, null, '通常 / エクセル→アレンジ大賞', 'エクセルをしようとしていましたが、ここのところエクセル続きという事もあり、今日は息抜きということで、久々にスクラッチで良いとのことで、アレンジ大賞中級に取り組みました。時間がないので、完成版からいきなりアレンジを加えていきました。ある程度まで進めたのですが、１時間では納得のいく出来にはならなかったようで、公開はしなくて良いとのことで終了となりました。', null, '時間帯: その他'),
  ('ba682174-6397-51aa-9423-d4e6707f970f', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-17', '16:30:00', null, '通常 / アレンジ大賞 中級', '前回の続きから作成していきました．作品としてはほとんど完成しているようでしたので，今までに制作した部分でさらに工夫できる部分がないかを探し，アレンジを行っていきました．今回の調整で僅かなバグを修正するのみとなったため，次回で完成させることができると感じました．', null, null),
  ('1b971233-c8e5-5e15-bc6c-a3e9efd16bfe', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-24', '16:30:00', null, '通常 / アレンジ大賞 中級', '前回の続きから制作していきました．本人はアレンジ大賞には飽きてきているようで，アレンジ部分の制作にはあまり力が入っていない様子でした．しかし，いくつかアイデアを出していったところ，うまくハマるものがあったようでそれ以降は順調に進めていくことができていました．次回で作品の調整を終わらせて完成まで持っていきたいです．', null, null),
  ('f2cf205b-fa8b-514c-939a-6d62ead3a1eb', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-24', null, null, '通常 / イラストコース1-2', 'アイビスペイントで描くのに少しずつ慣れてきたかと思い、教材を進めることにしました。アタリの円を描いてもらう際、対象定規を使って綺麗に円を描く方法を教えました。 今日は指示を出してやってもらったのですが、まだ技術が足りないのもあり脱線が多く、一旦は定規への慣れの時間を設けました。 レイヤーを忘れていたため改めての説明もしました。恐竜が好きなようで、いずれは作品として描いてもらえたらと思いました。', null, '時間帯: その他'),
  ('d1f53619-62b5-5745-b1f7-8a5019d654b6', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-24', null, null, '通常 / イラストコース キャラクター編 1章6~7', '授業前にアニメキャラの模写をしていました。とてもよく描けていて良かったです。 前回同様、黙々と描く作業を進めてくれました。最後、髪の毛の線画が完了した時の色の塗りつぶしの仕方について、自動選択ツールで効率よく塗る方法を教えました。 知らなかったようで、かなり驚いていました。 次回も活用してくれたらと思います。', null, '時間帯: その他'),
  ('cc8078b0-bb1c-5073-b8dc-68593c1fc4d6', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-24', '17:30:00', null, '通常 / イラストコース 模写', '前回正面からの全身を2回描いてくれたので、今回は教室にある教材から好きなポーズを選ばせ、模写をさせました。顔だけではなく最低でも首下まで描いてもらうことが条件です。 学校の部活や家で作っているものについて雑談を交え、黙々と作業が出来ていました。途中、他の生徒さんと一緒にプログラミング大会のホワイトボードにイラストをたくさん描いてくれました。', null, null),
  ('17069a84-a631-5362-9b4a-cff835b9ea7f', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-24', null, null, '通常 / アレンジ大賞完成', 'アレンジのラストスパートを進めました。自分でテストプレイをしたときに、好きなだけ弾を乱射できてしまうという欠陥があることに気付いたようで、銃弾の制限数を追加していました。またゲームクリアに必要な点数や初期HPなど、ゲームの難易度に関わる数値を試行錯誤して調整しました。最後にゲーム説明も書いて完成しました。', null, '時間帯: その他'),
  ('5f8f851c-70d4-52a7-b3da-fcdef101a5b1', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-24', null, null, '通常 / アレンジ大賞の完成', 'タイピングの後、少し遊びたそうにもしていましたが、声掛けをすると素直に「やるかー」とアレンジ大賞に取りかかっていました。 開始後すぐに、やりたいことはもうない、とだれそうになりましたが、いいBGMが見つからないとぼやいていたので一緒に曲を探そうかと声をかけると一気にやる気になりました。 Scratchでアンダーテールを検索し、作成者がOKしている作品から「音」の書き出しとアップロードを教えました。好きな曲をBGMに設定できたことでテンションが上がり、隕石を一生懸命複製しては色を変えて、とてもカラフルな作品に仕上げて満足そうにしていました。', '親子大会には参加しない、と明言していました。', '時間帯: その他
タイピング: タイピング表に記入していました
盛り上がり: 音楽を好みのものにできたことがとても嬉しそうで、説明文なども自分で熱心に入力していました。'),
  ('3af36578-fa6e-59df-afda-2cabc57cc4a3', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-24', null, null, '通常 / ロブロックス', 'アレンジ大賞が終わって久々のロブロックスで、新しい単元のレンガブロックを始めました。いつものように開始後しばらくはゲームを遊んでからレッスンを始めました。期間が空いたためか保存やメニュー表示などの操作を少し忘れていたようで、ゆっくりめのペースで進みました。', null, '時間帯: その他'),
  ('9cab2bfe-fb42-5022-9157-234811b23abd', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-24', null, null, '通常 / アレンジ大賞の完成', '途中何度か飽きたようなそぶりも見せていましたが、声をかけると復活して作成に戻ることはできていました。 そうすけくんの頭の中では色々考えたようで、制限時間は20秒で、8番出口方式だったり、間違い探しの対象のスプライトとダミーのスプライトがあったりという裏設定があるとのことでした。ただ、それをわかりやすく表現するのはまだ難しかったようで、すべての説明を背景に直接書いて済ませていました。 アイディアをいろいろ話せるようになったり、入力を自力で頑張ろうとしたりという成長は見られましたが、それを表現するのにはもう少し、といった感じでした。', null, '時間帯: その他
タイピング: 勧めてみましたが、今日はいい、とのことでした
盛り上がり: 作品が完成したことには喜んで、少し得意そうになっていました。'),
  ('df083388-6699-5178-9ce0-604407b8a995', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-24', null, null, '通常 / アレンジ大賞完成', 'ゲームに最後のブラッシュアップを行いました。低確率で出る隠しBGMをつけたり、隕石の速度を調整したりしていました。自分なりに満足いく完成度にできたようで、ゲーム説明を書くときにはルールやコンセプトをわかりやすく説明できていました。', null, '時間帯: その他'),
  ('ecc878ad-dcad-57b7-b4f0-ca06297035b2', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-24', null, null, '通常 / 基本操作コース', '図形を使って自分でキャラクターを描くのが好きなようで、天使と悪魔などいくつか作るのに時間をけっこう使っていました。内容としては、x座標やy座標による移動やコスチュームの変化を習得しました。x座標でやったことをy座標にも応用するなどして理解できていました。 マウス操作に慣れていないので、小さいマウスを用意して練習を進めたいところです。また自分でできることを大人にやってもらうことが多い傾向があるので、できるように促したいところです。', null, '時間帯: その他'),
  ('29d1bf58-24e5-5b2b-af3a-5f8db74cd5f9', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-26', '17:30:00', null, '通常 / 大会用作品制作', '大会出展作品を見て「ガチャ演出を作りたい」となり、乱数を使ってゲーム作りをしていました。乱数について考え方に詰まっていたようなので梅澤先生から助言をいただいていました。「1~6で起こる動き」と「7~10で起こる動き」に分けて確立を出したとのことだったので、新たに変数を作って条件分岐の不等号を使い、「7より小さいかそれ以外」「もし〜出なければ」を使うことを教えてもらっていました。', null, 'タイピング: なし'),
  ('bc2c5f8a-6e91-5232-bd6e-f31fdf407f6e', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-26', '16:30:00', null, '通常 / ピンポンゲーム', 'アレンジ大賞も終了したため，基本操作コースの学習に戻っていきました．今までに使用したブロックについてはしっかりと理解することができていたため，今回学習していった内容についてもスラスラと進めていくことができていました．作品を完成まで進めることができたため，本人としても満足していたようです．', null, null),
  ('41233469-93ad-5d0c-85c0-78201c5d96da', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-26', '16:30:00', null, '通常 / 大会出展作品の制作', '完全オリジナルで作品を作るのにアイデアがパッと思いつかなかったようで、最初はあまり手が動いていませんでした。今まで作った作品でお気に入りのをアレンジしてみたら？と提案すると、鉄道シュミレーターをアレンジする気になってくれました。 ただ、別サイトから素材など拝借した作品だったため、大会に出す際は「元作品を参考にした」との記載が必要です。 アレンジとしては、中島先生から特急あずさのゲームを作ってみたらどうか？と提案されたところ、かなりやる気になったみたいです。今回の授業では電車を特急あずさの見た目にアレンジをし、次回の授業でプログラミング的なアレンジも加えつつ、都会の新宿から地方の立川と八王子の駅を背景に変えるようにビジュアル面でもアレンジを進めさせる予定です。', null, 'タイピング: なし'),
  ('d938b8e2-9390-545e-8585-cb7f009fe317', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-26', '16:30:00', null, '通常 / 大会出展作品の制作', '算数シューティングゲームを作るとのことです。内容は段階ごとにステージが変わるものなようで、最初は小学1年生でも出来る四足演算から、最後の方に分数や少数を使った難しい式を全部で5段階で出題する予定です。本人のアイデアから、ルートや倍数など数学用語をいくつか知っているということが伝わりました。', null, 'タイピング: なし'),
  ('b6225e11-cc03-58b7-b1a5-8cf10ac3c134', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-05-26', '17:30:00', null, '通常 / ハラハラピンポール', '動画を見ながら，自分でアレンジを入れたい箇所に入れつつ動画内容の復習も兼ねて行うことができていました．制作途中でも止まることなく次々に完成させていき，最後の確認テスト部分でも問題なく正解することができていました．この調子で，次のロブロックスも順調に進めていきたいです．', null, null),
  ('84c9ce1a-5273-5d7a-b861-2f3a569a024d', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-26', '16:30:00', null, '通常 / 大会出展用作品の制作', '最初のスタート画面から次の画面に切り替わる時に出てくるスプライトの一つが、なぜか最初から表示されてしまってるという相談を受け、私の方で全く同じものを作りながら一緒に考えて解決をしました。 前回講師の方が入力してくれたであろう背景の切り替え用のコードに「〜秒待つ」があったので、それが必要なこと、表示したいスプライトに何と命令したら画面が切り替わった時に表示できるか、を教えました。 次に、「赤くて丸いものはなんだ」というクイズの問題だったので、調べるから解答を入力するコードを利用してやり方を一緒に模索しました。 出題するのに乱数を使って解決をしようとしたのですが、今の岳くんのスキルから思ったよりコードが複雑になりそうだなと感じました。一旦こちらの方で見本を作ってから 乱数などの概念について一応教えられたらと思います。', null, 'タイピング: なし'),
  ('1c454bcd-2828-5502-8de5-150030e92168', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-26', '17:30:00', null, '通常 / 大会出展用の作品の制作', '正直ゲーム制作にそこまで自信がなかったのですが、中島先生から着せ替えゲームの提案を受け取り掛かることになりました。実際に似たゲームをいくつか見せたのですが、どういうゲームか？というイメージがPCだけだと中々沸かず、ipadで描いていくうちにアイデアを確立していきました。 素体と下着、目を描いていて、目の色や髪型、服装を着せ替えできるよう手描きで素材を増やしていくようです。今回の絵は目が可愛くかけたと喜んでいました。', null, 'タイピング: アイデアが決まらなくて合間に少しやっていました。'),
  ('45f3977f-ca3c-50d1-a136-3823ef9aee0c', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-05-26', '17:30:00', null, '振替 / プログラミング親子大会の作品つくり', '大会の作品を作る。「天狗のイラストパズル」を作ることになりました。構想を考えて ①天狗のイラストを描く（次回までに家で描いてくる予定） ②イラストをいろいろな形に切る ③バラバラに配置されたピースを組み立てる 大まかに、そのような構想です。難関は、「あたり判定」です。よくあるパズルの仕組みをいくつか見たのですが。難しすぎて本人が意気消沈してしまったので。 ⇒下絵をつくり、下絵とピースに影武者を設定して、影武者（あ）が影武者（い＝下絵）に当たったらOK、という案で作ってみることにしました。 ※ピースを回転させてしまうと、あたり判定が難しいね、という話をしていたところ、「じゃあ、回転させないで置くようにする！」という案に！ 効率的なアイデアマンです(^^)v', '天狗のイラストを描いてくる。お迎えの時、お母さんにも伝えたので、持ってくると思いますので、よろしくお願いしまう。レッスン最後の方には、イラスト（画像）の切り方を練習していました(*´艸`*)', 'タイピング: ごめんみれてない
盛り上がり: 最初は、全く何を考えていいかわからない様子で、手が止まっていました。ジャンルを決めようと声をかけると、「ジャンル？って？」と。「シューティングとか、追いかけっことか、ゲームの種類」と答えると、「じゃ！パズル！」と即答でした。 考える入口に立つと、勘所の良さを発揮しますね(^^)v'),
  ('210b888b-12a6-527f-9d2f-948b16e714f3', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-24', null, null, '通常 / アレンジ大賞の完成', '作品は完成しているということで、説明文を熱心に入力していました。 今日は運動会だったとかで、疲れているけれどテンションが高いという感じで、おしゃべりやホワイトボードへのお絵描きなどの脱線をはさみながら、作品の見直しをして提出までこぎつけました。', null, '時間帯: その他
盛り上がり: おそらくアレンジ大賞の作品は完成していて興味が薄れかけているようでしたが、テンションは高く、ホワイトボードに熱心に絵を描いていました💦'),
  ('b0553110-25a8-5e95-be45-486a5874b60c', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-27', '16:30:00', null, '通常 / 基礎の定着', '基礎力の復習と定着をするためレッスンに取り組みました。ビームを撃つときの動きやゲームを止めるタイミングなどを細分化したところ、ある程度把握することができていました。基本的に動画を見ながら進めましたが、ブロックをどこに入れるかを間違えていることがあったので「[ずっと]ブロックには何が入る？」などと問いかけて修正してもらいました。[～を止める]ブロックは初めて使いましたが、何回か出てきたので場所を覚えられました。完成までもっていけて嬉しそうにしていました。', null, null),
  ('1331a5d7-19a6-5a9f-839e-eed1e39e7e61', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-27', '17:30:00', null, '通常 / スキルの積み上げ', 'U16の説明をすると乗り気だったので出すことを決めましたが、まだ締め切りまで時間もあるのでスキルを積み上げるためprgに取り組みました。細分化に慣れるため、まず各スプライトの重要な動きを言語化していきました。以前やった横スクロールも使うので復習したところよく覚えていました。自分でできるところは自分でやって残りは写経で作りましたが、 ・スプライトが動いて端に来たとき、隠れないために逆向きの動きで相殺する ・座標を変数に記録することで、その場所に新しいクローンを作る などの新しい考え方を学びました。', null, null),
  ('0386cd47-1e99-519e-9a0b-7e5623659b05', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-05-27', '16:30:00', null, '通常 / 八王子親子大会に向けての計画と作品づくり', 'タコ型クレーンゲームの制作を行いました。 アマギフをとても狙っていた。 入賞する為の基準(評価ポイント)を知りたいと言っていた。 テーマは考えられるが、コードを考えたり作るのが苦手なので親に手伝ってもらおうかなと話していました。 アイデアを紙に書き出してもらって他の人に伝えられるようになるとアドバイスなどからコードを考えやすくなると思いました。 （榊原）', null, 'タイピング: 久しぶりなのでちょっと遅くなった、と言っていました
盛り上がり: たこ焼きが好き、というところからイメージを膨らませていました。みうちゃんと話しながらも、手はきちんと動かして楽しそうでした。'),
  ('4518faaa-440f-5da5-94e8-b630efefa094', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-27', '16:30:00', null, '通常 / 自分で考えたアイディアをコードにする', '親子大会の説明は軽くしましたが、出したくないとのことでした。 ただ、今回のアレンジ大賞に続けて、自分で考えたアイディアを形にして作品として仕上げる練習を夏までしていきたい、というこちらの話は素直に聞いてくれました。 とはいっても、一から何かを作成するのはすぐに思いつかずに面倒モードに流れそうになったので、これまで作った作品の中で、自分が一番楽しく作成できたものを尋ねると、「これは自分でも頑張ったし楽しかった」と言って、ビームをよけろを開いてきました。 とりあえず、このゲームに手を入れながら、少し複雑なゲームを作る手順を思い出していこうというのを今日の目標にし、コードを見直ししてフェーズを増やすことを決めていました。 そうすけくんの好きなコスチュームいじりをしながらも、コードを見て条件分岐やメッセージを増やして、新しいフェーズを2つ付け加えていました。 コードがかなり長くなったため、少し整理しようかと声掛けをしましたが、今日は難しそうだからやりたくない、とのことで…機会を見つけながら定義などを活用していけると良いかと思います。', null, 'タイピング: 自分から始めていました
盛り上がり: 一瞬面倒モードに入りかけましたが、好きだったゲームのバージョンアップはそれなりに楽しかったのか、珍しく祥太君に話しかけたり作品を見せ合ったりもしていました。'),
  ('a63560fa-29d8-56e2-968e-e05ad235a682', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-05-27', '17:30:00', null, '通常 / 八王子親子大会に向けての計画と作品づくり', '親子大会に参加する気にはなったようですが、一からアイディアを考えるのにとても苦戦していて、アルスタジオのゲームを参考にいろいろプレイしながら、ずっとみうちゃんとおしゃべりしていました。中学や高校生活のことを聞いたり、とうきくんや周りのお友達の恋愛事情を話したりと、とても楽しそうでした。 ブレストカードを使ってみうちゃんやこうくんと話しながら、少しアイディアがわいてきたようで、カードのコピーをとってファイルにしまっていました。 メール？絵文字？が関係する作品を作っていく予定のようです。', null, '盛り上がり: 今日はアイディアを考えるということで、ひたすらしゃべりながら楽しそうにしていました。'),
  ('f9991212-acf5-5391-831c-4aee409fd690', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-24', null, null, '通常 / アレンジ大賞', '隕石が飛んでこないバグがあったので、お手本のコードと照らし合わせて原因を確認しました。変数名のブロックを使うべきところでタイピングで打ち込んでいたり、不等号の向きが間違っていたりしたので一緒に修正しました。その後説明を書き、自分なりに満足いく形で提出できました。', null, '時間帯: その他'),
  ('c3d62094-36ce-5d4c-ba87-0fe53d51dcd4', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-24', null, null, '振替 / 親子大会アイデア出し', '次の親子大会に向けてアイデア出しを始めました。好きな曲が出てくるゲームを作りたいとのことでしたが、著作権の問題があり、思っている通りにやることは厳しいことを伝えました。代替案としてフリー音源を使うことを提案したところ探していましたが、あまりしっくりくるものはなかったようでした。', null, '時間帯: その他'),
  ('7eb4be63-7f0a-57e6-908c-75ae9000089d', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-23', '16:30:00', null, '通常 / 乱数', '乱数の学習のため、サイコロ→チーズを探せ の順で取り組みました。全体的にめんどくさいという様子だったので「これができるようになればもっと楽しいゲームが作れるよ」などとモチベーションを促しましたがあまり刺さりはしなかったようでした。それでも中盤以降は授業を進めることができて、ランダムな数という乱数の概念自体はなんとなくわかったようでした。チーズを探せで上下左右の移動の際、x,y座標による作成をよく覚えていました。ただ今回は新しいスキルとして、向きを変えて10歩歩く方法を扱いました。チーズを探せ①の序盤で終わりました。 またパソコンのタッチ操作の際、狙ったところをうまく触れずに嫌になりかけてしまいました。単純に操作に慣れていないのもありますが、落ち着いて作業できるようになることも必要そうです。', null, null),
  ('48c46ac4-3e6e-5374-87eb-8693273b9edf', '53dc382f-637d-5a46-9b57-4204c79ee130', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-23', '17:30:00', null, '通常 / アレンジ大賞完成', '本人的には前回で完成のつもりだったようですが、まだ時間があるので直したいところがないかもう一度確かめてもらうと、自分で新しく追加した隕石が最終的に大きくなりすぎるのを直した方がいいと気づきました。大きさの拡大率を設定するコードを探してもらい、大きさを下げることができました。またその隕石に爆発のコスチュームがなかったので作成しました。完成度を上げて提出できました。', null, null),
  ('487cc28b-0803-5a48-aedb-110b4d26d724', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-23', '17:30:00', null, '通常 / アレンジ大賞完成', 'まずは数値の細かい調整をしたり、前回のようなバグがないか確認したりしました。作成は中盤で終えられ、タイトルと説明を書くことに時間を使えました。工夫した点などをわかりやすく書けていました。', null, null),
  ('4d2decc9-1611-5e7c-a553-66fb4dd99ab7', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-29', '16:30:00', null, '通常 / 親子大会に向けて', '親子大会に向けて依然作っていたソニックのプラットフォーマ―ゲームを継続して作りたいのことでした。そこで、まずは今日やる目標としてるいくんに「キャラが途中で変わり飛べるようになる」ことを決めました。変化の要因は色判定を作り、これはよく使っていたので一人で作れました。そのあとの、ジャンプの制限解除はこちらが質問をしながら作っていくことで、道筋を立てました。そのおかげで、その最中は気がそれることがなくコスの名前を利用した判定式ブロックを汲めることができました。', null, null),
  ('031bd693-5bfc-5eca-a5b7-3e3a1de50f19', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-29', '17:30:00', null, '通常 / U16大会に向けての準備', '小学生に親子大会の話をするついでに、中学生にはU16大会があると軽く触れたところ、今年はぜひリベンジをがんばりたいとのこと。締め切りまでは期間があるので、Excelと並行して進めていきたいとの希望により、本日はプロットの作成をしました。 どうしてもストーリーものがやりたいということなので、昨年の反省点をふまえ、テーマをハッキリさせること、Scratchで作成する意義が伝わるようにすること、画面を見て作品に興味を持ってもらえるようにすることなどを意識して考えてもらいました。 今回は、八王子の歴史に興味を持つきっかけになるようなストーリーとゲームにする方針で、熱心にプロットを作成していました。 作成したテキストファイルは、ベイマックスPCデスクトップの承太郎君フォルダと、Googleドライブのじょうたろうくんフォルダに保存しました。', null, 'タイピング: 虎太朗君に尊敬されてました
盛り上がり: こちらの予想以上にリベンジに熱心で、どうしてもやりたいと食いついてきました。 作品のプロットも、とてもスラスラと書いていました。 今までは年齢や教材がかぶらなかったため、他の子とは全く話していませんでしたが、今日は寿司打で虎太朗君に尊敬されたせいか、その後、虎太朗くんの宿題の漢字を教えたりしていました。'),
  ('ec6bb180-5420-5708-813c-c52fb3b09739', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-29', '17:30:00', null, '通常 / 親子大会に向けてアイデア', '親子大会に向けてアイデア作りをしてきました。そうたくんは歴史が好きなので、八王子にまつわる歴史のゲーム案を提案したり、また、実際に写真を撮ってきて背景に利用するなどをアイデアをこちらから巡らせました。これらに対してそうたくんは好印象を持っていたので、方向性は良さそうです。ただ、それをゲームにするか、図鑑にするか、お話にするか作品の表現を決めるのは苦手そうで、今日はあちこちいじって終わりました。なので、ゲーム性のひな型を作ってあげると良さそうです。', null, null),
  ('69d9e7bd-e6b8-5c70-8a70-3413b055ef9a', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-29', '16:30:00', null, '通常 / 大会用制作', '人物を押すとコスチュームが変わるといったギミックを作ろうとしていました。 人物を押した時にその人物が光るよう、黄色のスプライトを人物の周りにひたすら描いていました。 今回の授業では、メッセージを使って見た目が変わるように少しコードを書いてくれました。 攻撃の種類をもっとたくさん増やしたいとのことで、次回はスプライトとプログラミング両方頑張るとのことです。', null, 'タイピング: なし'),
  ('32440ec8-55c2-5ffe-a61b-81f0326811fb', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-05-29', '17:30:00', null, '通常 / 大会用作品制作', 'アイデアはすぐ出ていたのですがいくつか悩んでいたようで、自然をテーマに作品を作ることにしたようです。 ネットに使えそうな画像がなかったようで、ipadを使ってドット絵でイラストを描くことを勧めると良さそうだと思い描いてくれました。 ネットの画像を参考に炎の細かい部分まで再現しようとしていて、絵は久しぶりに描くとのことでしたがすごく上手に描けていると感じました。', null, 'タイピング: なし'),
  ('07874d9d-3ed5-5ddd-8c1d-13e122d7b6c6', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-29', '16:30:00', null, '通常 / 親子大会作品の作成', '飴を食べに行く頻度は相変わらずで、コンテストって恥ずかしくない？などと否定的なことを言いつつも、授業時間ぎりぎりまで作品を一つ作ろうとしていました。 忘れていることも多く、ヘルプ要請も多かったですが、それでも久しぶりに授業時間内のほとんどを作成に費やすことができました。 ピッチャーがキャッチャーにボールを投げる作品を作っていて、ボールを隠すタイミングなどにこだわりがあったようでした。 キャッチャーがピッチャーにボールを返すところで、メッセージと座標での動きの復習をしました。こちらが提案した、大きさを変えてボールの速さを表現するのはおもしろがって、数値を色々と変えて試していました。 審判が判定を話すタイミングなどで、メッセージを使用し、少し思い出せたようでした。 授業後に、タイピングの寿司打を熱心にやっていました。 お迎えの18時半まで残っていましたが、17時半の子たちに話しかけつつも、タイピングや宿題をやっていて、最近では一番まともに机に向かえていたかもしれません。', null, 'タイピング: 高級コースを熱心に繰り返してチャレンジしていました
盛り上がり: やっぱり野球は好きなのか、好きな作品を作っていいのが良かったのか、納得のいく動きを作ろうとがんばっていました。 授業後に、承太郎君に漢字を教えてもらって満足そうにしていました。'),
  ('526043fb-df82-59b8-bf06-81f53c65047f', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-29', '17:30:00', null, '通常 / U16大会に向けて', 'U16大会に向けて、オリジナルゲームを作っていくことにしました。テーマとゲーム性の方向性としては、武将系を題材にしたシミュレーションゲームを作っていくそうです。たいようくんはまずは、ねこにコスプレションして、武士風にアレンジしていました。ここのイラストの表現の使い方はうまいと思います。建物の城もよくできています。たいようくんは作り方の手順は頭の中で整理できているので、技術的に足りない所補助していけばよい作品になると思います。', null, null),
  ('0ee2e5b0-a005-58c2-b525-b0af3fa8fbe5', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-05-24', null, null, '通常 / アレンジ大賞作品の完成', '前日にアルスタジオのメッセージで質問がきていましたが、その後半日でかなり頑張ったらしく、ショップなども作り込んできていました。 ブロック定期の引数を使った変数設定やメッセージ送信などは、自分で試行錯誤して考えたそうです。 クローンの数量オーバーのせいなのか、リトライ時に隕石がうまく出てこないことがあるバグは直せませんでしたが、タイトル画面やゲームオーバー画面の工夫、独自のゲーム要素とコードなど、しっかりアレンジしたものができていたと思います。 本人も、自分のコードの説明などをしながら、とても楽しそうにしていました。', 'U16大会にもとても興味があるそうなので、大会の説明と作品の構想ができればと思います。', '時間帯: その他
盛り上がり: バグは残ったものの、とりあえず作品を作り上げることができたことが、とても嬉しそうでした。'),
  ('284897af-0cc1-59c1-982e-9189ef250045', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-29', '17:30:00', null, '通常 / 親子大会に向けて', 'ゲームの方向性はすぐに縦型シューティングと決まって作り出すことができました。過去の検定問題のコードを参考にしながら、自力でうまく作れていました。そして、銃撃による変数のHPもさっそく作りこめていました。クローンを落とし込めています。個人的な感触として、最初の3，4回くらいはテーマを決めず、ゲーム性を高めていき、あとからテーマを乗せた方がよい作品になると感じます。', null, null),
  ('5e4d1300-40a4-521d-90bc-5a506e501a2e', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-30', '16:30:00', null, '通常', '最初にゆき先生から親子プログラミング大会で、オリジナル作品を作ってはどうとの声がけがあり、一応オリジナル作品作ってみる？と聞いてみましたが、どうすれば良いかわからない雰囲気で、じゃあ基礎レッスンをしようとなりました。基本操作コース０６で、キャラクターにセリフを言わせたり、背景を変えたり、色を変えたりという、本当に基本的なことを進めました。タッチパッドに自分の腕や服が接触して、勝手にマウスポインタが動いたり、意図しない動きになることが多くて、困惑することが多かったです。その都度、腕とか手がタッチパッドに接触するとそうなってしまうよと伝えましたが、なかなか改善せず最後まで大変な状況が続きました。レッスンの中身は簡単なもので、基本的なブロックの使い方は問題ないとは思いますが、レッスン途中の脱線がかなり多く、かつ、タッチパッド接触による誤動作みたいなものも加わり、かなり進みが遅い感じです。生徒の人数が多く、つきっきりにはなれない状況の中、簡単な問題を出してやってみてと言って他の生徒のとこに行っている間に、なぜか急に、女の子のキャラクターの顔と、ゾンビの顔を入れ替えると言って、キャラクターをいじってたり、それがうまくいかなくなって、結局キャラクターを全部消してしまって空っぽのスクリプトにしてしまったりと、、、つきっきりで見ていないと、あらぬ方向に勝手に突っ走っていく感じでした。結局基本操作コース０６は終わらせることができませんでした。', null, null),
  ('882a6eb5-ed50-563c-986b-da1f15cff913', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-30', '16:30:00', null, '通常 / 親子プログラミング大会', '親子プログラミング大会の説明を聞いて、早速、オリジナルのゲーム作りを始めました。飛行機になることが多いことからか、飛行機の着陸ゲームのようなものを作ると決めて、ゲームの構想を練るというよりは、作りながら考えていくという感じで進めていました。飛行機のスプライトを導入して、滑走路を複数自作して、その滑走路にどうやって飛行機を着陸させるか、それをどうやって実現させるかを必死になって考えていました。良い滑り出しだと思います。', null, null),
  ('feaa0450-d630-5fe8-ac36-9676da7f495c', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-30', '17:30:00', null, '通常 / ロブロックス', 'すでに用意されている島に対して、レインボーロードを作るという動画なのですが、まずはこの島を探検してみようという項目があったらしく、そこですごい時間をかけてしまったようで、全部終了することはできませんでした。ただ、動画の中身に関してはしっかりと理解して、わからないところもないようです。途中、いつものように、ハルくんと、じゃれあいの喧嘩（？）のようなものをしたりで、二人で言い合いをしていました。ハルくんの独り言の愚痴のようなものに対していちいち反応していて、進みが遅い時間帯もありましたが、学ぶべきことはしっかり学んでコツコツ進めていると思います、', null, null),
  ('bc47ee56-c1dc-5ee7-9b9e-ed41cf3e8c6b', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-30', '17:30:00', null, '通常 / エクセル', 'エクセルの問題に取り掛かっていて、途中何回か基礎的な内容で質問を受けましたが、特に大きくつまづくことはなく進めることができたようです。 今日は、自分のPCで取り組んでいたらしく、具体的にどの問題に取り組んだかがわからず（申し訳ありません）、こちらに記録を残しておきますが、次回どの問題まで取り組んだかを確認して進めたらと思います。', null, null),
  ('06ad1efa-f97e-5b14-ac67-1d45364c051b', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-30', null, null, '通常 / エクセル', '３０時間マスターの実習１９、実習２０を終わらせました。特に質問もなく、大きなつまづきもなく完了させられたようでよかったです。最近、Roblox studioを教室で教えてるのを見て、とても興味があるような感じでした。やれるならやりたいとも言っていました。', null, '時間帯: その他'),
  ('f05e82d9-08c0-50cf-9b17-503dfc96a878', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-05-30', null, null, '通常 / ロブロックス', '最初に、前回のロブロックスで順番を飛ばしてしまい、なかなか難しかったようで、苦手意識とか持たないように、もっとロブロックスに興味を持ってもらえるように、改めて、ロブロックスの基礎やできること、スクラッチの比較について、レッスン冒頭で説明し、理解してもらえたと思います。その後、クイズロブロックスの動画を見ながら、レッスンを始めてもらいました。自分から質問をするようなことがなかったので、時々声がけしてみましたが、問題ない、きちんと理解して進めているとの事でした。終わらせるところまでできなかったので、次回は続きからで良いと思います。', null, '時間帯: その他'),
  ('8e0fa44a-db99-5eb9-869f-363817555a9c', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-31', null, null, '通常 / 親子大会の向けてアイデアづくり', '自分の過去の作品に戻って、何か作り増やしたいものを見直しました。そこで、「ランダムに出現＆移動」にする動きに気に入りました。それだけだと散らかりそうに思ったので、クリックしてスコアが稼げるシューティングゲーム」を提案してみました。そしたら、のあくんはこの提案が面白いと感じたので、その方向性作っていきました。その後は、食べ物を増やしたり、バグ段を追加して減点対象になるように自力で作っていけました。今後の方向性として、「特定のアイテムをクリックしたらボーナスタイムに変わる」みたいなことを伝えたら、面白がってくれたので、ゲーム性を増すためによさそうです。', null, '時間帯: その他
タイピング: よくしゅうちゅうしていました'),
  ('e4cab423-17f6-58a7-9c2e-a472ef0ca52d', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-31', null, null, '通常 / ロブロックス3回目', '前回確認テストができなかったので、まずはやっていきました。2週は開いていましたが、初見全問正解できていました。その後、「クイズでロブロックス」をやっていきました。文字のコードを初めて作成するセクションでしたが、特に関数の言葉に惑わされずに、作れていました。アレンジと確認テストが時間的にできなかったので、次回お願いします', null, '時間帯: その他'),
  ('f9c12817-1862-5ea7-9605-7a068125d2ce', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-31', null, null, '通常 / ロブロックス3回目', '前回から3週空いたので、まずは頂上目指せのアレンジから操作方法をおさらいしていきました。拡大縮小と移動がこんがらがっていたので、復習してよかったです。その後、確認テストでは1発で全問正解し、次へ進みました。 クイズrobloxで動画を見続けていきました。スプライトにコードを始めて書くとところまで終わっていたので、再度確認してかあ次は進めた方がいいと思います。', null, '時間帯: その他'),
  ('5193deda-e05b-5775-bbd3-526f3e00dc17', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-31', null, null, '通常 / 親子大会に向けてアイデア作り', '親子大会に向けてまずは作りたいものについて考えていきましたが、基本操作コースで作ったジャンピングゲームが気に入ったらしかったので、それを復習でもう一度作り直していきました。好きなゲームだったので、基本の「何回繰り返して飛ぶ」の仕組みは覚えていました。そして、今回は、おばけとコウモリのスプライトをもってきて、ホラーの演出になっていきました。変えたコウモリの大きさだとジャンプがしづらくなっていたので、どこで高さを変えられるか一緒に考えながら調節していきました。そして、自分の叫び声も録音してジャンプのタイミングで鳴らしホラー感を引き立てていました。', null, '時間帯: その他
タイピング: 説明中はいったんやめて話聞こうね'),
  ('ac7abda4-5fd0-545e-8d17-68d7dc470a1a', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-31', null, null, '通常 / 親子大会', '完全に自由に作成していいとなると最初はアイデアがわかずに困っていましたが、まずはゲームジャンルだけ決めようと促すとシューティング系にしていました。そこから、爆弾が降ってくるのを戦闘機で撃ち落とすというように構想がだんだん広がっていきました。加速度変数を使って滑らかに動くのを以前やったので、ここでも活用していました。まだスクラッチの経験が浅いのもあり、ランダムに座標を決めたりやクローンを使ったりしたいが方法がよくわからないというので一緒に作っていきました。それらのスキルは、覚えながら使えたようでした。', null, '時間帯: その他'),
  ('f8caf464-fd8e-55a1-ab09-3dc2072be2a0', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-31', null, null, '通常 / 親子大会', '自由に作っていいとなるとアルスタジオに収録されたスプライトだけでは物足りないようで、キャラクターなどの素材をインターネット上で探していきました。詰まってしまった前回からは進展して、フリーのイラストや音源から気に入ったものがいくつか見つかったようでした。ゲーム内容がまだあいまいだったので大枠を考えてもらったところ、犬と猫が一緒にゲームで遊ぶことにするそうです。', null, '時間帯: その他'),
  ('47c8dfe9-84ff-5ca4-bd0c-67bfeb5ccfae', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-31', null, null, '通常 / 基本操作コース', '大玉が学校の中で転がって暴れているというストーリーを話してくれたので、その内容に落とし込みながら授業を進めました。「～秒で座標を変える」やスプライトの大きさを(大きくするだけでなく)小さくする方法を扱いました。特に座標を設定することに関しては、2つの数の組で場所を指定することをよく理解して手際よくできていました。 終盤は集中力が切れてしまったようで脱線が多かったですが、それまでは頑張れていました。', null, '時間帯: その他
タイピング: 楽しかったようで結構長い時間やっていました
盛り上がり: 自分のファイルの後ろの方を見て、「これから面白そうなゲームがたくさん作れるんだ！」というのが頑張るモチベーションになったようでした。'),
  ('56069a29-ac96-5d56-8137-2b55f54422d3', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-31', null, null, '通常 / U16', '今日からU16の作成を始めました。まずは過去の入賞作品を見てイメージをつかんでもらい、作成に入りました。アイデアは比較的すぐ出てきて、「ランダムな折れ線を描いて、それを地形として使ったゲーム」ということでした。ペンによって折れ線を描くコードでは、線の曲がり度合いが小さすぎるなどの問題に対して試行錯誤していました。結果として、完全に上下ランダムに行くのではなく同じ方向に行く確率を高めることで、想定に近い線を描くことができました。', null, '時間帯: その他
タイピング: 正確に打てていました。'),
  ('b0d272b5-b7f8-5363-ba3a-23693af22399', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-05-31', null, null, '通常 / roblox', '中間テスト終わりでとりあえず15分は遊ばせせる。これが定例化になりつつあります。教材の方へ移ると、ところどころ愚痴は多いいですが、コードの仕組み内容は理解してやってます。まあほんと愚痴が多く、動作が重いとすぐ遊びのrobloxに戻っていきます。このレッスンが残り3分の一くらいまで進みました。', null, '時間帯: その他'),
  ('d2459bfc-2987-5149-91dc-52db337be1d0', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-31', null, null, '通常 / 親子大会', '作品のアイデア出しのためにアルスタジオを見ていたところ、バイクランや過去に作った横スクロール作品をもとに、今回も横スクロールを活用したゲームを作ることに決めていました。テトリミノをスクロールさせようとしましたが、コードは現状バックパックで移しただけでうまく動いていないので、中身を理解したうえで今回のゲームに合うように変更してほしいところです。', null, '時間帯: その他'),
  ('62e66d4d-acb0-561b-bbd8-1f5fd4e259e5', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-30', '17:30:00', null, '振替 / 親子大会', 'こうしろうくんらしく創作意欲旺盛で、ゲームの方向性はすぐ決まりました。銃を撃つ主人公とオレンジを投げる恐竜で戦うゲームとのことでした。銃を撃つコードをほぼ自作できていたので良かったですが、座標の設定を忘れていたことで動作せず、一緒に直しました。', null, null),
  ('d3832287-8ffa-5e63-a5fe-55eb1dc83fc2', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-02', '16:30:00', null, '通常 / 親子大会開始', '最初ゲームに夢中で先生の話を聞いていなかったのでやる気がないかと思われましたが、優勝賞品のことを聞くとモチベーションになったようですぐに制作を始められました。作品のアイデアもすらすらと出てきて話してくれました。 ・過去に作ったゲームを組み合わせる ・ゾンビゲームと別のシューティングゲームを合わせる ・ステージが途中で切り替わる というように、具体的にイメージできていました。ステージの切り替えにはメッセージを使いました。少し混乱しながらも、「旗を押したとき」と「次のステージに行ったとき」のスプライトの表示/非表示をそれぞれ考えて設定できました。', null, null),
  ('d43a6eb1-de10-5c49-a571-0ac0b38e2e1c', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-30', '17:30:00', null, '通常 / 自由作成？', '今日はスクラッチをやりました。今年もU16があると話をしましたが、去年の入賞はマグレ(?)だと思っているらしく、もう頑張りたくはないと言っていました。その後は個人的にミニゲーム(入賞作と似た雰囲気)を作っていましたが、それを組み込んだ作品をU16に出すことを勧めても乗り気ではありませんでした。', null, null),
  ('091194b4-9459-539e-9b67-6af548e49c92', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-02', '17:30:00', null, '通常', '親子大会は(アレンジ大賞のパワーアップにするとしても)やりたくないとのことだったのでprgに取り組みました。この徒競走ゲームは結構気に入ってくれました。繰り返し0.8倍にすることで減速する速度の変数が出てきたので内容を一緒に確認しました。小数の掛け算は未習なのでよくわからなかったようですが、0.8倍すると数が少し減ることを伝えると、だから滑るようにして止まっているんだと納得してくれました。', null, null),
  ('47e30926-5493-55c3-89cf-954b4e2a03f4', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-30', '17:30:00', null, '通常 / アレンジ大賞(欠席分)', '先週お休みでアレンジ大賞の説明が書けていなかったので書きました。悩みながらも、このアレンジの特徴を具体的に説明しようと頑張っていました。書き終わった後は「5秒で止めろ」を作成しました。小数第〇位まで表示する仕組みは難しいですがなんとなく理解して、表示範囲を広げることができていました。アレンジ含めて楽しそうにやっていたので、アイデア次第で親子大会にも活用できるかもしれません。', null, null),
  ('8ecf2e13-324e-500f-9bb2-019e4fa0dbb9', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-05-30', '18:40:00', null, '通常 / 親子大会', '親子大会のアイデアを考えながら雑談していたところ、お弁当の話題になったところで、お弁当作成ゲームを思いついていました。お弁当箱やご飯、おかずの種類を選べるようにするためにコスチュームを描き始めました。円や長方形などの図形を使って手際よく絵を描いていて楽しそうでした。ただ作るだけだと味気ないのでゲーム全体の展開についても考えてもらうと、作ったものを持ってピクニックに行くというストーリーが浮かんだようです。', null, null),
  ('c2e4c7bf-e784-5f84-8b9e-ffbabb7d5ffd', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-02', '16:30:00', null, '通常 / サイコロ乱数、DKゲーム迷路', 'サイコロを通して乱数について復習をしました。ボタンを連打して遊んだりしている場面もありましたが、「ランダムの意味ってわかる？」という概念の説明にもついてきてくれた上、理解もしてくれたようでよかったです。 また今回は迷路の「矢印キーでネズミを動かす」で上むきや横むきの角度について教え、理解してもらいました。矢印キーを使って動くプログラムを作ってほしいと頼んだ際に自分から「もし〜ならとか使いますか？」と聞いてくれたのもよかったです。', null, 'タイピング: なし'),
  ('46d7659e-acb9-5520-a2e8-a04ed0f4ba98', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-02', '17:30:00', null, '通常 / 大会作品制作', '前回書いたドラゴンなどのモンスターのイラストが上手く描けなかった！とのことで、新しく描き直してもらうことになりました。描きやすいタコのモンスターになっていて、今回は絵を描き上げるのに時間をほとんど費やしました。去年まみ先生と作った時のようなシューティングゲームを先週イメージしてい他はずなのですが、聞いたところ違うらしく、来週は改めてどのようなゲームかを確認した方が良さそうです。', null, 'タイピング: なし'),
  ('b659a935-367f-571d-a5e7-96cf252078ac', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-02', '16:30:00', null, '通常 / 親子大会作品作り', '今回はクイズの出し方と正解の判定を仕組みを作っていきました。基本はアレンジ大賞の間違え探しの仕組みを利用するように作っていきました。最初から変数まわりのコードを作ろうとすると、悩んで進まなかったので、間違え探しの時どのように作ったか説明してもらいました。そしたら、どこを変えればよいか気が付いたので、進めていけました。ただ、変数名が変わると、まだ全く別のものと思っているので、名前だけ違くて機能が一緒と感じるのはまだ先です。とりあえずは1問目の仕組みは完成できたので、これを繋げていけたらいいが、、', null, null),
  ('bb507859-eacb-5934-a880-9d625a2a9bde', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-02', '17:30:00', null, '通常 / ロブロックスでコードで座標を指定しよう', '今回の単元はロブロックスをもとから遊んでいた甲斐もあり、座標系は余裕そうでした。ただ、コードが長すぎると愚痴を漏らしていたので、次回からで楽になってくると思います。', null, null),
  ('a028ee58-dbd3-59b0-802c-af111bb06e50', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-02', '17:30:00', null, '通常 / エクセル模擬演習', '本人的には前回より難しく感じたそうですが、1ミスで40分程度でおわり、完璧でした。もう受けても問題なさそうです。', null, null),
  ('96843e88-2d44-5ab3-b696-298fd3ce0486', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-02', '17:30:00', null, '振替 / エクセル模擬演習', '最初に練習問題を今までやってきて、不安なところはないか聞いたところ、大丈夫と答えたので、模擬問題やっていきました。でも途中で、if文の式に立て方がすっぽ抜けていたり、数式が若干間違っていたりと時間がかかっていました。1時間で3問目までだったので、次回続きをお願いします。', null, null),
  ('eac9c93d-518a-55e7-bdc1-a80e00ca33c0', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-02', '17:30:00', null, '通常 / 大会作品制作', '"特急あずさを作ることになってからかなり意欲的な様子で、アイコンタクトをとって絵を見せてくれたり思ったことを少しだけ教えてくれたりしました。 電車に関してはほとんど資料も見ずに完璧に見た目を再現していて、細部までこだわれていてとてもよかったです。背景の制作にも入りましたが一人では難しかったようなので、一緒に検索しながら八王子駅に何があるのかを考えたり、下迫田先生からアドバイスをいただいたりもしました。"', null, 'タイピング: なし'),
  ('198275f3-a79f-5015-b770-8794192c7f02', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-03', '17:30:00', null, '通常 / スキルの積み上げ', 'まず、前回のシーティングの続きをやりました。幽霊の効果など初めて見たというものを解説しながら進めました。また、クローンにメッセージを送りたいときは変数で代替しないといけないことも押さえました。テストプレイした時にゲームオーバーにならないというバグを見つけたときは、その原因の場所を推測してから修正することができました。 後半は、リストを使ったランダムな配置を学ぶためおばけのかくれんぼに取り組みました。中学生なので、座標を均等に配置するための計算も一緒にやってみました。本題のリストについては、使ったことはあるようでしたが要素の追加を手作業でやったことしかないようなので「～を追加する」「リストの要素をすべて削除する」ブロックを用いた設定をやりました。[x座標を[リストの[乱数]番目]にする]という重要ポイントについては、入れ子状になっているため最初は混乱しましたが、最後は納得して使うことができました。 U16の製作のアイデアが思いついたら、スキル習得と同時並行で作っていいことを伝えました。', null, '盛り上がり: switch2が当選して嬉しかったそうです'),
  ('344f2f39-5717-5c15-971f-cd95ab1d0767', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-03', '16:30:00', null, '通常 / 親子大会作品の作成', 'クレーンの動作、クレーンゲームの機械の枠組み(デザイン)を作っていた。 手書きでデザインしている場面があったので直線や四角のツールを教えました。 クレーンの動作の改善点を自分で考えてコードを作り直していてよかったです⭕️ 集中して取り組んでいる場面がいつもより多かったです。 景品が確実に取れるコードになっているので当たり判定を別のスプリクトで作ったり、確率でとれるようにするとよりゲーム性が出るので声をかけてみようと思います。（榊原） クレーンでクリオネをキャッチする前と後で動きを変えたいと考えていたので、変数をフラグとして使ったらどうかと助言しました。この一言だけで、「最初は0にしておいて、キャッチしたら1にして、もし変数が1ならというコードを作ればいいんだよね？」とスラスラと話し出して、すぐに手を動かしていました。このあたりの回転は速かったです。 既存のクレーンゲームをうつそうとせずに、自分で動きを考えて作成しようと頑張っていました。（大原）', null, '盛り上がり: やりたい動きが少しずつ完成していくたびに、満足そうにしていました。今日は席がそうすけくんとはす向かいだったせいか、先生を通して少し会話したりする様子も見られました。'),
  ('ce5786a0-dafe-5c22-9cc3-1c857cf93fd9', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-03', '16:30:00', null, '通常 / 親子大会', '過去作のアレンジを進めていきました。現在フェーズを13まで増やしていて、それを全部「～でなければ」の入れ子にしているのでそのことについて話しました。(すでに作ったものはいいけど)今後似たことをやるなら「～でなければ」は不要であることを確認しました。その後は、スプライトの見た目だけでなく中身も追加できました。ずっと上から攻撃が降っていたところ、新しいフェーズとして別のビームが横から飛んでくるようにしていました。', null, null),
  ('0e407018-244d-5f4f-b6ff-75488344e5da', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-03', '17:30:00', null, '通常 / 親子大会作品の作成', '最近は勉強ばかりさせられて、ゲームも全然やっていないし何か好きなこともない、ということで、題材を考えるのがだるそうでした。勉強もどの単元が楽しい、というのが特にないそうで、親子大会の商品にも反応はイマイチでした。 口ではぼやきつつ、ずっとコスチュームをいじっていたので、コスチュームのデザインがきれいにできていることを褒め、好きなデザインを作ってそこから想像をふくらませていってもよいから、と伝えると、先生達との会話に載ってきて少しずつ楽しそうになってきました。 みうちゃんが、せっかく作ったキャラクターを使ってシューティングゲームを作らないかと提案してくれましたが、どうせうまく作れないから、という反応でした。 今日は好きなことをさせながら、作成へのモチベーションを高めていくことがメインとなりました。', 'デザインへのモチベーションをうまくコードに移行できるよう促していきたいところです。', '盛り上がり: 何をしたらよいのか自分でもわからない、といった感じだったので、好きなようにデザインをさせてそこを褒めていたら、だんだん口数も多くなって、後半は楽しそうに手は動かしていました。'),
  ('20c990e6-a85f-5cd8-981c-f8d7dd483243', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-03', '16:30:00', null, '通常 / 基本の定着', '前回やった矢印キーでの移動や「～に触れたなら」は今回も使うので軽く復習しました。復習した部分が登場した時はできれば自分で考えてもらいたかったですが、すぐに動画を見て答え合わせしたがっていました。新しいブロックとしては「端に着いたら跳ね返る」を習得しました。 余った時間で基本操作コースで未完だった部分の穴埋めをしました。スタンプを押すことを楽しみながら進め、03が全て埋まりました。', null, null),
  ('29eff747-7819-52a7-b9b8-f635919a9d31', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-05', '16:30:00', null, '通常 / 大会作品制作', '横にいた凛久くんの作品を見たり、朔太郎くんに遊んでもらいながら完成を進めていました。ドラゴン①についてのプログラミングで、「炎の攻撃を受けた時だけ点数3にしたい」とのことでしたが、上手くいかなかったようです。連なっているコードを分けてもダメだったようです。次回先生方に解決策を確認する必要がありそうです。', null, null),
  ('4871c050-66d3-51cd-aea3-89bb5d8b3203', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-05', '16:30:00', null, '通常 / シューティングゲーム宇宙バトル', '動画を見ながら取り組んでいました。今日はスクラッチのスマブラがやりたかったそうで、あまり集中力はなかったです。えみちゃんのゲームで遊んだり他の子の様子を見に行っていました。でも動画の手順は全てこなせたのでよかったです。 X・Y座標がどの向きの働きかを少しずつ理解していっている様子もあり、スキルアップできていました。', null, null),
  ('1d191dce-5ea5-5c0c-b6e5-3c7f2cdf7978', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-05', '17:30:00', null, '通常 / 大会作品制作', 'テニスの習い事のため遅れて参加しました。 前回作成途中だった着せ替え用イラストの続きを描いていて、洋服と髪型まで描き上げてくれました。まだズボンの作成が残っているようですが、あとはプログラミングでの作業だそうです。', null, null),
  ('84ab9bf9-acce-59de-b780-e125ff4dcf40', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-05', '17:30:00', null, '通常 / 大会作品制作', '隣の大遥くんと歴史について語り合いながら制作を楽しく進めていました。 ビンゴおじさんのスクラッチ教室より スクラッチでタワーディフェンスゲーム（城を守るゲーム） https://bingo-ojisan.xyz/2025/03/20/towerdefense/ 上記ゲームを参考に日本の城でタワーディフェンスゲームを作るようです。', null, null),
  ('e3312e70-5302-56a0-a5f2-fa0d06e79663', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-05', '17:30:00', null, '通常 / 隣の楓太くんと楽しそうに語り合っていました。戦国のシュミレーションゲームを作るようです。期限がまだ先なので、イメージを膨らませながら納得できる作品が作れると良さそうです。', null, null, null),
  ('84864ffd-0a59-5a99-a9dd-3f570d0e37a0', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-06-07', null, null, '通常 / アレンジ大賞の投票', 'アレンジ大賞の受賞作品を評価しました。各ゲームの説明を読むことなくプレイし始めて操作方法がわからずにキーを適当にカチャカチャするというのが見られたので、まず操作説明を一緒に見て、それから遊ぶという形にするとある程度楽しんでいたように見えました。 基本コンセプトが同じゲームが多かったので途中からは飽きてしまっていましたが、自分なりの評価基準で好きなゲームを決めることができていました。スクラッチは始めたばかりのようなので、まだ動作原理などに興味を持つ段階まではいっていないようです。 評価が終わった後に基本操作コースに行きたかったですが、集中力が切れてゲームを始めてしまっていてうまく導入にもっていけませんでした。 途中雑談した際には、Switch2を手に入れたことを嬉しそうに話してくれました。先日は一日中マリオカートをやっていたそうです。', null, '時間帯: その他
タイピング: ホームポジション列の練習をしていました。手元を見ずにやろうとしていて間違う場面が見受けられました。'),
  ('d6554950-1c49-5917-bb80-1db3b77aa25b', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-07', '16:30:00', null, '通常 / イラストコース_目の描き方', '平行四辺形を描くのに定規のツールを使いこなせていました。アイラインの弧を描くのに苦戦していたので手ブレ補正について教えてあげました。線が綺麗になったことに驚いていました。また、レイヤーをあまり分けないで描きがちなので、色を変更する時に大変なのでfレイヤーは必ず分けるよう伝えました。', null, null),
  ('f872cbb5-6723-5911-bf81-97827adb48d3', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-07', null, null, '通常 / イラストコース_髪の描き方', '素材配布にエアドロップの方法を伝えました。真剣に取り組むことが出来ていてよかったです。帰り際の雑談で絵しりとりをするゲームの話をすると、知ってる！とパッと顔が明るくなったので、いつか企画してみてもいいかもしれないと思いました。', null, '時間帯: その他'),
  ('8966cc21-df04-558b-9305-7e3d6d0ebe47', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-06-07', null, null, '通常 / アレンジ大賞の投票', 'アレンジ大賞入賞作品の評価。いつも通りだと思うのですが、楽しさ等を表に出さず黙々と遊んでマルを３つつけていたように思います。その後、親子大会用の作品を促して、オリジナル作品を作ってみるとのことで、作品作りに取り掛かりました。以前、全然作品構想が浮かばないようだったので、一緒に方向性を決めていきました。最終的には、以前プラットフォーマーゲームの作りかけ（？）のようなものがあったので、それをベースにオリジナルゲーム作成を始めました。隔週であまり時間がないので、来週には具体的にどのようなものを作るかのゴールがイメージできると良いのですが。。。', null, '時間帯: その他'),
  ('1aff2015-eac3-54ee-9d95-fe749b996dc4', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-07', null, null, '通常 / イラストコース_髪の描き方', 'いつも通り集中して取り組んでくれていて、ショートカットの男の子の難しい髪型でしたが、綺麗に再現できていてよかったです。授業前に見せてくれたアニメキャラの模写もとても上手でした。', null, '時間帯: その他'),
  ('e64fe151-1318-59cc-b1a6-41d563c8c23c', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-07', '17:30:00', null, '通常 / イラストコース_模写', '前回は教材（しんもと流漫画キャラの描き方）内から好きなポーズを選んで模写をしてもらったのでその続きと、身体は模写で顔は自分でアレンジしてキャラを描いてもらうようにしました。以前描いていたduoリンゴのキャラがお気に入りのようでまた描いていました。', null, null),
  ('9cfbe9b7-f269-55bc-8b57-7f877789a650', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-06-07', null, null, '通常 / アレンジ大賞の投票', 'アレンジ大賞の評価ですが、各ゲームをしっかりと遊んで評価していたようです。それだけに、時間がかかってしまい、レッスン時間全てをアレンジ大賞評価に費やしてしましました。ですが、本人もいろんな子供たちの作品に触れて、いろいろと触発されたようです。今後のオリジナル作りに良い影響になったと思います。', '親子大会の作品作り', '時間帯: その他'),
  ('fd63bca5-00e4-5d0b-a0bc-56cc33336798', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-07', null, null, '通常 / イラストコース_等身ごとの描き方', '前回の2Dイラストの制作の続きをしてもらいました。雑談を聞いていてもやはり学校生活が忙しそうです。この作品を終わった後は特にやりたいことが無いとのことで、教材を順番にやるというよりは教室内の教材を参考に、元々やりたかったキャラデザや3D制作など、ipadやノートPCのスペックで出来る範囲で制作する時間に充ててもらうことを提案しました。', null, '時間帯: その他'),
  ('cdb91b36-4c8f-5b58-a672-450874943f6d', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-06-07', null, null, '通常 / エクセル', '7章、データベース入門を黙々と進めて、例題２０、練習４９、練習５０まで終わらせました。途中、「オートフィル」というのがまだ習っていないということで教えましたが、おそらく、7章の前で習うものなのだと思います。それ以外には特に質問もなく進めていました。', 'エクセルの続きで良いと思います', '時間帯: その他'),
  ('df35585d-72a9-5826-babc-9ac64d5d8a8c', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-07', null, null, '通常 / アレンジ大賞投票、親子大会作成', 'まずはアレンジ大賞の投票をしてもらいました。「同じようなゲームが多くてよくわからない」と言っていましたが、「元のゲームが同じだから似ちゃうけど、違いを見つけられると良いね」と伝えると自分なりの基準で投票先を決められました。その後は、親子大会として出す予定のジャンピングゲームのアレンジを進めました。ジャンプから普通に落ちるとすぐ障害物にぶつかるので、しばらく滞空するようにしたいとのことでした。1秒待つことは気づけましたが、どこで待つかを何回か間違えてバグっていました。ジャンプ動作の時系列を一緒に確認しながら、上がってから降りるまでに待てばいいことを理解してもらいました。', null, '時間帯: その他'),
  ('d94aa829-3dd8-51cb-880a-1be1a1cceb50', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-07', null, null, '通常 / 親子大会作成', 'アレンジ大賞の投票をする日でしたが、親子大会の作成に夢中だったのでそのまま進めてもらいました。引き続き素材を取ってきたり、自分で簡単なイラストを描いたりしていました。しかし途中でいきなり今作っている作品はやめたいと良い、違うものを作り始めてしまいました。なぜやめてしまったかあまり聞き出せなかったのですが、新しい方向性をなんとなく考えてきてもらうように伝えました。', null, '時間帯: その他'),
  ('1bbedab1-5be3-537f-8805-356fa5d66aac', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-06-07', null, null, '通常 / アレンジ大賞投票・U16作品作り', 'アレンジ大賞', null, '時間帯: その他
タイピング: 集中して取り組んでいました
盛り上がり: アレンジ大賞の投票は、他の子の作品を興味深く観察しながら評価していました。投票が終わってからは、U16のオリジナル作品作りを始めました。その作品では、上空を飛んでいる視点で、森が上から下にスクロールしているのですが、それを３Dっぽく表現したいとのことで、アドバイスをしましたが、今日はお迎えが早くきて作成途中で終了となりました。次回はその続きからです。'),
  ('ff336182-5ced-5c35-adc9-63705f7f3993', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-07', null, null, '通常 / 大会投票', 'まずはアレンジ大賞の投票をしました。終わった後はずっと他のゲームで遊んでいましたが、授業終わり近くで親子大会制作のスイッチが入ったようで、お迎えが来るまでやっていました。「回転方法を左右のみにする」の記憶があいまいだったので少し復習しつつ、上下への移動を作ることができました。', null, '時間帯: その他'),
  ('47f9ccd3-4e63-548c-8920-3c1e66cbbc6c', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-07', null, null, '通常 / 大賞投票', 'アレンジ大賞の投票をしました。お気に入りのゲームが見つかったようで、自分の投票先にはすんなり納得して提出できました。親子大会の作成を続けてほしかったですが、今日はあまり乗り気ではなかったようで、こうしろうくんと遊んでいました。', null, '時間帯: その他
タイピング: 集中していました'),
  ('14f3716d-84db-5e53-b7c0-ab5ab57fc872', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-07', null, null, '通常 / 大賞投票', '入賞をお祝いすると喜んでくれました。アレンジ大賞の投票をしました。自分自身のゲームに票を入れつつ、やすのりくんにも隠しBGMなどのアピールポイントを伝えていました。投票を済ませたあと、親子大会の続きをやろうと伝えましたが今日はそういう気分ではないそうでした。', null, '時間帯: その他'),
  ('9d7c6c85-d1de-5d41-9ebf-0cc3a6e9afc5', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-06-07', null, null, '通常 / アレンジ大賞投票', 'いつものようにロブロックスに夢中になっており、時間を決めて、アレンジ大賞作品の評価をするよう約束。決めた時間を５分ほどオーバーして、アレンジ大賞作品の評価を開始しました。今日は、その評価で残り時間がほぼ終わリマした。デジタネをもっと早く進めて欲しいものです。', null, '時間帯: その他'),
  ('919566b0-2524-567a-aba5-de2b012a3395', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-07', null, null, '通常 / 大賞投票', 'アレンジ大賞の投票をしました。カオスシューティングが特に気に入っていました。ただそのうちダレてきてしまったので、しっかり全部のゲームをチェックして投票までし終えることを促したところ、再び集中して審査に取り組めました。', null, '時間帯: その他'),
  ('6254cd07-760e-5463-b19c-5711605c0a94', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-06-07', null, null, '通常 / アレンジ大賞の投票', 'アレンジ大賞の入賞作品を一つ一つ丁寧に遊んでしっかりと評価していました。時に、辛辣な評価を浴びせ、時にすっごい面白いと声を上げたりと、楽しそうにゲームをプレイしていました。特にりゅうとくんのゲームをすごい気に入って遊び続けていました。なかなか、評価が終わらず、結局アレンジ大賞の評価だけで今日のレッスンは終わってしまいました。次回からは、親子大会作品に本腰を入れたいです。', null, '時間帯: その他'),
  ('2cdb7d48-5170-5e36-94cf-0baada6cc096', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-09', '16:30:00', null, '通常 / アレンジ大賞評価', 'アレンジ大賞の入賞作品を遊んで評価していきました．３つのゲームジャンルの中でも，中級のシューティングゲームが特に気に入ったようで，長い時間遊んでいました．今までに見たことのないアイデアやゲーム内容に驚きつつも楽しんで遊んでいました．評価後は現在作成しているクイズゲームに着手していきました．クイズを２０問ほど作成し，ランダムで表示されるようにしていく予定です．', null, null),
  ('36350b89-70ab-5ca2-b22c-a42396fe8aac', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-05', '16:30:00', null, '通常 / 親子大会の作品作成', '親子大会の説明は聞いていましたが、自分で新しい作品を作る、ということがまったくイメージがわかないようでした。 大会までずっと作成を続けるのも飽きてきそうなので、とりあえず自分の過去の作品でもっとふくらませてみたいものがないか探してみようと持ち掛けました。 いくつか気に入った作品はあるようで、何度も見返して、少しコードも振り返っていました。', null, '盛り上がり: 自走させるのはかなり難しいですが、こちらが向き合おうとすると、素直に話を聞いて、何かをしようと手を動かせるようにはなってきました。'),
  ('2d11e53d-dd8a-57ee-867d-886a768ff3ac', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-09', '16:30:00', null, '通常 / アレンジ大賞評価＆チーズ探せ', '最初はアレンジ大賞の評価をしていきました。特にカオスシューティングがお気に入りで、カスタムが進んでだいぶ有利に進んでいきました。 後半は、前回の続きをチーズを探せを続きをやっていきました。自由に左右に動けるようになったので、めいろで区切られるようにするとき、仕組みは一緒に考えていきましたが、そのコードを入れる位置は自分で導けてバグが起こりにくいなるようなれました。この後に、チーズのコードを作りましたが、自作で「どこか行く」のコードを使ってチーズを取れない良いバグを発見できたので、次週さいころの仕組みを復習してから座標を乱数で指定する仕組み＋「まで待つ」を教えてください', null, null),
  ('2f37a2af-4593-5bec-80c4-885c05a95972', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-09', '17:30:00', null, '通常 / アレンジ大賞評価', 'アレンジ大賞入賞作品の評価を行っていきました．自分で作った作品が入賞していたこともあり，どれくらい票が入っているのか気にしている様子でした．それ以外の作品では，自分が作ったものよりも完成度の高いものがあったため，そのゲームを楽しみつつ取り入れられる内容を探していました．評価後は作成を続けている電車のデザインに取り組んでいきました．今回で車両の基礎部分については完成したため，次回塗装部分に入っていく予定です．', null, null),
  ('a4f470e8-12f1-5491-aae8-94bd5eb51bb3', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-05', '16:30:00', null, '通常 / 親子大会の作品作成', 'はじめはいつも通り、人のPCをのぞいたり、適当なゲームをしたりと落ち着きがなく、作成していた野球ゲームも、これ以上何をしたらいいのかわからないから、もう完成でもいいや、といった感じでしたが、野球に詳しいこたろうくんに敢えて、ピッチャーの球種について質問したところ、食いついてきました。そこで、投げる球を選べるようなゲームにしようと提案すると、熱心に画面上にボタンを作成し始めました。 今日はデザイン面で終わってしまいましたが、珍しく作成する気にはなっていました。', '球種をいくつか作成しながら、座標や大きさを変える動きの確認をしていく予定です。', '盛り上がり: 頑張っている野球に関して、こちらが聴く姿勢を見せると、熱心に解説してくれて作成意欲にもつながるようでした。'),
  ('5f04b07a-2646-560d-9b0f-06c13fbf850f', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-09', '17:30:00', null, '通常 / アレンジ大賞評価', '今回はExcelの模擬問題ではなく，アレンジ大賞の作品評価を行っていきました．久しぶりにアルスタジオに触れたため，作品の評価に対しても熱が入っている様子でした．上級生の評価についても，頼りにしていると言ったところより集中して取り組んでいました．評価後はExcelの問題集から短い箇所を取り組んでいきました．COUNTについての問題でしたが，つまづくことなく最後までやり遂げることができていました．', null, null),
  ('185a52d8-4d16-503f-bd3c-c10931e68387', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-09', '17:30:00', null, '通常 / ロブロックス＆アレンジ大賞評価', '座標と変数を関係を文字コードでも楽々わかっていたので、まだ順調そうです。 robloxを授業時間前に終わらせたので、アレンジ大賞の評価の方をしてくれました。そうたくんてきには複雑な操作があるゲームの方が楽しく遊んで評価ができていました。', null, null),
  ('287ede79-dee9-5f80-9f75-7de91b44048e', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-09', '16:30:00', null, '通常 / アレンジ大賞投票、大会作品制作続き', '投票にあたりゲームを楽しそうにプレイしていました。しばらくゲーム遊びに夢中になっていたため、制作に意識を切り替えるのが難しそうでした。まみ先生から投票でお気に入りのゲームを選んでアレンジをしようという提案を受け、練習としてコスチュームを変更していました。', null, null),
  ('0e274ffd-4127-549d-b49d-b4b95ad01aff', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-09', '17:30:00', null, '通常 / アレンジ大賞投票、大会作品制作', '投票中は楽しそうにゲームをして、大会作品は少し触ったとのことです。ずっとゲームと雑談をしていて、作るよう促しても作ろうとしないといった様子でした。隣にいた光梨ちゃんと楽しそうに過ごせていたのでそこはよかったです。', null, null),
  ('d405a895-3405-556f-98a1-9e3101b72219', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-05', '16:30:00', null, '通常 / 親子大会の作品作成', '親子大会へのやる気はさすがで、熱心に作成を進めていました。 クラスの雰囲気にもだいぶ慣れてきたようで、虎太朗くんと野球の話をしたりもしていました。 自宅での作業が多いこと、授業自体は隔週であることから、質問があるときに先生が見られるように、アルスタジオでの作成をお願いし、自宅でのログイン方法を連絡しました。', null, '盛り上がり: とにかく細胞への興味と愛？があって、作成しながら熱心に、その面白さを語ってくれました。'),
  ('8ed33cf4-9905-5059-9f06-cc227cc45fba', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-09', '17:30:00', null, '通常 / アレンジ大賞投票、大会用作品制作', 'アレンジ大賞投票用のゲームが少し複雑で難しかったようで、頭を抱えてプレイしていました。残りの時間ではゲーム用の靴やアクセサリーを追加で描いていました。レイヤーがたくさん増えたため管理が大変とのことです。', null, null),
  ('0335b7b3-4c96-56ae-b8b8-c00c2af2ac90', '53dc382f-637d-5a46-9b57-4204c79ee130', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-06', '17:30:00', null, '通常 / アレンジ大賞投票', 'アレンジ大賞の投票をしました。カフェオーダーゲームをはじめとして楽しみながら票を入れていきました。それが終わった後は自分の作品を作ることを勧めましたが、やらないと言っていました。作りたいものやモチベーションはあまりないようでした。', null, 'タイピング: 集中していました。'),
  ('0ed8df9a-aca0-583b-8c11-10ac1323a308', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-06', '16:30:00', null, '通常 / 投票、親子大会', 'アレンジ大賞の投票はさくっと終わらせ、賞金を取りたいと親子大会へのモチベーションが続いているのでそちらに取り組みました。場面ごとのスプライトの表示/非表示は先週から作っていますが、まだバグがあったので直していきました。コードの重複や不要なものがたくさんあったことでバグが起こりやすくなっていたため、まずは整理してもらいました。すると間違っていた場所が明確になり直すことができました。これからは3つ目の場面としてジャンプゲームを取り入れる予定だそうです。', null, null),
  ('8ac91ee8-c2cd-56fc-a65c-3a628d7bc1ad', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-06', '17:30:00', null, '通常 / 投票、ロブロックス', '今日はアレンジ大賞の投票をしました。けいとくんはゆづきくんの制作でアイデア出しを手伝っていたので、ゆづきくんのゲームは一番最後のお楽しみとして取っておき、楽しんでいました。終わった後ロブロックスをやりました。ただ前半のテンションを引きずってか、動画内で「これを遊んで確かめてみよう」という指示があったときにずっと遊んでいました。', null, null),
  ('4559827f-7993-5b5a-b61f-b88988293f04', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-06', '17:30:00', null, '通常 / 投票', 'アレンジ大賞の投票をしました。真剣に審査に取り組んでいて、どれも面白いから絞るのが難しいと悩んでいました。結果として目の前にいたゆづきくんに入れた票を外して笑いが起こっていましたが、きちんと自分の基準で考えて投票できました。', null, null),
  ('80a69faf-cece-5368-9923-49768b4d457c', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-06', '18:40:00', null, '通常', 'りょうやくんの入賞作は前の時間の子に人気で、「この人がりょうやくん？」と声を掛けられると若干照れたような様子でした。りくくんの作品に使われていた世界記録の仕組みに興味を持ったので、投票が終わるとクラウド変数のレッスンに取り組みました。内容はあまり難しくなかったようで、今後ゲームを作る時は登場させたいと言っていました。', null, null),
  ('de200279-90f8-5cac-8476-81bef49abd18', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-06', '18:40:00', null, '通常 / 投票、親子大会作成', 'まずはアレンジ大賞の投票をしました。同じテーブルになったりょうやくんとは今まであまり絡みがなかったですが、仲良く話しながら投票を進めていました。その後は製作に移りましたが、親子大会に出す予定のお弁当ゲームは少し行き詰まったようで、一旦新キャラクターのデザインをしていました。そのキャラはみんなに使ってほしいと公開していました。お弁当ゲームにそのキャラを出すことを勧めました。', null, null),
  ('16f05df3-11f2-519c-b28a-06ee68b3ae3e', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-10', '16:30:00', null, '通常 / 投票、親子大会作成', '投票の時、あまりにも早い時間で提出しようとしたのでもう少しじっくり考えて選ぶことを促しました。 それが終わると最近作っているビームをよけるゲームの作成を進めていました。大方は出来上がっていたようで、細かい座標や見た目の調整をしました。これで完成とのことで公開までしていました。創作意欲が出たのは良かったですが、ここで終えずに作りこめば親子大会に出せそうなので、アイデアなど話し合いたいところです。', null, null),
  ('6e90c7f2-7f16-50f6-94ce-0ad9cca45eb2', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-10', '16:30:00', null, '通常 / 投票、基本操作コース', '上級のゲームはクリアするのも難しいと言いながら遊んでいき、ちょうどいい難易度のゲームを選んで投票していました。それが終わると基本操作コースに移りました。ファイルにスタンプを押すのは楽しいようですが、興味を示さない項目が多かったです。恐竜がビームを撃つゲームを作りたいと話してくれたので、それに合わせて「～秒で座標を～にする」や途中での背景切り替えを選んで取り組みました。一度やったことの繰り返しでもすぐに「わからない」と言いがちなので、「さっきやったことを思い出してみて」と声をかけながら進めました。', null, null),
  ('154de193-bc75-58e8-8c1d-530bb6e896ff', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-10', '17:30:00', null, '通常 / 投票、親子大会作成', 'アレンジ大賞の投票をしたあとは、親子大会の製作を続けました。前回は絵文字を使ったゲームにすると決めましたがそこから展開が見えず、最近興味を持っているという難読漢字のクイズで作ることにしました。漢字を調べながら1-2問出題するところまで作れました。タイピングで解答できるようにすることを提案しましたが、難しそうと言って、今のところはセリフだけで問題を完結させたいようです。', null, null),
  ('ab7a7ab4-1765-5521-9f73-55b40e548214', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-10', '17:30:00', null, '通常 / 投票、スキル習得', 'まずはアレンジ大賞の投票をしました。比較的素早く投票先を決めていました。 休憩時間にスクラッチのクリッカーゲームで遊んでいて好きらしかったので、レッスン後半は簡単なクリッカーゲームを作りながら以下のスキルを扱いました。 ・長押し防止(ではないまで待つ) ・3種類の「止める」ブロックの使い分け(意外と認識があいまいだった) ・世界記録(クラウド変数)', null, null),
  ('867dc78a-faa2-5917-bd83-2adab2e4e70a', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-06', '17:30:00', null, '通常 / 投票', 'アレンジ大賞の投票をしました。特別賞が欲しい気持ちでまずは自分自身に入れていました。他の人に自分のゲームの説明などもしていました。他のゲームについては、純粋に楽しみながら投票していきました。', null, null),
  ('c9f599b0-2ca6-5509-b77b-f77c2e0e6e38', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-05', '17:30:00', null, '通常 / 親子大会の作品作成', '親子大会に出す気はない、とは言っていますが、それでも一生懸命に作っていました。', null, '盛り上がり: アレンジ大賞の結果が楽しみ半分、緊張半分、といった感じで、期待してないと言いつつ楽しみにしているようでした。'),
  ('23031784-0770-56a1-8eba-e25127730b86', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-12', '16:30:00', null, '通常 / アレンジ大賞評価', '入賞作品を遊びながら投票をしていきました．自身の作品を制作していた際にはあまり楽しくなさそうでしたが，今回の評価ではさまざまなアイデアの作品があり，楽しみながら投票を行えていました．', null, null),
  ('3bd863ed-30d1-500f-a7da-634609edac03', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-12', '17:30:00', null, '通常 / アレンジ大賞評価', 'アレンジ大賞の評価を行っていきました．今回が初めてのアレンジ大賞評価ということで，今までに見たことのないアレンジやデザインに驚きつつも，しっかりと評価を行っていました．評価後は9月に提出する大会用の作品を作っていきました．作りたいものははっきりとしているようなので，時間をかけてゆっくり作っていきたいです．', null, null),
  ('2eadf291-48c5-5d98-b358-0ca822a779d5', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-05', '17:30:00', null, '通常 / U16大会のオリジナル作品作成', 'そうたくんと歴史談義をしながら、楽しそうに作成していました。', null, '盛り上がり: とにかく歴史の話ができることが嬉しそうで、ひっきりなしにしゃべりながら作成していました。'),
  ('6651d411-e1ba-553d-b292-1c3b6e7059c8', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-12', '16:30:00', null, '通常 / アレンジ大賞採点＆レベルアップ変数などなど', '最初は、アレンジ大賞の採点でしたが、さくたろうにとっては難しく感じるものが多く、キーボードやマウスのガチャガチャするのがひどくなってきたのので、打ち切らせました。そこで前回の宇宙バトルの続きをやっていきました。基本操作コースの04にのっとてスコアをつけるところが復習していきました。前回、つくっ際にどのブロックを使ったのか色程度の識別で理解していたので、ある程度は身についていると感じました。スコアもつけ、クリア演出も生成を一緒に作り上げ、その作業中は何度かルイ君のパソコンをそ族ことはあったが、宇宙バトルやる前よりかは集中力がありました。そして、自分でバグなく完成を見届けることができたので、よかったです。 今回の様子を見るに、1つ具体的にやることを決めておかないと、集中力が散漫してしまう気がしまう、PCの勝手な操作が起こしてしまうことが発生するので、初めにやることをすぐ伝える方がやりやすいと感じました。', null, 'タイピング: アレンジ大賞の祭典に集中できなくなったので、切り替えて進めました。'),
  ('3861c6a4-0dae-5ccc-8031-8ac113630ef4', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-05', '17:30:00', null, '通常 / 親子大会作品の作成', '親子大会自体にはまだピンと来ていないような感じですが、最近学習したシューティングゲームをもう少し作り込んでみたいということで、自主的に縦スクロールの作品を作り始めていました。 2回連続でスクロールの学習をしたせいか、縦スクロールへの置き換えも自力でやろうとしていましたが、座標の指定が一か所だけ違っていて、うまくスクロールしないと悩んでいたので、晴君が書いたコードを言語化してもらったところ、自分でおかしいところに気付いて直すことができました。 使用した背景にグラデーションがかかっていたので、クローンの切れ目がはっきりわかってしまうところは、うまく画像を上下反転して解決し、満足そうでした。', null, '盛り上がり: 自作のゲームを作るのが楽しそうでした。'),
  ('4316ff03-26f1-5379-837b-5d7cd531f6a7', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-12', '17:30:00', null, '通常 / アレンジ大賞評価', '大会作品入賞者への投票を行なっていきました．作品を遊びながら，バグの発見やより効率的な動きの模索などデバッグ作業を行うように評価を行っていました．それでいて楽しみながら行えていたようでとても満足していました．その後はオリジナル作品の制作に取り組んでいました．現時点では親子大会に出すことは考えていないようですが，今後の進み方次第では考えていくようです．', null, null),
  ('fbcfdac2-aa2d-5235-aec4-f93d16fd5f45', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-12', '17:30:00', null, '通常 / アレンジ大賞の採点、親子大会作品の作成', '入賞したということで、嬉しそうに教室にやってきました。 自分の投票してよいのか、しばらく謙虚に悩んでいましたが、最終的に、こちらに確認をとりながら〇をしていました。 承太郎くんのゲームを一緒にプレイしたりと、だいぶクラスにもなじんできたようで、よくしゃべる様子も見られました。 オリジナル作品では、自分でやりたいことがあるようで、特に質問もなく、ずっと作成を進めていました。', null, '盛り上がり: 話せる友達や先生が増えてきたようで、楽しそうにしゃべりながらも作成の手は止めずにがんばっていました。'),
  ('cb94008a-984f-55e4-8d88-f3924a72f4a6', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-12', '17:30:00', null, '通常 / アレンジ大賞の採点', '中学生なので、コードもしっかり見て採点してくれました。それぞれに細かいところまで捜査をして堪能してくれたので、3つの選定にはかなり頭を悩ませていました。 そのあとに、オリジナル作品の作成でしたが、本人が自供するほど、あまり進んでいませんした。まあ、しっかりと作品を見てくれたので、提出まである時間あるし、こんな日もあってもいいと思いました。', null, '盛り上がり: 周りが昔のコナンやハリーポッターの話をするなかで、若干ついていけてない感じがしました。（笑）'),
  ('f29cfaa2-c6af-5cb7-8340-2103dae7afe9', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-12', '16:30:00', null, '通常 / アレンジ大賞投票・大会作品制作', '今日はやる気がかなりあり、授業前に投票を終えていました。制作では漢字を倒すゲームを作ろうと思っていたらしく、気に入っていたイチゴの反乱のコードを使ってまずはスプライトからアレンジを試みていました。ただ、ネットから適当に拾ってきた画像だったので講師の方で簡単な素材提供と、自分で描けることが一番望ましいことを伝えました。 一旦画像の方は取り込みとコードの差し替えができたようなので、ゲーム内に出てくる春夏秋冬の他の季節を使って何がアレンジ出来そうか、来週までに考えられたらいいねと伝えました。', null, 'タイピング: なし'),
  ('c7e3af59-bfe2-5fe5-92ec-b5ab0378fb36', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-06', '16:30:00', null, '通常 / アレンジ大賞の採点、親子大会作品の作成', '採点は、要くんとおしゃべりしながら盛り上がっていました。 そのせいか、いつもよりお遊びモードで集中しない様子も見られましたが、後半は作成の気分に戻れたようで、飛行機の体験談を話しながら着陸シミュレーション？を作成していました。 途中で着陸回数がうまく増えないことに悩んでいましたが、触れた判定をする対象の間違いに気づき、直すことができました。', null, '盛り上がり: 今日はわりとテンションが高めで、よくしゃべりながら作成していました。'),
  ('5099f212-7bc7-5f6f-9487-0a6a4103aaf5', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-06', '17:30:00', null, '通常 / アレンジ大賞の採点', '来室時は「何もしたくない」と言って、ロブロックスもScratchも気分じゃないとぼやいていましたが、他の子がアレンジ大賞の採点を始めたのを見て、「やってもいい」と言い出しました。 ぜひ中学生の視点で採点してみてね、と頼むと、とても丁寧に一つ一つの作品を見て、ひとりごとのようにコメントをしていましたが、とにかく作品をよく見てよいところを見つけているのがとても印象的でした。 とても誠実に作品と向き合ってくれて、丁寧に時間いっぱい使って投票をしてくれました。', null, '盛り上がり: 来室時の態度とは打って変わって、一つ一つの作品をきちんと楽しんでプレイして、投票をしてくれていました。'),
  ('881069c7-4ffc-5595-b52a-1e4432275b27', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-06', '17:30:00', null, '通常 / アレンジ大賞の採点', '一つ一つの作品をきちんとプレイして、感想をしゃべりながら一生懸命に採点をしていました。 さすがに疲れるようで、途中休憩もはさみながら、なんとかすべての作品をやり終えて、満足したようでした。', null, '盛り上がり: いろいろな作品にコメントをできるのが楽しかったようでした。'),
  ('75b649d4-73f3-5a3d-92e9-22aaa2ab8391', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-06', '18:40:00', null, '通常 / アレンジ大賞の採点', 'アレンジ大賞の発表を見て懐かしくなったのか、採点をしてみたいということだったので、参加してもらいました。 オンラインIT部で一緒の子の作品がある、と楽しそうにしながら、熱心に作品を選んで投票してくれました。 採点が終わったところで「ロブロックスに興味がある」と言ってきたので、デジタネの動画を少し見せました。今後、Scratchをやめて、Excelとロブロックスを併用してみたいということで、お家の方と相談してくるとのことでした。', null, '盛り上がり: アレンジ大賞の投票も、ロブロックスの視聴も、どちらも熱心に参加してくれていました。
備考: Excelの検定は受験したいとのことなので、ロブロックスとExcelを並行してやっていきたいそうです。'),
  ('db60929c-9d3c-59bf-9d01-ae6faae5bd91', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-06', '18:40:00', null, '振替 / アレンジ大賞の採点、U16大会の作品作成', '採点はとてもまじめにやってくれていました。最終的に、自分の作品に投票しなかったところに和真君の性格を感じました。他にはないアイディアの作品だったことを褒めましたが、少し嬉しそうにしつつも、一貫して謙虚な感じでした。 後半は熱心にオリジナル作品の作成を進めていました。', null, '盛り上がり: 大会への意欲はとてもあるようで、熱心に作成していました。'),
  ('4f0ab9cc-feda-5162-86bf-18c4947e2967', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-06-13', '18:40:00', null, '通常 / プログラミング親子大会', '親子大会に向けて横スクロールゲームの製作を始めました。キャラクターのジャンプ動作と床の判定については、「床にいるときとジャンプ中以外は基本的に落ちている」という点を理解しながら制作することができていましたが、壁にぶつかる当たり判定の実装で苦労しています。 「アクションゲーム」の教材を参考にしながら修正してそれっぽい動作をするようにはなりましたが、まだバグがみられていました。 次回は当たり判定の修正の続きと、ステージの横スクロールの実装をしていく予定です。', null, null),
  ('5abc1881-f227-5a88-8b79-df0dda065526', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-06-13', '17:30:00', null, '通常 / プログラミング親子大会', '親子大会に向けたゲーム制作を始めました。UNDERTALEのような弾幕ゲームを制作したいとのことで、まずはHPバーとダメージを受けたときの挙動、ゲームオーバーになったときの画面遷移を作成しました。HPバーについてはペンを使ったものでなく、コスチュームを変更していくという形で作りました。 ダメージを受けたときの挙動はメッセージの授受を用いて実装しました。私が少し提案したら自分から率先してコードを書いていました。 次回はクローンを用いて弾幕の挙動を作っていく予定です。', null, null),
  ('d29a3946-4f43-55e9-8962-50bf946dd5d6', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-06-13', '16:30:00', null, '通常 / 親子プログラミング大会', '親子プログラミング大会へ向けて、飛行機着陸シミュレーションゲームの製作を進めました。 複数の飛行機を衝突させることなく滑走路まで誘導するという管制官（？）のようなゲームを作りたいようで、誘導をどのように行うかを試行錯誤しながら、集中して制作していました。 飛行機の挙動について悩んでいましたが、飛行機をそれぞれ異なる方向へ飛ばし、端についたらもう片方の端からまた現れるという動作を実装できていました。滑走路までどのように誘導するかがまだ決められていないため、次回以降決めていきたいです。', null, null),
  ('afc72e29-3547-5055-ae1d-106d96aadcff', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-13', '16:30:00', null, '通常 / 親子大会作成', '親子大会の作成を続けました。3つ目のフェーズを追加するために、2つ目のフェーズのときと同じようにメッセージを使って移行していきました。この段階ではどのメッセージを使えばいいのかなど、ゲームの時系列に関する認識が段々できるようになってきています。まだ粗削りで重複した意味のコードを書いたりしがちですが、集中力を保って頑張れています。重複したときは、少しヒントを出すと要らないものを判別できています。 ただ、授業中とは打って変わって、休憩時間は関係ないyoutube動画を見てしまい、言ってもやめてくれないことが多いです。', null, null),
  ('aebcae0b-0b39-58a7-8aa6-8bafca85ac68', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-13', '17:30:00', null, '通常', '親子大会作品を作らないという気持ちは変わらないそうだったので、PRGにしました。前回終わっていなかったので続きからやりました。「ではないまで待つ」や「(変数)歩動かす」などのスキルポイントについて意味を一緒に確認しました。なんとなくは理解したようですが、次に出てきたときに使いこなせるかというと微妙なくらいでした。ステージ移行の部分だけできなかったので、次回前半くらいで終われそうです。', null, null),
  ('ab2ca4bb-303c-5f59-b2f8-21e109fba2a5', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-13', '18:40:00', null, '通常 / 親子大会作成', '親子大会作品作りを続けました。ご飯などのスプライトをマウスで動かせるようにしたいそうだったので「ドラッグできるようにする」の使い方を教えると使いこなせていました。その後はストーリーの流れを作るように促すと、ピクニックと学校というシチュエーションでそれぞれ作ると決めて、背景を自作していました。学校のパターンではホラー要素も入れるなど、今後作っていく具体的なストーリー内容もイメージできているようでした。', null, null),
  ('f16bfc4d-2101-598b-b5e7-5b645a93217f', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-06-13', '17:30:00', null, '通常 / ロブロックス', '前回途中で終わっていたレインボーブリッジの続きから。動画を見続ける集中力が続かないらしく、しょっちゅう、他の子の席にいったりしていました。動画が長くて面倒くさいみたいなことを言っていました。そんな中、動画を全部通してもるのつらいから、この動画内の覚えるべきことを覚えるから、教えてということで、レインボーブリッジのテキストファイルから、覚えるべきところだけを抜粋して、教えました。プログラムからPartの色を変える方法と、時間差で色を２回変える方法を教えて覚えて納得して、確認テストを完了させて、このかいを終了としました。動画を見続けるのができないこ、集中してみ続ける子の差が激しいかもしれません。まだ少し様子見が必要かもしれませんが、動画を見続けるのができないこに対しては、何かしらの対応対策が必要だなと感じます。', null, null),
  ('4b0a7b11-b405-5418-9e24-798e30b94534', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-06-13', '17:30:00', null, '通常 / ロブロックス', '今日は、ロブロックスのアカウントを新しく作ってきたと言って、ロブロックスに集中してくれそうな感じだったので、クイズロブロックスの動画視聴を始めてもらいました。が、一本目の動画を最後に、見てくれなくなりました。もうやりたくないと言いながら、なんとかロブロックススタジオでのアスレチックゲーム作成を始めましたが、それも長続きせず、クイズロブロックスで覚えるべきポイントだけでも覚えてねと、ブロックのプロパティの操作について（CanCollide, Transparency等）教えて、わかってくれました。残念ながら、やはり動画を見てくれないので進め方を考えなくてはいけないなと思います。', null, null),
  ('ddd4f73f-d4f5-540c-9958-94d33193c9ee', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-06-13', null, null, '通常 / ロブロックススタジオ初回', 'エクセルとロブロックスを併用するという許可を親から貰ったということで、デジタネはまだ登録していませんが、ロブロックススタジオの導入を行いました。ロブロックススタジオの基本の操作方法、Partの操作方法、プロパティについて等、スクラッチとの比較を用いて説明しました。デジタネで言う、頂上を目指せを完了した状態になるので、この動画は確認テストだけやってスキップで良いと思います。なので、次回のロブロックススタジオは、２回目のクイズロブロックスからで良いのかなと思います。動画は使わず、重要ポイントだけを駆け足で説明しましたが、とても興味深そうに聞いてくれていました。', null, '時間帯: その他'),
  ('59f3b0cc-de8d-5edb-be23-e342f76f3d0e', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-06-14', null, null, '通常 / 親子大会', '前回言っていた犬猫の作品は取りやめたようで、どのようなゲームを作りたいのか聞いても何もわからないといい作りたいものが定まらないようでした。 アルスタジオにある素材が気に食わないようでフリー素材サイトを周回していましたが、見つけたい素材も定まっていないようでした。好きなゲームを聞くとマイクラと答え、「自由」なゲームがいいと言っていました。 最後のほうでは以前自分で作った紙芝居系のゲームを改良していくと言っていたので、次回以降その方向で進められるとよいと思います。', null, '時間帯: その他
タイピング: タッチタイピングに挑戦するなど、よく集中していました。'),
  ('7dc4a780-7aaf-5304-bbc5-3431c0e7acd6', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-14', null, null, '通常 / ロブロックス', '前回の続きから行なっていきました．動画を見ながらロブロックスにおける基礎部分を固めていく中で，次々と進めて内容を吸収していました．途中で止まった部分もなく最後までやり終えることができ，確認テストにおいても全問正解することができていたため，内容理解もしっかりとできていました．', null, '時間帯: その他'),
  ('e7d11155-fbf8-551f-bbc0-5e1c8296d568', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-06-14', null, null, '通常 / 基本操作コース', '背景を変える、音を出す、キャラクターを喋らせるといった基本操作を学びました。自分でブロックを追加して背景を交互に変更させたり「はたをおしたら」を「スペースキーが押されたら」に変更したりと、好奇心のままにいじっているといった印象でした。 後半では集中力が途切れてしまい、セリフを変えたりキーを押し続けてみたりとあまり進められませんでした。 終わらせたコースにスタンプを押すのがモチベーションになっているようでした。', null, '時間帯: その他'),
  ('d7cbf1f8-6a59-55dc-84e1-332d602083ed', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-14', null, null, '通常 / ロブロックス', 'ロブロックスで新しい内容に挑戦していきました．動画内容をしっかりと把握しながら進めていくことができていました．アレンジ部分においては，実際にオリジナルのものを作った後に自分でクリアできるのかテストも行って確認していきました．確認クイズでも満点を取ることができていたため，内容理解もできていると感じました．', null, '時間帯: その他'),
  ('b41db97c-f49a-59a1-9b07-96702b60b508', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-06-14', null, null, '通常 / 親子大会作品作り', '親子大会に向けて、天狗のイラストのパズルゲームの作成を進めました。 「⇒下絵をつくり、下絵とピースに影武者を設定して、影武者（あ）が影武者（い＝下絵）に当たったらOK、という案で作ってみることにしました。」 の、ピースごとに影武者を作るというところまで進めることができました。影武者にどのような機能を持たせるかについて、教材を見ながら自分で試行錯誤していました。 次回は正解の場所に当たり判定用の影武者を追加し、ピースの影武者と接触したらOKという、パズルゲームの核となる機能を作成できるとよいです。', null, '時間帯: その他'),
  ('dd3a4018-8ff4-564d-910c-96ed171cce9c', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-14', null, null, '通常 / ロブロックス', '今回のロブロックスでは，100％まで行っていないものが２つあったためそちらを先に100％にしていきました．過去に行った内容についても確認テストで満点を取れているようなので，しっかりと覚えられているようです．今回行っていった単元については，途中までしか終わらなかったものの，口頭で説明することができていたので覚えられていると感じました．', null, '時間帯: その他'),
  ('0552dcf9-97d7-5d14-aaf8-dbe79435a1f4', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-14', '16:30:00', null, '通常 / 大会作品制作', '親子大会の作品制作に取り組んでいきました．ゲームとしては，二人プレイの対戦型シューティングゲームを作っていきたいようで，構想についても固まっている様子でした．今回でキャラクターの動きや発射する弾のクローンや動きを完成させていきました．しかし，本人の性格上あまり凝った作品を作ろうとは思っていないようなので，興味を向かせて作品にどう注力していくのかが課題となってきそうです．', null, null),
  ('037885b4-472e-5414-abd5-af2720093cba', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-14', '17:30:00', null, '通常 / ロブロックス', '前回に続いて魔法のレンガブロックを制作していきました．最初に20分ほど遊んでからスタートしていきました．しかし，スタート時にパスワードが不明などの理由で少し手こずってしまい，予定よりも開始が遅れてしまいました．それでも今回で最後まで完成させることができ，確認テストでも満点を取ることができていました．次回は抜けている２つの単元のどちらかを完成させていきたいです．', null, null),
  ('09f57134-66e2-546e-a67b-b04a638a7960', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-14', null, null, '通常 / 親子大会作成', 'クリックで撃つシューティングゲームを作っていきました。この先どう進めればいいか方向性に迷ったので、クリアとゲームオーバーの作成をすることを勧めました。クワガタに3回触れたらゲームオーバーにしたいとのことで、触れた回数を変数で記録しないといけないので、少し難しいですがやっていきました。その変数を増やす条件が間違っているのでそこから直すことになりそうです。', null, '時間帯: その他'),
  ('c727f261-4c06-5b86-a428-9975abec3c6d', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-14', null, null, '通常 / 親子大会作成', '正しい答えになる計算式を撃つ「算数シューティングゲーム」を作っていきました。大会に向けて制作意欲は高かったです。「スプライト作成は家でできるからコード作成をここでたくさんやろう」などと計画だてて取り組んでいました。クローンを使ってビームを撃つコードはだいたい自力でできましたが、隠した後の表示忘れなどのデバッグは一緒にやりました。問題の正誤判定が難しいから来週教室でやりたいと話してくれました。', null, '時間帯: その他'),
  ('0ee2579c-61d5-5489-8532-dac180117ea4', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-14', null, null, '通常 / 親子大会作成', '先週横スクロールをやりたいと言ってお手本をリミックスしたりしていましたが、作りたいものを具体的に言語化してもらったところ結構違うことがわかりました。主人公が歩くと足場のブロックが現れてスクロールしてくるようにしたいとのことでした。ひとまず主人公のジャンプ動作を作りました。y座標について「～ずつ変える」と「～にする」の違いなどもあやふやになっていたので復習すると思い出せました。ジャンプについては、高さを調整したり音を鳴らしたりして完成しました。次回はブロックの動きについて作る予定ですが、ブロックは主人公とは逆向きに動いているように見えるのがポイントになりそうです。', null, '時間帯: その他'),
  ('a32cdb1d-fd73-5d75-9ee8-5b2828c9dfd1', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-14', null, null, '通常 / 親子大会作成', '爆弾を落とす動きの続きから作りました。「端に触れるまで繰り返す」という部分について繰り返しの範囲が間違っていたので、各処理について「これは繰り返したい？最初だけやる？」というように考えてもらったところうまくいきました。HPや制限時間といった典型的な変数についての処理は自力で作れるようになってきました。またシューティングゲームというテーマはよくあるものなので、個性のある要素を入れて差別化するといいということを伝えました。それについてはとりあえず基本部分ができあがったら考えるとのことです。', null, '時間帯: その他'),
  ('37d2bd2d-aa67-5850-9cdc-339882627a90', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-14', null, null, '通常 / U16作成', '森を3D風にスクロールさせる作業を続けました。「中心から離れるほど木を小さくする→木が放射状に広がるようにする」というように、手順を細分化しながら進められていました。大きさや座標を決める式を、試行錯誤しながら決めていました。その中で三角関数も出てきて、これは学校では習っていないもののゲーム制作のため動画でざっくりした内容を学んだそうです。', null, '時間帯: その他'),
  ('fe5331d2-8ddf-5210-b778-a24c9e04e229', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-16', '16:30:00', null, '通常 / 親子大会作品提出', '最初はにゃんこ大戦争のような戦うゲームがいいとのことで、scratchサイトにてコードを一緒に見ていました。内容が難しそうとのことだったので、アルスタジオ内にあるスマブラをリミックスしてスプライトを置き換えるところまで制作しました。もっとアレンジができそうなので、プログラミングに関するアレンジなど他の講師の方にサポートしていただければと思います。', null, 'タイピング: なし'),
  ('4eaaed99-fb41-59d9-a79d-feb19b2a179e', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-14', '17:30:00', null, '通常 / ロブロックス あこがれのマイハウス！', '早く終わらせたいとのことで，少し早めに始めていきました．だんだんと難易度が上がってきているため，進めていくのにも時間がかかってきましたが，１つづつ解き進めていくことできていました．最後の確認問題では，１問間違ってしまいましたが，動画で該当箇所を見直して正解することができました．次回もこの調子で進めていきたいです．', null, null),
  ('6b5b5f9b-35e7-5b12-9b9d-9b9244f8938d', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-16', '17:30:00', null, '通常 / 親子大会作品の制作', '八王子に関する背景のアレンジを制作しました。アルスタジオ内のスプライトに関するツールで、カーソルを動かして図形の頂点を変形させて描くやり方を教えると、感心したようで、機能を使って高尾山やCEREOを作成してくれました。次回は新宿や他の背景の作成に入ればと思います。先々週からずっとビジュアル面でのアレンジなのでプログラミングに一旦移行してもいいかもしれません。', null, 'タイピング: なし'),
  ('74bff5ac-4456-5a74-a29a-54e4ae093eb3', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-14', '16:30:00', null, '通常 / 親子大会作品制作', '前回までで，クイズを作るという大まかな設定は考えていたため，今回はクイズの問題と次の問題へ移動する際のプログラムを作っていきました．クイズ問題に関しては事前にある程度考えていたようなので，スラスラと決めることができました．プログラム部分については，メッセージを用いて作成していく予定でしたが，メッセージについていまいち理解できていないようなので，次回メッセージの復習も兼ねて作っていきたいです．', null, null),
  ('064f58f9-71b5-555f-bf8a-ba5373d7aa8a', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-16', '16:30:00', null, '通常 / チーズを探せ', '前回の続きから作成してきました．乱数部分からのスタートだったため，サイコロを用いて乱数がどういうものか，そして今回のゲームにどう使っていくか説明してきました．その後は，ネズミが反対に動いてしまう不具合を修正していきました．迷路を全体を白塗りしていたので，条件が反応したため不具合が起きていたと気づくことができました．現在は，敵キャラを作っているところなので，次回で途中部分とゲームオーバーやゲームクリア部分を終えて完成させていきたいです．', null, null),
  ('48fb78d4-d85c-5b82-a9f4-4fdab9248b9b', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-16', '16:30:00', null, '通常 / DKゲーム2 チーズを探せ！', 'ネズミの動きについて，完成品を操作しながら考えていきました．実際の動きと作りたい動きをリンクさせて，むきを交えながら考えて作りました．チーズの乱数やスコアに関しても同じ考え方を用いていき，一緒に考えながら進めていくことができました．今回で動きやスコアの部分はできたため，次回で敵キャラなどを作っていけたら良いと考えています．', null, null),
  ('5f38ec96-7cf4-53d1-887c-5a5b2329dac0', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-06-16', '17:30:00', null, '通常 / 親子大会作品制作', '問題の出題方法をリストを用いて行っていきたいとのことで，問題の多いクイズ屋さんを参考に，リストを使って問題作成を行っていきました．難しい漢字の読みを答えていくクイズなので，読みの書き方をひらがなに統一するように工夫もしていました．今回である程度コードが完成したため，次回ではその続きを行うかグラフィック部分について作業を進めていきたいです．', null, null),
  ('8bac193e-3dcb-5e30-8357-13cfc38747f5', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-17', '16:30:00', null, '通常 / 親子大会作品の作成続き', 'クレーンが元に景品を落とした後の動作がうまく作動せず行き詰まっていた。 自分で考えて色での判定をスプライトに変えてみる、変数の判定の数値を＝から>に変えるなどをしていた。 コードが並列に同時に動作していた為、一本化することで正常に動作するようになった。 クレーンがディスプレイを通り越して動いている為、次回修正を促したいと思います。 （榊原） コードを分けて書く場合と一本化して書く場合の違いを簡単に説明し、納得できたようでした。（大原）', null, '盛り上がり: クラスのメンバーが慣れてきて、たまに雑談をしながら作成するのが楽しそうでした。 賞品のアマギフで何を買おうか、嬉しそうに考えていました。'),
  ('eff459fb-cb62-5504-8a32-85418842c5be', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-17', '16:30:00', null, '振替 / 親子大会作品の作成続き', 'オリジナリティーを出すために、熱心にコスチュームや背景を選んだり編集したりしていました。元のゲームとだいぶ印象が変わって戦国ゲームらしくなってきたのが楽しそうでした。 和田そうすけくんも歴史好きということで、少し話したりしていました。', null, '盛り上がり: 作成自体は楽しそうに、熱心にやっていました。 初めてのクラスへの参加でしたが、学校の話や歴史の話に積極的に参加していました。'),
  ('c9b73efc-6bc1-557c-ab60-61805af4469b', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-17', '16:30:00', null, '通常 / オリジナル作品の作成', '大会、という言葉に引いていたので、好きなゲームを作りながらスキル獲得していこう、という目標を伝えると、少し落ち着いたようでした。 これまで手を入れ続けていた「いちごの反乱」アレンジゲームも一旦完成とさせることに納得したので、ビンゴおじさんのゲームをいくつか見せて、興味があるものを探してもらいました。 今日の三浦そうたくんとの話で、そうすけくんも歴史好きということが判明し、同じようにタワーディフェンスゲームをやってみたいというので、こちらのアレンジをしていくことにしました。 ゲームをプレイして簡単にコードを見てもらい、自分の手の付けやすいところからアレンジをしていきました。真っ先にコインの設定をいじっていました。 その後はスプライトやコスチュームを色々と編集していました。', 'いつも見た目の編集から入るそうすけくんなので、しばらく好きにさせて、気が済んだ頃にコードのアレンジを勧めていきながら細かいスキルの獲得をさせていきたいです。', '盛り上がり: このクラスの雰囲気に慣れたのか、かなり雑談に参加してくるようになりました。 歴史が好きだというのも初めて話してくれて、戦国時代と昭和時代が好きとのことでした。 日光も楽しみにしているようです。'),
  ('db1e627a-53e9-54e0-8eec-81a1dae4deb4', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-17', '17:30:00', null, '通常 / Scratchのスキルチェックを兼ねたゲーム作成', '今日の目的を最初に説明して納得させてから、だるまさんがころんだの細分化をさせました。なぜ細分化をするのかという説明も素直に聞いてくれました。 ゲームをプレイしてスプライトの動きを細分化する際に、見た目の言葉からゲームの構成上の言葉に置きかえていくのは、少し面白かったようでした。 細分化ができた後は、素材のみの教材から、見本等を見ずに自力で仕上げることができていました。 ピッチについては知らなかったようで、軽く説明しました。 35分ほどで完成したため、小技から好きなものを選んで学習させました。 こちらもクローンの部分のブロックを外して編集させたところ、わりとすぐに理解できて、面白がっていました。', null, '盛り上がり: とうきくんや先生達とも慣れて、学校のことやSwitchのことなど、楽しそうに話しながらも熱心に作成していました。'),
  ('0a9124a8-a55f-5911-8ce3-29d2390d50ee', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-19', '17:30:00', null, '通常 / 親子大会の製作', '球が連続で打てないバグがあったので、その習性を行っていきました。その要因として、「ずっと」のなかに「1秒待つ」が入っていて、そのラグを生んでいました。それで、敵の当たり判定もスムーズにできていました。さらに、定義に使うことを提案しましたが、定義の条件分岐まで含めて作っていました。それだとコードがわかりづらくなるので、条件分岐の中身を定義すると、見やすいことを教えてあげました。', null, null),
  ('a693a278-0ee0-5ce2-bc1c-26b8551a8ce1', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-19', '16:30:00', null, '通常 / サメから逃げろの予定だった、、、', '今日は先週よりひどかったです。ほんとにひどいです。アルスタジオに関しては何一つ進んでいなかったです。最初は、アルスタジオに移るの嫌がり続け、遊んでいました。その後は、ほかの人のパソコンを見回りづづけたり、勝手にロブロックスを他人のアカウントで遊ぼうとしたり、散々です。最初にまみさんにやることを伝えてもらったが、切り替えで今日は何をやるかを聞いても、「わからない」「やりたくない」を連呼したり、キーボードマウスの乱雑な扱いも見られました。あの時間帯はるいくんもこたろうくんも同様なタイプなので、ずっと見ていないと何も進まないです。今日の朔太郎君のひどさは、2人が引くほどひどかったです。(2人にもブーメランすぎるぞ授業態度)', null, null),
  ('ac1f0a9c-3f84-5d38-b7a7-2daa880d5e9b', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-19', '16:30:00', null, '通常 / 親子大会制作', '今日は背景やBGM選びがメインとなっていました。ある程度本人で候補は選ぶが、最終的には先生の意見を取り入れて、選んでいました。魔法の種類とドラゴンの属性によって、スコアが変化する仕組みに関しては、変数で整理するのは、数字か文字かずれていただけだったので、その仕組みは気づいてからうまく作成できていました。', null, null),
  ('c25ec647-cf73-5444-85c2-43a84352d0cb', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-19', '16:30:00', null, '通常 / 親子大会作品の作成続き', '作りたい、という意欲はあるのですが、とにかく先生がそばにいないと進めることができないようです。「先生一緒にやろう」と声をかけまくり、やりたいことを説明してくれるのですが、説明をして課題を与えてそばを離れると自分も一緒に席を立ってウロウロし始めます…。 やろうとする意識が出てきただけ進歩ではあるのですが、一人でできないのと、他の子の動向に気が散りまくるのをなんとかするのが今後の課題というところです。 「秋」のスプライトからどんぐりが出るようにしたい、というので座標の確認をして修正しました。また、ドングリがおかしな方向に飛んでいくバグは、削除済みのスプライトに向きを向けていたことが原因だったため、確認するポイントを指定して直すことができました。 えみちゃんがiPadでキャラクターを描くという話に便乗してイラストをやりたがったので、もう少しコードが進んでから、となだめました。', null, '盛り上がり: 作品を作ること自体は楽しそうにしていました。自分のアイディアにも満足しているようです。'),
  ('07734090-edbf-5995-be55-2a98bcc26714', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-19', '17:30:00', null, '通常 / オリジナル作品作り', 'OPの作成がメインとなりました。作成中、U13大会のことを触れて、景品のことも見たら、親子大会よりも豪華じゃん、こっちの方がいいと、やる気が上がっていました。そうちゃんは期限があると最後つめっつめになってしまう傾向があるので、期限が遠いこっちの方が気軽に作れると思います。花火と爆発の構成がうまくすおとーりーに練ってあったので、会話の前後関係がよくなれば、OPは完成しそうです。', null, null),
  ('4b239636-e254-51a4-b695-b1424d296185', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-19', '16:30:00', null, '通常 / 親子大会作品の作成続き', '先週移動教室でお休みだったので、作成していたものを思い出すところから始めました。 ピッチャーが球種を選んで投げられるようにするところで、変数と定義を使って、投球のメインコードと各球種の球のコースのコードをわけて作成することを提案すると、初めは引いていましたが、サンプルを見せて、結果的にはコードが短くなると説明すると乗り気になってくれました。 定義は1級で扱う内容だと告げたことも、少しモチベーションアップになったようでした。 各定義ブロックの中の球種によるボールの動きの違いを、実際の動画を見ながらかなり熱心に調整していました。 いつも通り、他の人のPCを見たり話しかけたりという立ち歩きも多かったですが、野球に関係することだからか、作成も一生懸命にやっていました。', '残りの球種のブロック定義を完成させる', 'タイピング: 承太郎君に勝負をもちかけて完敗していました。もっと練習してくる、とやる気になったのは良かったです。
盛り上がり: 2時間連続の受講でしたが、これだけPCに向かってコードを作成したのは初めてかも？というくらい、頑張っていました。'),
  ('849f18fa-9607-5f56-b50d-13c29b3020e7', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-19', '17:30:00', null, '振替 / 親子大会作品の作成続き', '前時間と同様', null, 'タイピング: 前時間と同様
盛り上がり: 前時間と同様'),
  ('6cc54358-80a5-5881-bd40-db36c58841a4', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-19', '17:30:00', null, '通常 / 6/21体験会イベント用イラストの見本', '体験会で描いてもらうイラストの見本を描いてもらう時間をとりました。 元の絵の線を消して自分なりに髪型などアレンジしたり、描くのが難しい部分はアイビスペイント内の素材を活用してうまく完成させていました。', null, null),
  ('f1e263a6-08ac-5295-afeb-f06d0b644683', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-19', '17:30:00', null, '通常 / U16大会作成の続き＆Excel', 'Excelを忘れたら困るので、一回の授業で10～15分程度復習をしつつ、作品制作を進めようということで納得していました。 Excelは忘れていることをとても心配していましたが、今回の課題は完全に自力でできていて、ホッとしたようでした。 大会の作品については、家ではなかなかできないから、と、熱心に作成を進めていました。 作成していると好みのところだけ内容を濃くしていく傾向があるので、コンセプトがぶれないように声掛けをしました。', null, 'タイピング: 虎太朗くんに尊敬されつつ、相手をしてあげていました。
盛り上がり: 積極的に発言をする奏太朗くんや虎太朗くんに釣られたのか、たまに会話に参加したり、タイピングの相手をしてあげたりしていました。ゆきちゃん卒業以来、他の子との交流がほとんどなかったので、ちょっと楽しそうに見えました。'),
  ('4125614f-8061-57ab-81d4-5a662338132b', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-23', '16:30:00', null, '通常 / チーズを探せ完成', '前回までで敵の動きを半々までできていたので、アレンジを含めて作っていきました。敵にぶつかった際のゲームオーバーのコード作りで、あまりよく見れてなかったが、使うべきコードを自分で作れていました。もしを使うときに「ずっと」を使い忘れてることがあるが、一度使ったコードは覚えているようです。スコアによるゲームクリアの演出も＝と変数を使いこなせていて完成できていました。', null, null),
  ('b495fe6b-731f-5458-a2e4-49e2c202c6ed', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-23', '16:30:00', null, '通常 / エクセル', 'もう完璧です', null, null),
  ('aa93f8b2-3d67-503f-b1ec-3cc760458f71', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-23', '17:30:00', null, '振替 / アルスタジオ自由制作', '久しぶりにたいようくんに会えたので、なぜかアルスタジオの作品意欲がわいて自由に作っていました。基本はストーリーのお話を作っていていました。たいようくんのアイデアも混ぜながら。次回もアルスタジオをやりたいと言っていますが、ロブロックスをやってから続きを作ってくださいとお願いします。', null, '盛り上がり: 会話が弾み弾み、ライン交換もしていました。2人の会話に笑いをこらえる時が多かったです。'),
  ('14e8abe5-9127-5eaa-b793-9fca1d7fe985', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-23', '17:30:00', null, '通常 / オリジナル作品作り', 'けいとくんと久々に会えて、とんでもなく会話が弾んでいました。でも手が動いていたので、良しとしています。セレクト画面のボタンやコスも増えて順調に進んでいます。', null, '盛り上がり: けいとくんとライン交換出来て満足できていました。'),
  ('e75b51c2-f011-5d4f-825b-902d986e8304', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-23', '16:30:00', null, '振替 / 親子大会制作', 'お題の切り替えの条件がうまく動かないことがあ理直していきました。動いてたよいもののずっと起動してしまうので、「ないまで待つ」を取り入れて、解決できました。その後も、何度か聞かれることがあるが、試してみることを進めました。基本はそのままできていたので、無駄になるのだけ修正していきました。', null, null),
  ('f8d807b8-73fd-5fd3-aa3a-d60a3d12a65a', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-23', '16:30:00', null, '振替 / 親子大会作品作り', 'パズルのぴったりあうの条件について一緒に考えていきました。完成の位置から余裕を持たせて範囲の条件を作っていきました。不等号もあり理解できるか不安でしたが、「その間の位置に合えば、自動にはまる」と解釈できていて、よかったです。ほかのパーツへの理解はできそうです。', null, null),
  ('d38dd489-c045-5c2f-9e08-b84fa501517b', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-23', '16:30:00', null, '通常 / 親子大会作品制作', '前々回で作ってもらったスプライトを入れた際データが整理されていない状態になっており、またゲームとスプライトが連動していない状態だったため、スプライトや変数の名前を変えてもらうように案内しました。タイピングも最近習ったそうで、積極的に取り組んでくれました。', null, null),
  ('44f712a7-3070-5b21-b468-13b2b0aa360b', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-23', '16:30:00', null, '通常 / 親子大会作品制作', '問題文の背景スプライトで指しているスプライトの番号と、出題に関するコードの中にあるスプライトの番号が一致していなかったため直させました。 今日はいつもより集中力がなく、椅子もきちんと座れていない状態でした。進捗だけでなく次は何をやるべきなのか、細かく何度も確認してあげたほうが良誘うです。', null, null),
  ('6492f242-b314-537d-9395-fe679becb707', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-23', '16:30:00', null, '通常 / 親子大会制作', '授業初めに制作の続きをしてもらい、完成した各データをスクラッチデータ内に取り入れました。取り入れた際、画像の向きや気せ替えの土台となる絵と重なっていなかったため、残りの時間で画像の調整をしてもらいました。', null, 'タイピング: 授業前と授業終わりに熱心に取り組んでいました。最近ハマっているようです。'),
  ('f422de67-9810-54a8-b962-9fb0135d16f5', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-06-24', '17:30:00', null, '通常 / 親子大会作品制作', '前回でクイズの出題に関するコードはある程度完成していたため、殺風景だったグラフィックにキャラクターを追加して見栄えを良くし、問題数も増やしました。 また、正解と不正解の回数をカウントして表示するようにしました。点数部分のコーディングは、私が何も言わなくとも自分からサクサク行えていました。今回まででゲームの大筋は完成しているので、次回以降はグラフィックのさらなる改良や出題の工夫をしていければよいと思います。', null, null),
  ('b99b22b2-3d07-541c-bec1-366f429ac511', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-20', '17:30:00', null, '通常 / 親子大会', 'きょうは各種ボタンやキャラクターの作成を行っていました。それが終わると残り時間はあまりなく、弾幕の動きを作ったのは少しにとどまりました。ただ、「クローンを作って弾丸を発射する」「弾に当たったらダメージを受けるメッセージを送る」など、作業の見通しはうまくたっているようでした。', null, null),
  ('1d30107d-dfc5-5ded-9c73-7d0617218df7', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-20', '16:30:00', null, '通常 / 親子大会', '飛行機を飛ばすのはできたので、着陸させる処理を作りました。向きを変える→滑走路に移動させる という流れは自分で細分化でき、メッセージを使ってうまく動かせていました。飛行機の見た目上の向きと設定上の向きが違うことでややこしくなっていたので、コスチュームを編集することで向きを一致させるように促しました。大まかに着陸の動きはできたので、それを色々な飛行機や滑走路にも適用すればよさそうになりました。', null, null),
  ('a5e8a627-ccef-5230-9911-278fdfd8b780', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-20', '17:30:00', null, '通常 / 未習の場所を進める', '以前飛ばしてしまったコロコロボーリングに取り組みました。最初は他の子に絡んだり、席に座っても関係ないものを作ってしまったりとなかなか進みませんでした。後半でようやくスイッチが入り、コースの作成に少し取り掛かりました。また魔法のレンガブロックについてはchapter4と演習だけやっていないので、今のが終わり次第そちらもやってほしいところです。', null, null),
  ('e432d18e-7ab6-5440-bf3a-3b3bc7be6df8', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-20', '17:30:00', null, '通常 / できそうなことを進める', 'robloxで未習の部分をやっていこうとしましたが、動画に沿って少し進めたところでやる気をなくしてしまいました。そのあとはroblox studio内で、(レッスンとは関係なく)銃の素材など取ってきてシューティングゲームのようなものを作っていました。robloxにもscratch(U16)にも意欲を失っているようなので、一度きちんと話しあった方がいいかもしれません。', null, null),
  ('11e8768a-491b-59a7-985e-0a95001edd60', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-20', '17:30:00', null, '通常 / prg', '100m走の続きからやり、できていなかったステージの遷移を作りました。メッセージを送る条件と送り先を意識しながらできて、完成までもっていけました。そのあとはprgで次の脱出ゲームに移りました。遊んでもらったところこちらもゲーム性は気に入ったようでゲームクリアまで粘っていました。そこまで時間が残らなかったのでスクリプト一つだけ作りました。', null, null),
  ('bd1c32f1-191d-5404-b10b-64dfd8b05873', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-20', '18:40:00', null, '通常 / ロブロックス', '前回の続きからやりました。スクリプトでのprintやCancollideなどの新しい事項を理解しながら進め、しっかり動くように作れました。ただ集中できていなかった時間が割とあり進んだ量が多くなかったので、次回は「きょうの目標」を決めるなどしてメリハリをつけたいところです。', null, null),
  ('a19f1d59-eafd-563f-b17c-0d1244e5a7b2', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-20', '18:40:00', null, '通常 / 親子大会', 'お弁当ゲームのストーリー作成に取り掛かりました。まずはスタートボタンを押したときに、どのスプライトは表示してどのスプライトは隠すのかなどの初期設定をしました。一つ一つ考えながら設定できました。その次はキャラクターやセリフも作っていきました。主人公について、名字ではなくファーストネームを「田中」にするなど面白味をもたせながら作れました。', null, null),
  ('ce4ac6c4-91c6-54ae-a04f-3c7945d051d8', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-28', null, null, '通常 / エクエル基礎練習', '以前、関数周りができていなかった印象だったので、4章の問題に取り掛かりました。票の空欄を関数を用いて、埋めていくような問題でしたが、最初はそのまま数字を映しているだけでした。こちらが、ここに問題文が書いてあるからその通りに進めてと言えばよかったと思います。その訂正をしたら、関数は使いこなせていましたが、四捨五入や桁数の能登と柄の部分ができて田舎たのでえ、ショートカットやctrlの方法を教えていきました。この流れがあったので、読み取る力が若干不安に感じます。', null, '時間帯: その他'),
  ('745446d0-43db-5c4a-8be7-2e5112d1a6a3', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-06-28', null, null, '通常 / 基本操作コース', '前回の復習で登場人物にしゃべらせる練習から始めましたが、序盤は集中しておらずキーボードをむやみに叩き続けるなどしていました。 スタンプを押しまくるのが好きなようで、「物語を作ろう」というよりは「スタンプを押していこう」という風に目標立てると進めることができました。 背景を変える、オブジェクトを動かす、自分で録音したものを使うという機能について学びました。ゼロからコードを作るのは難しいので、どのキーで動かしたいのか、そのためにはどのコードが必要なのかと説明しながら誘導していきました。 残り10分くらいになると集中が切れて適当に遊び始めてしまうので、最初に立てた目標を達成できたら残りは遊び時間という風にしました。', null, '時間帯: その他
タイピング: 「あいうえお」を打つときにキーボードに書いてあるかな表記の「あ」を打とうとするなど、ローマ字タイピングというものを理解していない雰囲気がありました。'),
  ('e0c48bf5-25a2-5993-89dd-895eee6c128d', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-28', '16:30:00', null, '通常 / イラストコース', '授業前に見せてくれた絵がよく描けていて、イラストコースが始まってから継続的に絵を描く習慣を身につけてくれているようです。キャラクターデザインも指示をしてから黙々と作業をしていました。', null, null),
  ('39f349f1-13ea-5798-a555-79149b259a7f', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-28', '16:30:00', null, '通常 / デザインアレンジ 教材より配色の仕組み', '落書きに夢中で、ちょっと講師の話を聞けていないシーンが多かったです。作業は最初のデータ送付以外は滞りなく進めたのでよかったです。', null, null),
  ('eb314cfa-c21c-5a02-b4c9-6c0cf7fb7d4c', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-28', '16:30:00', null, '通常 / デザインアレンジ 教材より配色の仕組み', 'デザインの色選びに関する内容を説明してあげると、具体的なイメージが湧いてきたようですぐに取り掛かってくれました。今日は何を思ったのか指で描こうとチャレンジしていましたが、結局ペンに戻りました。', null, null),
  ('fdc0324d-8c8a-5f1f-b410-691fde2b446f', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-28', null, null, '通常 / オリジナル作品作り', '前回の様子から、やりたいことが思考や言語に追いついない感じだったので、なにから始めるかわからなかった。なので、少しでも傾いたところから一緒に固めていくことをやりました。まず、スプライトで優柔不断な行動を起こしたので、１つだけ選ぶようにさせました。 そこからポット出の発想をこちらからつなぎ合わせていくようにしました。途中、こちから出したアイデアが「できるのかな？？」と考えが踏み止まろうとしたので先生がいるから大丈夫と押してあげることができたので良かったです。そこで決まった全体像として、 ・フンツノが操作可能 ・ガチャポンをコインで回して、チケット?を出していく ・チケットでプレゼントボックスが開く ・プレゼントボックスから動物が出てくる ・コインはパソコンのスプライトでミニゲームをして集める ・コイン3枚で1回ガチャが回せる そこで、フンツノがガチャに触れているときに、スペースキーを押したら回せる、のような仕組みにしようとしました。けど、そこはうまくいかず次回直してください。 今日は、発想をゲームの形としてつなぎ合わせることができ、本人も全体の行く末が見えたと思う。なので、残りのアイデア出しとしてミニゲームの内容を考えてほしいので、過去に作ったものを利用させてもいいかもしれません。', null, '時間帯: その他'),
  ('46d3d176-0d5f-5d12-9f61-7cfbff4218c0', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-28', '16:30:00', null, '通常 / DKゲーム迷路', 'しばらくアレンジ続きだったようなので、復習として以前学んだ乱数を使ったゲームを作ってもらうことにしました。サイコロで乱数の仕組みを復習したあと、まずは矢印キーでネズミを動かしてもらうことにしました。ちょっとずつヒントを出しながら本人の進行に任せました。以前見たコードや角度が必要なことなど、自分で閃いた時がすごく楽しそうに制作できていると感じました。', null, 'タイピング: タイピングがとても早く上位10%に入っていましたが、ミスタイプがかなり多かったです。'),
  ('6d4aee1d-2c9e-5552-8d07-840ec8f612c2', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-28', '17:30:00', null, '通常 / デザインアレンジ 教材より配色の仕組み', '本人のipadのロックの関係で今回は講師のipadを貸出しました。宇宙人のキャライメージで独特な髪型デザインを考えており、どうやら得意分野なのだろうなと感じました。', null, null),
  ('9466d74a-4c2d-5830-9055-2295594de05d', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-06-28', '16:30:00', null, '通常 / デザインアレンジ 教材より配色の仕組み', '遅延で40分しか枠が取れませんでしたが、キャラデザ作成にしっかり取り組んでもらえました。', null, null),
  ('192651ec-16b1-5dbf-b9de-634a080766d8', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-28', null, null, '通常 / ロブロックス', '色の出力を変えるコードの部分を進めていきました。テンプレの海の世界に遊びに気がとられつつありながらも、集中してできていました。', null, '時間帯: その他
タイピング: お得まであともう少し'),
  ('0f6c09d9-1305-5ca0-94d5-b07daead6f26', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-28', null, null, '通常 / 親子大会つくり', 'クリックシューティングゲームの続きをやっていきました。主にゲームオーバーの爆弾の仕組みを作っていきました。3回クリックしたらオーバーしたいとのことだったので、まずはのあくん自身で考えていました。あれやこれやとコードを試していたが、うまくいかない感じがあったので、＝の演算式のヒントを与えてあげると、うまく進めることができました。できた時には、報告にしに来るくらい創作意欲がわいていました。その後、爆発後の背景を作っていましたが、少し寂しいので、デザインをもっと工夫できればいいと思います。また、ゲームクリアの要件として、スコアが2000いったらクリアとなります。クリア演出で雪だるまのイラストを使いたいのことでしたが、ざっくりしているので、そこも深めてみてください。', null, '時間帯: その他'),
  ('b7329a00-fec6-5b48-be16-02e8c7fbe049', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-28', null, null, '通常 / 親子大会', 'プラットフォーマーゲームの基礎部分の製作を続けました。「キーを押してジャンプする」「ジャンプしたら地面や障害物に触れるまで落ち続ける」「障害物に横から触れるとゲームオーバー」のような細分化をまず一緒にやって、これからの作業を確認しました。普通のジャンプなら自分でも作れるようでしたが、段差があって着地タイミングが一定でないパターンは初めてでつまづいていました。そこで、「アクションゲーム_移動とジャンプ 完成版ステージアップ【LR】」を参考にしつつ、地面に触れたときとそうでないときの違いに着目しながら作成してもらいました。 次回はゲームオーバーの処理に入れそうで、キャラの右端に障害物が触れたという判定がポイントになりそうです。', null, '時間帯: その他'),
  ('de57fa86-c7a1-5222-abd6-be4ebd5bd77b', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-28', null, null, '通常 / 親子大会', 'まずは基本的な処理の続きから作りました。待機画面からゲーム画面への移行や、制限時間切れした時などの動きをやりました。同じタイミングで動作するコードを何回も書いていて効率が良くなかったので、こういうときにメッセージで一斉に合図を出すのが便利だと伝えて試してもらいました。結構ハイレベルなこともできる一方で経験の浅さによりこういう基礎が抜けていたりもするので、補強していきたいところです。 以前オリジナリティを出していこうという話をしたので、それを受けて考えたアイデアを話してくれました。コインによりアイテムショップを作るとのことで、ゲーム中にコインを配置したりと、少しずつその作成にも取り掛かっています。', null, '時間帯: その他'),
  ('f66b58cf-a97c-5d0b-9100-8661c8700746', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-06-28', null, null, '通常 / 作品のレベルを上げる', '今日の目標として、今までのスキルを活かしてもっと凝った作品にしていこうという話をしました。とりあえず途中だったゲームクリアとゲームオーバーの作成を終えると、新しいアイデアを考えていきました。すると、怖い要素のあるゲームにしたいということで、音や背景をそれに合わせて作っていきました。ただもう少し動きのあるアレンジをすると入賞を狙いやすいことを伝えると、ストーリーを付けることを思いつきました。ゲームオーバーになると電車が追いかけてきて逃げるが襲われてしまうという内容に決めていました。(トレインイーターという怖いキャラクターが元ネタ)', null, '時間帯: その他'),
  ('9d303491-e8df-59a4-8d37-6c5c564d52b2', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-20', '16:30:00', null, '通常 / 親子大会作品の作成続き 基本操作コースのスキルを確認しながら進める', '相変わらずお喋りと飴を食べることは止まらないですが、何か新しいものを作りたいという意欲は見せてきたので、ゾンビを倒せを提案しました。自分に理解できそうなレベルだとわかると、のってくることもあるのかもしれません。 覚えた範囲で作成しようとして、説明動画はほとんどみていないため、上下左右の動きを各方向ずつ分けて、それぞれ「旗が押されたとき」ブロックにつなげていました。次回以降、同種のコードをまとめて書くことを教えても良いかと思います。（今回は指摘しようとしたとたん本人のモチベーションが下がりそうだったので、あえてそのままにしてあります） 表示と隠すはわかりやすいのか、自信ありげに使用していました。 うまく作成できている時は、短時間ではありますが、わり集中して楽しく作業ができるのですが、ちょっと躓くとすぐに気持ちが他にいってしまうかな…。', 'ライフル弾の動きを直すついでに（弾が銃ではなくアルゴンか出ているので）座標の学習をし直しても良いかもしれません。本人が興味を持てば、ですが💦', '盛り上がり: どういうふうに弾が発射されて欲しいとか、敵の色々な動きをどうしたいかなど、アイディアを語るときはとて楽しそうで、意図した通りに動くと得意そうでした。'),
  ('3f879dff-b4f1-5b54-9cbe-3030bbe53c79', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-20', '17:30:00', null, '通常 / Excelのスキルアップ', 'TAの時と同様、生徒としても楽しそうにやってくれてます。 Excelの3球範囲の数式や書式設定などは問題なさそうですが、グラフの凡例やラベル、軸の最大値などの細かいところで、見本の図と問題文との照合が間に合っていなかったり混乱したりするところが見受けられました。', null, '盛り上がり: 生徒の立場、TAの立場をそれぞれ楽しんでこなしてくれているようです。'),
  ('97a71224-1bf1-5906-ba23-c33a20557092', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-20', null, null, '通常 / Excelのグラフの学習を進める', '久しぶりの来室でしたが、Excelをやる気で来てくれました。 前回教材が整っていなくてできなかったグラフの学習ができたせいか、途中でダレることもなく、しっかり集中して取り組めていました。 問題や完成例の読み飛ばしか、細かい設定が抜けることもありますが、かなり自力でできるようになってきて、基本は該当箇所のメニューを出してみるということにも慣れ、少し自信もついたようでした', null, '時間帯: その他
盛り上がり: 苦手だと言っていたグラフの問題を自力で進められるようになったためか、熱心に取り組めていました。'),
  ('31d98271-5ac3-5397-b3b0-2b5863c558b3', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-20', null, null, '通常 / Excelまたはロブロックス 先週から併用を始めたので、今日はやりたい方かな？Excelの30時間マスターを１～2題やって、残りはロブロックスでも可。 ロブロックスなら「クイズRoblox！」の初めから、Excelなら4章の実習11、12あたり。', '今日の希望を確認したところ、予想通り「ロブロックスの続きをやりたい」とのことだったので、2回目ということもあり、本人のやる気に任せてロブロックスを進めさせました。', null, '時間帯: その他'),
  ('72678a4f-b349-5a65-92de-2efcb68cda03', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-24', '16:30:00', null, '通常 / 既存作品のアレンジをしながらスキルを学ぶ', '前回取り組んだタワーディフェンスゲームは、これ以上のアレンジが思いつかないとのことで、新しい作品に移りたいとの申し出がありました。 一から作るのは嫌だ、というので、アレンジでも構わないから、その中で少しでも新しいスキルを勉強していこうね、という目標を話しました。それに対して賛成！という感じではありませんでしたが、まあわかった、という感じの反応でした。 取り組みたい作品が特にあるわけでもなさそうだったので、以前ずっと手を入れていた「いちごの反乱」からの連想で、シューティングゲームを提案しました。 アレンジ前にコードの確認をさせたところ、読み取ることはおおよそできているようでした。自分がやりたいと思ったところのコードをいじるのも早いです。ただ、思ったままにどんどんコードをいじっていて、うまく行かなかったら条件分岐の位置を変えてみる！など、とりあえず動かしてみてうまく行く場所が見つかったらラッキー、とい作り方が目につきます💦', null, 'タイピング: タイピングを嫌がらず、授業前に取り組む習慣ができてきました
盛り上がり: 相変わらず面倒そうな様子も見せますが、今日は先生たちや他の子達との雰囲気が嫌ではなかったのか、たまに雑談にも参加しながら作成を続けることができました。'),
  ('403ef7ad-c294-58f1-9522-535423506f9b', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-24', '16:30:00', null, '通常 / チーズをとったときの動きと敵キャラの作成を通して条件分岐と乱数を学ぶ', 'とてもやる気で来室して、授業前から、ゲームをしなくてからすぐに作り始めたい！といってきました。前回作りかけの「チーズを探せ」をみておくように伝えると、おとなしく従っていましたが、とにかく構ってもらって一緒にやりたい、という意識が強く、大原の後をついてまわっていました💦 現状、一人でできるはずのことでもほぼ自走はできず、先生にみてもらっていないと落ち着いて作業ができないようで、そばを離れると、トイレに行くか、飴を食べるか、他の子の指導を覗きにくるか、となります。トイレに入っていても、ドアを開けて必死に話しかけてきます。プレッシャーを与えすぎても咳から嘔吐くことがあるようなので、今後は様子をみて、必要であれば保護者と相談しながら少しずつ自走の時間と一人でもできるという自信を持たせていきたいところです。 作品作り自体はとても楽しんでいて、チーズが迷路のスプライトに重なると取れなくなることにも自分で気づき、解決するための乱数による座標の指定を頑張って取り組めていました。', null, 'タイピング: 毎回勧めてみるのですが、タイピングは嫌で、プログラミングがやりたい！という意識が強いようです
盛り上がり: ゲームを作成できるのがとても楽しそうで、お母さんからも、毎回とても楽しんで満足している、とのことでした。'),
  ('f658fc3f-be10-597f-9c69-ad13a2d20e56', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-24', '17:30:00', null, '通常 / 手順書に従って作成しながらスキルアップを目指す', '今日の目標を説明してから手順書を渡して、まずは自主作成してもらいました。完成したらアレンジができる、というのを楽しみに取り組んでくれました。 ゲームをプレイした時の印象よりも簡単なコードでゲームができてしまう、ということに驚いていました。 完成まではスムーズに進み、ジャンプ力や回数などを色々と調整して楽しんでいました。 初めての定期試験は無事に終わったそうで、英語を頑張ったそうです。試験が終わったので、友達を呼んでSwitch2をするのだと嬉しそうに話していました。', null, 'タイピング: 既に相当速くタイピングできているので、向上心を持たせるには、明確な目標がある方が良いかもしれません
盛り上がり: 色々なゲームを作れるようになることを、素直に楽しんで取り組めているようでした。'),
  ('84cb43aa-180b-5b1e-a155-4bf9c3eb69e4', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-28', null, null, '通常 / U16作品の作成', '作りたいもののイメージは決まっているようで、今日直したいところもはっきりしていました。 メニュー画面に戻った時に、文字の背景が半透明のはずなのに濃くなってしまうことに悩んでいて、クローンが複数重なっていることもマウスでずらあいてみて気づいていたので、どこまでのコードが動いているのか、要所要所にカウントする変数あお入れることを提案してみました。 その結果から、どの部分が意図しない回数切り返しているのか判明したようで、あとは自分で修正できていました。', null, '時間帯: その他
盛り上がり: 悩んでいる時もなんとなく楽しげで、とにかく作成を楽しんでいる感じでした。'),
  ('ecea6f70-6c92-5ea7-910d-e8e8894d6e64', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, null, '2025-07-03', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('7fa28d02-f90a-5e01-b552-0ff698d20f9d', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-03', '16:30:00', null, '通常 / オリジナル作品作り', '最初に季節変わるタイミングを作ろうと決めてから始めました。けど、いつも変わらずいろんなことに気が散って中途半端になりがちでした。その流れで、電源をオフにするショートカットを自滅的に押してしょげていました。その機会を切り替えのチャンスとして、コードに向き合わせるようにしました。ヘーゲルの攻撃のコードをそのまま引用したので、どこで攻撃が変わっているか見ることに良い機会になりました。春夏秋冬分まではゲームの出来栄えとして作ってほしいです', null, null),
  ('168088fe-4b07-59ff-b5b6-1810481123fa', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-03', '16:30:00', null, '通常 / 親子大会作品作りの絵描き', '今日はずっと絵にかくことに集中していました。まあ作品の方はゲーム性としてはほぼほぼ完成していたので、納得のいくまで描きなおしをしていました。', null, null),
  ('a4d0ac0e-5810-5482-a144-89e7f343f01e', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-03', '16:30:00', null, '通常 / きちんと今日の課題に取り組む', '今日は授業の55分前に来室して、学校でタイピングをやるようになったから、とすぐにパソコンを触りたがりました。授業前はプレイグラムを見て、やった箇所を教えてくれた程度で、あとはScratchのゼルダやスマブラで遊んでいましたが、今日はキーボードをたたくこともだいぶ減っていました。 授業開始時に鷺山姉弟しかいなかったせいか、タイピングにやる気があったのか、わりとスムーズにタイピングに移行してくれました。ホームポジションと指づかいを教えると、きちんと守って打とうとするため、大げさに褒めてみたところ、素直に聞いて何度も繰り返し練習してくれました。あいうえおは下を見ないで打とうとがんばっていました。 タイピングの後に少し塁くんとおしゃべりしたり、パソコンをのぞきに行ったりもしましたが、タイピングで少し自尊心が芽生えたのか、一つの課題だけクリアしようという声掛けに乗ってきてくれて、途中飴休憩をはさみながらも最後まで作成をすることができました。 上下左右キーが押されたときに座標を〇ずつ変える、というブロックの組み合わせがくることは覚えていたので、xとyの違いだけ復習して、あとは自分で作成させました。 ゲームをプレイしてみて、ゲームオーバー後にもサメが動き続けるのがおかしい、と言っていたので、その気づきをほめて、どうしたいかを考えさせました。 サメに食べられたキャラが消えたら、サメの動きも止めたい、とのことだったので、他のスプライトに合図を出すメッセージの解説をし、完成させることができました。 一つの作品を作り終えた、ということがとても嬉しそうで、残り5分は堂々と席をはなれて、承太郎君の寿司打を熱心に見ていました。「タイピングの速い中学生」と尊敬しているようでした。', null, 'タイピング: 学校でプレイグラムでのタイピング練習が始まったそうで、とても熱心に練習していました
盛り上がり: 今日はタイピングとプログラミングと2つで達成感を得ることができたためか、授業終わりから帰るまで、ニコニコと得意げにしていました。'),
  ('0a916137-72f3-5bba-a927-ca3d329b93fa', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-03', '16:30:00', null, '通常 / 親子大会制作', '最初にどこを進めればよいかわからんという感じになっていたので、まずは本人がやりたい仕組みに対して現状のバグを見直していきました。旗が押されたときに、所定の背景になっていなかったので、背景のコードの場所を探してもらいました。そして、門のHPが0未満になった際に、背景だけ変わり門が残り続けていたので、そこをどうしたいかヒアリングを行いました。そしたら、「敵はいったん消えて、やぐらに変わる」のことだったので、コード作りのサポートをしました。その作業中、どのコードを使えばよいかわかっているが、場所が見当違いの場所を探している場面が何度か見られました。このことからコードの妊娠が少し甘いです。 次回は、今回背景が変わりやぐらの場面になったので、同様に門からやぐらまで攻め込むステージを作ってあげたらよさそう。そして、ステージの切り替えでせりふを交えたらストーリー性も上がりそう', null, null),
  ('b2ea6833-8a85-5a6a-8173-a8f3be82dcff', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-03', '16:30:00', null, '通常 / 親子大会作品の作成続き', '学校で漢字テストをやっていたということで、20分近く遅れて来室しました。入るときにきちんと「遅れてすみません」と挨拶ができていました。 今日は塁くんも朔太郎くんも席についていたからか、虎太朗くんも塁くんと声を掛け合ったあとは素直に作成に入っていました。 メインのコードで、選んだ球種ごとに作成した定義に分岐する部分を作成し、動画を見てカーブの動きを研究して、それを座標の動きに置きかえていました。', null, 'タイピング: 合間時間にひとりでやっていました
盛り上がり: 前回から悩んでいたカーブの動きが納得できるように作れたようで、満足そうにしていました。'),
  ('295f5dc5-7918-5ef9-951e-c09d919a25eb', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-03', '16:30:00', null, '通常 / オリジナル作品作り', '今回は、武士のキャラクターづくりがメインでした。それぞれの個性を出すために、めんどくさいを言いつつも特徴がはっきりとしていて、想像力がすごいです。総勢8体までそろいました。', null, '盛り上がり: じょうたろうがキャラを見て羨ましがっていました'),
  ('ba9feb45-d84c-5789-b5ba-39ad2847e061', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-03', '17:30:00', null, '通常 / Excelの学習とU16大会作品の作成', '来室するなり、「タイピングの速い中学生だ」とさくたろうくんに寄ってこられて照れていました。 Excelでは、問題文の順序の通りに式を入れようとして、ROUND関数の数値に何を入れたら良いのか混乱していたので、問題文を読んで関数の指定があったら、まず関数から入力することを伝え、納得していました。また、桁数を先に指定してしまってあとから直すこともあるため、Excel特有の作業の順序には慣れた方が良いかもしれません。 理解はできているようですが、慣れのために、もう一度同問題か類問をやっておくほうが良いと思います。 大会の作品では、絵が描けないため状況説明を全部セリフでしないといけなくて、ブロックの量が膨大になると悩んでいました。今は楽しく作成を続けているので、どこかでコードの整理を考える必要が出てくるかもしれません。', null, 'タイピング: こたろうくんとさくたろうくんに左右に張り付かれた状態で、謙遜しながら頑張っていました
盛り上がり: ゆきちゃんが卒業後、ずっと一人で黙々とやっていたので、最近は先生や他の子たちの会話に入ってみたり、小学生が話しかけてくるのに答えたりと、だいぶ明るい雰囲気になりました。'),
  ('0bfc7ac5-5b0b-5803-9dd4-4308b60dab17', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-03', '17:30:00', null, '通常 / 大会作品の作成', '発表で評価されるのが苦手なので親子大会には出たくない、と言っていたのですが、作品は作りたいという意欲があるので、発表が評価対象にならないU13大会の話をしたところ、そっちに出してみたい！とのことでした。とりあえず作成は頑張っているので、様子を見ながら続けさせています。 作中のキャラクターのセリフに対する受け答えでコードを分岐したい、とのことだったので、「○○と聞いて待つ」と、「答え」を使った演算式のやり方を教えました。こちらの解説で理解できて、その後は自分で作成を進めていました。 オープニングの分岐点では、どちらを選んでもBad Endになり、そこからゲームへとつながるのだそうです。楽しそうに、順調に作成を進められていました。', null, '盛り上がり: 虎太朗くんが少し落ち着いた（態度というよりも、他者に対する言動？）ためか、一時、会話がかみあわなくなっていた虎太朗くんと仲良く音楽を選んだりしながらも、基本は席について熱心に作成できていました。'),
  ('cffb4d95-561f-5c1c-84ce-43d8e3f8c4d1', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-03', '17:30:00', null, '通常 / 親子大会作品の作成続き', '基本的には黙々と作成をしていました。たまに、話しかけてくる虎太朗くんに返事をしたり、周りの会話に笑ったりすることもありました。 一人でなんとかしようと頑張ってしまう傾向があるので、こちらも意識して定期的に声をかけました。何度目かの声掛けで、HP変数がうまく減らないと悩んでいて、見た感じではコードに間違いもなかったのですが、よくよく見ると、－のみが全角になっていました。続く数字が半角だったため、見分けがつきづらかったようです。 定義の名前を「○○なら」として、それが条件分岐の代わりになる、と勘違いしているようなところがあったため、条件分岐と定義の使い方を軽くおさらいしました。', null, '盛り上がり: 前回から悩んでいたところがあっけなく解決したためか、後半はハイペースで作成を進めていました。'),
  ('ea981501-e9a9-5aa9-a78e-566cb562e9c7', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, null, '2025-07-04', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('eb11c43d-900a-565a-9b8f-93d6a33c8d7d', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, null, '2025-07-04', '17:30:00', null, '休み（未対象）', null, null, null),
  ('b004cc87-47af-541e-ba80-0ff0442ffbf2', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-07-04', '16:30:00', null, '通常 / 親子大会', '前回の着地処理を４つすべての飛行機に適応させ、着後は再びランダムな位置に移動しとび始めるという処理を実装しました。メッセージを用いて着地の実装をしているため各飛行機に各滑走路で違うメッセージを用いなければならずこんがらがっている様子もありましたが、自分で考えながら作ることができていました。 滑走路毎の処理がまだできていないため次回でそれを完成させれると良いと思います。また、現在だとゲームの目標がなくクリアもないため、時間制限や点数をつけるなどゲーム性の設計もできるとよいと思います。', null, null),
  ('6782c6bf-426a-522d-9d98-b94764e0996c', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-07-04', '17:30:00', null, '通常 / 親子大会', '今日はプレイヤーが枠内に当たった時のダメージと当たり判定、弾幕の基本的な動き方についてやっていました。 弾幕の作り方についてはクローンを用いて作るのだということはわかっていましたが、具体的にどう書けばよいのかはわからなかったようなので弾幕シューティングの例で実際に動きを見せつつ、「角度を変える->クローンを作成する->端まで動かす」という一連の流れでできるというように説明したところコードは自分で書くことができていました。 最初に弾幕を作ろうと促してもUIをいじり続けていて、自信がないことへ取り組むことへの忌避感を少し感じましたが、教え始めると自分で悩みながら考えられていました。 今回で弾幕の動きの基礎が完成したので、次回でステージの進行処理とステージごとの弾幕の動きを変えるのをはじめられると思います。', null, null),
  ('c379d385-7a6a-5955-bfd2-a01d77379ad6', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-07-04', '18:40:00', null, '通常 / 親子大会', '親子大会に向けて、お弁当のゲームの作成を進めました。 お弁当を作った後、ピクニックに行くことを選択するとハッピーエンド画面、学校にいくことを選択するとバッドエンド画面に移るというゲームにするようです。 授業の最初では友達とふざけあっている場面もありましたが、お弁当の具材を選択すると自分の声が流れるようにしたり「キャラ弁だ」といってご飯に人の顔を張り付けるなど、本人なりに楽しみながら作成することができていました。 またハッピーエンド、バッドエンドの画面についてはipadのドット絵メーカーで自作することにして、後半は絵を描いていました。 次回は絵の続きから始められるとよいと思います。', null, null),
  ('076bb514-7533-5439-bc55-95ffbf76731f', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-04', '17:30:00', null, '通常 / excel', 'あまり詰まることもなく進められました。グラフや印刷の設定をよく理解し、細かい指示も読み落とさずに取り組めました。最後はファイルを自分でドライブに上げてくれました。', null, null),
  ('223cd103-3ba5-5338-a24e-54885faff9ff', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-04', '18:40:00', null, '通常 / クイズゲーム完成', '今日から本格的に自分のrobloxアカウント/デジタネアカウントでやり始めました。cancollideやprint関数を扱い、手際よく作業を進めました。動画の内容をしっかり吸収しようとしていたため、バグなどもなくゲームは完成して、確認テストでも重要用語はきちんと覚えていました。', null, null),
  ('760e56a3-743d-57dd-be47-af67c8feb52c', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-07-04', '18:40:00', null, '通常 / エクセル', 'エクセルの練習問題02~03の途中まで終えました。集中を欠かすことなく黙々と取り組んでいました。 途中フッターやヘッダーの表記を変える方法がわからないなど細かい質問はありましたが、表やグラフの作成はテキストを参考に問題なく理解できているようでした。', null, null),
  ('269d1665-3dd7-53f9-89af-15a6f440cd14', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-04', '18:40:00', null, '通常 / クイズ完成', 'クイズrobloxの続きをやりました。クイズを3問作るところで、手ごたえのある難易度になるようにじっくり考えていました。ゲーム作成自体はできるようになりましたが、確認テストに出てくる用語「関数」「プロパティ」などを覚えていなかったので復習し、無事満点を取りました。', null, null),
  ('59a50dc0-7d3f-5ebe-a35d-57c25ab9a092', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-05', null, null, '通常 / ロブロックススタジオ', '前回に引き続きレインボーブリッジを作ろう。Roblox studioでエクスプローラーが表示されていないとかで質問が何回かありましたが、動画の内容自体は順調に進められたようで、動画の最後まで完了させられました。ただ、確認テストまでは終了していないので、次回は、確認テストで復習をしてから次の動画に進むようにすれば良いと思います。', null, '時間帯: その他
タイピング: 集中して取り組んでいました'),
  ('ae6414bd-f20c-543d-a559-476d8206ce3c', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-07-05', '16:30:00', null, '通常 / 親子大会作品', '制作をただ何となく進める前に、今日はどこまで進めるか目的をはっきりさせたことで脱線せずに制作を進められたと思います。今回の時間ではホラーな背景を作ること、時間があればアニメーションも完成させることが目標で、最終的にアニメーション制作の途中まで進めていました。背景はipadで描いてもらいました。', null, 'タイピング: 久々にタイピングをしてくれました。練習と特訓をそれぞれ1回ずつやって満足していました。'),
  ('6244d7f8-f29a-5309-a84a-8d8944c8036a', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, null, '2025-07-05', null, null, '通常 / 親子大会作品制作', 'ほとんど自分で黙々と進めていたようです。テーマがまだ決まっておらず、 とりあえずシューティングゲーム形式のものを作っているようですが、大会の趣旨に沿ったものではなくまずは自由なものを作りたいとのことです。 どこかのタイミングで今作っているものが大会のテーマに沿っているのか、またどうすればテーマに沿えるのかという確認が必要かと思います。', null, '時間帯: その他
タイピング: なし'),
  ('1be3d165-6724-5e49-b8be-5c52ae26eecc', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-05', null, null, '通常 / 学習目標をきちんと達成する', 'スプライトで円を描いてぐだーっとしていたので、今日は基本操作コース4のカードを終わらせよう、と声をかけ、最初のページを見せました。左右に動かすのは覚えていると言ったことをちょっとオーバーにほめたところ、得意になって始めてくれました。 自分でできるかな？というと、「わからないところもあるかも」と返してきますが、イベントのブロックと、どちらの座標を使うかということはわかっていたので、そこを褒めた上で、座標の確認をしました。〇ずつ変える、と、〇にする、との違いがまだ少しあやふやです。繰り返し確認して定着させてほしいです。 途中でスプライトの大きさを変えることにハマったりもしましたが、あえて否定せずに最小値と最大値を探させたところ、面白がっていました。 変数の学習では、「ゲームで見たことがある！」と喜んでいました。 自分でプレイをしてみて、変数を最初に0にする必要があることにも気づくことができ、ブロックを入れる場所も自分で考えることができました。 スタンプを押すときだけ、ギューギューと押し付けて真っ赤にしていましたが、授業中のパソコンの扱いは乱暴にすることもなく、席を立つこともなく、45分間しっかりと授業を受けることができました。 最後の15分間は、ご褒美でゲームタイムにしました。イチゴの反乱やスネークゲームをやっていました。', null, '時間帯: その他
タイピング: 先生が目を離すとキーボードをガチャガチャやっていました
盛り上がり: 褒められたことに対して得意げに作業を進める感じで、しっかりと授業をすることができました。ゲームを完成することができて、ゆきとくんも達成感が得られたのではないかと思います。'),
  ('0bb3a62a-3928-5b23-8997-231ccf78b6cd', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-05', null, null, '通常 / ロブロックススタジオ', 'Robloxのアカウントを忘れてしまったようで、it自由研究室のアカウントで進めてもらいました。動画の中身は、特に質問もなく、黙々と進められました。大体６０％位完了したところで今日は終了となりました。次回は続きからとなりますが、自分のアカウントでやるとなると、途中まで作ったデータがないので、進め方は完成形を持ってくるなどして、何かしら対応が必要かもしれません。', null, '時間帯: その他
タイピング: 集中して取り組んでいました'),
  ('30103802-44c6-5635-a7ea-35111ad267d5', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-05', null, null, '通常 / ロブロックススタジオ', '途中何回か状況確認するも、特に何の質問もなく、順調に進めらたようです。今回の動画も、80%くらい進められました。次回は続きからとなります。スクリプトで色の変え方をしっかり復習して進められたらと思います。', null, '時間帯: その他
タイピング: 集中して取り組んでいました'),
  ('ac6dc0b4-de00-5727-9ecf-84ae190ac765', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-07-05', '17:30:00', null, '通常 / 親子大会作品制作', 'ゲームがどのようなフローでどう作るべきか、を本人と確認する時間にほとんど当ててしまったため作業が停滞しています。本人の頭の中ではどうしてこのスクリプトが入っているのか、ゲームをどうプレイしてもらうのかは入っているようですが、影武者を使ってどう制作するかは本人も周囲にいた講師陣も整理出来ていない状態でした。 そのため、次回は以下の方法で制作を提案する予定です。 ※可能であれば始める前にまず講師同士で影武者での制作方法について話し合い、もし影武者の方法が理に適ったものであるなら、変更せずにそのままの方法で進めてください。 ①元の多角形のパズルを正方形のピースにし、正方形で区切られたパズルを完成させるゲームにする。 ②画像をもう一度正方形の形に沿って切断させる(9ピース程度)。 ③各ピースごとのスプライトに正解の座標(±10~15程度)を設定し、ピースを設定された座標付近にドラッグすると正解の座標に自動的に配置されるようにする。 ④難易度が簡単すぎる場合、天狗の描かれた正方形のスプライトの向きをランダムに変えた状態でスタートをさせる。 ⑤プレイヤーが角度を変える場合はクリックで角度が変えれるようにする。', null, 'タイピング: なし'),
  ('52ff94e4-3e45-50cb-ae5f-2a68e70c6181', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-05', null, null, '通常 / PRG09', '最初に遊んでもらって、実際に、ゲームを作ってもらいました。ネズミをマウスに連動して動かす方法、猫をランダムの方向に動かして壁で反射する方法、説明するもの、大体すべてきちんと瞬時に理解できていました。飲み込みはとても良いと思います。今回、このPRG09を時間内に、完成させることができ、覚えるべきこともしっかり覚えられたと思います。', null, '時間帯: その他
タイピング: 低学年としてはかなり早いタイピングだと思います。上位９％位でした'),
  ('85fa1c2b-0418-5a3f-80e2-ef00e7adabe1', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-05', null, null, '通常 / U16作品作り', 'オリジナルゲームを黙々と作成していました。ゲームの内容を聞いてみたところ、２Dで見える部分を、軸切り替えで、別の視点から見えるようになって、何かをするみたいなのですが、具体的に、何をするのか？何をすればゲームクリアなのか？ゲームのウリはなんなのか？みたいなものがまだ決まっていないみたいで、その辺をある程度イメージしてから作ったほうが良いかもね。。。とアドバイスをしました。ひとまず、今進めているところ進めてもらいつつも、並行して、きちんと上記のことを考えてねと伝えておきました。ただ、ゲームの見た目等は良い感じになっていると思います。', null, '時間帯: その他'),
  ('5f7f8b89-9869-5b18-9789-e308901753f8', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-07-07', '16:30:00', null, '通常 / 大会作品制作', '今回から大会作品の制作を開始していくということで，既存の作品をアレンジしていく方針で進めていきました．内容としては，ピンポンゲームの作品をアレンジして，ブロック崩しとして作っていくことのことでした．本日は，ボールを２つに増やしゲームとしての難易度上昇と，ステージのデザイン変更を行っていきました．次回で，ブロック崩しのブロック部分をクローンして破壊可能状態にすることで完成まで持っていきたいです．', null, null),
  ('d0dc7c10-3af6-546d-8657-ff476f306096', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-07', '16:30:00', null, '通常 / 親子大会の作品作り', 'オリジナルのイラストでスマブラ風のゲームへの変換を行っていきました。元イラストを置き換えたり、必殺技の大きさ調整をバグが起きないように手探り調整してくれました。途中で、岳君からの誘惑もありましたが、やってほしいところは最後までやってくれました。タコボンドの方だけy座標が-175以下よりいかないバグがのこってしまってここはバグ探し検討中です。', null, null),
  ('3948cbe7-2316-5d4a-949c-b8e1ec2241e3', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-07', '16:30:00', null, '通常 / 親子大会作品作り', '前回まで、ほとんど進んでいなかった気がしたので、強行的に今回は進めることができました。クイズを出題し、クリックしたら製誤判定をするところまではできていましたが、次に進むことがあやふやでコードを探して来いと指示しても気が背いてしまうことがあったので、前までは進んでいかなかった気がします。なので、今回は、使いたいコードを先に手元に出して、コードについて考えさせる時間を与えました。がくくんは知識はまあまあ蓄えている方なので、「まで待つ」コードの機能を理解して、すぐ組み立てられる流れを作ることができました。これで、1問の流れを作ることができたので、さいしょのがくくん想定の3問までできました。次回EDを作るとのこと言っていましたが、もう少し問題を出してほしい所です。', null, null),
  ('57dae43d-6883-5990-8ce0-9b3beae54152', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-07', '17:30:00', null, '通常 / ロブロックス', '毎度のことながら、早く来て授業始まるときには確認テストをやっていきました。途中robloxstudioが落ちてやり直す場面がありましたが、コードの間隔は途切れずに作り切れていました。次で、ステージ1の部分が終わりそうです。', null, null),
  ('dd3050ab-166e-5887-8947-6548206fde2e', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-07-07', '17:30:00', null, '通常 / 大会作品制作', '大会作品制作の続きを進めていきました．電車のデザインには特にこだわっているようで，今回の時間を全て使って作成していました．システム部分は既に完成しているようなので，次回もデザイン部分に取り組んでいくと思います．ゲームとしてのオリジナル性に少し欠ける部分があると感じたため，可能であれば新たな要素の追加を行えればなお良いと感じました．', null, null),
  ('c1d3e085-84e4-5e7d-a450-bb4b350ff1e6', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-05', '17:30:00', null, '通常 / Excel検定の準備', '今日も来室するなり、忙しそうにガサガサ探検隊関係？の仕事をしていました。 教室のPCのパスワードは知ってるみたいですね💦自分でログインしてました。 授業時間になった際に、生徒として来ている時間は生徒として授業を受けてみようと声掛けをしたところ、やりたいことがあるので半分くらいなら、という感じで了承したので、Excelの実習問題を2題やりました。質問はなく、自分でできたと自己申告してきたので保存をさせ、あとは好きなように作業をさせました。', null, '盛り上がり: Excelもやってくれてはいますが、やはりお仕事モードの方が生き生きとして積極的に動いていました。'),
  ('5dec77d3-d681-553f-8604-04779f3abdba', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-04', '16:30:00', null, '通常 / 親子大会', '改めて提出の意志を再確認したところ、出すとはっきり言ってくれました。今日の目標として第二ステージから第三ステージに移行する部分を作成することを確認して始めました。一度テストプレイして、何のキャラをどう直せばいいのか把握してもらい、修正に入りました。同一のメッセージを色々なところで送ってしまっていたので、メッセージは一か所で合図として送ってあとはみんな受け取ればいいことを伝えて参考にしてもらいました。ただ中盤で眠くなり集中力が落ちてしまったので、お散歩に行ってリフレッシュすると再び力を取り戻せました。', null, 'タイピング: 授業最後にやるスタイルで取り組んでいました'),
  ('340ce06c-ef4f-5ef0-8675-dc337d9ab058', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-04', '17:30:00', null, '通常 / roblox', '動画学習を促しましたがやはりやる気がないようでした。roblox studioで自分のゲーム(シューティング系？)を作りたいと言って、ずっとその制作を集中してやっていました。授業最後にデジタネの確認テストだけはすぐ終わるからやってみようと伝えましたが、それも受け入れてくれませんでした。スキルのインプットがまだあまりできていないので、自由製作に役立ちそうな部分から学んでいくのも選択肢だと感じました。', null, null),
  ('4dbc47bb-f494-5bdb-a333-5ccbdd37c26c', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-04', '17:30:00', null, '通常 / スキルチェック', 'スキルチェックとしてレベル1の最初の問題をやってもらったところ、やる気を持って取り組んでくれました。ただ最後までやって答え合わせすると20問中6問正解で、思ったよりできていなかったと少し落ち込んでしまいました。そこで、見慣れない形式でいきなりだと難しいから大丈夫だよと伝えて間違えた場所の復習に移りました。すると4択から2択へのしぼりこみは結構自力でできていたので自信を持ってもらいました。動作の順番や繰り返しの中身など、抜けていたポイントをしっかり理解して終わることができました。', null, null),
  ('c03d1491-49fa-5e58-9af1-3ad6432aaeef', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-05', null, null, '通常 / 親子大会作品の作成続き', '作成自体は順調で、バグも自分で検証して、メッセージ名の間違いに気づいて直していました。 自分で思いついたアイディアをすぐにコードにして実行しては、面白がったり、やっぱりなんか違うと言って消したりと、ひっきりなしに手を加えていました。 やりたいことを次々と思いつくのはすごいところですが、計算シューティングゲームとしての面白さがあるので、あまりに方向性が違うことをやってしまうとテーマがぼやけてしまいかねないかな？ゲームの方向性はある程度一貫性があった方が良いかも？', null, '時間帯: その他
盛り上がり: とにかくいじってみるのが楽しくて仕方ない、という感じでした。計算についても熱心に説明してくれました。'),
  ('081830e0-d61a-59c1-89dc-70b8e31cbf3c', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-07-08', '18:40:00', null, '通常 / 親子大会', '今回は主にクイズ問題を増やしました。難読漢字バージョンと都道府県の読み方バージョンを二つ作って、どっちを提出するかは直前で決めると言い出したので、それなら難読漢字と都道府県どちらも一つのゲームにして２セクション制にしたらどうかと提案したらその方向で制作していました。 また、旗を押すとノータイムでゲームが始まるためスタート画面を作ることを提案するとあまり乗り気ではなさそうでしたが作っていました。 ゲーム部分のプログラミングが終わっていてグラフィックも少し修正する程度なため本人はもうほとんど完成している気分なようで、前回より関心が薄まっているような雰囲気がありました。 モノとしても完成に近くはあるので、次回はスタート画面やゲーム終了時の処理を付け加えていければよいと思います。', null, null)
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
